function setGameUIFont() {
    if (typeof CodeaLite === "undefined" || !CodeaLite.state) {
        return;
    }

    CodeaLite.state.fontName =
        '"Zen Kaku Gothic New", "Hiragino Sans", "Noto Sans JP", sans-serif';
}

function installColaRollUnicodeNfcText() {
    const root =
        typeof globalThis !== "undefined"
            ? globalThis
            : (
                typeof window !== "undefined"
                    ? window
                    : {}
            );

    if (
        root.__colaRollUnicodeNfcTextInstalled
    ) {
        return;
    }

    if (
        typeof text !== "function"
    ) {
        return;
    }

    root.__colaRollUnicodeNfcTextInstalled =
        true;

    function normalizeColaRollText(
        value
    ) {
        if (
            typeof value !== "string" ||
            typeof value.normalize !==
                "function"
        ) {
            return value;
        }

        return value.normalize(
            "NFC"
        );
    }

    /*
     * Codea Lite の text() を一度だけ包む。
     *
     * 「か」+ 結合濁点 のような分解形を、
     * 描画直前に通常の「が」へ統一する。
     *
     * データ内容そのものは変更しないため、
     * 既存の判定・名前生成・レア条件には影響しない。
     */
    const textBaseForUnicodeNfc =
        text;

    text = function(
        value,
        x,
        y
    ) {
        return textBaseForUnicodeNfc(
            normalizeColaRollText(
                value
            ),
            x,
            y
        );
    };
}




function strokeCap(
    mode
) {
    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        return;
    }

    let capStyle =
        "butt";

    if (
        mode === "round" ||
        mode === "ROUND" ||
        mode === ROUND
    ) {
        capStyle =
            "round";
    } else if (
        mode === "square" ||
        mode === "SQUARE" ||
        mode === SQUARE
    ) {
        capStyle =
            "square";
    } else if (
        mode === "project" ||
        mode === "PROJECT" ||
        mode === PROJECT
    ) {
        capStyle =
            "square";
    }

    nativeContext.lineCap =
        capStyle;
}

function strokeWeight(
    value
) {
    /*
     * BoardIconRefresh 内で使った
     * strokeWeight を、Codea Lite 側の
     * strokeWidth へつなぐ互換処理。
     */
    return strokeWidth(
        value
    );
}


