function touched(touch) {
    try {
        /*
         * マップ取っ手は「押している間」を扱うため、
         * ENDEDだけに絞る既存処理より先に
         * BEGAN / MOVING / ENDEDをすべて受け取る。
         */
        if (
            typeof colaRollHandleMapOverviewTouch ===
                "function" &&
            colaRollHandleMapOverviewTouch(
                touch
            )
        ) {
            return;
        }

        if (touch.state !== ENDED) {
            return;
        }

        const languageButton =
            getLanguageButtonRect();

        if (
            gameState.phase === "TITLE" &&
            touch.x >=
                languageButton.x &&
            touch.x <=
                languageButton.x +
                languageButton.w &&
            touch.y >=
                languageButton.y &&
            touch.y <=
                languageButton.y +
                languageButton.h
        ) {
            colaRollHandleLanguagePlateTouch(
                touch
            );

            return;
        }

        if (
            gameState.phase ===
            "TITLE_TRANSITION"
        ) {
            return;
        }

        if (gameState.phase === "RESULT") {
            /*
             * 記録メニューが背後の素材や
             * 補充ボタンへ入力を渡さないよう、
             * RESULT入力の先頭で処理する。
             */
            if (
                colaRollHandleResultRecordTouch(
                    touch
                )
            ) {
                return;
            }

            const ingredientHit =
                getResultIngredientHitAt(
                    touch.x,
                    touch.y
                );

            if (ingredientHit) {
                showResultIngredientTooltip(
                    ingredientHit
                );

                return;
            }

            const button =
                getResultRestartButtonRect();

            if (
                touch.x >= button.x &&
                touch.x <= button.x + button.w &&
                touch.y >= button.y &&
                touch.y <= button.y + button.h
            ) {
                restartGame();
            }

            return;
        }

        if (gameState.phase === "TITLE") {
            startTitleTransition();
            return;
        }

        if (
            gameState.phase ===
                "WAIT_EVENT_ROLL" &&
            pointInsidePanel(
                touch.x,
                touch.y,
                layout.cap
            )
        ) {
            rollEventDice();
            return;
        }

        if (
            gameState.phase ===
                "WAIT_MYSTERY_ROLL" &&
            pointInsidePanel(
                touch.x,
                touch.y,
                layout.cap
            )
        ) {
            startMysteryRoulette();
            return;
        }

        if (
            gameState.phase ===
                "WAIT_CAP_POWER" &&
            pointInsidePanel(
                touch.x,
                touch.y,
                layout.cap
            )
        ) {
            /*
             * 起動中の早押しも含め、
             * 確定前の処理は lockCapPower() に集約する。
             */
            lockCapPower(
                touch.x
            );
        }
    } catch (error) {
        captureGameDebugError(
            error,
            "touched"
        );
    }
}



function pointInsidePanel(x, y, panel) {
    return (
        x >= panel.x &&
        x <= panel.x + panel.w &&
        y >= panel.y &&
        y <= panel.y + panel.h
    );
}

/*
 * ============================================================
 * 工房マップ俯瞰機能・第1段階
 * 独立機能ブロック
 * ============================================================
 *
 * 既に反映済みの以下の処理から呼び出される。
 *
 * - updateBoardCamera()
 * - touched()
 * - drawBoardPanel()
 *
 * このブロックは、それらが利用する関数本体だけを
 * 一か所へまとめて追加する。
 *
 * 操作:
 * - 盤面上下の真鍮の取っ手を押す
 * - 押している間だけ工房全体へズームアウト
 * - 指を離すと現在地へ戻る
 *
 * 第1段階では上下スクロールとバネ復帰は入れない。
 */


function colaRollEnsureMapOverviewState() {
    if (!gameState) {
        return null;
    }

    if (!gameState.mapOverview) {
        gameState.mapOverview = {
            active: false,

            progress: 0,
            targetProgress: 0,

            source: null,

            /*
             * 第2段階：
             * 俯瞰中の縦スクロール。
             */
            scrollY: 0,
            targetScrollY: 0,

            touchStartY: 0,
            lastTouchY: 0,
            dragged: false,
        };
    }

    return gameState.mapOverview;
}



function colaRollMapOverviewClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            Number(value) || 0
        )
    );
}


function colaRollMapOverviewSmooth(
    value
) {
    const t =
        colaRollMapOverviewClamp(
            value
        );

    return (
        t *
        t *
        (
            3 -
            2 * t
        )
    );
}


/*
 * Codea Lite側のタッチ定数が数値でも文字列でも
 * 判定できるようにする。
 */
function colaRollMapOverviewTouchStateIs(
    touch,
    stateName
) {
    if (!touch) {
        return false;
    }

    const value =
        touch.state;

    if (
        String(value).toUpperCase() ===
        String(stateName).toUpperCase()
    ) {
        return true;
    }

    const root =
        typeof globalThis !== "undefined"
            ? globalThis
            : (
                typeof window !== "undefined"
                    ? window
                    : {}
            );

    const constant =
        root[stateName];

    return (
        constant !== undefined &&
        value === constant
    );
}


function colaRollMapOverviewIsGameplayPhase() {
    if (
        !gameState ||
        !layout ||
        !layout.board
    ) {
        return false;
    }

    const blockedPhases = {
        TITLE: true,
        TITLE_TRANSITION: true,
        NIGHT_DISPATCH: true,
        RESULT: true,
        DELIVERY_COMPLETE: true,
        BOTTLE_HISTORY: true,
        HISTORY: true,
    };

    return !blockedPhases[
        gameState.phase
    ];
}


function colaRollGetMapOverviewHandleRects() {
    const panel =
        layout &&
        layout.board
            ? layout.board
            : null;

    if (!panel) {
        return {
            top: null,
            bottom: null,
        };
    }

    const handleWidth =
        Math.min(
            70,
            panel.w * 0.25
        );

    /*
     * 見た目より当たり判定を少し大きくして、
     * iPhoneでも押しやすくする。
     */
    const hitHeight =
        28;

    const centerX =
        panel.x +
        panel.w * 0.5;

    return {
        top: {
            x:
                centerX -
                handleWidth * 0.5,

            y:
                panel.y +
                panel.h -
                hitHeight,

            w:
                handleWidth,

            h:
                hitHeight,
        },

        bottom: {
            x:
                centerX -
                handleWidth * 0.5,

            y:
                panel.y,

            w:
                handleWidth,

            h:
                hitHeight,
        },
    };
}


function colaRollMapOverviewHit(
    touch,
    rectInfo
) {
    return !!(
        touch &&
        rectInfo &&
        touch.x >= rectInfo.x &&
        touch.x <=
            rectInfo.x +
            rectInfo.w &&
        touch.y >= rectInfo.y &&
        touch.y <=
            rectInfo.y +
            rectInfo.h
    );
}


function colaRollGetMapOverviewBounds() {
    if (
        typeof BOARD_NODES ===
            "undefined" ||
        !BOARD_NODES
    ) {
        return null;
    }

    const nodes =
        Object.values(
            BOARD_NODES
        );

    if (nodes.length <= 0) {
        return null;
    }

    let minX =
        Infinity;

    let maxX =
        -Infinity;

    let minY =
        Infinity;

    let maxY =
        -Infinity;

    for (
        const node of nodes
    ) {
        if (
            !node ||
            typeof node.nx !==
                "number" ||
            typeof node.ny !==
                "number"
        ) {
            continue;
        }

        const worldX =
            node.nx *
            CONFIG.mapWidth;

        const worldY =
            node.ny *
            CONFIG.mapHeight;

        minX =
            Math.min(
                minX,
                worldX
            );

        maxX =
            Math.max(
                maxX,
                worldX
            );

        minY =
            Math.min(
                minY,
                worldY
            );

        maxY =
            Math.max(
                maxY,
                worldY
            );
    }

    if (
        !Number.isFinite(minX) ||
        !Number.isFinite(maxX) ||
        !Number.isFinite(minY) ||
        !Number.isFinite(maxY)
    ) {
        return null;
    }

    return {
        minX: minX,
        maxX: maxX,
        minY: minY,
        maxY: maxY,

        centerX:
            (
                minX +
                maxX
            ) *
            0.5,

        centerY:
            (
                minY +
                maxY
            ) *
            0.5,
    };
}


function colaRollGetMapOverviewZoom(
    bounds
) {
    const normalZoom =
        HEIGHT > WIDTH
            ? 0.96
            : 1.02;

    if (
        !bounds ||
        !layout ||
        !layout.board
    ) {
        return normalZoom * 0.62;
    }

    const panel =
        layout.board;

    const worldWidth =
        Math.max(
            1,
            bounds.maxX -
                bounds.minX
        );

    /*
     * 全体を一画面へ押し込まず、
     * 盤面の横幅を85％ほど使う倍率にする。
     *
     * 縦方向はドラッグして確認する。
     */
    const horizontalPadding =
        Math.max(
            58,
            (
                CONFIG.nodeSize ||
                24
            ) *
                2.8
        );

    const widthZoom =
        (
            panel.w -
            34
        ) /
        (
            worldWidth +
            horizontalPadding * 2
        );

    /*
     * 以前の完全俯瞰倍率より大きくし、
     * アイコンと配管を読み取れる大きさに保つ。
     */
    return Math.max(
        normalZoom * 0.54,
        Math.min(
            normalZoom * 0.72,
            widthZoom
        )
    );
}

function colaRollGetMapOverviewScrollRange(
    bounds,
    overviewZoom
) {
    if (
        !bounds ||
        !layout ||
        !layout.board
    ) {
        return {
            min: 0,
            max: 0,
        };
    }

    const panel =
        layout.board;

    const worldHeight =
        Math.max(
            1,
            bounds.maxY -
                bounds.minY
        );

    const visibleWorldHeight =
        panel.h /
        Math.max(
            0.001,
            overviewZoom
        );

    /*
     * 上下端のノードが取っ手に隠れないよう、
     * 少し余白を残す。
     */
    const edgePadding =
        74 /
        Math.max(
            0.001,
            overviewZoom
        );

    const overflow =
        Math.max(
            0,
            (
                worldHeight +
                edgePadding * 2 -
                visibleWorldHeight
            ) *
                0.5
        );

    return {
        min:
            -overflow,

        max:
            overflow,
    };
}


function colaRollClampMapOverviewScroll(
    value,
    range
) {
    return Math.max(
        range.min,
        Math.min(
            range.max,
            value
        )
    );
}


function colaRollResistMapOverviewScroll(
    value,
    range
) {
    if (value < range.min) {
        return (
            range.min +
            (
                value -
                range.min
            ) *
                0.24
        );
    }

    if (value > range.max) {
        return (
            range.max +
            (
                value -
                range.max
            ) *
                0.24
        );
    }

    return value;
}




function colaRollUpdateMapOverviewProgress() {
    const overview =
        colaRollEnsureMapOverviewState();

    if (!overview) {
        return null;
    }

    overview.targetProgress =
        overview.active
            ? 1
            : 0;

    const delta =
        typeof DeltaTime ===
            "number"
            ? DeltaTime
            : 1 / 60;

    const zoomSpeed =
        overview.active
            ? 7.2
            : 9.4;

    overview.progress +=
        (
            overview.targetProgress -
            overview.progress
        ) *
        Math.min(
            1,
            delta * zoomSpeed
        );

    /*
     * 指を離したあとは、
     * スクロール量も静かに中央へ戻す。
     */
    if (!overview.active) {
        overview.scrollY +=
            (
                0 -
                overview.scrollY
            ) *
            Math.min(
                1,
                delta * 8.6
            );
    } else if (
        !overview.dragged
    ) {
        overview.scrollY +=
            (
                overview.targetScrollY -
                overview.scrollY
            ) *
            Math.min(
                1,
                delta * 10
            );
    }

    if (
        Math.abs(
            overview.targetProgress -
            overview.progress
        ) < 0.001
    ) {
        overview.progress =
            overview.targetProgress;
    }

    if (
        !overview.active &&
        Math.abs(
            overview.scrollY
        ) < 0.01
    ) {
        overview.scrollY =
            0;
    }

    return overview;
}



function colaRollHandleMapOverviewTouch(
    touch
) {
    if (
        !touch ||
        !colaRollMapOverviewIsGameplayPhase()
    ) {
        return false;
    }

    const overview =
        colaRollEnsureMapOverviewState();

    if (!overview) {
        return false;
    }

    const handles =
        colaRollGetMapOverviewHandleRects();

    const began =
        colaRollMapOverviewTouchStateIs(
            touch,
            "BEGAN"
        );

    const moving =
        colaRollMapOverviewTouchStateIs(
            touch,
            "MOVING"
        ) ||
        colaRollMapOverviewTouchStateIs(
            touch,
            "CHANGED"
        );

    const ended =
        colaRollMapOverviewTouchStateIs(
            touch,
            "ENDED"
        ) ||
        colaRollMapOverviewTouchStateIs(
            touch,
            "CANCELLED"
        );

    if (began) {
        let source =
            null;

        if (
            colaRollMapOverviewHit(
                touch,
                handles.top
            )
        ) {
            source =
                "top";
        } else if (
            colaRollMapOverviewHit(
                touch,
                handles.bottom
            )
        ) {
            source =
                "bottom";
        }

        if (source) {
            const bounds =
                colaRollGetMapOverviewBounds();

            const zoom =
                colaRollGetMapOverviewZoom(
                    bounds
                );

            const range =
                colaRollGetMapOverviewScrollRange(
                    bounds,
                    zoom
                );

            overview.active =
                true;

            overview.source =
                source;

            overview.touchStartY =
                touch.y;

            overview.lastTouchY =
                touch.y;

            overview.dragged =
                false;

            /*
             * 上の取っ手なら上側、
             * 下の取っ手なら下側から見始める。
             *
             * ただし端まで飛ばさず、
             * 中央寄りから自然に開始する。
             */
            overview.targetScrollY =
                source === "top"
                    ? range.max * 0.52
                    : range.min * 0.52;

            overview.scrollY =
                overview.targetScrollY;

            return true;
        }

        return (
            overview.progress >
            0.001
        );
    }

    if (
        overview.active &&
        moving
    ) {
        const bounds =
            colaRollGetMapOverviewBounds();

        const zoom =
            colaRollGetMapOverviewZoom(
                bounds
            );

        const range =
            colaRollGetMapOverviewScrollRange(
                bounds,
                zoom
            );

        const deltaY =
            touch.y -
            overview.lastTouchY;

        overview.lastTouchY =
            touch.y;

        if (
            Math.abs(
                touch.y -
                overview.touchStartY
            ) > 4
        ) {
            overview.dragged =
                true;
        }

        /*
         * 指の移動量をワールド座標へ変換。
         *
         * 指を上へ動かすと、
         * マップの下側を見られる。
         */
        const worldDelta =
            deltaY /
            Math.max(
                0.001,
                zoom
            );

        overview.targetScrollY =
            colaRollResistMapOverviewScroll(
                overview.targetScrollY -
                    worldDelta,
                range
            );

        overview.scrollY =
            overview.targetScrollY;

        return true;
    }

    if (
        ended &&
        (
            overview.active ||
            overview.progress >
                0.001
        )
    ) {
        overview.active =
            false;

        overview.source =
            null;

        overview.dragged =
            false;

        /*
         * 指を離したら、
         * スクロール位置も現在地復帰に備えて戻す。
         */
        overview.targetScrollY =
            0;

        return true;
    }

    if (overview.active) {
        return true;
    }

    return (
        overview.progress >
        0.001
    );
}



function colaRollDrawMapOverviewHandle(
    rectInfo,
    active,
    position
) {
    if (!rectInfo) {
        return;
    }

    const visualHeight =
        15;

    const cx =
        rectInfo.x +
        rectInfo.w * 0.5;

    /*
     * 当たり判定の中央ではなく、
     * パネル枠へ寄せて描く。
     */
    const cy =
        position === "top"
            ? rectInfo.y +
                rectInfo.h -
                visualHeight * 0.5 -
                3
            : rectInfo.y +
                visualHeight * 0.5 +
                3;

    const pressOffset =
        active
            ? (
                position === "top"
                    ? -1.5
                    : 1.5
            )
            : 0;

    rectMode(CENTER);

    /*
     * 影。
     */
    noStroke();

    fill(
        5,
        3,
        2,
        145
    );

    rect(
        cx,
        cy - 2,
        rectInfo.w,
        visualHeight,
        7
    );

    /*
     * 真鍮本体。
     */
    fill(
        active
            ? 108
            : 82,
        active
            ? 67
            : 50,
        active
            ? 36
            : 28,
        245
    );

    rect(
        cx,
        cy +
            pressOffset,
        rectInfo.w,
        visualHeight,
        7
    );

    noFill();

    stroke(
        active
            ? 232
            : 188,
        active
            ? 165
            : 119,
        active
            ? 89
            : 57,
        active
            ? 225
            : 180
    );

    strokeWidth(
        active
            ? 1.8
            : 1.2
    );

    rect(
        cx,
        cy +
            pressOffset,
        rectInfo.w - 2,
        visualHeight - 2,
        6
    );

    /*
     * 指を掛ける中央の溝。
     */
    stroke(
        240,
        190,
        118,
        active
            ? 190
            : 105
    );

    strokeWidth(1);

    line(
        cx -
            rectInfo.w * 0.20,
        cy +
            pressOffset,
        cx +
            rectInfo.w * 0.20,
        cy +
            pressOffset
    );

    noStroke();
    rectMode(CORNER);
}


function colaRollDrawMapOverviewHandles() {
    if (
        !colaRollMapOverviewIsGameplayPhase()
    ) {
        return;
    }

    const overview =
        colaRollEnsureMapOverviewState();

    const handles =
        colaRollGetMapOverviewHandleRects();

    colaRollDrawMapOverviewHandle(
        handles.top,
        !!(
            overview &&
            overview.active &&
            overview.source ===
                "top"
        ),
        "top"
    );

    colaRollDrawMapOverviewHandle(
        handles.bottom,
        !!(
            overview &&
            overview.active &&
            overview.source ===
                "bottom"
        ),
        "bottom"
    );
}


function isShotGaugeStartupActive() {
    return !!(
        gameState &&
        gameState.shotGaugeStartup &&
        gameState.shotGaugeStartup.active
    );
}

function finishShotGaugeStartupForEarlyTap() {
    const startup =
        gameState &&
        gameState.shotGaugeStartup;

    if (
        !startup ||
        !startup.active
    ) {
        return;
    }

    /*
     * 起動の見た目だけをその場で完了させる。
     * 針の現在位置は変えないので、
     * 早押しならその位置の弱いショットになる。
     */
    startup.active =
        false;

    startup.elapsed =
        startup.duration;

    startup.tickProgress =
        1;

    startup.ringProgress =
        1;

    startup.ringAlpha =
        0;

    startup.labelAlpha =
        1;
}


function getLanguageButtonRect() {
    const width = 76;
    const height = 24;
    const margin = 8;

    const resultOffset =
        gameState.phase === "RESULT"
            ? 44
            : 0;

    return {
        x:
            WIDTH -
            margin -
            width,

        y:
            HEIGHT -
            margin -
            height -
            resultOffset,

        w: width,
        h: height,
    };
}



function updateCapPower() {
    const cap = gameState.cap;

    cap.power +=
        cap.powerDirection *
        CONFIG.capGaugeSpeed *
        DeltaTime;

    if (cap.power >= 1) {
        cap.power = 1;
        cap.powerDirection = -1;
    } else if (cap.power <= 0) {
        cap.power = 0;
        cap.powerDirection = 1;
    }
}


function updateCapSlide() {
    const cap =
        gameState.cap;

    const slide =
        gameState.capSlide;

    if (!slide) {
        finishCapPowerSlide();
        return;
    }

    const dt =
        Math.min(
            0.05,
            Math.max(
                0,
                DeltaTime
            )
        );

    slide.elapsed +=
        dt;

    const progress =
        Math.min(
            1,
            slide.elapsed /
                slide.duration
        );

    cap.power +=
        slide.velocity *
        dt;

    const wobbleStrength =
        CAP_SLIDE_CONFIG.wobbleAmplitude *
        (
            1 -
            progress
        );

    cap.power +=
        Math.sin(
            slide.elapsed *
                CAP_SLIDE_CONFIG.wobbleFrequency +
            slide.phase
        ) *
        wobbleStrength *
        dt *
        8;

    if (cap.power >= 1) {
        cap.power = 1;

        slide.velocity =
            -Math.abs(
                slide.velocity
            ) *
            CAP_SLIDE_CONFIG.boundaryBounce;

        cap.powerDirection =
            -1;
    } else if (
        cap.power <= 0
    ) {
        cap.power = 0;

        slide.velocity =
            Math.abs(
                slide.velocity
            ) *
            CAP_SLIDE_CONFIG.boundaryBounce;

        cap.powerDirection =
            1;
    } else if (
        Math.abs(
            slide.velocity
        ) >
        0.001
    ) {
        cap.powerDirection =
            slide.velocity >= 0
                ? 1
                : -1;
    }

    slide.velocity *=
        Math.pow(
            CAP_SLIDE_CONFIG.friction,
            dt * 60
        );

    if (
        progress >= 1 ||
        Math.abs(
            slide.velocity
        ) <=
            CAP_SLIDE_CONFIG.minVelocity
    ) {
        const jitter =
            (
                Math.random() *
                2 -
                1
            ) *
            CAP_SLIDE_CONFIG.finalJitter;

        cap.power =
            Math.max(
                0,
                Math.min(
                    1,
                    cap.power +
                        jitter
                )
            );

        gameState.capSlide =
            null;

        finishCapPowerSlide();
    }
}

function updateCrownPhysics() {
    const physics =
        gameState.crownPhysics;

    const cap =
        gameState.cap;

    if (
        !physics ||
        !physics.active
    ) {
        return;
    }

    const panel =
        layout.cap;

    const board =
        getCrownPhysicsLayout(
            panel
        );

    const frameTime =
        Math.min(
            0.045,
            Math.max(
                0,
                DeltaTime
            )
        );

    physics.elapsed +=
        frameTime;

    physics.trailTimer +=
        frameTime;

    physics.wallFlash =
        Math.max(
            0,
            physics.wallFlash -
                frameTime *
                CROWN_PHYSICS_CONFIG.wallFlashFade
        );

    physics.impactFlash =
        Math.max(
            0,
            physics.impactFlash -
                frameTime *
                CROWN_PHYSICS_CONFIG.wallRingFade
        );

    const substeps =
        CROWN_PHYSICS_CONFIG.substeps;

    const stepTime =
        frameTime /
        substeps;

    for (
        let step = 0;
        step < substeps;
        step += 1
    ) {
        cap.x +=
            physics.vx *
            stepTime;

        cap.y +=
            physics.vy *
            stepTime;

        cap.rotation +=
            physics.spin *
            stepTime;

        const dx =
            cap.x -
            board.centerX;

        const dy =
            cap.y -
            board.centerY;

        const distance =
            Math.sqrt(
                dx * dx +
                dy * dy
            );

        if (
            distance >
            board.maxDistance
        ) {
            const normalX =
                distance > 0
                    ? dx / distance
                    : 0;

            const normalY =
                distance > 0
                    ? dy / distance
                    : 1;

            cap.x =
                board.centerX +
                normalX *
                    board.maxDistance;

            cap.y =
                board.centerY +
                normalY *
                    board.maxDistance;

            const outwardSpeed =
                physics.vx *
                    normalX +
                physics.vy *
                    normalY;

            const impactStrength =
                Math.min(
                    1,
                    Math.abs(
                        outwardSpeed
                    ) /
                    (
                        board.radius *
                        1.65
                    )
                );

            physics.impactX =
                cap.x;

            physics.impactY =
                cap.y;

            physics.impactNormalX =
                normalX;

            physics.impactNormalY =
                normalY;

            physics.impactStrength =
                impactStrength;

            physics.impactFlash =
                1;

            physics.wallFlash =
                1;

            if (
                outwardSpeed > 0
            ) {
                physics.vx -=
                    (
                        1 +
                        CROWN_PHYSICS_CONFIG.wallBounce
                    ) *
                    outwardSpeed *
                    normalX;

                physics.vy -=
                    (
                        1 +
                        CROWN_PHYSICS_CONFIG.wallBounce
                    ) *
                    outwardSpeed *
                    normalY;
            }

            const tangentX =
                -normalY;

            const tangentY =
                normalX;

            const tangentKick =
                (
                    Math.random() *
                    2 -
                    1
                ) *
                board.radius *
                (
                    0.025 +
                    impactStrength *
                        0.075
                );

            physics.vx +=
                tangentX *
                tangentKick;

            physics.vy +=
                tangentY *
                tangentKick;

            physics.spin *=
                -CROWN_PHYSICS_CONFIG.wallSpinLoss;

            physics.spin +=
                tangentKick *
                3.2;

            physics.collisionCount +=
                1;

            colaRollPlaySound(
                "cap_hit"
            );
        }

        const friction =
            Math.pow(
                CROWN_PHYSICS_CONFIG.friction,
                stepTime * 60
            );

        physics.vx *=
            friction;

        physics.vy *=
            friction;

        physics.spin *=
            Math.pow(
                0.982,
                stepTime * 60
            );
    }

    const speed =
        Math.sqrt(
            physics.vx *
                physics.vx +
            physics.vy *
                physics.vy
        );

    if (
        physics.trailTimer >=
            CROWN_PHYSICS_CONFIG.trailInterval &&
        speed >=
            board.radius *
            CROWN_PHYSICS_CONFIG.trailMinSpeedRatio
    ) {
        physics.trailTimer =
            0;

        physics.trail.push(
            {
                x: cap.x,
                y: cap.y,
                rotation:
                    cap.rotation,
                speed:
                    Math.min(
                        1,
                        speed /
                            (
                                board.radius *
                                2
                            )
                    ),
            }
        );

        while (
            physics.trail.length >
            CROWN_PHYSICS_CONFIG.trailLength
        ) {
            physics.trail.shift();
        }
    }

    const stopSpeed =
        board.radius *
        CROWN_PHYSICS_CONFIG.stopSpeedRatio;

    if (
        (
            physics.elapsed >=
                CROWN_PHYSICS_CONFIG.minimumDuration &&
            speed <=
                stopSpeed
        ) ||
        physics.elapsed >=
            CROWN_PHYSICS_CONFIG.maximumDuration
    ) {
        finishCrownPhysics();
    }
}


function finishCrownPhysics() {
    const physics =
        gameState.crownPhysics;

    const cap =
        gameState.cap;

    if (!physics) {
        return;
    }

    physics.active =
        false;

    colaRollPlaySound(
        "cap_stop"
    );

    physics.vx =
        0;

    physics.vy =
        0;

    physics.impactFlash =
        0;

    const board =
        getCrownPhysicsLayout(
            layout.cap
        );

    const dx =
        cap.x -
        board.centerX;

    const dy =
        cap.y -
        board.centerY;

    const distance =
        Math.sqrt(
            dx * dx +
            dy * dy
        );

    const stopRatio =
        Math.min(
            1,
            distance /
                board.maxDistance
        );

    const result =
        resolveCrownStopDistance(
            stopRatio
        );

    const branchIndex =
        resolveCrownBranchIndex(
            cap.x,
            board.centerX
        );

    cap.distance =
        result.distance;

    cap.isOverPower =
        cap.lockedPower >=
        CONFIG.capOverStart;

    gameState.rollBranchIndex =
        branchIndex;

    gameState.rollBranchDirection =
        branchIndex === 0
            ? "left"
            : "right";

    physics.resultValue =
        cap.distance;

    physics.branchIndex =
        branchIndex;

    physics.stopRatio =
        stopRatio;

    physics.resultPulse =
        1;

    physics.stopFlash =
        1;

    physics.stopRing =
        0;

    const settleRotation =
        Math.round(
            cap.rotation /
            30
        ) *
        30;

    tween(
        CROWN_PHYSICS_CONFIG.settleDuration,
        cap,
        {
            rotation:
                settleRotation,
        },
        tween.easing.bounceOut
    );

    tween(
        CROWN_PHYSICS_CONFIG.stopRingDuration,
        physics,
        {
            stopFlash: 0,
            stopRing: 1,
        },
        tween.easing.quadOut
    );

    tween(
        CROWN_PHYSICS_CONFIG.trailFadeDuration,
        physics,
        {
            trailAlpha: 0,
        },
        tween.easing.quadOut
    );

    gameState.phase =
        "CAP_POWER_RESULT";

    const timer = {
        value: 0,
    };

    tween(
        CROWN_PHYSICS_CONFIG.resultHoldDuration,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            startMoveCounterTransfer();
        }
    );
}


function updateBoardCamera() {
    const currentNode =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!currentNode) {
        return;
    }

    const overview =
        colaRollUpdateMapOverviewProgress();

    let normalTargetX =
        currentNode.nx *
        CONFIG.mapWidth;

    let normalTargetY =
        currentNode.ny *
            CONFIG.mapHeight +
        CONFIG.cameraLookAheadY;

    if (
        gameState.targetNodeId &&
        gameState.moveAnimation
    ) {
        const targetNode =
            BOARD_NODES[
                gameState.targetNodeId
            ];

        if (targetNode) {
            const moveProgress =
                gameState.moveAnimation
                    .progress;

            const currentWorldX =
                currentNode.nx *
                CONFIG.mapWidth;

            const currentWorldY =
                currentNode.ny *
                CONFIG.mapHeight;

            const nextWorldX =
                targetNode.nx *
                CONFIG.mapWidth;

            const nextWorldY =
                targetNode.ny *
                CONFIG.mapHeight;

            normalTargetX =
                currentWorldX +
                (
                    nextWorldX -
                    currentWorldX
                ) *
                    moveProgress;

            normalTargetY =
                currentWorldY +
                (
                    nextWorldY -
                    currentWorldY
                ) *
                    moveProgress +
                CONFIG.cameraLookAheadY;
        }
    }

    const bounds =
        colaRollGetMapOverviewBounds();

    const rawProgress =
        overview
            ? overview.progress
            : 0;

    const overviewProgress =
        colaRollMapOverviewSmooth(
            rawProgress
        );

    const overviewZoom =
        colaRollGetMapOverviewZoom(
            bounds
        );

    const normalZoom =
        HEIGHT > WIDTH
            ? 0.96
            : 1.02;

    /*
     * 横方向は工房中央へ寄せる。
     * 縦方向は俯瞰スクロールを加える。
     */
    const overviewTargetX =
        bounds
            ? bounds.centerX
            : normalTargetX;

    const overviewTargetY =
        (
            bounds
                ? bounds.centerY
                : normalTargetY
        ) +
        (
            overview
                ? overview.scrollY
                : 0
        );

    const targetWorldX =
        normalTargetX +
        (
            overviewTargetX -
            normalTargetX
        ) *
            overviewProgress;

    const targetWorldY =
        normalTargetY +
        (
            overviewTargetY -
            normalTargetY
        ) *
            overviewProgress;

    const targetZoom =
        normalZoom +
        (
            overviewZoom -
            normalZoom
        ) *
            overviewProgress;

    const followSpeed =
        rawProgress >
            0.001
            ? 11
            : 7;

    const follow =
        Math.min(
            1,
            (
                typeof DeltaTime ===
                    "number"
                    ? DeltaTime
                    : 1 / 60
            ) *
                followSpeed
        );

    gameState.camera.x +=
        (
            targetWorldX -
            gameState.camera.x
        ) *
            follow;

    gameState.camera.y +=
        (
            targetWorldY -
            gameState.camera.y
        ) *
            follow;

    gameState.camera.zoom +=
        (
            targetZoom -
            gameState.camera.zoom
        ) *
            follow;

    if (
        gameState.landingPulse > 0
    ) {
        gameState.landingPulse -=
            DeltaTime * 4.5;

        if (
            gameState.landingPulse < 0
        ) {
            gameState.landingPulse =
                0;
        }
    }
}




function resolveCrownStopDistance(
    stopRatio
) {
    if (
        stopRatio <=
        CROWN_PHYSICS_CONFIG.centerZoneEnd
    ) {
        return {
            distance: 3,
            zone: "center",
        };
    }

    if (
        stopRatio <=
        CROWN_PHYSICS_CONFIG.outerZoneEnd
    ) {
        return {
            distance: 2,
            zone: "middle",
        };
    }

    return {
        distance: 1,
        zone: "outer",
    };
}

function resolveCrownBranchIndex(
    capX,
    centerX
) {
    return capX < centerX
        ? 0
        : 1;
}

function getPendingBranchWithinSteps(
    maxSteps
) {
    let node =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    let steps = 0;

    const visited = {};

    while (
        node &&
        steps <= maxSteps
    ) {
        if (
            node.choices &&
            node.choices.length >= 2 &&
            !gameState.selectedRoutes[
                node.id
            ]
        ) {
            if (
                steps === 0 ||
                steps < maxSteps
            ) {
                return node;
            }

            return null;
        }

        let nextNodeId =
            node.next;

        if (
            node.choices &&
            node.choices.length > 0
        ) {
            const selectedChoiceId =
                gameState.selectedRoutes[
                    node.id
                ];

            let selectedChoice =
                null;

            for (
                const choice of
                node.choices
            ) {
                if (
                    choice.id ===
                    selectedChoiceId
                ) {
                    selectedChoice =
                        choice;

                    break;
                }
            }

            if (!selectedChoice) {
                return null;
            }

            nextNodeId =
                selectedChoice.next;
        }

        if (
            !nextNodeId ||
            visited[nextNodeId]
        ) {
            break;
        }

        visited[node.id] =
            true;

        node =
            BOARD_NODES[
                nextNodeId
            ];

        steps += 1;
    }

    return null;
}


function isCrownBranchRelevant(
    resultVisible
) {
    const maxSteps =
        resultVisible
            ? Math.max(
                0,
                gameState.cap.distance
            )
            : 3;

    return (
        getPendingBranchWithinSteps(
            maxSteps
        ) !== null
    );
}


function lockCapPower(
    touchX
) {
    /*
     * パネル早押しと外部からの直接呼び出しを、
     * ここ一箇所で同じ扱いにする。
     *
     * 起動の見た目だけ完了させ、針の現在値は保つ。
     */
    if (
        isShotGaugeStartupActive()
    ) {
        finishShotGaugeStartupForEarlyTap();
    }

    const cap =
        gameState.cap;

    const panel =
        layout.cap;

    const normalizedX =
        Math.max(
            0,
            Math.min(
                1,
                (
                    touchX -
                    panel.x
                ) /
                panel.w
            )
        );

    let aimValue =
        (
            normalizedX -
            0.5
        ) *
        2;

    const absoluteAim =
        Math.abs(
            aimValue
        );

    if (
        absoluteAim <=
        CROWN_PHYSICS_CONFIG.aimDeadZone
    ) {
        aimValue =
            0;
    } else {
        const aimSign =
            aimValue < 0
                ? -1
                : 1;

        aimValue =
            aimSign *
            (
                absoluteAim -
                CROWN_PHYSICS_CONFIG.aimDeadZone
            ) /
            (
                1 -
                CROWN_PHYSICS_CONFIG.aimDeadZone
            );
    }

    gameState.crownAim = {
        value:
            Math.max(
                -1,
                Math.min(
                    1,
                    aimValue
                )
            ),

        normalizedX:
            normalizedX,

        lockedAt:
            ElapsedTime,
    };

    const direction =
        cap.powerDirection >= 0
            ? 1
            : -1;

    const speedRatio =
        CAP_SLIDE_CONFIG.minSpeedRatio +
        Math.random() *
        (
            CAP_SLIDE_CONFIG.maxSpeedRatio -
            CAP_SLIDE_CONFIG.minSpeedRatio
        );

    gameState.capSlide = {
        elapsed: 0,

        duration:
            CAP_SLIDE_CONFIG.minDuration +
            Math.random() *
            (
                CAP_SLIDE_CONFIG.maxDuration -
                CAP_SLIDE_CONFIG.minDuration
            ),

        velocity:
            direction *
            CONFIG.capGaugeSpeed *
            speedRatio,

        phase:
            Math.random() *
            Math.PI *
            2,
    };

    cap.lockedPower =
        cap.power;

    gameState.phase =
        "CAP_SLIDING";
}

const lockCapPowerBaseForMakingOneBottleNotice =
    lockCapPower;

lockCapPower = function(
    touchX
) {
    const phaseBefore =
        gameState
            ? gameState.phase
            : "";

    const result =
        lockCapPowerBaseForMakingOneBottleNotice(
            touchX
        );

    if (
        phaseBefore ===
            "WAIT_CAP_POWER" &&
        gameState &&
        gameState.phase ===
            "CAP_SLIDING"
    ) {
        gameState.makingOneBottleNotice = {
            elapsed: 0,
            delay: 0.10,
            fadeIn: 0.14,
            hold: 0.34,
            fadeOut: 0.20,
        };

        /*
         * 見た目上は「ロックして即発射」の一操作なので、
         * 二つの短い音を同じタップで重ねる。
         */
        colaRollPlayShot();
    }

    return result;
};




function finishCapPowerSlide() {
    const cap =
        gameState.cap;

    const panel =
        layout.cap;

    cap.lockedPower =
        cap.power;

    const board =
        getCrownPhysicsLayout(
            panel
        );

    const aimValue =
        gameState.crownAim
            ? gameState.crownAim.value
            : 0;

    cap.distance =
        1;

    cap.isOverPower =
        cap.lockedPower >=
        CONFIG.capOverStart;

    cap.x =
        board.centerX;

    cap.y =
        board.launchY;

    cap.rotation =
        aimValue * 10;

    gameState.crownPhysics = {
        active: false,
        elapsed: 0,
        vx: 0,
        vy: 0,
        spin: 0,
        collisionCount: 0,
        wallFlash: 0,
        impactFlash: 0,
        impactStrength: 0,
        impactX:
            board.centerX,
        impactY:
            board.launchY,
        impactNormalX: 0,
        impactNormalY: -1,
        resultValue: null,
        stopRatio: 1,
        stopFlash: 0,
        stopRing: 0,
        trail: [],
        trailTimer: 0,
        trailAlpha: 1,
        aimValue:
            aimValue,
        launchDirectionRatio:
            0,
    };

    gameState.capSnapEffect = {
        visible: true,
        ring: 0,
        spark: 0,
        alpha: 255,
    };

    gameState.phase =
        "CAP_PHYSICS";

    tween(
        CAP_SNAP_CONFIG.pressDuration,
        gameState.capSnapEffect,
        {
            ring: 0.16,
            spark: 0.12,
        },
        tween.easing.quadOut
    );

    tween(
        CAP_SNAP_CONFIG.pressDuration,
        cap,
        {
            y:
                board.launchY -
                CAP_SNAP_CONFIG.pullbackDistance,

            rotation:
                aimValue * 10 -
                11,
        },
        tween.easing.quadOut,
        function() {
            tween(
                CAP_SNAP_CONFIG.releaseDuration,
                gameState.capSnapEffect,
                {
                    ring: 1,
                    spark: 1,
                    alpha: 0,
                },
                tween.easing.quadOut
            );

            tween(
                CAP_SNAP_CONFIG.releaseDuration,
                cap,
                {
                    y:
                        board.launchY +
                        CAP_SNAP_CONFIG.releaseKick,

                    rotation:
                        aimValue * 10 +
                        14,
                },
                tween.easing.bounceOut,
                function() {
                    if (
                        gameState.capSnapEffect
                    ) {
                        gameState.capSnapEffect.visible =
                            false;
                    }

                    const power =
                        cap.lockedPower;

                    let speedFactor =
                        0.35 +
                        power *
                            1.70;

                    if (
                        power > 0.82
                    ) {
                        speedFactor +=
                            (
                                power -
                                0.82
                            ) *
                            6;
                    }

                    const launchSpeed =
                        board.radius *
                        speedFactor;

                    const randomDirection =
                        (
                            Math.random() *
                            2 -
                            1
                        ) *
                        CROWN_PHYSICS_CONFIG.horizontalJitter;

                    let directionRatio =
                        aimValue *
                            CROWN_PHYSICS_CONFIG.aimInfluence +
                        randomDirection;

                    directionRatio =
                        Math.max(
                            -CROWN_PHYSICS_CONFIG.maxDirectionRatio,
                            Math.min(
                                CROWN_PHYSICS_CONFIG.maxDirectionRatio,
                                directionRatio
                            )
                        );

                    const horizontalSpeed =
                        launchSpeed *
                        directionRatio;

                    const verticalSpeed =
                        launchSpeed *
                        Math.sqrt(
                            Math.max(
                                0,
                                1 -
                                    directionRatio *
                                    directionRatio
                            )
                        );

                    gameState.crownPhysics.vx =
                        horizontalSpeed;

                    gameState.crownPhysics.vy =
                        verticalSpeed;

                    gameState.crownPhysics.launchDirectionRatio =
                        directionRatio;

                    gameState.crownPhysics.spin =
                        (
                            horizontalSpeed >= 0
                                ? -1
                                : 1
                        ) *
                        (
                            420 +
                            power *
                                540
                        );

                    gameState.crownPhysics.elapsed =
                        0;

                    /*
                     * 王冠の周囲だけに、
                     * 発射方向へ少し傾く短い炭酸の尾を出す。
                     *
                     * 瓶の泡全体には力を加えない。
                     */
                    colaRollStartCapBubbleFeedback(
                        board,
                        directionRatio,
                        power
                    );

                    /*
                     * 発射音は、ロックしたタップの瞬間ではなく、
                     * 王冠が実際に飛び出すフレームで一度だけ鳴らす。
                     * 同一タップ内の二重 Audio 操作を避ける。
                     */
                    colaRollPlaySound(
                        "cap_launch",
                        {
                            volume: 0.50,
                            cooldown: 0,
                        }
                    );

                    gameState.crownPhysics.active =
                        true;
                }
            );
        }
    );
}


function startMoveCounterTransfer() {
    const counter =
        gameState.moveCounter;

    const cap =
        gameState.cap;

    counter.visible =
        true;

    counter.displayValue =
        cap.distance;

    counter.alpha =
        255;

    counter.scale =
        1.08;

    counter.x =
        layout.cap.x +
        cap.x;

    counter.y =
        layout.cap.y +
        cap.y;

    gameState.moveTotal =
        cap.distance;

    gameState.phase =
        "TRANSFERRING_MOVE_COUNT";

    /*
     * 移動数札が王冠パネルから
     * 飛び始める瞬間の音。
     *
     * 盤面への到着時ではなく、
     * 「次はこの数だけ進む」が
     * 動き出す合図として鳴らす。
     */
    colaRollPlaySound(
        "move_counter_set",
        {
            volume: 0.34,
            cooldown: 0,
        }
    );

    const targetX =
        layout.cap.x +
        layout.cap.w * 0.80;

    const targetY =
        layout.board.y +
        38;

    tween(
        CONFIG.moveCounterTransferDuration,
        counter,
        {
            x: targetX,
            y: targetY,
            scale: 0.72,
        },
        tween.easing.quadInOut,
        function() {
            resetCapAfterResult();

            startBoardMovement(
                gameState.moveTotal
            );
        }
    );
}




function resetCapAfterResult() {
    const cap =
        gameState.cap;

    const panel =
        layout.cap;

    const gaugeLayout =
        getMainGaugeLayout(
            panel
        );

    gameState.capSlide =
        null;

    gameState.crownPhysics =
        null;

    gameState.capSnapEffect =
        null;

    gameState.crownAim =
        null;

    cap.power =
        0;

    cap.powerDirection =
        1;

    cap.lockedPower =
        0;

    cap.distance =
        1;

    cap.isOverPower =
        false;

    cap.x =
        gaugeLayout.centerX;

    cap.y =
        gaugeLayout.centerY;

    cap.rotation =
        0;
}

const resetCapAfterResultBase =
    resetCapAfterResult;

resetCapAfterResult = function() {
    const resultDistance =
        typeof gameState.moveTotal ===
        "number"
            ? gameState.moveTotal
            : null;

    resetCapAfterResultBase();

    if (
        resultDistance !== null
    ) {
        gameState.cap.distance =
            resultDistance;
    }
};



function startBoardMovement(distance) {
    advanceColaMaturityForShot();

    gameState.remainingSteps =
        distance;

    gameState.moveCounter.displayValue =
        distance;

    gameState.exactStopEligible =
        true;

    gameState.exactStopStartDistance =
        distance;

    const timer = {
        value: 0,
    };

    tween(
        0.08,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            moveOneStep();
        }
    );
}



function moveOneStep() {
    const currentNode =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!currentNode) {
        finishMovement();
        return;
    }

    if (
        currentNode.id ===
        "goal"
    ) {
        gameState.remainingSteps =
            0;

        gameState.moveCounter.displayValue =
            0;

        finishMovement();
        return;
    }

    if (
        gameState.remainingSteps <=
        0
    ) {
        finishMovement();
        return;
    }

    let nextNodeId =
        currentNode.next;

    /* 未選択の分岐を初めて確定した時だけ、切替音を一度鳴らす。 */
    let routeWasJustSelected =
        false;

    if (
        currentNode.choices &&
        currentNode.choices.length > 0
    ) {
        let selectedChoiceId =
            gameState.selectedRoutes[
                currentNode.id
            ];

        if (!selectedChoiceId) {
            const rollBranchIndex =
                typeof gameState.rollBranchIndex ===
                "number"
                    ? gameState.rollBranchIndex
                    : 0;

            const choiceIndex =
                Math.max(
                    0,
                    Math.min(
                        currentNode.choices.length -
                            1,
                        rollBranchIndex
                    )
                );

            const automaticChoice =
                currentNode.choices[
                    choiceIndex
                ];

            if (!automaticChoice) {
                finishMovement();
                return;
            }

            selectedChoiceId =
                automaticChoice.id;

            gameState.selectedRoutes[
                currentNode.id
            ] =
                automaticChoice.id;

            routeWasJustSelected =
                true;
        }

        let selectedChoice =
            null;

        for (
            const choice of
            currentNode.choices
        ) {
            if (
                choice.id ===
                selectedChoiceId
            ) {
                selectedChoice =
                    choice;

                break;
            }
        }

        if (!selectedChoice) {
            const fallbackIndex =
                Math.max(
                    0,
                    Math.min(
                        currentNode.choices.length -
                            1,
                        typeof gameState.rollBranchIndex ===
                            "number"
                            ? gameState.rollBranchIndex
                            : 0
                    )
                );

            selectedChoice =
                currentNode.choices[
                    fallbackIndex
                ];

            if (!selectedChoice) {
                finishMovement();
                return;
            }

            gameState.selectedRoutes[
                currentNode.id
            ] =
                selectedChoice.id;

            routeWasJustSelected =
                true;
        }

        if (routeWasJustSelected) {
            /*
             * 左右の分岐が王冠の結果で決まった瞬間。
             * 通常マスや既に確定済みの分岐では鳴らさない。
             */
            colaRollPlaySound(
                "route_switch",
                {
                    volume: 0.38,
                    cooldown: 0,
                }
            );
        }

        nextNodeId =
            selectedChoice.next;
    }

    if (!nextNodeId) {
        gameState.remainingSteps =
            0;

        gameState.moveCounter.displayValue =
            0;

        finishMovement();
        return;
    }

    const targetNode =
        BOARD_NODES[
            nextNodeId
        ];

    if (!targetNode) {
        gameState.remainingSteps =
            0;

        gameState.moveCounter.displayValue =
            0;

        finishMovement();
        return;
    }

    gameState.targetNodeId =
        targetNode.id;

    gameState.moveAnimation.progress =
        0;

    gameState.phase =
        "MOVING";

    tween(
        CONFIG.moveDuration,
        gameState.moveAnimation,
        {
            progress: 1,
        },
        tween.easing.quadInOut,
        function() {
            gameState.currentNodeId =
                targetNode.id;

            /*
             * ゴールのチャイムは、後段のカウンター減算や
             * 結果演出を待たず、瓶がゴールマスへ着いた瞬間に鳴らす。
             */
            if (targetNode.id === "goal") {
                colaRollPlayCriticalSound(
                    "finish_chime",
                    {
                        volume: 0.56,
                        cooldown: 0,
                    }
                );
            } else {
                colaRollPlaySound(
                    "move_step"
                );
            }

            gameState.targetNodeId =
                null;

            gameState.moveAnimation.progress =
                0;

            gameState.remainingSteps =
                Math.max(
                    0,
                    gameState.remainingSteps -
                        1
                );

            const reachedGoal =
                targetNode.id ===
                "goal";

            animateMoveCounterDecrease(
                function() {
                    if (!reachedGoal) {
                        moveOneStep();
                        return;
                    }

                    if (
                        gameState.remainingSteps >
                        0
                    ) {
                        gameState.exactStopEligible =
                            false;

                        gameState.remainingSteps =
                            0;

                        animateMoveCounterDecrease(
                            function() {
                                finishMovement();
                            }
                        );

                        return;
                    }

                    finishMovement();
                }
            );
        }
    );
}


function animateMoveCounterDecrease(onComplete) {
    const counter =
        gameState.moveCounter;

    const currentNode =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    const reachedGoal =
        currentNode &&
        currentNode.id === "goal";

    if (
        reachedGoal &&
        gameState.remainingSteps > 0
    ) {
        gameState.exactStopEligible =
            false;
    }

    gameState.phase =
        "MOVE_COUNT_TICK";

    tween(
        CONFIG.moveCounterTickDuration,
        counter,
        {
            scale: 0.46,
        },
        tween.easing.quadIn,
        function() {
            counter.displayValue =
                gameState.remainingSteps;

            tween(
                CONFIG.moveCounterTickDuration,
                counter,
                {
                    scale: 0.79,
                },
                tween.easing.bounceOut,
                function() {
                    tween(
                        CONFIG.moveCounterTickDuration,
                        counter,
                        {
                            scale: 0.72,
                        },
                        tween.easing.quadOut,
                        function() {
                            const timer = {
                                value: 0,
                            };

                            tween(
                                CONFIG.moveCounterStepPause,
                                timer,
                                {
                                    value: 1,
                                },
                                tween.easing.linear,
                                function() {
                                    if (onComplete) {
                                        onComplete();
                                    }
                                }
                            );
                        }
                    );
                }
            );
        }
    );
}


function finishMovement() {
    const counter =
        gameState.moveCounter;

    gameState.phase =
        "MOVE_COUNT_ZERO";

    counter.displayValue = 0;

    let counterFinished =
        false;

    let impactFinished =
        false;

    let landingStarted =
        false;

    const continueLanding =
        function() {
            if (
                landingStarted ||
                !counterFinished ||
                !impactFinished
            ) {
                return;
            }

            landingStarted =
                true;

            registerExactStopBonus();

            resolveLandingTile();
        };

    gameState.phase =
        "LANDING";

    startLandingImpactEffect(
        function() {
            impactFinished =
                true;

            continueLanding();
        }
    );

    const holdTimer = {
        value: 0,
    };

    tween(
        CONFIG.moveCounterZeroHoldDuration,
        holdTimer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            tween(
                CONFIG.moveCounterFadeDuration,
                counter,
                {
                    scale: 0.12,
                    alpha: 0,
                },
                tween.easing.quadIn,
                function() {
                    counter.visible =
                        false;

                    counter.scale =
                        0.72;

                    counter.alpha =
                        255;

                    counterFinished =
                        true;

                    continueLanding();
                }
            );
        }
    );
}


function startLandingImpactEffect(onComplete) {
    const node =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!node) {
        if (onComplete) {
            onComplete();
        }

        return;
    }

    const effect = {
        visible: true,
        nodeId: node.id,
        progress: 0,
        impact: 0,
        alpha: 255,
        completed: false,
    };

    gameState.landingImpact =
        effect;

    gameState.landingPulse =
        1;

    /*
     * 最終到着時、輪っかが出始める瞬間。
     *
     * move_step は「パイプを進む」音。
     * tile_arrival は「このマスが反応する」音。
     * ゴールは finish_chime が到着を担うので重ねない。
     */
    if (node.id !== "goal") {
        colaRollPlaySound(
            "tile_arrival",
            {
                volume: 0.32,
                cooldown: 0.16,
            }
        );
    }

    tween(
        0.14,
        effect,
        {
            progress: 0.16,
            impact: 1,
        },
        tween.easing.bounceOut,
        function() {
            tween(
                0.32,
                effect,
                {
                    progress: 1,
                    alpha: 0,
                },
                tween.easing.quadOut,
                function() {
                    effect.visible =
                        false;

                    effect.completed =
                        true;

                    gameState.landingImpact =
                        null;

                    if (onComplete) {
                        onComplete();
                    }
                }
            );
        }
    );
}

function getLandingImpactAccent(node) {
    if (
        node &&
        node.id === "goal"
    ) {
        return {
            r: 255,
            g: 209,
            b: 104,
        };
    }

    if (
        typeof getBoardStationType ===
            "function" &&
        typeof getBoardStationActivationColor ===
            "function"
    ) {
        const stationType =
            getBoardStationType(
                node
            );

        const accent =
            getBoardStationActivationColor(
                node,
                stationType
            );

        if (accent) {
            return accent;
        }
    }

    return {
        r: 239,
        g: 173,
        b: 91,
    };
}

function drawLandingImpactEffect() {
    const effect =
        gameState.landingImpact;

    if (
        !effect ||
        !effect.visible ||
        !effect.nodeId
    ) {
        return;
    }

    const node =
        BOARD_NODES[
            effect.nodeId
        ];

    if (!node) {
        return;
    }

    const position =
        getBoardNodeScreenPosition(
            effect.nodeId
        );

    const accent =
        getLandingImpactAccent(
            node
        );

    const progress =
        Math.max(
            0,
            Math.min(
                1,
                effect.progress
            )
        );

    const impact =
        Math.max(
            0,
            Math.min(
                1,
                effect.impact
            )
        );

    const alpha =
        Math.max(
            0,
            Math.min(
                255,
                effect.alpha
            )
        );

    const baseSize =
        CONFIG.currentNodeSize;

    const ringSize =
        baseSize *
        (
            0.96 +
            progress * 2.15
        );

    const innerRingSize =
        baseSize *
        (
            0.64 +
            progress * 1.26
        );

    const flashSize =
        baseSize *
        (
            0.54 +
            impact * 0.88
        );

    noStroke();

    fill(
        accent.r,
        accent.g,
        accent.b,
        alpha *
            (
                0.16 +
                impact * 0.14
            )
    );

    ellipse(
        position.x,
        position.y -
            baseSize * 0.03,
        flashSize
    );

    noFill();

    stroke(
        accent.r,
        accent.g,
        accent.b,
        alpha *
            (
                0.68 -
                progress * 0.28
            )
    );

    strokeWidth(
        3.6 -
        progress * 1.4
    );

    ellipse(
        position.x,
        position.y,
        ringSize
    );

    stroke(
        255,
        238,
        191,
        alpha *
            (
                0.74 -
                progress * 0.34
            )
    );

    strokeWidth(
        1.8
    );

    ellipse(
        position.x,
        position.y,
        innerRingSize
    );

    noStroke();

    for (
        let index = 0;
        index < 8;
        index += 1
    ) {
        const angle =
            (
                Math.PI * 2 *
                index
            ) /
            8 -
            Math.PI * 0.5;

        const particleStart =
            baseSize * 0.28;

        const particleDistance =
            baseSize *
            (
                0.54 +
                progress * 1.22
            );

        const particleX =
            position.x +
            Math.cos(
                angle
            ) *
                (
                    particleStart +
                    particleDistance
                );

        const particleY =
            position.y +
            Math.sin(
                angle
            ) *
                (
                    particleStart +
                    particleDistance
                ) +
            progress *
                baseSize *
                0.16;

        const particleAlpha =
            alpha *
            Math.max(
                0,
                0.80 -
                    progress * 0.62
            );

        const particleSize =
            2.8 +
            (
                index % 3
            ) *
                0.9 +
            impact * 1.5;

        fill(
            accent.r,
            accent.g,
            accent.b,
            particleAlpha
        );

        ellipse(
            particleX,
            particleY,
            particleSize
        );
    }

    fill(
        255,
        250,
        222,
        alpha *
            (
                0.50 +
                impact * 0.28
            )
    );

    ellipse(
        position.x -
            baseSize * 0.16,
        position.y +
            baseSize * 0.10,
        3.4 +
            impact * 2
    );

    noStroke();
}


function registerExactStopBonus() {
    if (
        gameState.exactStopEligible ===
        false
    ) {
        return;
    }

    const node =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!node) {
        return;
    }

    const bonusNode =
        node.id === "goal" ||
        (
            node.choices &&
            node.choices.length > 0
        );

    if (!bonusNode) {
        return;
    }

    if (
        !gameState.perfectStopNodes
    ) {
        gameState.perfectStopNodes =
            {};
    }

    if (
        gameState.perfectStopNodes[
            node.id
        ]
    ) {
        return;
    }

    gameState.perfectStopNodes[
        node.id
    ] =
        true;

    gameState.perfectStopCount =
        (
            gameState.perfectStopCount ||
            0
        ) +
        1;

    if (
        node.id === "goal"
    ) {
        gameState.perfectGoalStop =
            true;
    }

    gameState.exactStopEffect = {
        visible: true,
        nodeId: node.id,
        progress: 0,
        alpha: 255,
        rotation: 0,
    };

    tween(
        0.62,
        gameState.exactStopEffect,
        {
            progress: 1,
            alpha: 0,
            rotation: 160,
        },
        tween.easing.quadOut,
        function() {
            if (
                gameState.exactStopEffect
            ) {
                gameState.exactStopEffect.visible =
                    false;
            }
        }
    );
}

function drawExactStopEffect() {
    drawLandingImpactEffect();

    const effect =
        gameState.exactStopEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const position =
        getBoardNodeScreenPosition(
            effect.nodeId
        );

    const progress =
        effect.progress;

    const alpha =
        effect.alpha;

    const ringSize =
        36 +
        progress * 46;

    noFill();

    stroke(
        255,
        213,
        112,
        alpha
    );

    strokeWidth(
        3 -
        progress
    );

    ellipse(
        position.x,
        position.y,
        ringSize
    );

    stroke(
        255,
        238,
        181,
        alpha * 0.55
    );

    strokeWidth(1.5);

    ellipse(
        position.x,
        position.y,
        ringSize * 1.32
    );

    pushMatrix();

    translate(
        position.x,
        position.y
    );

    rotate(
        effect.rotation
    );

    for (
        let index = 0;
        index < 8;
        index += 1
    ) {
        rotate(45);

        line(
            ringSize * 0.42,
            0,
            ringSize * 0.58,
            0
        );
    }

    popMatrix();

    noStroke();
}


function resolveLandingTile() {
    const node =
        BOARD_NODES[
            gameState.currentNodeId
        ];

    if (!node) {
        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    if (node.id === "goal") {
        startGoalSequence();
        return;
    }

    startBoardStationActivation(
        node,
        function() {
            resolveLandingTileEffect(
                node
            );
        }
    );
}

function resolveLandingTileEffect(node) {
    if (
        node.nodeType ===
            "event_gate" &&
        !gameState.resolvedEvents[
            node.eventId
        ]
    ) {
        startEventGate(node);
        return;
    }

    if (
        node.effect &&
        node.effect.addMystery
    ) {
        startMysteryIngredient();
        return;
    }

    if (
        node.effect &&
        node.effect.addIngredient
    ) {
        startAddingIngredient(
            node.effect.addIngredient
        );

        return;
    }

    const finishEffect = function() {
        gameState.phase =
            "WAIT_CAP_POWER";
    };

    const applyPressure = function() {
        if (
            node.effect &&
            node.effect.pressureDelta
        ) {
            const pressureDelta =
                node.effect.pressureDelta;

            const changePressureAfterGet =
                function() {
                    if (
                        pressureDelta > 0
                    ) {
                        gameState.totalCarbonationGets =
                            (
                                gameState.totalCarbonationGets ||
                                0
                            ) + 1;
                    }

                    changePressure(
                        pressureDelta,
                        finishEffect
                    );
                };

            if (
                pressureDelta > 0 &&
                typeof startCarbonationGetEffect ===
                    "function"
            ) {
                startCarbonationGetEffect(
                    changePressureAfterGet
                );

                return;
            }

            changePressureAfterGet();
            return;
        }

        finishEffect();
    };

    if (
        node.effect &&
        node.effect.garnish
    ) {
        const garnish =
            node.effect.garnish;

        const finishGarnish =
            function() {
                /*
                 * showGarnishReveal 側でも保存されるが、
                 * ここでも安全に確定させる。
                 * addCollectedGarnish は重複を追加しない。
                 */
                if (
                    typeof addCollectedGarnish ===
                    "function"
                ) {
                    addCollectedGarnish(
                        garnish
                    );
                }

                gameState.glass.garnish =
                    garnish;

                /*
                 * 圧力変化があっても瓶は膨らませず、
                 * 小皿の着地リアクションへ渡す。
                 */
                gameState.useGarnishTrayPressureResponse =
                    true;

                if (
                    typeof startGarnishTrayReaction ===
                    "function"
                ) {
                    startGarnishTrayReaction(
                        garnish
                    );
                }

                applyPressure();
            };

        /*
         * 壊れた startGarnishGetEffect を経由しない。
         * 盤面から小皿への既存の安全な演出を直接使う。
         */
        if (
            typeof showGarnishReveal ===
            "function"
        ) {
            showGarnishReveal(
                garnish,
                finishGarnish
            );
        } else {
            finishGarnish();
        }

        return;
    }

    applyPressure();
}


/*
 * Board station activation entry point.
 *
 * Carbonation previews are intentionally triggered before the station
 * animation begins, matching the former wrapper order. Keeping this at
 * the entry point means callers always use the same activation route.
 */
function startBoardStationActivation(
    node,
    onComplete
) {
    startCarbonationStationPreview(
        node
    );

    return runBoardStationActivationCore(
        node,
        onComplete
    );
}

function runBoardStationActivationCore(
    node,
    onComplete
) {
    const stationType =
        getBoardStationType(
            node
        );

    const directBottleProcess =
        stationType === "syrup" ||
        stationType === "spice" ||
        stationType === "cooling" ||
        stationType === "shake" ||
        stationType === "garnish";

    if (
        !stationType ||
        stationType === "bottle" ||
        stationType === "serve" ||
        directBottleProcess
    ) {
        if (onComplete) {
            onComplete();
        }

        return;
    }

    const effect =
        gameState.stationAnimation;

    effect.visible = true;
    effect.nodeId = node.id;
    effect.stationType =
        stationType;
    effect.progress = 0;
    effect.pulse = 0;
    effect.rotation = 0;
    effect.alpha = 255;

    const firstDuration =
        CONFIG.stationActivationDuration *
        0.38;

    const secondDuration =
        CONFIG.stationActivationDuration *
        0.62;

    tween(
        firstDuration,
        effect,
        {
            progress: 0.42,
            pulse: 1,
            rotation: 24,
        },
        tween.easing.quadOut,
        function() {
            tween(
                secondDuration,
                effect,
                {
                    progress: 1,
                    pulse: 0.28,
                    rotation: 42,
                },
                tween.easing.quadInOut,
                function() {
                    tween(
                        CONFIG.stationActivationSettleDuration,
                        effect,
                        {
                            pulse: 0,
                            alpha: 0,
                        },
                        tween.easing.quadOut,
                        function() {
                            effect.visible =
                                false;

                            effect.nodeId =
                                null;

                            effect.stationType =
                                null;

                            effect.progress =
                                0;

                            effect.rotation =
                                0;

                            effect.alpha =
                                0;

                            if (onComplete) {
                                onComplete();
                            }
                        }
                    );
                }
            );
        }
    );
}


function getBoardStationActivationColor(
    node,
    stationType
) {
    if (
        node &&
        node.effect &&
        node.effect.addIngredient &&
        INGREDIENTS[
            node.effect.addIngredient
        ]
    ) {
        return INGREDIENTS[
            node.effect.addIngredient
        ].color;
    }

    if (
        stationType ===
        "carbonation"
    ) {
        return {
            r: 185,
            g: 232,
            b: 247,
        };
    }

    if (
        stationType ===
        "cooling"
    ) {
        return {
            r: 205,
            g: 241,
            b: 250,
        };
    }

    if (
        stationType ===
        "shake"
    ) {
        return {
            r: 240,
            g: 190,
            b: 116,
        };
    }

    if (
        stationType ===
        "mystery"
    ) {
        return {
            r: 211,
            g: 160,
            b: 222,
        };
    }

    if (
        stationType ===
            "garnish" &&
        node.effect &&
        node.effect.garnish ===
            "cherry"
    ) {
        return {
            r: 220,
            g: 68,
            b: 62,
        };
    }

    if (
        stationType ===
        "garnish"
    ) {
        return {
            r: 228,
            g: 222,
            b: 86,
        };
    }

    return {
        r: 233,
        g: 177,
        b: 101,
    };
}


function drawBoardStationActivation() {
    const effect =
        gameState.stationAnimation;

    if (
        !effect ||
        !effect.visible ||
        !effect.nodeId
    ) {
        return;
    }

    const node =
        BOARD_NODES[
            effect.nodeId
        ];

    if (!node) {
        return;
    }

    const position =
        getBoardNodeScreenPosition(
            node.id
        );

    const panel =
        layout.board;

    if (
        position.x <
            panel.x - 40 ||
        position.x >
            panel.x +
                panel.w +
                40 ||
        position.y <
            panel.y - 40 ||
        position.y >
            panel.y +
                panel.h +
                40
    ) {
        return;
    }

    const stationType =
        effect.stationType;

    const progress =
        Math.max(
            0,
            Math.min(
                1,
                effect.progress
            )
        );

    const pulse =
        effect.pulse;

    const alpha =
        effect.alpha;

    const accent =
        getBoardStationActivationColor(
            node,
            stationType
        );

    const ringSize =
        CONFIG.stationActivationRingSize *
        (
            0.82 +
            progress * 0.44 +
            pulse * 0.12
        );

    noFill();

    stroke(
        accent.r,
        accent.g,
        accent.b,
        alpha *
            (
                0.25 +
                pulse * 0.45
            )
    );

    strokeWidth(
        2 +
        pulse * 2
    );

    ellipse(
        position.x,
        position.y,
        ringSize
    );

    stroke(
        255,
        226,
        172,
        alpha *
            pulse *
            0.42
    );

    strokeWidth(1.5);

    ellipse(
        position.x,
        position.y,
        ringSize * 1.30
    );

    noStroke();

    pushMatrix();

    translate(
        position.x,
        position.y
    );

    if (
        stationType === "syrup" ||
        stationType === "spice"
    ) {
        const nozzleY =
            18 -
            progress * 7;

        fill(
            48,
            31,
            24,
            alpha
        );

        rectMode(CENTER);

        rect(
            0,
            nozzleY + 5,
            17,
            8,
            3
        );

        fill(
            184,
            124,
            69,
            alpha
        );

        rect(
            0,
            nozzleY,
            6,
            13,
            2
        );

        fill(
            235,
            183,
            104,
            alpha
        );

        rect(
            0,
            nozzleY - 7,
            10,
            3,
            1
        );

        const dropY =
            nozzleY -
            9 -
            progress *
                CONFIG.stationActivationDropDistance;

        fill(
            accent.r,
            accent.g,
            accent.b,
            alpha
        );

        ellipse(
            0,
            dropY,
            5 +
                pulse * 2
        );

        fill(
            accent.r,
            accent.g,
            accent.b,
            alpha * 0.55
        );

        ellipse(
            -5,
            dropY + 7,
            2.5
        );

        ellipse(
            5,
            dropY + 3,
            2
        );

        rectMode(CORNER);
    } else if (
        stationType === "carbonation"
    ) {
        const nozzleY =
            19 -
            progress * 11;

        rectMode(CENTER);

        fill(
            52,
            40,
            34,
            alpha
        );

        rect(
            0,
            nozzleY + 5,
            20,
            8,
            3
        );

        fill(
            177,
            126,
            73,
            alpha
        );

        rect(
            0,
            nozzleY - 2,
            7,
            15,
            2
        );

        fill(
            226,
            190,
            126,
            alpha
        );

        rect(
            0,
            nozzleY - 10,
            11,
            3,
            1
        );

        rectMode(CORNER);

        for (
            let index = 0;
            index < 6;
            index += 1
        ) {
            const bubbleProgress =
                (
                    progress +
                    index * 0.17
                ) %
                1;

            const bubbleX =
                Math.sin(
                    index * 2.4
                ) *
                8;

            const bubbleY =
                nozzleY -
                10 -
                bubbleProgress * 27;

            noFill();

            stroke(
                accent.r,
                accent.g,
                accent.b,
                alpha *
                    (
                        0.35 +
                        bubbleProgress *
                            0.55
                    )
            );

            strokeWidth(1.2);

            ellipse(
                bubbleX,
                bubbleY,
                3 +
                    (
                        index % 3
                    )
            );
        }

        noStroke();
    } else if (
        stationType === "ice"
    ) {
        pushMatrix();

        translate(
            0,
            13
        );

        rotate(
            -38 *
            progress
        );

        rectMode(CENTER);

        fill(
            52,
            63,
            67,
            alpha
        );

        rect(
            0,
            0,
            22,
            7,
            2
        );

        fill(
            180,
            215,
            224,
            alpha
        );

        rect(
            0,
            1,
            17,
            3,
            1
        );

        rectMode(CORNER);

        popMatrix();

        const cubeY =
            8 -
            progress *
                CONFIG.stationActivationDropDistance;

        pushMatrix();

        translate(
            0,
            cubeY
        );

        rotate(
            effect.rotation
        );

        rectMode(CENTER);

        fill(
            accent.r,
            accent.g,
            accent.b,
            alpha * 0.92
        );

        rect(
            0,
            0,
            10,
            10,
            2
        );

        noFill();

        stroke(
            246,
            255,
            255,
            alpha * 0.80
        );

        strokeWidth(1);

        rect(
            0,
            0,
            10,
            10,
            2
        );

        noStroke();
        rectMode(CORNER);

        popMatrix();
    } else if (
        stationType === "stir"
    ) {
        const armY =
            19 -
            progress * 10;

        stroke(
            42,
            28,
            22,
            alpha
        );

        strokeWidth(6);

        line(
            0,
            armY + 8,
            0,
            armY - 15
        );

        stroke(
            230,
            185,
            113,
            alpha
        );

        strokeWidth(3);

        line(
            0,
            armY + 8,
            0,
            armY - 15
        );

        pushMatrix();

        translate(
            0,
            armY - 15
        );

        rotate(
            effect.rotation
        );

        stroke(
            255,
            220,
            157,
            alpha
        );

        strokeWidth(3);

        line(
            -9,
            0,
            9,
            0
        );

        line(
            0,
            -6,
            0,
            6
        );

        noStroke();

        popMatrix();
    } else if (
        stationType === "mystery"
    ) {
        pushMatrix();

        translate(
            0,
            12 +
                progress * 4
        );

        rotate(
            -32 *
            progress
        );

        rectMode(CENTER);

        fill(
            78,
            48,
            86,
            alpha
        );

        rect(
            0,
            0,
            20,
            6,
            2
        );

        fill(
            210,
            158,
            222,
            alpha * 0.65
        );

        rect(
            0,
            1,
            15,
            2,
            1
        );

        rectMode(CORNER);

        popMatrix();

        for (
            let index = 0;
            index < 3;
            index += 1
        ) {
            const questionProgress =
                Math.max(
                    0,
                    progress -
                        index * 0.14
                );

            fill(
                accent.r,
                accent.g,
                accent.b,
                alpha *
                    questionProgress
            );

            fontSize(
                11 +
                index * 2
            );

            textAlign(CENTER);

            text(
                "?",
                (
                    index -
                    1
                ) *
                    9,
                4 -
                    questionProgress *
                        28
            );
        }
    } else if (
        stationType === "garnish"
    ) {
        pushMatrix();

        translate(
            0,
            11
        );

        rotate(
            (
                node.effect.garnish ===
                "cherry"
                    ? 1
                    : -1
            ) *
            25 *
            progress
        );

        rectMode(CENTER);

        fill(
            70,
            46,
            34,
            alpha
        );

        rect(
            0,
            0,
            22,
            7,
            3
        );

        fill(
            151,
            99,
            57,
            alpha
        );

        rect(
            0,
            1,
            17,
            3,
            1
        );

        rectMode(CORNER);

        popMatrix();

        const garnishY =
            7 -
            progress *
                CONFIG.stationActivationDropDistance;

        if (
            node.effect.garnish ===
            "cherry"
        ) {
            fill(
                accent.r,
                accent.g,
                accent.b,
                alpha
            );

            ellipse(
                0,
                garnishY,
                9
            );

            stroke(
                83,
                128,
                66,
                alpha
            );

            strokeWidth(1.5);

            line(
                1,
                garnishY + 4,
                6,
                garnishY + 10
            );

            noStroke();
        } else {
            noFill();

            stroke(
                accent.r,
                accent.g,
                accent.b,
                alpha
            );

            strokeWidth(4);

            ellipse(
                0,
                garnishY,
                11
            );

            stroke(
                83,
                129,
                66,
                alpha
            );

            strokeWidth(2);

            ellipse(
                0,
                garnishY,
                5
            );

            noStroke();
        }
    }

    popMatrix();

    noStroke();
    rectMode(CORNER);
}


function startGoalSequence() {
    gameState.phase =
        "GOAL_ARRIVAL";

    gameState.remainingSteps =
        0;

    gameState.moveCounter.visible =
        false;

    gameState.moveCounter.displayValue =
        0;

    createResultData();

    const effect =
        gameState.goalEffect;

    effect.visible =
        true;

    effect.stage =
        "cap";

    effect.scale =
        0.94;

    effect.alpha =
        0;

    effect.ring =
        0;

    effect.capProgress =
        0;

    effect.capRotation =
        -35;

    effect.press =
        0;

    effect.labelProgress =
        0;

    effect.complete =
        0;

    tween(
        0.22,
        effect,
        {
            scale: 1,
            alpha: 255,
            ring: 0.48,
            capProgress: 1,
            capRotation: 0,
        },
        tween.easing.bounceOut,
        function() {
            effect.stage =
                "press";

            tween(
                0.13,
                effect,
                {
                    scale: 1.07,
                    ring: 0.92,
                    press: 1,
                },
                tween.easing.quadOut,
                function() {
                    tween(
                        0.14,
                        effect,
                        {
                            scale: 1,
                            ring: 1.08,
                            press: 0.10,
                        },
                        tween.easing.bounceOut,
                        function() {
                            effect.stage =
                                "label";

                            tween(
                                0.24,
                                effect,
                                {
                                    labelProgress: 1,
                                    ring: 1.34,
                                },
                                tween.easing.quadOut,
                                function() {
                                    effect.stage =
                                        "handoff";

                                    effect.complete =
                                        1;

                                    effect.press =
                                        0;

                                    startResultScreen();

                                    tween(
                                        0.30,
                                        effect,
                                        {
                                            scale: 1.24,
                                            alpha: 0,
                                            ring: 2.32,
                                        },
                                        tween.easing.quadIn,
                                        function() {
                                            effect.visible =
                                                false;

                                            effect.stage =
                                                "idle";
                                        }
                                    );
                                }
                            );
                        }
                    );
                }
            );
        }
    );
}


function createBaseResultData() {
    const slots =
        gameState.glass.slots;

    let sweetness = 0;
    let spice = 0;
    let strange = 0;
    let legacyIceCount = 0;

    const strangeIds = [];
    const ingredientIds = [];
    const ingredientCounts = [];
    const ingredientCountMap = {};

    let topIngredientId =
        null;

    for (
        const token of slots
    ) {
        const ingredient =
            INGREDIENTS[
                token.ingredientId
            ];

        if (!ingredient) {
            continue;
        }

        if (
            ingredient.id ===
            "ice"
        ) {
            legacyIceCount += 1;
            continue;
        }

        sweetness +=
            ingredient.sweetness || 0;

        spice +=
            ingredient.spice || 0;

        strange +=
            ingredient.strange || 0;

        topIngredientId =
            ingredient.id;

        ingredientIds.push(
            ingredient.id
        );

        ingredientCountMap[
            ingredient.id
        ] =
            (
                ingredientCountMap[
                    ingredient.id
                ] ||
                0
            ) +
            1;

        if (
            ingredient.strange > 0 &&
            strangeIds.indexOf(
                ingredient.id
            ) < 0
        ) {
            strangeIds.push(
                ingredient.id
            );
        }
    }

    for (
        const ingredientId of
        Object.keys(
            ingredientCountMap
        )
    ) {
        ingredientCounts.push(
            {
                id:
                    ingredientId,

                count:
                    ingredientCountMap[
                        ingredientId
                    ],
            }
        );
    }

    const coolingCount =
        Math.min(
            CONFIG.coolingMaxLevel,
            (
                gameState.chillCount ||
                0
            ) +
            legacyIceCount
        );

    const carbonationGets =
        gameState.totalCarbonationGets ===
            undefined
            ? (
                gameState.glass.pressure > 0
                    ? gameState.glass.pressure
                    : 0
            )
            : gameState.totalCarbonationGets;

    const routePrimary =
        gameState.selectedRoutes[
            "branch1"
        ] ||
        null;

    const routeFinal =
        gameState.selectedRoutes[
            "branch2"
        ] ||
        routePrimary;

    const uniqueIngredientIds =
        Object.keys(
            ingredientCountMap
        );

    const colaBaseIds = [
        "base_syrup",
        "thick_syrup",
        "brown_sugar",
        "secret_syrup",
        "caramel",
    ];

    let hasColaBase =
        false;

    for (
        const ingredientId of
        uniqueIngredientIds
    ) {
        if (
            colaBaseIds.indexOf(
                ingredientId
            ) >= 0
        ) {
            hasColaBase = true;
            break;
        }
    }

    const hasFizz =
        carbonationGets > 0 ||
        gameState.glass.pressure > 0;

    const singleIngredientId =
        uniqueIngredientIds.length === 1
            ? uniqueIngredientIds[0]
            : null;

    let drinkType =
        "cola";

    if (hasColaBase) {
        drinkType =
            hasFizz
                ? "cola"
                : "syrup";
    } else if (
        uniqueIngredientIds.length === 0
    ) {
        drinkType =
            hasFizz
                ? "plain_soda"
                : "nothing";
    } else if (
        uniqueIngredientIds.length === 1
    ) {
        drinkType =
            hasFizz
                ? "single_soda"
                : "single";
    } else {
        drinkType =
            "scrap";
    }

    gameState.resultData = {
        topIngredientId:
            topIngredientId,

        ingredientIds:
            ingredientIds,

        ingredientCounts:
            ingredientCountMap,

        ingredientCountList:
            ingredientCounts,

        uniqueIngredientIds:
            uniqueIngredientIds,

        sweetness:
            sweetness,

        spice:
            spice,

        chill:
            coolingCount,

        strange:
            strange,

        iceCount:
            coolingCount,

        coolingCount:
            coolingCount,

        sweetnessLevel:
            sweetness >= 3
                ? "high"
                : "low",

        carbonationLevel:
            gameState.glass.pressure >= 3
                ? "high"
                : gameState.glass.pressure <= 0
                    ? "none"
                    : "low",

        carbonationGets:
            carbonationGets,

        stillFinish:
            !hasFizz,

        hasFizz:
            hasFizz,

        hasColaBase:
            hasColaBase,

        drinkType:
            drinkType,

        singleIngredientId:
            singleIngredientId,

        chillLevel:
            coolingCount >= 2
                ? "high"
                : "low",

        pressure:
            gameState.glass.pressure,

        garnish:
            gameState.glass.garnish,

        spilledCount:
            gameState.glass.spilledTokens.length,

        burstCount:
            gameState.burstCount,

        stirCount:
            gameState.stirCount,

        mysteryCount:
            gameState.mysteryCount,

        glassFullCount:
            gameState.glassFullCount,

        routePrimary:
            routePrimary,

        routeFinal:
            routeFinal,

        strangeIngredientIds:
            strangeIds,
    };
}

function getResultScrapTitle(
    result,
    language
) {
    let category =
        "neutral";

    if (
        result.strange > 0
    ) {
        category =
            "mystery";
    } else if (
        result.sweetness >= 3
    ) {
        category =
            "sweet";
    } else if (
        result.spice >= 2
    ) {
        category =
            "spice";
    } else if (
        result.chill >= 2 ||
        result.garnish === "lemon" ||
        result.ingredientIds.indexOf(
            "lemon_peel"
        ) >= 0 ||
        result.ingredientIds.indexOf(
            "herb"
        ) >= 0
    ) {
        category =
            "fresh";
    }

    const titlePools = {
        ja: {
            sweet: [
                "開発途中ペースト",
                "未確認シロップ片",
                "コーラになる予定だったもの",
                "甘い気配の断片",
            ],
            spice: [
                "香りの下書き",
                "調合途中の断片",
                "途中の気配",
                "何かの痕跡",
            ],
            fresh: [
                "まだ名前のない液体",
                "香りだけ集まった何か",
                "味のメモ",
                "仕込みかけの何か",
            ],
            mystery: [
                "工房メモ No.3",
                "瓶に残った構想",
                "未確認シロップ片",
                "何かの痕跡",
            ],
            neutral: [
                "仕込みかけの何か",
                "まだ名前のない液体",
                "途中の気配",
                "開発途中ペースト",
            ],
        },

        en: {
            sweet: [
                "Prototype Paste",
                "Unknown Syrup Fragment",
                "Future Cola Candidate",
                "Sweet Trace",
            ],
            spice: [
                "Aroma Draft",
                "Half-Mixed Fragment",
                "Something in Progress",
                "Trace of Something",
            ],
            fresh: [
                "Unnamed Liquid",
                "Collected Aroma",
                "Flavor Memo",
                "Half-Made Something",
            ],
            mystery: [
                "Workshop Memo No.3",
                "Bottled Idea",
                "Unknown Syrup Fragment",
                "Trace of Something",
            ],
            neutral: [
                "Half-Made Something",
                "Unnamed Liquid",
                "Something in Progress",
                "Prototype Paste",
            ],
        },
    };

    const pool =
        titlePools[
            language
        ][category];

    let signature = 0;

    for (
        const ingredientId of
        result.ingredientIds
    ) {
        const count =
            result.ingredientCounts[
                ingredientId
            ] || 1;

        for (
            let index = 0;
            index <
                ingredientId.length;
            index += 1
        ) {
            signature +=
                ingredientId.charCodeAt(
                    index
                ) *
                count;
        }
    }

    signature +=
        (result.pressure || 0) * 7 +
        (result.chill || 0) * 11 +
        (result.spilledCount || 0) * 13 +
        (result.burstCount || 0) * 17 +
        (result.stirCount || 0) * 19 +
        (result.mysteryCount || 0) * 23 +
        (result.glassFullCount || 0) * 29;

    return pool[
        signature %
            pool.length
    ];
}

function getResultMainFlavorDescription(
    result,
    language
) {
    const ingredientId =
        result.topIngredientId ||
        result.singleIngredientId ||
        null;

    if (language === "ja") {
        if (
            ingredientId ===
            "base_syrup"
        ) {
            return "素朴な甘みが、まっすぐ瓶の中に残っています。";
        }

        if (
            ingredientId ===
            "thick_syrup"
        ) {
            return "濃いシロップの重なりで、どっしりした仕上がりです。";
        }

        if (
            ingredientId ===
            "vanilla"
        ) {
            return "バニラの甘い香りで、やわらかくまとまりました。";
        }

        if (
            ingredientId ===
            "caramel"
        ) {
            return "キャラメルの香ばしさが、少し丸い余韻を残します。";
        }

        if (
            ingredientId ===
            "ginger"
        ) {
            return "生姜の香りがまっすぐ立った、少し刺激的な仕上がりです。";
        }

        if (
            ingredientId ===
            "cinnamon"
        ) {
            return "シナモンの香りが、静かに奥行きを足しています。";
        }

        if (
            ingredientId ===
            "lemon_peel"
        ) {
            return "レモンピールの香りが軽く抜ける、さっぱりした仕上がりです。";
        }

        if (
            ingredientId ===
            "herb"
        ) {
            return "薬草の青い香りが、少しだけ不思議な後味を残します。";
        }

        if (
            ingredientId ===
            "brown_sugar"
        ) {
            return "黒糖の深い甘みが、瓶の底にゆっくり残る一本です。";
        }

        if (
            ingredientId ===
            "secret_syrup"
        ) {
            return "秘伝の香りが、最後まで正体を隠しています。";
        }

        return "集めた素材が瓶の中で、ひとつの味にまとまりました。";
    }

    if (
        ingredientId ===
        "base_syrup"
    ) {
        return "A simple sweetness settles neatly inside the bottle.";
    }

    if (
        ingredientId ===
        "thick_syrup"
    ) {
        return "The thick syrup gives it a deep and weighty finish.";
    }

    if (
        ingredientId ===
        "vanilla"
    ) {
        return "Vanilla softens the whole drink with a gentle aroma.";
    }

    if (
        ingredientId ===
        "caramel"
    ) {
        return "Caramel leaves a warm, rounded sweetness behind.";
    }

    if (
        ingredientId ===
        "ginger"
    ) {
        return "Ginger stands straight at the front with a small sharp kick.";
    }

    if (
        ingredientId ===
        "cinnamon"
    ) {
        return "Cinnamon quietly adds a little depth to the finish.";
    }

    if (
        ingredientId ===
        "lemon_peel"
    ) {
        return "Lemon peel gives it a light and refreshing edge.";
    }

    if (
        ingredientId ===
        "herb"
    ) {
        return "A green herbal note leaves a slightly mysterious finish.";
    }

    if (
        ingredientId ===
        "brown_sugar"
    ) {
        return "Brown sugar leaves a slow, deep sweetness at the bottom of the bottle.";
    }

    if (
        ingredientId ===
        "secret_syrup"
    ) {
        return "The secret syrup keeps its true flavor hidden to the end.";
    }

    return "Everything collected has settled into one small finished flavor.";
}


function startResultScreen() {
    gameState.phase =
        "RESULT";

    gameState.resultReveal.scale =
        0.985;

    gameState.resultReveal.alpha =
        0;

    gameState.resultCrownReveal = {
        alpha: 0,
        rotation: -96,
        scale: 0.26,
        yOffset: 10,
        sparkAlpha: 0,
        sparkScale: 0.72,
        sparkRotation: -14,
    };

    const fizzTransition = {
        active: true,
        startedAt: ElapsedTime,
        darkAlpha: 0,
        bubbleAlpha: 0,
        bubbles:
            createTitleTransitionBubbles(),
    };

    gameState.resultFizzTransition =
        fizzTransition;

    /*
     * 瓶が完成し、結果画面へ向かう泡が上がり始める瞬間。
     */
    colaRollPlaySound(
        "start",
        {
            volume: 0.40,
        }
    );

    tween(
        0.22,
        fizzTransition,
        {
            darkAlpha: 255,
            bubbleAlpha: 245,
        },
        tween.easing.quadOut,
        function() {
            const holdTimer = {
                value: 0,
            };

            tween(
                0.28,
                holdTimer,
                {
                    value: 1,
                },
                tween.easing.linear,
                function() {
                    tween(
                        0.30,
                        gameState.resultReveal,
                        {
                            scale: 1,
                            alpha: 255,
                        },
                        tween.easing.quadOut,
                        function() {
                            /*
                             * 完成ボトルとラベルが結果画面で落ち着いた瞬間。
                             * ゴール到着の finish_chime とは役割を分ける。
                             */
                            colaRollPlaySound(
                                "bottle_finish",
                                {
                                    volume: 0.42,
                                    cooldown: 0,
                                }
                            );

                            const crownDelay = {
                                value: 0,
                            };

                            tween(
                                0.08,
                                crownDelay,
                                {
                                    value: 1,
                                },
                                tween.easing.linear,
                                function() {
                                    tween(
                                        0.24,
                                        gameState.resultCrownReveal,
                                        {
                                            alpha: 255,
                                            rotation: 16,
                                            scale: 1.12,
                                            yOffset: -2,
                                        },
                                        tween.easing.quadOut,
                                        function() {
                                            tween(
                                                0.18,
                                                gameState.resultCrownReveal,
                                                {
                                                    rotation: 0,
                                                    scale: 1,
                                                    yOffset: 0,
                                                },
                                                tween.easing.bounceOut,
                                                function() {
                                                    gameState.resultCrownReveal.sparkAlpha =
                                                        220;

                                                    /*
                                                     * 完成チャイムはゴール到着時だけ。
                                                     * 結果画面の王冠キラリは無音にする。
                                                     */

                                                    gameState.resultCrownReveal.sparkScale =
                                                        0.76;

                                                    gameState.resultCrownReveal.sparkRotation =
                                                        -10;

                                                    tween(
                                                        0.34,
                                                        gameState.resultCrownReveal,
                                                        {
                                                            sparkAlpha: 0,
                                                            sparkScale: 1.16,
                                                            sparkRotation: 18,
                                                        },
                                                        tween.easing.quadOut
                                                    );
                                                }
                                            );
                                        }
                                    );
                                }
                            );
                        }
                    );

                    tween(
                        0.34,
                        fizzTransition,
                        {
                            darkAlpha: 0,
                            bubbleAlpha: 0,
                        },
                        tween.easing.quadIn,
                        function() {
                            fizzTransition.active =
                                false;
                        }
                    );
                }
            );
        }
    );
}


function drawResultFizzTransition() {
    const transition =
        gameState.resultFizzTransition;

    if (
        !transition ||
        !transition.active
    ) {
        return;
    }

    const darkAlpha =
        Math.max(
            0,
            Math.min(
                255,
                transition.darkAlpha
            )
        );

    const bubbleAlpha =
        Math.max(
            0,
            Math.min(
                255,
                transition.bubbleAlpha
            )
        );

    const elapsed =
        Math.max(
            0,
            ElapsedTime -
                transition.startedAt
        );

    if (
        darkAlpha > 0
    ) {
        rectMode(CORNER);
        noStroke();

        fill(
            15,
            10,
            9,
            darkAlpha
        );

        rect(
            0,
            0,
            WIDTH,
            HEIGHT
        );
    }

    if (
        bubbleAlpha <= 0
    ) {
        rectMode(CORNER);
        noStroke();
        return;
    }

    const bubbles =
        transition.bubbles || [];

    for (
        let index = 0;
        index < bubbles.length;
        index += 1
    ) {
        const bubble =
            bubbles[index];

        const progress =
            (
                elapsed -
                bubble.delay
            ) /
            bubble.life;

        if (
            progress <= 0 ||
            progress >= 1
        ) {
            continue;
        }

        const bubbleX =
            bubble.x +
            Math.sin(
                progress *
                    bubble.wobbleSpeed +
                bubble.phase
            ) *
                bubble.wobble;

        const bubbleY =
            bubble.startY +
            bubble.travel *
                progress;

        const size =
            bubble.size *
            (
                0.76 +
                progress * 0.42
            );

        const localAlpha =
            bubbleAlpha *
            Math.sin(
                progress *
                Math.PI
            );

        noFill();

        stroke(
            221,
            246,
            250,
            localAlpha * 0.88
        );

        strokeWidth(
            Math.max(
                0.8,
                size * 0.14
            )
        );

        ellipse(
            bubbleX,
            bubbleY,
            size
        );

        stroke(
            255,
            239,
            198,
            localAlpha * 0.38
        );

        strokeWidth(
            Math.max(
                0.6,
                size * 0.075
            )
        );

        ellipse(
            bubbleX -
                size * 0.16,
            bubbleY +
                size * 0.12,
            size * 0.42
        );

        noStroke();

        fill(
            255,
            247,
            224,
            localAlpha * 0.34
        );

        ellipse(
            bubbleX -
                size * 0.18,
            bubbleY +
                size * 0.20,
            Math.max(
                1.2,
                size * 0.18
            )
        );
    }

    rectMode(CORNER);
    noStroke();
}


function generateBaseResultName() {
    const result =
        gameState.resultData;

    const language =
        gameState.language;

    if (!result) {
        return language === "ja"
            ? "できたてコーラ"
            : "Fresh Cola";
    }

    const drinkType =
        result.drinkType ||
        "cola";

    if (
        drinkType ===
        "single" ||
        drinkType ===
        "single_soda"
    ) {
        const ingredient =
            INGREDIENTS[
                result.singleIngredientId
            ];

        if (
            drinkType ===
            "single_soda"
        ) {
            if (language === "ja") {
                if (
                    result.singleIngredientId ===
                    "lemon_peel"
                ) {
                    return "レモンソーダ";
                }

                if (ingredient) {
                    return (
                        ingredient.ja +
                        "ソーダ"
                    );
                }

                return "何かのソーダ";
            }

            if (
                result.singleIngredientId ===
                "lemon_peel"
            ) {
                return "Lemon Soda";
            }

            if (ingredient) {
                return (
                    ingredient.en +
                    " Soda"
                );
            }

            return "Something Soda";
        }

        if (ingredient) {
            return ingredient[
                language
            ];
        }

        return language === "ja"
            ? "何か"
            : "Something";
    }

    if (
        drinkType ===
        "plain_soda"
    ) {
        if (language === "ja") {
            if (
                result.pressure >= 3
            ) {
                return "勢いのある炭酸水";
            }

            if (
                result.chill >= 2
            ) {
                return "ひんやり炭酸水";
            }

            return "ただの炭酸水";
        }

        if (
            result.pressure >= 3
        ) {
            return "Brisk Sparkling Water";
        }

        if (
            result.chill >= 2
        ) {
            return "Chilled Sparkling Water";
        }

        return "Plain Sparkling Water";
    }

    if (
        drinkType ===
        "nothing"
    ) {
        return language === "ja"
            ? "仕込み前の瓶"
            : "Bottle Before Brewing";
    }

    if (
        drinkType ===
        "scrap"
    ) {
        if (
            typeof getResultScrapTitle ===
            "function"
        ) {
            return getResultScrapTitle(
                result,
                language
            );
        }

        return language === "ja"
            ? "仕込みかけの何か"
            : "Half-Made Something";
    }

    let prefix = "";

    if (
        result.topIngredientId &&
        RESULT_WORDS[
            language
        ] &&
        RESULT_WORDS[
            language
        ].topFlavor
    ) {
        prefix =
            RESULT_WORDS[
                language
            ].topFlavor[
                result.topIngredientId
            ] || "";
    }

    if (
        prefix === "" &&
        result.topIngredientId &&
        INGREDIENTS[
            result.topIngredientId
        ]
    ) {
        prefix =
            INGREDIENTS[
                result.topIngredientId
            ][language];
    }

    if (language === "ja") {
        if (prefix === "") {
            prefix = "不思議な";
        }

        let garnishText = "";

        if (
            result.garnish ===
            "cherry"
        ) {
            garnishText =
                "チェリー浮かぶ";
        } else if (
            result.garnish ===
            "lemon"
        ) {
            garnishText =
                "レモン添えの";
        }

        if (
            drinkType ===
            "syrup"
        ) {
            let syrupName =
                "泡待ちシロップ";

            if (
                result.sweetness >= 4
            ) {
                syrupName =
                    "濃厚コーラの素";
            } else if (
                result.strange > 0
            ) {
                syrupName =
                    "静かな秘伝シロップ";
            } else if (
                result.chill >= 2
            ) {
                syrupName =
                    "ひんやりコーラの素";
            }

            return (
                colaRollAvoidDuplicateSyrupPrefix(
                    prefix,
                    syrupName,
                    result,
                    language
                ) +
                garnishText +
                syrupName
            );
        }

        let baseName =
            "コーラ";

        if (
            result.burstCount > 0 ||
            result.pressure >=
                CONFIG.pressureMax
        ) {
            baseName =
                "限界炭酸コーラ";
        } else if (
            result.pressure >= 3
        ) {
            baseName =
                "強炭酸コーラ";
        }

        return (
            prefix +
            garnishText +
            baseName
        );
    }

    if (prefix === "") {
        prefix = "Mysterious";
    }

    let garnishText = "";

    if (
        result.garnish ===
        "cherry"
    ) {
        garnishText =
            " Cherry";
    } else if (
        result.garnish ===
        "lemon"
    ) {
        garnishText =
            " Lemon";
    }

    if (
        drinkType ===
        "syrup"
    ) {
        let syrupName =
            " Waiting-for-Fizz Syrup";

        if (
            result.sweetness >= 4
        ) {
            syrupName =
                " Rich Cola Base";
        } else if (
            result.strange > 0
        ) {
            syrupName =
                " Quiet Secret Syrup";
        } else if (
            result.chill >= 2
        ) {
            syrupName =
                " Chilled Cola Base";
        }

        return (
            colaRollAvoidDuplicateSyrupPrefix(
                prefix,
                syrupName,
                result,
                language
            ) +
            garnishText +
            syrupName
        );
    }

    let baseName =
        " Cola";

    if (
        result.burstCount > 0 ||
        result.pressure >=
            CONFIG.pressureMax
    ) {
        baseName =
            " Limit Fizz Cola";
    } else if (
        result.pressure >= 3
    ) {
        baseName =
            " Extra Fizzy Cola";
    }

    return (
        prefix +
        garnishText +
        baseName
    );
}

/*
 * シロップ結果名だけに使う重複回避。
 *
 * 完成後の文字列を一律に削るのではなく、
 * 最多素材 topIngredientId が示す語と、これから付ける
 * シロップ系のベース名が実際に衝突する時だけ、
 * 素材側の前置きを外す。
 *
 * コーラ名、レアレシピ名、結合帯の名前生成には触れない。
 */
function colaRollAvoidDuplicateSyrupPrefix(
    prefix,
    syrupName,
    result,
    language
) {
    if (
        !prefix ||
        !syrupName ||
        !result ||
        !result.topIngredientId
    ) {
        return prefix || "";
    }

    const topIngredientId =
        result.topIngredientId;

    const conflictWords = {
        ja: {
            base_syrup: [
                "シロップ",
            ],

            roast_syrup: [
                "焙煎",
            ],

            secret_syrup: [
                "秘伝",
                "シロップ",
            ],
        },

        en: {
            base_syrup: [
                "syrup",
            ],

            roast_syrup: [
                "roast",
                "roasted",
            ],

            secret_syrup: [
                "secret",
                "syrup",
            ],
        },
    };

    const languageTable =
        language === "en"
            ? conflictWords.en
            : conflictWords.ja;

    const words =
        languageTable[
            topIngredientId
        ];

    if (
        !words ||
        words.length <= 0
    ) {
        return prefix;
    }

    const normalizedPrefix =
        normalizeColaRollResultText(
            prefix
        ).toLowerCase();

    const normalizedBaseName =
        normalizeColaRollResultText(
            syrupName
        ).toLowerCase();

    const hasConflict =
        words.some(
            function(word) {
                const normalizedWord =
                    normalizeColaRollResultText(
                        word
                    ).toLowerCase();

                return (
                    normalizedWord &&
                    normalizedPrefix.indexOf(
                        normalizedWord
                    ) >= 0 &&
                    normalizedBaseName.indexOf(
                        normalizedWord
                    ) >= 0
                );
            }
        );

    return hasConflict
        ? ""
        : prefix;
}


function generateBaseResultDescription() {
    const result =
        gameState.resultData;

    const language =
        gameState.language;

    if (!result) {
        return "";
    }

    const drinkType =
        result.drinkType ||
        "cola";

    const safeFlavorDescription = function() {
        if (
            typeof getResultMainFlavorDescription ===
            "function"
        ) {
            return getResultMainFlavorDescription(
                result,
                language
            );
        }

        return language === "ja"
            ? "集めた素材が瓶の中で、ひとつの味にまとまりました。"
            : "Everything collected has settled into one small finished flavor.";
    };

    if (language === "ja") {
        if (
            drinkType ===
            "single"
        ) {
            const ingredient =
                INGREDIENTS[
                    result.singleIngredientId
                ];

            const name =
                ingredient
                    ? ingredient.ja
                    : "何か";

            return (
                "今日は" +
                name +
                "が主役です。飲みものというより、かなり堂々とした素材そのもの。"
            );
        }

        if (
            drinkType ===
            "single_soda"
        ) {
            const ingredient =
                INGREDIENTS[
                    result.singleIngredientId
                ];

            const name =
                ingredient
                    ? ingredient.ja
                    : "何か";

            if (
                result.singleIngredientId ===
                "lemon_peel"
            ) {
                return "レモンの香りと炭酸だけで、思ったよりちゃんと爽やかです。";
            }

            if (
                result.singleIngredientId ===
                "ginger"
            ) {
                return "生姜と炭酸だけで押し切った、妙にまっすぐな一杯です。";
            }

            if (
                result.singleIngredientId ===
                "herb"
            ) {
                return "薬草と炭酸だけで仕上がった、少し不思議なソーダです。";
            }

            return (
                name +
                "だけを頼りに仕上がった、まっすぐなソーダです。"
            );
        }

        if (
            drinkType ===
            "plain_soda"
        ) {
            if (
                result.chill >= 2
            ) {
                return "素材は少ないのに、炭酸だけはしっかり冷えています。";
            }

            return "素材は集まりませんでしたが、炭酸だけは元気に残りました。";
        }

        if (
            drinkType ===
            "nothing"
        ) {
            return "素材は集まりませんでしたが、瓶だけは無事にゴールしました。";
        }

        if (
            drinkType ===
            "scrap"
        ) {
            if (
                result.hasFizz
            ) {
                if (
                    result.spice >= 2
                ) {
                    return "香りは立っていますが、名前をつけるにはまだ少し早い炭酸の何かです。";
                }

                if (
                    result.sweetness >= 3
                ) {
                    return "甘みと炭酸はあります。あとは名乗る勇気だけです。";
                }

                return "いくつか混ざった結果、名前のつかない炭酸の何かができました。";
            }

            if (
                result.spice >= 2
            ) {
                return "香りはいくつか集まりましたが、まだ飲みものになる前の気配です。";
            }

            if (
                result.sweetness >= 3
            ) {
                return "甘い方向には進んでいます。完成までは、もう少し相談が必要そうです。";
            }

            return "いくつか混ざりましたが、まだ何になるかは誰にも分かりません。";
        }

        if (
            drinkType ===
            "syrup"
        ) {
            if (
                result.topIngredientId ===
                "secret_syrup" ||
                (
                    result.strangeIngredientIds &&
                    result.strangeIngredientIds.indexOf(
                        "secret_syrup"
                    ) >= 0
                )
            ) {
                return "泡はありませんが、香りはなかなか本気です。炭酸を足せばきっと完成。";
            }

            if (
                result.topIngredientId ===
                "brown_sugar"
            ) {
                return "黒糖の深い甘みが残る、コーラになる前の濃い仕込みです。";
            }

            if (
                result.chill >= 2
            ) {
                return "しっかり冷えているのに、泡だけがまだ来ていません。これはこれで濃い一杯です。";
            }

            if (
                result.sweetness >= 4
            ) {
                return "泡はないけれど、甘みは十分。コーラになる前のごちそうです。";
            }

            return "炭酸は入りませんでしたが、香りはしっかり仕上がりました。";
        }

        if (
            result.burstCount >= 2
        ) {
            return "何度も炭酸の限界を越えた、かなり危険な一本。";
        }

        if (
            result.burstCount === 1
        ) {
            return "一度はじけても、まだ炭酸は元気です。";
        }

        if (
            result.stirCount >= 3
        ) {
            return "何度も混ぜられ、味の重なりがすっかり変わりました。";
        }

        if (
            result.spilledCount > 0
        ) {
            return (
                safeFlavorDescription() +
                " 少しこぼれましたが、それも含めて今回の仕上がりです。"
            );
        }

        if (
            result.chill >= 2
        ) {
            return (
                safeFlavorDescription() +
                " しっかり冷えて、飲み頃になっています。"
            );
        }

        if (
            result.chill === 1
        ) {
            return (
                safeFlavorDescription() +
                " ひんやり仕上がった一本です。"
            );
        }

        return safeFlavorDescription();
    }

    if (
        drinkType ===
        "single"
    ) {
        const ingredient =
            INGREDIENTS[
                result.singleIngredientId
            ];

        const name =
            ingredient
                ? ingredient.en
                : "Something";

        return (
            "Today, " +
            name +
            " takes center stage. Less a drink, more a very confident ingredient."
        );
    }

    if (
        drinkType ===
        "single_soda"
    ) {
        const ingredient =
            INGREDIENTS[
                result.singleIngredientId
            ];

        const name =
            ingredient
                ? ingredient.en
                : "Something";

        if (
            result.singleIngredientId ===
            "lemon_peel"
        ) {
            return "Lemon and bubbles only. Somehow, that is enough.";
        }

        if (
            result.singleIngredientId ===
            "ginger"
        ) {
            return "Ginger and bubbles push this drink forward with surprising confidence.";
        }

        if (
            result.singleIngredientId ===
            "herb"
        ) {
            return "Herbs and bubbles make a slightly mysterious soda.";
        }

        return (
            "A very direct soda made almost entirely out of " +
            name +
            "."
        );
    }

    if (
        drinkType ===
        "plain_soda"
    ) {
        if (
            result.chill >= 2
        ) {
            return "Not much else made it in, but the sparkling water is nicely chilled.";
        }

        return "Few ingredients showed up, but the bubbles still did their job.";
    }

    if (
        drinkType ===
        "nothing"
    ) {
        return "No real ingredients were collected, but the bottle still made it to the finish.";
    }

    if (
        drinkType ===
        "scrap"
    ) {
        if (
            result.hasFizz
        ) {
            if (
                result.spice >= 2
            ) {
                return "The aroma is there, but it is still too early to give this fizzy thing a proper name.";
            }

            if (
                result.sweetness >= 3
            ) {
                return "It has sweetness and bubbles. Now it only needs the courage to introduce itself.";
            }

            return "Several things were mixed together, and somehow it turned into an unnamed fizzy something.";
        }

        if (
            result.spice >= 2
        ) {
            return "Several aromas gathered here, but it still feels like a drink before becoming a drink.";
        }

        if (
            result.sweetness >= 3
        ) {
            return "It is moving in a sweet direction, but the recipe still needs another conversation.";
        }

        return "Several things were mixed together, and nobody is quite sure what it wants to become.";
    }

    if (
        drinkType ===
        "syrup"
    ) {
        if (
            result.topIngredientId ===
            "secret_syrup" ||
            (
                result.strangeIngredientIds &&
                result.strangeIngredientIds.indexOf(
                    "secret_syrup"
                ) >= 0
            )
        ) {
            return "No bubbles yet, but the aroma is oddly serious. Add fizz and it might be complete.";
        }

        if (
            result.topIngredientId ===
            "brown_sugar"
        ) {
            return "Brown sugar leaves a deep sweetness in this cola base before it becomes cola.";
        }

        if (
            result.chill >= 2
        ) {
            return "Well chilled, strangely quiet, and still waiting for its bubbles.";
        }

        if (
            result.sweetness >= 4
        ) {
            return "No fizz, plenty of sweetness. A tasty thing just before it becomes cola.";
        }

        return "No sparkling water made it in, but the flavor still found a way.";
    }

    if (
        result.burstCount >= 2
    ) {
        return "A dangerously fizzy bottle that crossed the limit more than once.";
    }

    if (
        result.burstCount === 1
    ) {
        return "It burst once, but the fizz is still going strong.";
    }

    if (
        result.stirCount >= 3
    ) {
        return "Stirred again and again until every flavor changed places.";
    }

    if (
        result.spilledCount > 0
    ) {
        return (
            safeFlavorDescription() +
            " A little spilled, but that is part of this bottle too."
        );
    }

    if (
        result.chill >= 2
    ) {
        return (
            safeFlavorDescription() +
            " Thoroughly chilled and ready to drink."
        );
    }

    if (
        result.chill === 1
    ) {
        return (
            safeFlavorDescription() +
            " Gently chilled for the finish."
        );
    }

    return safeFlavorDescription();
}

function appendResultSpillMemory(
    description
) {
    return description;
}


/*
 * 焙煎シロップは、結果タイトルを奪わない。
 * チェリーやレモンなど表に出る素材はそのままにして、
 * 結果本文の最後でだけ、奥行きとして香りを残す。
 */
const generateBaseResultDescriptionBaseForRoastAftertaste =
    generateBaseResultDescription;

generateBaseResultDescription = function() {
    const description =
        generateBaseResultDescriptionBaseForRoastAftertaste.apply(
            this,
            arguments
        );

    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : null;

    if (
        !result ||
        !result.ingredientCounts ||
        !result.ingredientCounts.roast_syrup
    ) {
        return description;
    }

    /*
     * 焙煎シロップが主役の時は、
     * すでに専用の結果文で焙煎について説明している。
     * ここで同じ内容を重ねない。
     */
    const normalizedDescription =
        String(
            description || ""
        ).toLowerCase();

    const alreadyMentionsRoast =
        gameState.language === "ja"
            ? normalizedDescription.indexOf(
                "焙煎"
            ) >= 0
            : (
                normalizedDescription.indexOf(
                    "roast"
                ) >= 0 ||
                normalizedDescription.indexOf(
                    "bittersweet"
                ) >= 0
            );

    if (alreadyMentionsRoast) {
        return description;
    }

    if (gameState.language === "ja") {
        return (
            String(
                description || ""
            ) +
            " その奥に、焙煎のほろ苦い香りが静かに残ります。"
        );
    }

    return (
        String(
            description || ""
        ) +
        " A quiet roasted bitterness lingers underneath."
    );
};


