function getResultRestartButtonRect() {
    const portrait =
        HEIGHT > WIDTH;

    const recordState =
        gameState &&
        gameState.resultRecord
            ? gameState.resultRecord
            : null;

    /*
     * 画像取得中は、結果画面本体が描く
     * 「もう一本つくる」ボタンも画面外へ退避する。
     *
     * 後付けの「補充する」「記録」だけでなく、
     * 元からある再プレイボタンも保存画像に含めない。
     */
    if (
        recordState &&
        recordState.captureMode &&
        gameState &&
        gameState.phase === "RESULT"
    ) {
        return {
            x: -10000,
            y: -10000,
            w: 1,
            h: 1,
        };
    }

    /*
     * 補充完了画面の「次の一本をつくる」は、
     * 従来どおり中央配置に戻す。
     */
    if (
        gameState &&
        gameState.phase ===
            "DELIVERY_COMPLETE"
    ) {
        const deliveryWidth =
            Math.min(
                220,
                portrait
                    ? WIDTH * 0.64
                    : WIDTH * 0.28
            );

        return {
            x:
                WIDTH * 0.5 -
                deliveryWidth * 0.5,

            y: 20,
            w: deliveryWidth,
            h: 46,
        };
    }

    /*
     * 通常の結果画面では、
     * 右側の記録ボタンぶんだけ
     * 補充ボタンを少し細くする。
     */
    const resultWidth =
        Math.min(
            190,
            portrait
                ? WIDTH * 0.54
                : WIDTH * 0.25
        );

    const resultCenterX =
        portrait
            ? WIDTH * 0.46
            : WIDTH * 0.67;

    return {
        x:
            resultCenterX -
            resultWidth * 0.5,

        y: 20,
        w: resultWidth,
        h: 46,
    };
}




function restartGame() {
    if (
        gameState.resultRestartTransition &&
        gameState.resultRestartTransition.active
    ) {
        return;
    }

    const language =
        gameState.language;

    if (
        tween &&
        typeof tween.stopAll ===
            "function"
    ) {
        tween.stopAll();
    }

    const restartTransition = {
        active: true,
        startedAt: ElapsedTime,
        darkAlpha: 0,
        bubbleAlpha: 0,
        bubbles:
            createTitleTransitionBubbles(),
    };

    gameState.resultRestartTransition =
        restartTransition;

    tween(
        0.22,
        restartTransition,
        {
            darkAlpha: 255,
            bubbleAlpha: 245,
        },
        tween.easing.quadOut,
        function() {
            const holdTimer = {
                value: 0,
            };

            tween(
                0.18,
                holdTimer,
                {
                    value: 1,
                },
                tween.easing.linear,
                function() {
                    initGameState();

                    gameState.language =
                        language;

                    updateLayout(true);

                    gameState.phase =
                        "WAIT_CAP_POWER";

                    gameState.resultRestartTransition =
                        restartTransition;

                    startShotGaugeStartup();

                    tween(
                        0.34,
                        restartTransition,
                        {
                            darkAlpha: 0,
                            bubbleAlpha: 0,
                        },
                        tween.easing.quadIn,
                        function() {
                            restartTransition.active =
                                false;

                            if (
                                gameState.resultRestartTransition ===
                                restartTransition
                            ) {
                                gameState.resultRestartTransition =
                                    null;
                            }
                        }
                    );
                }
            );
        }
    );
}


function weightedRandomIngredient() {
    const pool = [
        {
            id: "vanilla",
            weight: 3,
        },
        {
            id: "caramel",
            weight: 3,
        },
        {
            id: "ginger",
            weight: 3,
        },
        {
            id: "cinnamon",
            weight: 3,
        },
        {
            id: "lemon_peel",
            weight: 3,
        },
        {
            id: "ice",
            weight: 3,
        },
        {
            id: "herb",
            weight: 1,
        },
        {
            id: "brown_sugar",
            weight: 1,
        },
        {
            id: "secret_syrup",
            weight: 1,
        },
    ];

    let totalWeight = 0;

    for (
        const item of pool
    ) {
        totalWeight +=
            item.weight;
    }

    let value =
        Math.random() *
        totalWeight;

    for (
        const item of pool
    ) {
        value -=
            item.weight;

        if (value < 0) {
            return item.id;
        }
    }

    return "vanilla";
}

const ROULETTE_FLOW_CONFIG = {
    rollCount: 10,
    rollStep: 0.08,
    rollStepGrowth: 0.016,
    resultHoldDuration: 0.9,
};



function startMysteryIngredient() {
    gameState.phase =
        "WAIT_MYSTERY_ROLL";

    gameState.mysteryCount =
        (
            gameState.mysteryCount ||
            0
        ) +
        1;

    gameState.mystery = {
        visible: true,
        ingredientId: null,
        rollIndex: 0,
        scale: 1,
        alpha: 255,
        ringRotation: 0,
        locked: false,
    };
}

function startMysteryRoulette() {
    const mystery =
        gameState.mystery;

    if (
        gameState.phase !==
            "WAIT_MYSTERY_ROLL" ||
        !mystery
    ) {
        return;
    }

    gameState.phase =
        "MYSTERY_ROLLING";

    mystery.rollIndex = 0;
    mystery.locked = false;
    mystery.scale = 0.82;
    mystery.alpha = 255;

    let step =
        ROULETTE_FLOW_CONFIG.rollStep;

    const rollNext = function() {
        const currentMystery =
            gameState.mystery;

        if (!currentMystery) {
            return;
        }

        currentMystery.rollIndex += 1;

        colaRollPlayRouletteTick(
            currentMystery.rollIndex
        );

        let nextIngredient =
            weightedRandomIngredient();

        let attempts = 0;

        while (
            nextIngredient ===
                currentMystery.ingredientId &&
            attempts < 4
        ) {
            nextIngredient =
                weightedRandomIngredient();

            attempts += 1;
        }

        currentMystery.ingredientId =
            nextIngredient;

        currentMystery.scale = 0.82;

        tween(
            step,
            currentMystery,
            {
                scale: 1.04,
                ringRotation:
                    currentMystery.ringRotation +
                    48,
            },
            tween.easing.quadOut
        );

        if (
            currentMystery.rollIndex <
            ROULETTE_FLOW_CONFIG.rollCount
        ) {
            const timer = {
                value: 0,
            };

            tween(
                step,
                timer,
                {
                    value: 1,
                },
                tween.easing.linear,
                rollNext
            );

            step +=
                ROULETTE_FLOW_CONFIG.rollStepGrowth;

            return;
        }

        currentMystery.locked = true;

        colaRollPlaySound(
            "roulette_lock"
        );

        gameState.phase =
            "MYSTERY_RESULT";

        tween(
            0.18,
            currentMystery,
            {
                scale: 1.14,
                ringRotation:
                    currentMystery.ringRotation +
                    72,
            },
            tween.easing.bounceOut
        );

        const resultTimer = {
            value: 0,
        };

        tween(
            ROULETTE_FLOW_CONFIG.resultHoldDuration,
            resultTimer,
            {
                value: 1,
            },
            tween.easing.linear,
            function() {
                const ingredientId =
                    currentMystery.ingredientId;

                currentMystery.visible =
                    false;

                startAddingIngredient(
                    ingredientId
                );
            }
        );
    };

    rollNext();
}


function startEventGate(node) {
    gameState.resolvedEvents[
        node.eventId
    ] = true;

    gameState.eventResultData = null;
    gameState.eventTarget1 = null;
    gameState.eventTarget2 = null;
    gameState.eventAnim = null;

    gameState.phase =
        "WAIT_EVENT_ROLL";
}

function rollEventDice() {
    if (
        gameState.phase !==
        "WAIT_EVENT_ROLL"
    ) {
        return;
    }

    gameState.phase =
        "EVENT_ROLLING";

    let rollCount = 0;

    let step =
        ROULETTE_FLOW_CONFIG.rollStep;

    const rollNext = function() {
        rollCount += 1;

        colaRollPlayRouletteTick(
            rollCount
        );

        const eventIndex =
            Math.floor(
                Math.random() *
                EVENT_DIE.length
            );

        gameState.eventResultData =
            EVENT_DIE[eventIndex];

        if (
            rollCount <
            ROULETTE_FLOW_CONFIG.rollCount
        ) {
            const timer = {
                value: 0,
            };

            tween(
                step,
                timer,
                {
                    value: 1,
                },
                tween.easing.linear,
                rollNext
            );

            step +=
                ROULETTE_FLOW_CONFIG.rollStepGrowth;

            return;
        }

        gameState.phase =
            "SHOWING_EVENT_RESULT";

        colaRollPlaySound(
            "roulette_lock"
        );

        const resultTimer = {
            value: 0,
        };

        tween(
            ROULETTE_FLOW_CONFIG.resultHoldDuration,
            resultTimer,
            {
                value: 1,
            },
            tween.easing.linear,
            function() {
                startEventWarning(
                    gameState.eventResultData.id
                );
            }
        );
    };

    rollNext();
}


function startEventWarning(eventId) {
    gameState.phase =
        "EVENT_WARNING";

    const slots =
        gameState.glass.slots;

    const isSpill =
        eventId === "spill";

    gameState.eventTarget1 = null;
    gameState.eventTarget2 = null;
    gameState.eventSpillPresentation =
        null;

    if (
        eventId === "swap" &&
        slots.length > 1
    ) {
        const index =
            Math.floor(
                Math.random() *
                (slots.length - 1)
            );

        gameState.eventTarget1 =
            slots[index];

        gameState.eventTarget2 =
            slots[index + 1];
    } else if (
        isSpill &&
        slots.length > 0
    ) {
        const spilled =
            slots[
                slots.length - 1
            ];

        const direction =
            layout.glass.x +
                layout.glass.w *
                    0.5 <
            WIDTH * 0.5
                ? -1
                : 1;

        gameState.eventTarget1 =
            spilled;

        gameState.eventSpillPresentation = {
            active: true,
            stage: "warning",
            ingredientId:
                spilled.ingredientId,
            direction: direction,
            startedAt: 0,
            duration: 0.46,
        };

        resetTokenVisualTransform(
            spilled,
            getGlassSlotLocalY(
                slots.length - 1
            )
        );

        const motion =
            ensureTokenLiquidMotion(
                spilled
            );

        tween(
            0.16,
            spilled,
            {
                drawX:
                    direction * 6,
                drawY:
                    getGlassSlotLocalY(
                        slots.length - 1
                    ) + 4,
                rot:
                    direction * 4,
            },
            tween.easing.quadOut
        );

        tween(
            0.16,
            motion,
            {
                waveBoost: 0.76,
                stretchX: 1.045,
            },
            tween.easing.quadOut
        );
    }

    gameState.eventAnim = {
        iconX: WIDTH * 0.5,
        iconY: HEIGHT * 0.5,
        iconSize: isSpill
            ? 58
            : 104,
        iconAlpha: isSpill
            ? 190
            : 255,
        panelMaskAlpha: 0,
    };

    const warningDuration =
        isSpill
            ? 0.18
            : CONFIG.eventWarningDuration;

    tween(
        warningDuration,
        gameState.eventAnim,
        {
            iconX:
                layout.glass.x +
                layout.glass.w -
                (
                    isSpill
                        ? 22
                        : 34
                ),
            iconY:
                layout.glass.y +
                layout.glass.h -
                (
                    isSpill
                        ? 22
                        : 34
                ),
            iconSize: isSpill
                ? 18
                : 36,
            iconAlpha: isSpill
                ? 0
                : 255,
            panelMaskAlpha: isSpill
                ? 0
                : 145,
        },
        tween.easing.quadOut,
        function() {
            gameState.phase =
                "ANIMATING_EVENT";

            applyEventAnimation(
                eventId
            );
        }
    );
}


function applyEventAnimation(eventId) {
    gameState.stirCount += 1;

    startBottleShakeCycle(
        eventId
    );

    if (eventId === "flip") {
        applyFlipEvent();
        return;
    }

    if (eventId === "swap") {
        applySwapEvent();
        return;
    }

    if (eventId === "spill") {
        applySpillEvent();
        return;
    }

    finishEvent();
}

function startBottleShakeCycle(eventId) {
    let intensity = 0.72;
    let speed = 34;
    let travelX = 5;
    let travelY = 1.5;
    let rotation = 3.5;

    if (eventId === "flip") {
        intensity = 0.92;
        speed = 29;
        travelX = 4;
        travelY = 4;
        rotation = 7;
    } else if (
        eventId === "swap"
    ) {
        intensity = 0.78;
        speed = 38;
        travelX = 7;
        travelY = 1;
        rotation = 3;
    } else if (
        eventId === "spill"
    ) {
        intensity = 1;
        speed = 43;
        travelX = 9;
        travelY = 2;
        rotation = 8;
    }

    gameState.shakeMotion = {
        visible: true,
        eventId: eventId,
        intensity: 0,
        targetIntensity:
            intensity,
        speed: speed,
        travelX: travelX,
        travelY: travelY,
        rotationAmount:
            rotation,
        alpha: 0,
        clamp: 0,
        pulse: 0,
    };

    tween(
        0.16,
        gameState.shakeMotion,
        {
            intensity:
                intensity,
            alpha: 255,
            clamp: 1,
            pulse: 1,
        },
        tween.easing.bounceOut,
        function() {
            tween(
                0.22,
                gameState.shakeMotion,
                {
                    pulse: 0.25,
                },
                tween.easing.quadOut
            );
        }
    );
}

function getBottleShakeOffset() {
    const motion =
        gameState.shakeMotion;

    if (
        !motion ||
        !motion.visible
    ) {
        return {
            x: 0,
            y: 0,
            rotation: 0,
            intensity: 0,
        };
    }

    const intensity =
        motion.intensity || 0;

    const speed =
        motion.speed || 34;

    const wave1 =
        Math.sin(
            ElapsedTime *
            speed
        );

    const wave2 =
        Math.sin(
            ElapsedTime *
            speed *
            0.63 +
            1.7
        );

    let x =
        wave1 *
        motion.travelX *
        intensity;

    let y =
        wave2 *
        motion.travelY *
        intensity;

    let rotation =
        wave1 *
        motion.rotationAmount *
        intensity;

    if (
        motion.eventId ===
        "flip"
    ) {
        x *= 0.62;

        y +=
            Math.sin(
                ElapsedTime *
                speed *
                0.48
            ) *
            3.5 *
            intensity;

        rotation +=
            wave2 *
            4 *
            intensity;
    } else if (
        motion.eventId ===
        "spill"
    ) {
        const kick =
            Math.max(
                0,
                Math.sin(
                    ElapsedTime *
                    speed *
                    0.37
                )
            );

        x +=
            kick *
            5 *
            intensity;

        rotation +=
            kick *
            4 *
            intensity;
    }

    return {
        x: x,
        y: y,
        rotation: rotation,
        intensity:
            intensity,
    };
}

function drawBottleShakeRig() {
    const motion =
        gameState.shakeMotion;

    if (
        !motion ||
        !motion.visible ||
        motion.alpha <= 0
    ) {
        return;
    }

    const nodePosition =
        getBoardNodeScreenPosition(
            gameState.currentNodeId
        );

    const boardBottleX =
        nodePosition.x;

    const boardBottleY =
        nodePosition.y +
        CONFIG.boardBottleRailOffset -
        (
            CONFIG.boardBottleScreenLift ||
            0
        );

    const inspection =
        getBottleInspectionGeometry();

    const shake =
        getBottleShakeOffset();

    drawBoardBottleShakeClamp(
        boardBottleX,
        boardBottleY,
        motion,
        shake
    );

    drawInspectionBottleShakeClamp(
        inspection,
        motion,
        shake
    );
}

function drawBoardBottleShakeClamp(
    x,
    y,
    motion,
    shake
) {
    const alpha =
        motion.alpha;

    const clamp =
        motion.clamp;

    const intensity =
        shake.intensity;

    const bodyHalfW =
        CONFIG.boardBottleWidth *
        0.5 +
        8;

    const clampX =
        bodyHalfW +
        (
            1 -
            clamp
        ) *
        13;

    const clampY =
        y + 4;

    rectMode(CENTER);
    ellipseMode(CENTER);

    noStroke();

    fill(
        7,
        5,
        4,
        alpha * 0.38
    );

    rect(
        x,
        y - 1,
        62,
        8,
        4
    );

    fill(
        55,
        37,
        27,
        alpha * 0.94
    );

    rect(
        x,
        y - 1,
        58,
        6,
        3
    );

    fill(
        157,
        101,
        55,
        alpha * 0.94
    );

    rect(
        x - clampX,
        clampY,
        9,
        22,
        3
    );

    rect(
        x + clampX,
        clampY,
        9,
        22,
        3
    );

    fill(
        226,
        174,
        104,
        alpha * 0.72
    );

    rect(
        x - clampX + 2,
        clampY,
        2,
        16,
        1
    );

    rect(
        x + clampX - 2,
        clampY,
        2,
        16,
        1
    );

    noFill();

    stroke(
        236,
        194,
        126,
        alpha * 0.68
    );

    strokeWidth(1.4);

    rect(
        x - clampX,
        clampY,
        9,
        22,
        3
    );

    rect(
        x + clampX,
        clampY,
        9,
        22,
        3
    );

    noStroke();

    const lineAlpha =
        alpha *
        intensity *
        0.72;

    if (lineAlpha > 1) {
        stroke(
            245,
            205,
            137,
            lineAlpha
        );

        strokeWidth(1.6);

        const motionDistance =
            12 +
            intensity * 7;

        for (
            let index = 0;
            index < 3;
            index += 1
        ) {
            const offsetY =
                -13 +
                index * 13;

            line(
                x -
                clampX -
                7,
                clampY +
                offsetY,
                x -
                clampX -
                motionDistance,
                clampY +
                offsetY
            );

            line(
                x +
                clampX +
                7,
                clampY +
                offsetY,
                x +
                clampX +
                motionDistance,
                clampY +
                offsetY
            );
        }

        noStroke();
    }

    if (
        motion.eventId ===
        "flip"
    ) {
        noFill();

        stroke(
            245,
            207,
            142,
            lineAlpha * 0.85
        );

        strokeWidth(1.8);

        const arcRadius =
            23 +
            intensity * 5;

        const nativeContext =
            typeof CodeaLite !==
                "undefined" &&
            CodeaLite.state
                ? CodeaLite.state.ctx
                : null;

        if (nativeContext) {
            const ctx =
                nativeContext;

            ctx.save();

            ctx.beginPath();

            ctx.arc(
                x,
                y + 3,
                arcRadius,
                Math.PI * 0.10,
                Math.PI * 0.90
            );

            ctx.strokeStyle =
                "rgba(245,207,142," +
                String(
                    Math.max(
                        0,
                        Math.min(
                            1,
                            lineAlpha /
                            255 *
                            0.85
                        )
                    )
                ) +
                ")";

            ctx.lineWidth = 1.8;

            ctx.stroke();

            ctx.restore();
        }

        noStroke();
    }

    rectMode(CORNER);
}

function drawInspectionBottleShakeClamp(
    geometry,
    motion,
    shake
) {
    const alpha =
        motion.alpha;

    const intensity =
        shake.intensity;

    const centerX =
        geometry.centerX;

    const bodyCenterY =
        geometry.centerY +
        (
            geometry.bodyBottom +
            geometry.bodyTop
        ) *
        geometry.scale *
        0.5;

    const bodyHalfW =
        geometry.bodyWidth *
        geometry.scale *
        0.5;

    const bodyHalfH =
        geometry.bodyHeight *
        geometry.scale *
        0.5;

    const clampX =
        bodyHalfW + 7;

    const clampW = 9;

    const clampH =
        Math.min(
            44,
            bodyHalfH * 0.58
        );

    rectMode(CENTER);

    noStroke();

    fill(
        8,
        5,
        4,
        alpha * 0.32
    );

    rect(
        centerX,
        bodyCenterY,
        bodyHalfW * 2 +
        48,
        9,
        4
    );

    fill(
        54,
        36,
        27,
        alpha * 0.90
    );

    rect(
        centerX,
        bodyCenterY,
        bodyHalfW * 2 +
        43,
        6,
        3
    );

    fill(
        147,
        94,
        52,
        alpha * 0.92
    );

    rect(
        centerX - clampX,
        bodyCenterY,
        clampW,
        clampH,
        3
    );

    rect(
        centerX + clampX,
        bodyCenterY,
        clampW,
        clampH,
        3
    );

    fill(
        229,
        178,
        107,
        alpha * 0.62
    );

    rect(
        centerX -
        clampX +
        2,
        bodyCenterY,
        2,
        clampH - 9,
        1
    );

    rect(
        centerX +
        clampX -
        2,
        bodyCenterY,
        2,
        clampH - 9,
        1
    );

    noFill();

    stroke(
        232,
        188,
        117,
        alpha * 0.62
    );

    strokeWidth(1.4);

    rect(
        centerX - clampX,
        bodyCenterY,
        clampW,
        clampH,
        3
    );

    rect(
        centerX + clampX,
        bodyCenterY,
        clampW,
        clampH,
        3
    );

    noStroke();

    const lineAlpha =
        alpha *
        intensity *
        0.64;

    if (lineAlpha > 1) {
        stroke(
            244,
            205,
            139,
            lineAlpha
        );

        strokeWidth(1.5);

        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            const lineY =
                bodyCenterY -
                25 +
                index * 17;

            const length =
                8 +
                (
                    index % 2
                ) *
                5 +
                intensity * 4;

            line(
                centerX -
                clampX -
                5,
                lineY,
                centerX -
                clampX -
                length,
                lineY
            );

            line(
                centerX +
                clampX +
                5,
                lineY,
                centerX +
                clampX +
                length,
                lineY
            );
        }

        noStroke();
    }

    if (
        motion.eventId ===
        "spill"
    ) {
        stroke(
            247,
            183,
            113,
            lineAlpha * 0.90
        );

        strokeWidth(2);

        line(
            centerX +
                bodyHalfW +
                10,
            bodyCenterY +
                bodyHalfH *
                0.58,
            centerX +
                bodyHalfW +
                26,
            bodyCenterY +
                bodyHalfH *
                0.72
        );

        line(
            centerX +
                bodyHalfW +
                19,
            bodyCenterY +
                bodyHalfH *
                0.68,
            centerX +
                bodyHalfW +
                26,
            bodyCenterY +
                bodyHalfH *
                0.72
        );

        line(
            centerX +
                bodyHalfW +
                23,
            bodyCenterY +
                bodyHalfH *
                0.60,
            centerX +
                bodyHalfW +
                26,
            bodyCenterY +
                bodyHalfH *
                0.72
        );

        noStroke();
    }

    rectMode(CORNER);
}


function applyFlipEvent() {
    const slots =
        gameState.glass.slots;

    if (slots.length === 0) {
        finishEventAfterDelay(0.35);
        return;
    }

    if (slots.length === 1) {
        const token =
            slots[0];

        token.drawX = 0;
        token.drawY =
            getGlassSlotLocalY(0);
        token.rot = 0;

        tween(
            CONFIG.flipLiftDuration,
            token,
            {
                drawY:
                    token.drawY + 22,
                rot: 18,
            },
            tween.easing.quadOut,
            function() {
                tween(
                    CONFIG.flipSettleDuration,
                    token,
                    {
                        drawY:
                            getGlassSlotLocalY(
                                0
                            ),
                        rot: 0,
                    },
                    tween.easing.bounceOut,
                    function() {
                        resetGlassTokenTransforms();
                        finishEvent();
                    }
                );
            }
        );

        return;
    }

    for (
        let index = 0;
        index < slots.length;
        index += 1
    ) {
        const token =
            slots[index];

        const startY =
            getGlassSlotLocalY(
                index
            );

        const targetY =
            getGlassSlotLocalY(
                slots.length -
                    index -
                    1
            );

        const direction =
            index % 2 === 0
                ? -1
                : 1;

        token.drawX = 0;
        token.drawY = startY;
        token.rot = 0;

        tween(
            CONFIG.flipLiftDuration,
            token,
            {
                drawY:
                    startY + 20,
                rot:
                    direction * 12,
            },
            tween.easing.quadOut,
            function() {
                tween(
                    CONFIG.flipMoveDuration,
                    token,
                    {
                        drawX:
                            direction * 42,
                        drawY: targetY,
                        rot:
                            direction * 28,
                    },
                    tween.easing.sineInOut,
                    function() {
                        tween(
                            CONFIG.flipSettleDuration,
                            token,
                            {
                                drawX: 0,
                                rot: 0,
                            },
                            tween.easing.quadIn
                        );
                    }
                );
            }
        );
    }

    /*
     * 返し仕込みの動きが始まる瞬間に鳴らす。
     * 完了時には鳴らさない。
     */
    colaRollPlaySound(
        "slot_shuffle"
    );

    const totalDuration =
        CONFIG.flipLiftDuration +
        CONFIG.flipMoveDuration +
        CONFIG.flipSettleDuration;

    const timer = {
        value: 0,
    };

    tween(
        totalDuration,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            gameState.glass.slots.reverse();
            resetGlassTokenTransforms();

            finishEvent();
        }
    );
}

function applySwapEvent() {
    const slots =
        gameState.glass.slots;

    const token1 =
        gameState.eventTarget1;

    const token2 =
        gameState.eventTarget2;

    if (
        slots.length > 1 &&
        token1 &&
        token2
    ) {
        const index1 =
            slots.indexOf(token1);

        const index2 =
            slots.indexOf(token2);

        if (
            index1 < 0 ||
            index2 < 0
        ) {
            finishEventAfterDelay(0.35);
            return;
        }

        const y1 =
            getGlassSlotLocalY(
                index1
            );

        const y2 =
            getGlassSlotLocalY(
                index2
            );

        /*
         * 入れ替えアニメーションが始まる瞬間に鳴らす。
         * 終了時には鳴らさない。
         */
        colaRollPlaySound(
            "slot_shuffle"
        );

        resetTokenVisualTransform(
            token1,
            y1
        );

        resetTokenVisualTransform(
            token2,
            y2
        );

        const motion1 =
            ensureTokenLiquidMotion(
                token1
            );

        const motion2 =
            ensureTokenLiquidMotion(
                token2
            );

        tween(
            0.12,
            token1,
            {
                drawX: -10,
                rot: -4,
            },
            tween.easing.quadOut
        );

        tween(
            0.12,
            token2,
            {
                drawX: 10,
                rot: 4,
            },
            tween.easing.quadOut
        );

        tween(
            0.12,
            motion1,
            {
                waveBoost: 0.8,
                stretchX: 1.04,
            },
            tween.easing.quadOut
        );

        tween(
            0.12,
            motion2,
            {
                waveBoost: 0.8,
                stretchX: 1.04,
            },
            tween.easing.quadOut,
            function() {
                tween(
                    0.28,
                    token1,
                    {
                        drawY: y2,
                        drawX: 6,
                        rot: 2,
                    },
                    tween.easing.sineInOut
                );

                tween(
                    0.28,
                    token2,
                    {
                        drawY: y1,
                        drawX: -6,
                        rot: -2,
                    },
                    tween.easing.sineInOut
                );

                tween(
                    0.28,
                    motion1,
                    {
                        waveBoost: 1.25,
                        stretchX: 1.01,
                    },
                    tween.easing.sineInOut
                );

                tween(
                    0.28,
                    motion2,
                    {
                        waveBoost: 1.25,
                        stretchX: 1.01,
                    },
                    tween.easing.sineInOut,
                    function() {
                        tween(
                            0.14,
                            token1,
                            {
                                drawX: 0,
                                rot: 0,
                            },
                            tween.easing.quadIn
                        );

                        tween(
                            0.14,
                            token2,
                            {
                                drawX: 0,
                                rot: 0,
                            },
                            tween.easing.quadIn
                        );

                        tween(
                            0.14,
                            motion1,
                            {
                                waveBoost: 0,
                                stretchX: 1,
                            },
                            tween.easing.quadOut
                        );

                        tween(
                            0.14,
                            motion2,
                            {
                                waveBoost: 0,
                                stretchX: 1,
                            },
                            tween.easing.quadOut,
                            function() {
                                slots[index1] =
                                    token2;

                                slots[index2] =
                                    token1;

                                settleTokensToCurrentSlots();

                                finishEvent();
                            }
                        );
                    }
                );
            }
        );

        return;
    }

    if (slots.length === 1) {
        const token =
            slots[0];

        resetTokenVisualTransform(
            token,
            getGlassSlotLocalY(0)
        );

        const motion =
            ensureTokenLiquidMotion(
                token
            );

        tween(
            0.16,
            motion,
            {
                waveBoost: 1.0,
                stretchX: 1.05,
            },
            tween.easing.sineInOut,
            function() {
                tween(
                    0.18,
                    motion,
                    {
                        waveBoost: 0,
                        stretchX: 1,
                    },
                    tween.easing.sineInOut,
                    function() {
                        settleTokensToCurrentSlots();
                        finishEvent();
                    }
                );
            }
        );

        return;
    }

    finishEventAfterDelay(0.35);
}


function applySpillEvent() {
    const slots =
        gameState.glass.slots;

    const spilled =
        gameState.eventTarget1;

    if (
        slots.length === 0 ||
        !spilled
    ) {
        finishEventAfterDelay(0.40);
        return;
    }

    const index =
        slots.indexOf(spilled);

    if (index < 0) {
        finishEventAfterDelay(0.40);
        return;
    }

    const presentation =
        gameState.eventSpillPresentation;

    const spillDirection =
        presentation &&
        presentation.direction
            ? presentation.direction
            : 1;

    const spillDuration =
        Math.max(
            0.46,
            CONFIG.spillMoveDuration ||
                0
        );

    const hasLeadIn =
        presentation &&
        presentation.active &&
        presentation.ingredientId ===
            spilled.ingredientId;

    if (!hasLeadIn) {
        resetTokenVisualTransform(
            spilled,
            getGlassSlotLocalY(index)
        );
    }

    const spilledMotion =
        ensureTokenLiquidMotion(
            spilled
        );

    for (
        let i = index + 1;
        i < slots.length;
        i += 1
    ) {
        const token =
            slots[i];

        resetTokenVisualTransform(
            token,
            getGlassSlotLocalY(i)
        );

        ensureTokenLiquidMotion(
            token
        );
    }

    tween(
        0.12,
        spilledMotion,
        {
            waveBoost: 1.15,
            stretchX: 1.07,
        },
        tween.easing.quadOut,
        function() {
            if (presentation) {
                presentation.stage =
                    "spilling";

                colaRollPlaySound(
                    "spill"
                );

                presentation.startedAt =
                    typeof ElapsedTime !==
                        "undefined"
                        ? ElapsedTime
                        : 0;

                presentation.duration =
                    spillDuration;
            }

            tween(
                spillDuration,
                spilled,
                {
                    drawX:
                        spillDirection * 34,
                    drawY:
                        getGlassSlotLocalY(
                            index
                        ) + 14,
                    rot:
                        spillDirection * 16,
                },
                tween.easing.quadInOut
            );

            tween(
                spillDuration,
                spilledMotion,
                {
                    alpha: 0,
                    fillProgress: 0.08,
                    waveBoost: 1.8,
                    surfaceLift: 5,
                    stretchX: 1.10,
                },
                tween.easing.quadIn,
                function() {
                    if (presentation) {
                        presentation.stage =
                            "settling";
                    }

                    const currentIndex =
                        slots.indexOf(
                            spilled
                        );

                    if (currentIndex >= 0) {
                        slots.splice(
                            currentIndex,
                            1
                        );
                    }

                    spilled.spillReason =
                        "event";

                    clearTokenLiquidMotion(
                        spilled
                    );

                    delete spilled.drawX;
                    delete spilled.drawY;
                    delete spilled.rot;

                    if (
                        !gameState.glass.spilledTokens
                    ) {
                        gameState.glass.spilledTokens =
                            [];
                    }

                    gameState.glass.spilledTokens.push(
                        spilled
                    );

                    if (slots.length <= 0) {
                        finishEvent();
                        return;
                    }

                    let completed =
                        0;

                    const required =
                        slots.length;

                    const onSettled =
                        function() {
                            completed += 1;

                            if (
                                completed >=
                                required
                            ) {
                                settleTokensToCurrentSlots();
                                finishEvent();
                            }
                        };

                    for (
                        let i = 0;
                        i < slots.length;
                        i += 1
                    ) {
                        const token =
                            slots[i];

                        const motion =
                            ensureTokenLiquidMotion(
                                token
                            );

                        tween(
                            0.24,
                            token,
                            {
                                drawY:
                                    getGlassSlotLocalY(
                                        i
                                    ),
                                drawX: 0,
                                rot: 0,
                            },
                            tween.easing.quadOut
                        );

                        tween(
                            0.24,
                            motion,
                            {
                                waveBoost: 0.85,
                                stretchX: 1.03,
                            },
                            tween.easing.quadOut,
                            function() {
                                tween(
                                    0.16,
                                    motion,
                                    {
                                        waveBoost: 0,
                                        stretchX: 1,
                                    },
                                    tween.easing.quadOut,
                                    onSettled
                                );
                            }
                        );
                    }
                }
            );
        }
    );
}



function finishEventAfterDelay(duration) {
    const timer = {
        value: 0,
    };

    tween(
        duration,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            finishEvent();
        }
    );
}

function finishEvent() {
    gameState.phase =
        "EVENT_FINISHED";

    if (gameState.eventAnim) {
        tween(
            CONFIG.eventFinishHoldDuration,
            gameState.eventAnim,
            {
                iconAlpha: 0,
                panelMaskAlpha: 0,
            },
            tween.easing.quadIn
        );
    }

    if (
        gameState.shakeMotion &&
        gameState.shakeMotion.visible
    ) {
        tween(
            CONFIG.eventFinishHoldDuration,
            gameState.shakeMotion,
            {
                intensity: 0,
                alpha: 0,
                clamp: 0,
                pulse: 0,
            },
            tween.easing.quadIn
        );
    }

    const timer = {
        value: 0,
    };

    tween(
        CONFIG.eventFinishHoldDuration,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            resetGlassTokenTransforms();

            gameState.eventResultData =
                null;

            gameState.eventTarget1 =
                null;

            gameState.eventTarget2 =
                null;

            gameState.eventAnim =
                null;

            if (
                gameState.shakeMotion
            ) {
                gameState.shakeMotion.visible =
                    false;

                gameState.shakeMotion =
                    null;
            }

            if (
                gameState.remainingSteps > 0
            ) {
                moveOneStep();
            } else {
                gameState.phase =
                    "WAIT_CAP_POWER";
            }
        }
    );
}


function showGarnishReveal(
    garnish,
    onComplete
) {
    startGarnishGetPopup(
        garnish,
        function() {
            startGarnishTrayReveal(
                garnish,
                onComplete
            );
        }
    );
}


startGarnishGetEffect = function(
    garnish,
    onComplete
) {
    startGarnishGetEffectBaseForMultipleGarnishes(
        garnish,
        function() {
            /*
             * この直後に pressureDelta が処理されても、
             * 瓶ではなく小皿が反応するよう印を立てる。
             */
            gameState.useGarnishTrayPressureResponse =
                true;

            startGarnishTrayReaction(
                garnish
            );

            if (onComplete) {
                onComplete();
            }
        }
    );
};


function getGarnishTrayScreenPosition() {
    const geometry =
        getBottleInspectionGeometry();

    const panel =
        geometry.panel;

    const desiredX =
        geometry.centerX -
        geometry.bodyWidth *
            geometry.scale *
            0.78;

    const desiredY =
        geometry.centerY +
        (
            geometry.bodyBottom +
            10
        ) *
        geometry.scale;

    return {
        x:
            Math.max(
                panel.x +
                    20,
                desiredX
            ),

        y:
            Math.max(
                panel.y +
                    18,
                desiredY
            ),
    };
}


function drawGarnishSymbol(
    garnish,
    x,
    y,
    size,
    alpha,
    rotationValue
) {
    pushMatrix();

    translate(
        x,
        y
    );

    rotate(
        rotationValue || 0
    );

    ellipseMode(CENTER);
    rectMode(CENTER);

    if (
        garnish === "cherry"
    ) {
        stroke(
            78,
            118,
            62,
            alpha
        );

        strokeWidth(
            Math.max(
                1,
                size * 0.10
            )
        );

        line(
            size * 0.08,
            size * 0.28,
            size * 0.44,
            size * 0.78
        );

        noStroke();

        fill(
            185,
            42,
            48,
            alpha
        );

        ellipse(
            0,
            0,
            size
        );

        fill(
            236,
            78,
            73,
            alpha * 0.82
        );

        ellipse(
            -size * 0.18,
            size * 0.18,
            size * 0.38
        );

        fill(
            255,
            177,
            160,
            alpha * 0.72
        );

        ellipse(
            -size * 0.22,
            size * 0.24,
            size * 0.16
        );
    } else {
        fill(
            218,
            210,
            62,
            alpha
        );

        noStroke();

        ellipse(
            0,
            0,
            size
        );

        fill(
            239,
            228,
            96,
            alpha
        );

        ellipse(
            0,
            0,
            size * 0.72
        );

        fill(
            63,
            96,
            46,
            alpha
        );

        ellipse(
            0,
            0,
            size * 0.24
        );

        stroke(
            255,
            246,
            165,
            alpha * 0.72
        );

        strokeWidth(
            Math.max(
                1,
                size * 0.07
            )
        );

        line(
            0,
            -size * 0.36,
            0,
            size * 0.36
        );

        line(
            -size * 0.36,
            0,
            size * 0.36,
            0
        );

        noStroke();
    }

    rectMode(CORNER);

    popMatrix();
}


function changePressure(
    delta,
    onComplete
) {
    if (delta === 0) {
        if (onComplete) {
            onComplete();
        }

        return;
    }

    const useTrayResponse =
        gameState.useGarnishTrayPressureResponse ===
        true;

    gameState.useGarnishTrayPressureResponse =
        false;

    if (
        delta > 0 &&
        gameState.glass.pressure >=
            CONFIG.pressureMax
    ) {
        triggerBurst(
            onComplete
        );

        return;
    }

    gameState.phase =
        "PRESSURE_CHANGE";

    const previousPressure =
        gameState.glass.pressure;

    gameState.glass.pressure =
        Math.max(
            CONFIG.pressureMin,
            Math.min(
                CONFIG.pressureMax,
                gameState.glass.pressure +
                    delta
            )
        );

    const changed =
        gameState.glass.pressure -
        previousPressure;

    if (changed > 0) {
        spawnCarbonationParticles(
            CONFIG.pressureBubbleCount,
            false
        );

        if (
            gameState.pendingBottleEffectSound ===
            "fizz"
        ) {
            gameState.pendingBottleEffectSound =
                null;

            colaRollPlaySound(
                "fizz"
            );
        }
    }

    /*
     * レモン・チェリー取得時は、
     * 瓶ではなく小皿の着地アニメーションを使う。
     */
    if (useTrayResponse) {
        gameState.glassPulse.scale =
            1;

        if (
            typeof tween === "undefined" ||
            !tween ||
            !tween.easing
        ) {
            if (onComplete) {
                onComplete();
            }

            return;
        }

        const timer = {
            value: 0,
        };

        tween(
            CONFIG.pressureChangeDuration,
            timer,
            {
                value: 1,
            },
            tween.easing.linear,
            function() {
                gameState.glassPulse.scale =
                    1;

                if (onComplete) {
                    onComplete();
                }
            }
        );

        return;
    }

    gameState.glassPulse.scale =
        changed > 0
            ? 0.92
            : 1.08;

    tween(
        CONFIG.pressureChangeDuration,
        gameState.glassPulse,
        {
            scale: 1,
        },
        tween.easing.bounceOut,
        function() {
            if (onComplete) {
                onComplete();
            }
        }
    );
}


function triggerBurst(onComplete) {
    gameState.phase =
        "BURSTING";

    gameState.pendingBottleEffectSound =
        null;

    colaRollPlaySound(
        "spill"
    );

    gameState.burstCount += 1;

    gameState.burstState = {
        shake: 1,
        flash: 1,
    };

    spawnCarbonationParticles(
        CONFIG.burstParticleCount,
        true
    );

    tween(
        CONFIG.burstDuration,
        gameState.burstState,
        {
            shake: 0,
            flash: 0,
        },
        tween.easing.quadOut
    );

    if (
        gameState.glass.slots.length > 0
    ) {
        const tokenIndex =
            gameState.glass.slots.length -
            1;

        const position =
            getGlassSlotScreenPosition(
                tokenIndex
            );

        const spilled =
            gameState.glass.slots.pop();

        spilled.spillReason =
            "burst";

        gameState.burstToken = {
            ingredientId:
                spilled.ingredientId,
            sourceToken: spilled,
            x: position.x,
            y: position.y,
            rotation: 0,
            scale: 1,
            alpha: 255,
        };

        tween(
            CONFIG.burstTokenFlightDuration,
            gameState.burstToken,
            {
                x:
                    position.x +
                    Math.random() * 110 -
                    55,
                y:
                    position.y +
                    170 +
                    Math.random() * 45,
                rotation:
                    220 +
                    Math.random() * 180,
                scale: 0.65,
                alpha: 80,
            },
            tween.easing.quadOut,
            function() {
                gameState.glass.spilledTokens.push(
                    spilled
                );

                gameState.burstToken =
                    null;
            }
        );
    }

    const timer = {
        value: 0,
    };

    tween(
        CONFIG.burstDuration,
        timer,
        {
            value: 1,
        },
        tween.easing.linear,
        function() {
            gameState.glass.pressure =
                CONFIG.burstResetPressure;

            gameState.phase =
                "BURST_RESULT";

            const holdTimer = {
                value: 0,
            };

            tween(
                CONFIG.burstResultHoldDuration,
                holdTimer,
                {
                    value: 1,
                },
                tween.easing.linear,
                function() {
                    gameState.burstState =
                        null;

                    if (onComplete) {
                        onComplete();
                    }
                }
            );
        }
    );
}

function getGlassScreenGeometry() {
    const geometry =
        getBottleInspectionGeometry();

    return {
        centerX:
            geometry.centerX,

        centerY:
            geometry.centerY +
            (
                geometry.bodyBottom +
                geometry.bodyTop
            ) *
            geometry.scale *
            0.5,

        scale:
            geometry.scale,

        glassH:
            geometry.bodyTop -
            geometry.bodyBottom,

        topW:
            geometry.bodyWidth,

        bottomW:
            geometry.bodyWidth,

        left:
            geometry.centerX -
            geometry.bodyWidth *
                geometry.scale *
                0.5,

        right:
            geometry.centerX +
            geometry.bodyWidth *
                geometry.scale *
                0.5,

        bottom:
            geometry.centerY +
            geometry.bodyBottom *
                geometry.scale,

        top:
            geometry.centerY +
            geometry.bodyTop *
                geometry.scale,
    };
}

function getBottleInspectionGeometry() {
    const panel =
        layout.glass;

    const scaleValue =
        Math.min(
            panel.w / 142,
            panel.h / 286,
            0.92
        );

    const centerX =
        panel.x +
        panel.w * 0.5;

    const centerY =
        panel.y +
        panel.h * 0.43;

    const bodyBottom =
        -CONFIG.inspectionBottleBodyHeight *
        0.5 -
        18;

    const bodyTop =
        CONFIG.inspectionBottleBodyHeight *
        0.5 -
        18;

    const shoulderY =
        bodyTop + 7;

    const neckBottom =
        bodyTop + 17;

    const neckTop =
        neckBottom +
        CONFIG.inspectionBottleNeckHeight;

    return {
        panel: panel,
        centerX: centerX,
        centerY: centerY,
        scale: scaleValue,

        bodyWidth:
            CONFIG.inspectionBottleBodyWidth,

        bodyHeight:
            CONFIG.inspectionBottleBodyHeight,

        bodyBottom:
            bodyBottom,

        bodyTop:
            bodyTop,

        shoulderY:
            shoulderY,

        neckBottom:
            neckBottom,

        neckTop:
            neckTop,

        neckWidth:
            CONFIG.inspectionBottleNeckWidth,

        mouthWidth:
            CONFIG.inspectionBottleMouthWidth,

        mouthHeight:
            CONFIG.inspectionBottleMouthHeight,
    };
}

function spawnCarbonationParticles(count, burst) {
    const geometry =
        getGlassScreenGeometry();

    for (
        let index = 0;
        index < count;
        index += 1
    ) {
        const startX =
            geometry.centerX +
            Math.random() *
                geometry.bottomW *
                geometry.scale -
            geometry.bottomW *
                geometry.scale *
                0.5;

        const startY =
            burst
                ? geometry.centerY +
                    Math.random() *
                        geometry.glassH *
                        geometry.scale *
                        0.55
                : geometry.bottom +
                    Math.random() * 30;

        const life =
            burst
                ? 0.75 +
                    Math.random() * 0.75
                : 0.65 +
                    Math.random() * 0.55;

        gameState.carbonationParticles.push(
            {
                x: startX,
                y: startY,
                vx:
                    burst
                        ? Math.random() *
                                150 -
                            75
                        : Math.random() *
                                18 -
                            9,
                vy:
                    burst
                        ? 80 +
                            Math.random() *
                                150
                        : 45 +
                            Math.random() *
                                45,
                size:
                    3 +
                    Math.random() * 5,
                life: life,
                maxLife: life,
                burst: burst,
            }
        );
    }
}

function updateCarbonationParticles() {
    if (
        gameState.glass.pressure > 0 &&
        gameState.phase !== "TITLE" &&
        Math.random() <
            gameState.glass.pressure *
                DeltaTime *
                0.75
    ) {
        spawnCarbonationParticles(
            1,
            false
        );
    }

    for (
        let index =
            gameState.carbonationParticles.length -
            1;
        index >= 0;
        index -= 1
    ) {
        const particle =
            gameState.carbonationParticles[
                index
            ];

        particle.life -=
            DeltaTime;

        particle.x +=
            particle.vx *
            DeltaTime;

        particle.y +=
            particle.vy *
            DeltaTime;

        particle.vx *=
            0.985;

        if (particle.burst) {
            particle.vy -=
                120 *
                DeltaTime;
        } else {
            particle.x +=
                Math.sin(
                    ElapsedTime * 8 +
                    index
                ) *
                10 *
                DeltaTime;
        }

        if (particle.life <= 0) {
            gameState.carbonationParticles.splice(
                index,
                1
            );
        }
    }

    /*
     * 瓶の炭酸とは別に、
     * 王冠周辺の短い泡だけを更新する。
     */
    colaRollUpdateCapBubbleFeedback();
}

/*
 * 王冠発射時だけ使う、短い炭酸の尾。
 *
 * 瓶の泡全体は動かさず、王冠パネル内の王冠周辺にだけ出す。
 * 泡は基本的に上昇しながら、発射方向へ少し傾く。
 */
function colaRollUpdateCapBubbleFeedback() {
    if (
        !gameState ||
        !gameState.capBubbleFeedback
    ) {
        return;
    }

    const feedback =
        gameState.capBubbleFeedback;

    feedback.elapsed +=
        DeltaTime;

    for (
        let index =
            feedback.particles.length - 1;
        index >= 0;
        index -= 1
    ) {
        const particle =
            feedback.particles[
                index
            ];

        particle.life -=
            DeltaTime;

        particle.x +=
            particle.vx *
            DeltaTime;

        particle.y +=
            particle.vy *
            DeltaTime;

        /*
         * 横方向の勢いはすぐに弱まり、
         * 泡本来の上昇へ戻る。
         */
        particle.vx *=
            Math.pow(
                0.90,
                DeltaTime * 60
            );

        particle.vy +=
            22 *
            DeltaTime;

        particle.vy =
            Math.min(
                particle.vy,
                particle.riseSpeed
            );

        /*
         * 完全な直線にせず、
         * 炭酸らしい小さな揺らぎを残す。
         */
        particle.x +=
            Math.sin(
                ElapsedTime *
                    particle.wobbleSpeed +
                particle.wobbleOffset
            ) *
            particle.wobbleAmount *
            DeltaTime;

        if (
            particle.life <= 0
        ) {
            feedback.particles.splice(
                index,
                1
            );
        }
    }

    if (
        feedback.particles.length <= 0 ||
        feedback.elapsed >=
            feedback.duration
    ) {
        gameState.capBubbleFeedback =
            null;
    }
}


function colaRollHasSeenCapBubbleGuide() {
    if (
        typeof localStorage ===
        "undefined"
    ) {
        return false;
    }

    try {
        return (
            localStorage.getItem(
                "midnightColaBubbleGuideSeen"
            ) === "1"
        );
    } catch (error) {
        return false;
    }
}


function colaRollStoreCapBubbleGuideSeen() {
    if (
        typeof localStorage ===
        "undefined"
    ) {
        return;
    }

    try {
        localStorage.setItem(
            "midnightColaBubbleGuideSeen",
            "1"
        );
    } catch (error) {
        /*
         * 保存できない環境でも
         * ゲーム進行には影響させない。
         */
    }
}


function colaRollStartCapBubbleFeedback(
    board,
    directionRatio,
    power
) {
    if (
        !gameState ||
        !board
    ) {
        return;
    }

    const firstGuide =
        !colaRollHasSeenCapBubbleGuide();

    /*
     * 初回だけ少し分かりやすくする。
     * 2回目以降も、ごく短い反応は残す。
     */
    const particleCount =
        firstGuide
            ? 14
            : 8;

    const strength =
        Math.max(
            0.18,
            Math.min(
                1,
                power
            )
        );

    const directionX =
        Math.max(
            -1,
            Math.min(
                1,
                directionRatio
            )
        );

    const particles = [];

    for (
        let index = 0;
        index < particleCount;
        index += 1
    ) {
        const spread =
            Math.random() *
                2 -
            1;

        const startDistance =
            Math.random() *
            board.capSize *
            0.42;

        /*
         * 王冠の少し後ろから出し、
         * 王冠の進行方向へ短く伸ばす。
         */
        const startX =
            board.centerX +
            spread *
                board.capSize *
                0.32 -
            directionX *
                startDistance *
                0.24;

        const startY =
            board.launchY +
            Math.random() *
                board.capSize *
                0.30 -
            board.capSize *
                0.08;

        const directionSpeed =
            (
                firstGuide
                    ? 48
                    : 34
            ) *
            (
                0.55 +
                strength *
                    0.75
            );

        const riseSpeed =
            (
                firstGuide
                    ? 56
                    : 46
            ) +
            Math.random() *
                22;

        const life =
            (
                firstGuide
                    ? 0.46
                    : 0.34
            ) +
            Math.random() *
                0.20;

        particles.push(
            {
                x:
                    startX,

                y:
                    startY,

                vx:
                    directionX *
                        directionSpeed *
                        (
                            0.72 +
                            Math.random() *
                                0.38
                        ) +
                    spread * 7,

                /*
                 * Codea座標では正方向が上。
                 */
                vy:
                    riseSpeed *
                    (
                        0.70 +
                        Math.random() *
                            0.25
                    ),

                riseSpeed:
                    riseSpeed,

                size:
                    (
                        firstGuide
                            ? 2.6
                            : 2.2
                    ) +
                    Math.random() *
                        2.8,

                life:
                    life,

                maxLife:
                    life,

                wobbleSpeed:
                    9 +
                    Math.random() *
                        6,

                wobbleOffset:
                    Math.random() *
                    Math.PI *
                    2,

                wobbleAmount:
                    3 +
                    Math.random() *
                        4,
            }
        );
    }

    gameState.capBubbleFeedback = {
        particles:
            particles,

        elapsed:
            0,

        duration:
            firstGuide
                ? 0.78
                : 0.58,

        firstGuide:
            firstGuide,
    };

    if (firstGuide) {
        colaRollStoreCapBubbleGuideSeen();
    }
}


function startAddingIngredient(ingredientId) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    startIngredientGetEffect(
        ingredientId,
        function() {
            if (
                ingredientId === "ice"
            ) {
                startBottleCooling();
                return;
            }

            beginIngredientFlightAfterGet(
                ingredientId
            );
        }
    );
}


function startIngredientGetEffect(
    ingredientId,
    onComplete
) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    const isCooling =
        ingredientId === "ice";

    const centerX =
        WIDTH * 0.5;

    const centerY =
        HEIGHT * 0.535;

    gameState.phase =
        "INGREDIENT_GET";

    gameState.ingredientGetEffect = {
        visible: true,
        kind: isCooling
            ? "cooling"
            : "ingredient",
        ingredientId: ingredientId,
        displayName: isCooling
            ? (
                gameState.language === "ja"
                    ? "冷却"
                    : "Cooling"
            )
            : "",
        detailText: "",
        x: centerX,
        baseY: centerY,
        y: centerY + 42,
        alpha: 0,
        scale: 0.88,
        glow: 0,
        ring: 0,
        elapsed: 0,
        inDuration: 0.20,
        holdDuration: 0.68,
        outDuration: 0.24,
        completed: false,
        onComplete: onComplete,
    };

    colaRollPlaySound(
        "material_popup"
    );
}

function startCarbonationGetEffect(
    onComplete
) {
    const centerX =
        WIDTH * 0.5;

    const centerY =
        HEIGHT * 0.535;

    const beginBottleCarbonation =
        function() {
            /*
             * ポップアップ後、実際に圧力が瓶へ反映される時だけ
             * fizz を鳴らすための印。
             */
            gameState.pendingBottleEffectSound =
                "fizz";

            if (onComplete) {
                onComplete();
            }
        };

    gameState.phase =
        "INGREDIENT_GET";

    gameState.ingredientGetEffect = {
        visible: true,
        kind: "carbonation",
        ingredientId: null,
        displayName:
            gameState.language === "ja"
                ? "炭酸水"
                : "Sparkling Water",
        detailText: "",
        accentColor: {
            r: 178,
            g: 224,
            b: 255,
        },
        x: centerX,
        baseY: centerY,
        y: centerY + 42,
        alpha: 0,
        scale: 0.88,
        glow: 0,
        ring: 0,
        elapsed: 0,
        inDuration: 0.20,
        holdDuration: 0.68,
        outDuration: 0.24,
        completed: false,
        onComplete: beginBottleCarbonation,
    };

    colaRollPlaySound(
        "material_popup"
    );
}




function updateIngredientGetEffect() {
    const effect =
        gameState.ingredientGetEffect;

    if (
        !effect ||
        !effect.visible ||
        effect.completed
    ) {
        return;
    }

    effect.elapsed +=
        Math.max(
            0,
            DeltaTime
        );

    const inDuration =
        effect.inDuration || 0.20;

    const holdDuration =
        effect.holdDuration || 0.68;

    const outDuration =
        effect.outDuration || 0.24;

    const totalDuration =
        inDuration +
        holdDuration +
        outDuration;

    if (
        effect.elapsed >=
        totalDuration
    ) {
        const onComplete =
            effect.onComplete;

        effect.completed = true;
        effect.visible = false;
        effect.alpha = 0;

        gameState.ingredientGetEffect =
            null;

        if (onComplete) {
            onComplete();
        }
    }
}



function beginIngredientFlightAfterGet(
    ingredientId
) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    completeIngredientAddition(
        ingredientId
    );
}



function drawIngredientGetEffect() {
    const effect =
        gameState.ingredientGetEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const ingredient =
        effect.ingredientId
            ? INGREDIENTS[
                effect.ingredientId
            ]
            : null;

    if (
        !ingredient &&
        !effect.displayName
    ) {
        return;
    }

    const elapsed =
        effect.elapsed || 0;

    const inDuration =
        effect.inDuration || 0.20;

    const holdDuration =
        effect.holdDuration || 0.68;

    const outDuration =
        effect.outDuration || 0.24;

    const baseY =
        effect.baseY || HEIGHT * 0.535;

    let alpha = 255;
    let y = baseY;
    let scaleValue = 1;
    let glow = 1;
    let ring = 0.42;

    if (
        elapsed <
        inDuration
    ) {
        const t =
            Math.max(
                0,
                Math.min(
                    1,
                    elapsed /
                        inDuration
                )
            );

        const ease =
            1 -
            Math.pow(
                1 - t,
                2
            );

        alpha =
            255 * ease;

        y =
            baseY +
            42 *
                (1 - ease);

        scaleValue =
            0.88 +
            0.12 * ease;

        glow = ease;
        ring =
            0.42 * ease;
    } else if (
        elapsed <
        inDuration +
            holdDuration
    ) {
        const t =
            (
                elapsed -
                inDuration
            ) /
            holdDuration;

        alpha = 255;
        y = baseY;

        scaleValue =
            1 +
            Math.sin(
                t * Math.PI
            ) *
                0.018;

        glow =
            1 - t * 0.18;

        ring =
            0.42 + t * 0.18;
    } else {
        const t =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed -
                        inDuration -
                        holdDuration
                    ) /
                        outDuration
                )
            );

        const ease = t * t;

        alpha =
            255 *
            (1 - ease);

        y =
            baseY +
            48 * ease;

        scaleValue =
            1 -
            0.06 * ease;

        glow =
            0.82 *
            (1 - ease);

        ring =
            0.60 +
            0.40 * ease;
    }

    const colorValue =
        effect.accentColor ||
        (
            ingredient &&
            ingredient.color
                ? ingredient.color
                : {}
        );

    const accentR =
        colorValue.r === undefined
            ? 232
            : colorValue.r;

    const accentG =
        colorValue.g === undefined
            ? 167
            : colorValue.g;

    const accentB =
        colorValue.b === undefined
            ? 73
            : colorValue.b;

    const panelW =
        Math.min(
            230,
            WIDTH * 0.58
        );

    const panelH =
        Math.min(
            154,
            HEIGHT * 0.19
        );

    const panelOffsetY = 10;

    const iconCenterY =
        panelOffsetY +
        panelH * 0.12;

    const nameY =
        panelOffsetY -
        panelH * 0.30;

    const dividerY =
        panelOffsetY -
        panelH * 0.10;

    const detailY =
        panelOffsetY +
        panelH * 0.31;

    const iconSize =
        Math.min(
            34,
            WIDTH * 0.084
        );

    const name =
        effect.displayName ||
        ingredient[
            gameState.language
        ] ||
        ingredient.en ||
        "";

    const detailText =
        effect.detailText || "";

    pushMatrix();

    translate(
        effect.x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    noStroke();

    fill(
        4,
        3,
        3,
        alpha * 0.28
    );

    ellipse(
        8,
        panelOffsetY -
            panelH * 0.53,
        panelW * 0.82,
        18
    );

    fill(
        20,
        13,
        11,
        alpha * 0.92
    );

    rect(
        0,
        panelOffsetY,
        panelW,
        panelH,
        17
    );

    fill(
        63,
        35,
        23,
        alpha * 0.42
    );

    rect(
        0,
        panelOffsetY +
            panelH * 0.06,
        panelW - 16,
        panelH - 18,
        13
    );

    noFill();

    stroke(
        202,
        139,
        68,
        alpha * 0.88
    );

    strokeWidth(2);

    rect(
        0,
        panelOffsetY,
        panelW,
        panelH,
        17
    );

    stroke(
        255,
        223,
        158,
        alpha * 0.36
    );

    strokeWidth(1);

    rect(
        0,
        panelOffsetY,
        panelW - 9,
        panelH - 9,
        13
    );

    noFill();

    stroke(
        accentR,
        accentG,
        accentB,
        alpha *
            (
                0.18 +
                glow * 0.32
            )
    );

    strokeWidth(2);

    ellipse(
        0,
        iconCenterY,
        iconSize * 1.74 +
            ring * 18
    );

    noStroke();

    fill(
        255,
        239,
        190,
        alpha * 0.13
    );

    ellipse(
        0,
        iconCenterY,
        iconSize * 1.56
    );

    drawGetPopupIcon(
        effect,
        0,
        iconCenterY,
        iconSize,
        alpha
    );

    fill(
        255,
        229,
        169,
        alpha
    );

    fontSize(
        Math.min(
            18,
            WIDTH * 0.044
        )
    );

    textAlign(CENTER);

    text(
        name,
        0,
        nameY
    );

    noStroke();

    if (detailText) {
        noStroke();

        fill(
            accentR,
            accentG,
            accentB,
            alpha * 0.82
        );

        fontSize(
            Math.min(
                10,
                WIDTH * 0.026
            )
        );

        text(
            detailText,
            0,
            detailY
        );
    }

    noStroke();

    fill(
        255,
        244,
        210,
        alpha * 0.42
    );

    ellipse(
        -panelW * 0.32,
        panelOffsetY +
            panelH * 0.25,
        3
    );

    fill(
        207,
        239,
        244,
        alpha * 0.30
    );

    ellipse(
        panelW * 0.34,
        panelOffsetY +
            panelH * 0.20,
        2.6
    );

    rectMode(CORNER);

    popMatrix();

    noStroke();
}


function drawGetPopupIcon(
    effect,
    x,
    y,
    size,
    alpha
) {
    if (!effect) {
        return;
    }

    if (
        effect.kind ===
        "garnish"
    ) {
        if (
            typeof drawGarnishSymbol ===
            "function"
        ) {
            drawGarnishSymbol(
                effect.garnish,
                x,
                y,
                size * 0.92,
                alpha,
                effect.garnish === "cherry"
                    ? -16
                    : 12
            );

            return;
        }

        pushMatrix();

        translate(
            x,
            y
        );

        noStroke();

        if (
            effect.garnish ===
            "cherry"
        ) {
            fill(
                220,
                74,
                68,
                alpha
            );

            ellipse(
                0,
                0,
                size * 0.58
            );

            stroke(
                86,
                132,
                72,
                alpha
            );

            strokeWidth(
                Math.max(
                    1,
                    size * 0.08
                )
            );

            line(
                size * 0.08,
                size * 0.20,
                size * 0.26,
                size * 0.44
            );
        } else {
            noFill();

            stroke(
                225,
                214,
                68,
                alpha
            );

            strokeWidth(
                Math.max(
                    2,
                    size * 0.12
                )
            );

            ellipse(
                0,
                0,
                size * 0.62
            );

            stroke(
                88,
                138,
                72,
                alpha
            );

            strokeWidth(
                Math.max(
                    1,
                    size * 0.06
                )
            );

            ellipse(
                0,
                0,
                size * 0.28
            );
        }

        noStroke();

        popMatrix();

        return;
    }

    if (
        effect.kind ===
        "carbonation"
    ) {
        pushMatrix();

        translate(
            x,
            y
        );

        noStroke();

        fill(
            185,
            230,
            255,
            alpha * 0.22
        );

        ellipse(
            0,
            0,
            size * 0.92
        );

        fill(
            206,
            241,
            255,
            alpha * 0.92
        );

        ellipse(
            -size * 0.12,
            size * 0.08,
            size * 0.16
        );

        ellipse(
            size * 0.10,
            -size * 0.02,
            size * 0.21
        );

        ellipse(
            0,
            -size * 0.18,
            size * 0.28
        );

        noFill();

        stroke(
            232,
            248,
            255,
            alpha * 0.88
        );

        strokeWidth(
            Math.max(
                1.2,
                size * 0.05
            )
        );

        ellipse(
            -size * 0.18,
            size * 0.16,
            size * 0.16
        );

        ellipse(
            size * 0.20,
            size * 0.04,
            size * 0.20
        );

        ellipse(
            0,
            -size * 0.18,
            size * 0.28
        );

        stroke(
            168,
            214,
            245,
            alpha * 0.72
        );

        strokeWidth(
            Math.max(
                1,
                size * 0.04
            )
        );

        line(
            -size * 0.24,
            -size * 0.26,
            size * 0.24,
            -size * 0.26
        );

        noStroke();

        popMatrix();

        return;
    }

    if (
        effect.ingredientId &&
        typeof drawIngredientIcon ===
            "function"
    ) {
        drawIngredientIcon(
            effect.ingredientId,
            x,
            y,
            size,
            alpha
        );

        return;
    }

    pushMatrix();

    translate(
        x,
        y
    );

    noStroke();

    fill(
        232,
        167,
        73,
        alpha * 0.90
    );

    ellipse(
        0,
        0,
        size * 0.72
    );

    fill(
        255,
        230,
        170,
        alpha * 0.38
    );

    ellipse(
        -size * 0.15,
        -size * 0.14,
        size * 0.18
    );

    popMatrix();
}

function drawRoastBeanPairCore(
    x,
    y,
    size,
    alpha,
    options
) {
    const settings =
        options || {};

    const beanScale =
        settings.beanScale === undefined
            ? 1
            : settings.beanScale;

    const showSyrupDrop =
        settings.showSyrupDrop === undefined
            ? true
            : !!settings.showSyrupDrop;

    const glowAlpha =
        settings.glowAlpha === undefined
            ? 0
            : settings.glowAlpha;

    pushMatrix();
    translate(x, y);
    noStroke();

    if (glowAlpha > 0) {
        fill(
            244,
            181,
            96,
            alpha * glowAlpha
        );

        ellipse(
            0,
            0,
            size * 1.02
        );

        fill(
            255,
            229,
            173,
            alpha * glowAlpha * 0.65
        );

        ellipse(
            0,
            0,
            size * 0.72
        );
    }

    function drawBean(
        beanX,
        beanY,
        beanW,
        beanH,
        rotationDeg
    ) {
        pushMatrix();
        translate(beanX, beanY);
        rotate(rotationDeg);

        fill(
            68,
            38,
            21,
            alpha
        );

        ellipse(
            0,
            0,
            beanW,
            beanH
        );

        fill(
            112,
            62,
            34,
            alpha * 0.82
        );

        ellipse(
            -beanW * 0.11,
            beanH * 0.08,
            beanW * 0.46,
            beanH * 0.56
        );

        noFill();
        stroke(
            223,
            162,
            96,
            alpha * 0.90
        );
        strokeWidth(
            Math.max(
                1.0,
                size * 0.050
            )
        );
        line(
            0,
            -beanH * 0.30,
            0,
            beanH * 0.30
        );

        noStroke();
        popMatrix();
    }

    const beanW =
        size * 0.30 * beanScale;

    const beanH =
        size * 0.48 * beanScale;

    drawBean(
        -size * 0.17,
        size * 0.03,
        beanW,
        beanH,
        -24
    );

    drawBean(
        size * 0.17,
        -size * 0.03,
        beanW,
        beanH,
        22
    );

    if (showSyrupDrop) {
        fill(
            182,
            107,
            48,
            alpha * 0.92
        );

        ellipse(
            0,
            -size * 0.28,
            size * 0.15,
            size * 0.20
        );

        fill(
            246,
            196,
            122,
            alpha * 0.56
        );

        ellipse(
            -size * 0.03,
            -size * 0.24,
            size * 0.05,
            size * 0.08
        );
    }

    fill(
        255,
        224,
        164,
        alpha * 0.54
    );

    ellipse(
        -size * 0.28,
        size * 0.24,
        Math.max(
            1.8,
            size * 0.10
        )
    );

    popMatrix();
}

const drawGetPopupIconBaseForRoastSyrupRefresh =
    drawGetPopupIcon;

drawGetPopupIcon = function(
    effect,
    x,
    y,
    size,
    alpha
) {
    if (
        effect &&
        effect.ingredientId ===
            "roast_syrup"
    ) {
        drawRoastBeanPairCore(
            x,
            y,
            size * 1.18,
            alpha,
            {
                beanScale: 1.08,
                showSyrupDrop: true,
                glowAlpha: 0.12,
            }
        );

        return;
    }

    return drawGetPopupIconBaseForRoastSyrupRefresh(
        effect,
        x,
        y,
        size,
        alpha
    );
};


function startGarnishTrayReveal(
    garnish,
    onComplete
) {
    gameState.phase =
        "GARNISH_REVEAL";

    const source =
        getBoardNodeScreenPosition(
            gameState.currentNodeId
        );

    const target =
        getGarnishTrayScreenPosition();

    const effect =
        gameState.garnishEffect;

    effect.visible = true;
    effect.garnish = garnish;

    effect.startX =
        source.x;

    effect.startY =
        source.y;

    effect.x =
        source.x;

    effect.y =
        source.y + 2;

    effect.targetX =
        target.x;

    effect.targetY =
        target.y;

    effect.scale = 0.42;
    effect.alpha = 0;
    effect.rotation = 0;
    effect.progress = 0;
    effect.arrivalPulse = 0;

    tween(
        CONFIG.garnishRevealDuration *
        0.42,
        effect,
        {
            y:
                source.y + 19,

            scale: 1.12,
            alpha: 255,
        },
        tween.easing.bounceOut,
        function() {
            tween(
                CONFIG.garnishRevealDuration *
                0.92,
                effect,
                {
                    x:
                        target.x,

                    y:
                        target.y + 3,

                    scale: 0.82,

                    rotation:
                        garnish === "cherry"
                            ? 210
                            : -210,

                    progress: 1,
                },
                tween.easing.sineInOut,
                function() {
                    gameState.glass.garnish =
                        garnish;

                    if (
                        typeof addCollectedGarnish ===
                        "function"
                    ) {
                        addCollectedGarnish(
                            garnish
                        );
                    }

                    if (
                        typeof startGarnishTrayReaction ===
                        "function"
                    ) {
                        startGarnishTrayReaction(
                            garnish,
                            true
                        );
                    }

                    effect.arrivalPulse =
                        1;

                    /* ガーニッシュは瓶の代わりに小皿へ到着した瞬間。 */
                    colaRollPlaySound(
                        "ingredient_drop",
                        {
                            volume: 0.36,
                        }
                    );

                    effect.scale =
                        1.22;

                    tween(
                        0.22,
                        effect,
                        {
                            scale: 0.78,
                            arrivalPulse: 0,
                        },
                        tween.easing.bounceOut,
                        function() {
                            tween(
                                CONFIG.garnishHoldDuration *
                                0.55,
                                effect,
                                {
                                    alpha: 0,
                                    scale: 0.68,
                                },
                                tween.easing.quadIn,
                                function() {
                                    effect.visible =
                                        false;

                                    effect.garnish =
                                        null;

                                    effect.scale =
                                        1;

                                    effect.alpha =
                                        255;

                                    effect.rotation =
                                        0;

                                    effect.progress =
                                        0;

                                    effect.arrivalPulse =
                                        0;

                                    if (onComplete) {
                                        onComplete();
                                    }
                                }
                            );
                        }
                    );
                }
            );
        }
    );
}



function startGarnishGetPopup(
    garnish,
    onComplete
) {
    const isCherry =
        garnish === "cherry";

    const centerX =
        WIDTH * 0.5;

    const centerY =
        HEIGHT * 0.535;

    gameState.phase =
        "INGREDIENT_GET";

    gameState.ingredientGetEffect = {
        visible: true,
        kind: "garnish",
        garnish: garnish,
        hideTrayPreview: true,
        ingredientId: null,
        displayName:
            gameState.language === "ja"
                ? (
                    isCherry
                        ? "チェリー"
                        : "レモンピール"
                )
                : (
                    isCherry
                        ? "Cherry"
                        : "Lemon Peel"
                ),
        detailText: "",
        accentColor:
            isCherry
                ? {
                    r: 219,
                    g: 85,
                    b: 72,
                }
                : {
                    r: 231,
                    g: 216,
                    b: 74,
                },
        x: centerX,
        baseY: centerY,
        y: centerY + 42,
        alpha: 0,
        scale: 0.88,
        glow: 0,
        ring: 0,
        elapsed: 0,
        inDuration: 0.20,
        holdDuration: 0.68,
        outDuration: 0.24,
        completed: false,
        onComplete: onComplete,
    };

    colaRollPlaySound(
        "material_popup"
    );
}


function drawIngredientGetBackdrop() {

    const effect =

        gameState.ingredientGetEffect;

    if (

        !effect ||

        !effect.visible

    ) {

        return;

    }

    const panel =

        layout.board;

    if (!panel) {

        return;

    }

    const elapsed =

        effect.elapsed || 0;

    const inDuration =

        effect.inDuration || 0.20;

    const holdDuration =

        effect.holdDuration || 0.68;

    const outDuration =

        effect.outDuration || 0.24;

    let fade = 1;

    if (

        elapsed <

        inDuration

    ) {

        fade =

            Math.max(

                0,

                Math.min(

                    1,

                    elapsed /

                        inDuration

                )

            );

    } else if (

        elapsed >

        inDuration +

            holdDuration

    ) {

        fade =

            1 -

            Math.max(

                0,

                Math.min(

                    1,

                    (

                        elapsed -

                        inDuration -

                        holdDuration

                    ) /

                    outDuration

                )

            );

    }

    rectMode(CORNER);

    noStroke();

    fill(

        0,

        0,

        0,

        88 * fade

    );

    rect(

        panel.x + 6,

        panel.y + 6,

        panel.w - 12,

        panel.h - 12,

        18

    );

    fill(

        25,

        12,

        6,

        34 * fade

    );

    rect(

        panel.x + 18,

        panel.y + 18,

        panel.w - 36,

        panel.h - 36,

        14

    );

    noStroke();

}


function startBottleCooling() {
    gameState.phase =
        "COOLING_BOTTLE";

    gameState.chillCount =
        Math.min(
            CONFIG.coolingMaxLevel,
            (
                gameState.chillCount ||
                0
            ) +
            1
        );

    /* 冷却値が瓶へ反映された瞬間。 */
    colaRollPlaySound(
        "ice_drop"
    );

    const effect =
        gameState.coolingEffect;

    effect.visible = true;
    effect.nodeId =
        gameState.currentNodeId;
    effect.progress = 0;
    effect.pulse = 0;
    effect.alpha = 0;

    gameState.glassPulse.scale =
        0.92;

    tween(
        CONFIG.coolingRevealDuration,
        gameState.glassPulse,
        {
            scale: 1.06,
        },
        tween.easing.bounceOut,
        function() {
            tween(
                CONFIG.coolingFadeDuration,
                gameState.glassPulse,
                {
                    scale: 1,
                },
                tween.easing.quadOut
            );
        }
    );

    tween(
        CONFIG.coolingRevealDuration,
        effect,
        {
            progress: 1,
            pulse: 1,
            alpha: 255,
        },
        tween.easing.quadOut,
        function() {
            const holdTimer = {
                value: 0,
            };

            tween(
                CONFIG.coolingHoldDuration,
                holdTimer,
                {
                    value: 1,
                },
                tween.easing.linear,
                function() {
                    tween(
                        CONFIG.coolingFadeDuration,
                        effect,
                        {
                            progress: 1.35,
                            pulse: 0,
                            alpha: 0,
                        },
                        tween.easing.quadIn,
                        function() {
                            effect.visible =
                                false;

                            effect.nodeId =
                                null;

                            effect.progress =
                                0;

                            effect.pulse =
                                0;

                            effect.alpha =
                                0;

                            gameState.phase =
                                "WAIT_CAP_POWER";
                        }
                    );
                }
            );
        }
    );
}

function getBottleChillCount() {
    let legacyIceCount = 0;

    if (
        gameState.glass &&
        gameState.glass.slots
    ) {
        for (
            const token of
            gameState.glass.slots
        ) {
            if (
                token.ingredientId ===
                "ice"
            ) {
                legacyIceCount += 1;
            }
        }
    }

    return Math.min(
        CONFIG.coolingMaxLevel,
        (
            gameState.chillCount ||
            0
        ) +
        legacyIceCount
    );
}

function drawBottleChillIndicator() {
    const chillCount =
        getBottleChillCount();

    if (chillCount <= 0) {
        return;
    }

    const geometry =
        getBottleInspectionGeometry();

    const alpha =
        42 +
        chillCount * 24;

    pushMatrix();

    translate(
        geometry.centerX,
        geometry.centerY
    );

    scale(
        geometry.scale,
        geometry.scale
    );

    noFill();

    stroke(
        205,
        238,
        248,
        alpha * 0.68
    );

    strokeWidth(
        0.9 +
        chillCount * 0.18
    );

    line(
        -geometry.bodyWidth *
            0.41,
        geometry.bodyBottom + 30,
        -geometry.bodyWidth *
            0.38,
        geometry.bodyTop - 28
    );

    stroke(
        232,
        250,
        255,
        alpha * 0.28
    );

    strokeWidth(0.9);

    line(
        geometry.bodyWidth *
            0.38,
        geometry.bodyBottom + 36,
        geometry.bodyWidth *
            0.34,
        geometry.bodyTop - 44
    );

    noStroke();

    const dotCount =
        Math.min(
            5,
            2 + chillCount
        );

    for (
        let index = 0;
        index < dotCount;
        index += 1
    ) {
        const side =
            index % 2 === 0
                ? -1
                : 1;

        const x =
            side *
            (
                geometry.bodyWidth *
                    0.20 +
                (
                    index % 2
                ) *
                    5
            );

        const y =
            geometry.bodyBottom +
            48 +
            index * 24;

        fill(
            232,
            252,
            255,
            alpha * 0.34
        );

        ellipse(
            x,
            y,
            2.2 +
            chillCount * 0.14
        );
    }

    noStroke();

    rectMode(CORNER);

    popMatrix();
}


function drawBottleCoolingEffect() {
    const effect =
        gameState.coolingEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const nodePosition =
        getBoardNodeScreenPosition(
            effect.nodeId
        );

    const boardBottleX =
        nodePosition.x;

    const boardBottleY =
        nodePosition.y +
        CONFIG.boardBottleRailOffset;

    const geometry =
        getBottleInspectionGeometry();

    const progress =
        effect.progress;

    const pulse =
        effect.pulse;

    const alpha =
        effect.alpha;

    const ringProgress =
        Math.max(
            0,
            Math.min(
                1,
                progress
            )
        );

    noFill();

    stroke(
        202,
        238,
        249,
        alpha * 0.66
    );

    strokeWidth(
        1.8 +
        pulse * 1.1
    );

    ellipse(
        boardBottleX,
        boardBottleY,
        CONFIG.coolingBoardRingSize *
        (
            0.70 +
            ringProgress * 0.42
        )
    );

    stroke(
        235,
        251,
        255,
        alpha * 0.22
    );

    strokeWidth(1.1);

    ellipse(
        boardBottleX,
        boardBottleY,
        CONFIG.coolingBoardRingSize *
        (
            1.00 +
            ringProgress * 0.54
        )
    );

    const mistCount = 6;

    noStroke();

    for (
        let index = 0;
        index < mistCount;
        index += 1
    ) {
        const angle =
            (
                index /
                mistCount
            ) *
            Math.PI *
            2 +
            progress * 2.0;

        const distance =
            10 +
            ringProgress * 18;

        const mistX =
            boardBottleX +
            Math.cos(
                angle
            ) *
            distance;

        const mistY =
            boardBottleY +
            Math.sin(
                angle
            ) *
            distance *
            0.60;

        fill(
            220,
            246,
            252,
            alpha * 0.22
        );

        ellipse(
            mistX,
            mistY,
            3.4
        );
    }

    pushMatrix();

    translate(
        geometry.centerX,
        geometry.centerY
    );

    scale(
        geometry.scale,
        geometry.scale
    );

    noFill();

    stroke(
        205,
        239,
        248,
        alpha *
        (
            0.28 +
            pulse * 0.10
        )
    );

    strokeWidth(
        1.2 +
        pulse * 0.4
    );

    line(
        -geometry.bodyWidth *
            0.42,
        geometry.bodyBottom + 28,
        -geometry.bodyWidth *
            0.45,
        geometry.bodyTop - 32
    );

    stroke(
        235,
        253,
        255,
        alpha * 0.16
    );

    strokeWidth(1.0);

    line(
        geometry.bodyWidth *
            0.39,
        geometry.bodyBottom + 34,
        geometry.bodyWidth *
            0.34,
        geometry.bodyTop - 46
    );

    noStroke();

    for (
        let index = 0;
        index < 4;
        index += 1
    ) {
        const side =
            index % 2 === 0
                ? -1
                : 1;

        const x =
            side *
            geometry.bodyWidth *
            0.22;

        const y =
            geometry.bodyBottom +
            46 +
            index * 26;

        fill(
            230,
            252,
            255,
            alpha *
            (
                0.14 +
                pulse * 0.05
            )
        );

        ellipse(
            x,
            y,
            2.6
        );
    }

    rectMode(CORNER);

    popMatrix();

    noStroke();
}

function drawBottleCoolingFog() {
    const effect =
        gameState.coolingEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const geometry =
        getBottleInspectionGeometry();

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        return;
    }

    const progress =
        Math.max(
            0,
            effect.progress || 0
        );

    const alphaRatio =
        Math.max(
            0,
            Math.min(
                1,
                (effect.alpha || 0) /
                    255
            )
        );

    const fogPeak =
        Math.max(
            0,
            1 -
            Math.abs(
                progress - 0.64
            ) /
            0.58
        );

    const fogAlpha =
        alphaRatio *
        (
            0.06 +
            fogPeak * 0.34
        );

    if (fogAlpha <= 0.01) {
        return;
    }

    pushMatrix();

    translate(
        geometry.centerX,
        geometry.centerY
    );

    scale(
        geometry.scale *
            gameState.glassPulse.scale,
        geometry.scale *
            gameState.glassPulse.scale
    );

    const ctx =
        nativeContext;

    const bodyCenterY =
        geometry.bodyTop +
        (
            geometry.bodyBottom -
            geometry.bodyTop
        ) *
        0.52;

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        5
    );

    ctx.clip();

    const verticalFog =
        ctx.createLinearGradient(
            0,
            geometry.neckTop,
            0,
            geometry.bodyBottom
        );

    verticalFog.addColorStop(
        0,
        "rgba(244, 253, 255, 0)"
    );

    verticalFog.addColorStop(
        0.22,
        "rgba(244, 253, 255, " +
        String(
            fogAlpha * 0.42
        ) +
        ")"
    );

    verticalFog.addColorStop(
        0.58,
        "rgba(248, 255, 255, " +
        String(
            fogAlpha * 0.76
        ) +
        ")"
    );

    verticalFog.addColorStop(
        1,
        "rgba(244, 253, 255, 0)"
    );

    ctx.fillStyle =
        verticalFog;

    ctx.fillRect(
        -geometry.bodyWidth,
        geometry.neckTop - 12,
        geometry.bodyWidth * 2,
        geometry.bodyBottom -
            geometry.neckTop +
            24
    );

    const centerFog =
        ctx.createRadialGradient(
            -geometry.bodyWidth * 0.08,
            bodyCenterY,
            geometry.bodyWidth * 0.06,
            0,
            bodyCenterY,
            geometry.bodyWidth * 0.74
        );

    centerFog.addColorStop(
        0,
        "rgba(255, 255, 255, " +
        String(
            fogAlpha * 0.88
        ) +
        ")"
    );

    centerFog.addColorStop(
        0.48,
        "rgba(240, 252, 255, " +
        String(
            fogAlpha * 0.42
        ) +
        ")"
    );

    centerFog.addColorStop(
        1,
        "rgba(240, 252, 255, 0)"
    );

    ctx.fillStyle =
        centerFog;

    ctx.fillRect(
        -geometry.bodyWidth,
        geometry.bodyTop - 18,
        geometry.bodyWidth * 2,
        geometry.bodyBottom -
            geometry.bodyTop +
            36
    );

    ctx.restore();

    popMatrix();
}



function getBoardNodeScreenPosition(nodeId) {
    const node =
        BOARD_NODES[nodeId];

    const panel =
        layout.board;

    if (!node) {
        return {
            x:
                panel.x +
                panel.w * 0.5,
            y:
                panel.y +
                panel.h * 0.5,
        };
    }

    const worldX =
        node.nx *
        CONFIG.mapWidth;

    const worldY =
        node.ny *
        CONFIG.mapHeight;

    return {
        x:
            panel.x +
            (worldX -
                gameState.camera.x) *
                gameState.camera.zoom +
            panel.w * 0.5,

        y:
            panel.y +
            (worldY -
                gameState.camera.y) *
                gameState.camera.zoom +
            panel.h * 0.28,
    };
}

function getBoardBottleMouthScreenPosition(
    nodeId
) {
    const nodePosition =
        getBoardNodeScreenPosition(
            nodeId
        );

    const angle =
        (
            CONFIG.boardBottleBaseRotation ||
            0
        ) *
        Math.PI /
        180;

    const localMouthY =
        -CONFIG.boardBottleHeight *
        0.75;

    const bottleScale = 1;

    const rotatedMouthX =
        -localMouthY *
        Math.sin(angle) *
        bottleScale;

    const rotatedMouthY =
        localMouthY *
        Math.cos(angle) *
        bottleScale;

    return {
        x:
            nodePosition.x +
            rotatedMouthX,

        y:
            nodePosition.y +
            CONFIG.boardBottleRailOffset -
            (
                CONFIG.boardBottleScreenLift ||
                0
            ) +
            rotatedMouthY +
            CONFIG.ingredientBottleMouthInsetY,
    };
}

function getGlassSlotScreenPosition(
    slotIndex
) {
    const geometry =
        getBottleInspectionGeometry();

    return {
        x:
            geometry.centerX,

        y:
            geometry.centerY +
            getGlassSlotLocalY(
                slotIndex
            ) *
            geometry.scale,
    };
}


function getGlassSlotLocalY(
    slotIndex
) {
    const innerBottom =
        CONFIG.inspectionBottleInnerBottom;

    const innerTop =
        CONFIG.inspectionBottleInnerTop;

    const slotHeight =
        (
            innerTop -
            innerBottom
        ) /
        CONFIG.glassCapacity;

    return (
        innerBottom +
        slotHeight *
            (
                slotIndex +
                0.5
            )
    );
}

function drawBottleInspectionPanel() {
    const geometry =
        getBottleInspectionGeometry();

    const panel =
        geometry.panel;

    clip(
        panel.x,
        panel.y,
        panel.w,
        panel.h
    );

    const shakeActive =
        typeof isEventActionPhase ===
            "function" &&
        isEventActionPhase();

    const shakeX =
        shakeActive
            ? Math.sin(
                ElapsedTime * 42
            ) * 5
            : 0;

    const shakeRotation =
        shakeActive
            ? Math.sin(
                ElapsedTime * 37
            ) * 3
            : 0;

    pushMatrix();

    translate(
        geometry.centerX +
            shakeX,
        geometry.centerY
    );

    rotate(
        shakeRotation
    );

    scale(
        geometry.scale *
            gameState.glassPulse.scale,
        geometry.scale *
            gameState.glassPulse.scale
    );

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        popMatrix();
        clip();
        return;
    }

    const ctx =
        nativeContext;

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        -4
    );

    ctx.fillStyle =
        "rgba(5, 3, 2, 0.42)";

    ctx.setTransform(
        ctx.getTransform()
    );

    ctx.translate(
        5,
        -8
    );

    ctx.fill();

    ctx.restore();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        0
    );

    ctx.fillStyle =
        "rgba(32, 20, 14, 0.94)";

    ctx.strokeStyle =
        "rgba(225, 207, 174, 0.54)";

    ctx.lineWidth = 3;

    ctx.fill();
    ctx.stroke();

    ctx.restore();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        6
    );

    ctx.fillStyle =
        "rgba(92, 57, 31, 0.38)";

    ctx.fill();

    ctx.clip();

    const slots =
        gameState.glass.slots;

    const slotHeight =
        (
            CONFIG.inspectionBottleInnerTop -
            CONFIG.inspectionBottleInnerBottom
        ) /
        CONFIG.glassCapacity;

    for (
        let index = 0;
        index < slots.length;
        index += 1
    ) {
        const token =
            slots[index];

        const ingredient =
            INGREDIENTS[
                token.ingredientId
            ];

        if (!ingredient) {
            continue;
        }

        const baseY =
            getGlassSlotLocalY(
                index
            );

        const drawY =
            token.drawY ===
            undefined
                ? baseY
                : token.drawY;

        const drawX =
            token.drawX ===
            undefined
                ? 0
                : token.drawX;

        const rotation =
            token.rot ===
            undefined
                ? 0
                : token.rot;

        ctx.save();

        ctx.translate(
            drawX,
            drawY
        );

        ctx.rotate(
            rotation *
                Math.PI /
                180
        );

        drawInspectionBottleLiquidBand(
            ctx,
            geometry,
            ingredient,
            slotHeight,
            index
        );

        ctx.restore();

        pushMatrix();

        translate(
            drawX,
            drawY
        );

        rotate(
            rotation
        );

        drawIngredientIcon(
            token.ingredientId,
            0,
            0,
            Math.min(
                13,
                slotHeight * 0.52
            ),
            205
        );

        popMatrix();
    }

    if (
        slots.length > 0
    ) {
        const liquidTop =
            getGlassSlotLocalY(
                slots.length - 1
            ) +
            slotHeight * 0.43;

        const wave =
            Math.sin(
                ElapsedTime * 2.6
            ) * 1.8;

        ctx.beginPath();

        ctx.moveTo(
            -geometry.bodyWidth,
            liquidTop
        );

        ctx.bezierCurveTo(
            -geometry.bodyWidth *
                0.35,
            liquidTop + wave,
            geometry.bodyWidth *
                0.35,
            liquidTop - wave,
            geometry.bodyWidth,
            liquidTop
        );

        ctx.strokeStyle =
            "rgba(255, 228, 176, 0.34)";

        ctx.lineWidth = 1.5;

        ctx.stroke();
    }

    const pressure =
        gameState.glass.pressure;

    if (pressure > 0) {
        const bubbleCount =
            Math.min(
                16,
                pressure * 4
            );

        for (
            let index = 0;
            index < bubbleCount;
            index += 1
        ) {
            const bubbleX =
                Math.sin(
                    index * 7.31
                ) *
                geometry.bodyWidth *
                0.28;

            const travel =
                (
                    ElapsedTime * 18 +
                    index * 17
                ) %
                (
                    CONFIG.inspectionBottleInnerTop -
                    CONFIG.inspectionBottleInnerBottom
                );

            const bubbleY =
                CONFIG.inspectionBottleInnerBottom +
                travel;

            const bubbleSize =
                2.4 +
                (
                    index % 4
                ) * 0.75;

            ctx.beginPath();

            ctx.ellipse(
                bubbleX,
                bubbleY,
                bubbleSize * 0.5,
                bubbleSize * 0.5,
                0,
                0,
                Math.PI * 2
            );

            ctx.strokeStyle =
                "rgba(218, 244, 249, 0.56)";

            ctx.lineWidth = 1;

            ctx.stroke();
        }
    }

    const amberOverlay =
        ctx.createLinearGradient(
            -geometry.bodyWidth * 0.5,
            0,
            geometry.bodyWidth * 0.5,
            0
        );

    amberOverlay.addColorStop(
        0,
        "rgba(25, 12, 7, 0.22)"
    );

    amberOverlay.addColorStop(
        0.28,
        "rgba(214, 145, 74, 0.06)"
    );

    amberOverlay.addColorStop(
        0.72,
        "rgba(90, 43, 20, 0.04)"
    );

    amberOverlay.addColorStop(
        1,
        "rgba(17, 8, 5, 0.30)"
    );

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        7
    );

    ctx.fillStyle =
        amberOverlay;

    ctx.fill();

    ctx.restore();

    drawInspectionBottleVectorHighlights(
        ctx,
        geometry
    );

    drawPendingBottleGarnish(
        geometry
    );

    if (
        gameState.glass.garnish
    ) {
        const garnishX =
            geometry.bodyWidth *
            0.64;

        const garnishY =
            geometry.bodyTop + 18;

        fill(
            20,
            13,
            10,
            225
        );

        noStroke();

        ellipse(
            garnishX,
            garnishY,
            22
        );

        noFill();

        stroke(
            218,
            169,
            99,
            165
        );

        strokeWidth(1.5);

        ellipse(
            garnishX,
            garnishY,
            22
        );

        noStroke();

        if (
            gameState.glass.garnish ===
            "cherry"
        ) {
            fill(
                211,
                61,
                58,
                235
            );

            ellipse(
                garnishX,
                garnishY,
                8
            );

            fill(
                255,
                157,
                145,
                170
            );

            ellipse(
                garnishX - 2,
                garnishY + 2,
                2.5
            );
        } else {
            noFill();

            stroke(
                228,
                218,
                75,
                235
            );

            strokeWidth(3);

            ellipse(
                garnishX,
                garnishY,
                9
            );

            stroke(
                82,
                127,
                65,
                220
            );

            strokeWidth(1.2);

            line(
                garnishX - 4,
                garnishY,
                garnishX + 4,
                garnishY
            );

            noStroke();
        }
    }

    rectMode(CORNER);
    ellipseMode(CENTER);

    popMatrix();

    clip();
}


function traceInspectionBottleVectorPath(
    ctx,
    geometry,
    inset
) {
    const bodyHalf =
        Math.max(
            18,
            geometry.bodyWidth *
                0.5 -
                inset
        );

    const shoulderHalf =
        Math.max(
            bodyHalf,
            CONFIG.inspectionBottleShoulderWidth *
                0.5 -
                inset * 0.72
        );

    const neckHalf =
        Math.max(
            7,
            geometry.neckWidth *
                0.5 -
                inset * 0.42
        );

    const mouthHalf =
        Math.max(
            neckHalf + 2,
            geometry.mouthWidth *
                0.5 -
                inset * 0.28
        );

    const bottom =
        geometry.bodyBottom +
        inset;

    const bodyTop =
        geometry.bodyTop -
        inset * 0.18;

    const shoulderY =
        geometry.shoulderY -
        inset * 0.12;

    const neckBottom =
        geometry.neckBottom +
        inset * 0.20;

    const neckTop =
        geometry.neckTop -
        inset * 0.12;

    const cornerRadius =
        Math.max(
            7,
            18 -
            inset * 0.65
        );

    ctx.beginPath();

    ctx.moveTo(
        -mouthHalf,
        neckTop + 3
    );

    ctx.bezierCurveTo(
        -mouthHalf,
        neckTop + 7,
        -neckHalf,
        neckTop + 7,
        -neckHalf,
        neckTop
    );

    ctx.lineTo(
        -neckHalf,
        neckBottom
    );

    ctx.bezierCurveTo(
        -neckHalf,
        neckBottom - 9,
        -shoulderHalf,
        shoulderY + 12,
        -bodyHalf,
        bodyTop - 25
    );

    ctx.lineTo(
        -bodyHalf,
        bottom + cornerRadius
    );

    ctx.bezierCurveTo(
        -bodyHalf,
        bottom + 5,
        -bodyHalf + 6,
        bottom,
        -bodyHalf +
            cornerRadius,
        bottom
    );

    ctx.lineTo(
        bodyHalf -
            cornerRadius,
        bottom
    );

    ctx.bezierCurveTo(
        bodyHalf - 6,
        bottom,
        bodyHalf,
        bottom + 5,
        bodyHalf,
        bottom + cornerRadius
    );

    ctx.lineTo(
        bodyHalf,
        bodyTop - 25
    );

    ctx.bezierCurveTo(
        shoulderHalf,
        shoulderY + 12,
        neckHalf,
        neckBottom - 9,
        neckHalf,
        neckBottom
    );

    ctx.lineTo(
        neckHalf,
        neckTop
    );

    ctx.bezierCurveTo(
        neckHalf,
        neckTop + 7,
        mouthHalf,
        neckTop + 7,
        mouthHalf,
        neckTop + 3
    );

    ctx.lineTo(
        mouthHalf,
        neckTop + 7
    );

    ctx.bezierCurveTo(
        mouthHalf,
        neckTop + 11,
        -mouthHalf,
        neckTop + 11,
        -mouthHalf,
        neckTop + 7
    );

    ctx.closePath();
}

function drawInspectionBottleLiquidBandBase(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    const bandWidth =
        geometry.bodyWidth +
        28;

    const halfHeight =
        layerHeight * 0.43;

    const token =
        gameState &&
        gameState.glass &&
        gameState.glass.slots
            ? gameState.glass.slots[
                index
            ]
            : null;

    const reveal =
        token &&
        token.bandReveal
            ? token.bandReveal
            : null;

    const motion =
        token &&
        token.liquidMotion
            ? token.liquidMotion
            : null;

    const revealProgress =
        reveal
            ? Math.max(
                0,
                Math.min(
                    1,
                    reveal.progress || 0
                )
            )
            : 1;

    const revealEase =
        1 -
        Math.pow(
            1 - revealProgress,
            3
        );

    const motionFill =
        motion &&
        motion.fillProgress !==
            undefined
            ? Math.max(
                0,
                Math.min(
                    1,
                    motion.fillProgress
                )
            )
            : 1;

    const motionAlpha =
        motion &&
        motion.alpha !==
            undefined
            ? Math.max(
                0,
                Math.min(
                    1,
                    motion.alpha
                )
            )
            : 1;

    const waveBoost =
        motion &&
        motion.waveBoost !==
            undefined
            ? motion.waveBoost
            : 0;

    const stretchX =
        motion &&
        motion.stretchX !==
            undefined
            ? motion.stretchX
            : 1;

    const surfaceLift =
        motion &&
        motion.surfaceLift !==
            undefined
            ? motion.surfaceLift
            : 0;

    const fillProgress =
        Math.max(
            0.001,
            Math.min(
                1,
                revealEase *
                    motionFill
            )
        );

    const alpha =
        revealEase *
        motionAlpha;

    const baseWave =
        Math.sin(
            ElapsedTime * 2.4 +
            index * 1.7
        ) *
        1.8;

    const entryWave =
        reveal
            ? Math.sin(
                revealEase *
                Math.PI
            ) *
            2.8
            : 0;

    const activeWave =
        Math.sin(
            ElapsedTime * 10.0 +
            index * 2.3
        ) *
        2.2 *
        waveBoost;

    const wave =
        baseWave +
        entryWave +
        activeWave;

    ctx.save();

    /*
     * 帯の下端を固定する。
     * progress = 0 では底に薄くたまり、
     * progress = 1 で本来の高さまで下から満ちる。
     */
    ctx.translate(
        0,
        -halfHeight +
            surfaceLift
    );

    ctx.scale(
        stretchX,
        fillProgress
    );

    ctx.translate(
        0,
        halfHeight
    );

    ctx.beginPath();

    ctx.moveTo(
        -bandWidth,
        -halfHeight
    );

    ctx.bezierCurveTo(
        -bandWidth * 0.35,
        -halfHeight + wave,
        bandWidth * 0.35,
        -halfHeight - wave,
        bandWidth,
        -halfHeight
    );

    ctx.lineTo(
        bandWidth,
        halfHeight
    );

    ctx.bezierCurveTo(
        bandWidth * 0.35,
        halfHeight - wave * 0.45,
        -bandWidth * 0.35,
        halfHeight + wave * 0.45,
        -bandWidth,
        halfHeight
    );

    ctx.closePath();

    ctx.fillStyle =
        "rgba(" +
        String(
            ingredient.color.r
        ) +
        "," +
        String(
            ingredient.color.g
        ) +
        "," +
        String(
            ingredient.color.b
        ) +
        "," +
        String(
            0.84 * alpha
        ) +
        ")";

    ctx.fill();

    const highlight =
        ctx.createLinearGradient(
            -bandWidth,
            0,
            bandWidth,
            0
        );

    highlight.addColorStop(
        0,
        "rgba(255, 242, 213, " +
        String(
            0.02 * alpha
        ) +
        ")"
    );

    highlight.addColorStop(
        0.28,
        "rgba(255, 242, 213, " +
        String(
            0.17 * alpha
        ) +
        ")"
    );

    highlight.addColorStop(
        0.55,
        "rgba(255, 242, 213, " +
        String(
            0.04 * alpha
        ) +
        ")"
    );

    highlight.addColorStop(
        1,
        "rgba(20, 8, 4, " +
        String(
            0.16 * alpha
        ) +
        ")"
    );

    ctx.fillStyle =
        highlight;

    ctx.fill();

    ctx.beginPath();

    ctx.moveTo(
        -bandWidth,
        -halfHeight
    );

    ctx.bezierCurveTo(
        -bandWidth * 0.35,
        -halfHeight + wave,
        bandWidth * 0.35,
        -halfHeight - wave,
        bandWidth,
        -halfHeight
    );

    ctx.strokeStyle =
        "rgba(255, 231, 186, " +
        String(
            0.24 * alpha
        ) +
        ")";

    ctx.lineWidth = 1;

    ctx.stroke();

    ctx.restore();
}



function ensureTokenLiquidMotion(
    token
) {
    if (!token) {
        return null;
    }

    if (!token.liquidMotion) {
        token.liquidMotion = {
            alpha: 1,
            fillProgress: 1,
            waveBoost: 0,
            surfaceLift: 0,
            stretchX: 1,
        };
    }

    return token.liquidMotion;
}

function clearTokenLiquidMotion(
    token
) {
    if (!token) {
        return;
    }

    delete token.liquidMotion;
}

function resetTokenVisualTransform(
    token,
    y
) {
    if (!token) {
        return;
    }

    token.drawX = 0;
    token.drawY = y;
    token.rot = 0;
}

function settleTokensToCurrentSlots() {
    const slots =
        gameState.glass.slots;

    for (
        let index = 0;
        index < slots.length;
        index += 1
    ) {
        const token =
            slots[index];

        resetTokenVisualTransform(
            token,
            getGlassSlotLocalY(
                index
            )
        );

        clearTokenLiquidMotion(
            token
        );
    }
}


function drawInspectionBottleVectorHighlights(
    ctx,
    geometry
) {
    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        0
    );

    ctx.strokeStyle =
        "rgba(233, 222, 199, 0.54)";

    ctx.lineWidth = 2.1;

    ctx.stroke();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        3
    );

    ctx.clip();

    ctx.lineCap =
        "round";

    ctx.lineJoin =
        "round";

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth *
            0.34,
        geometry.bodyBottom + 24
    );

    ctx.lineTo(
        -geometry.bodyWidth *
            0.31,
        geometry.bodyTop - 16
    );

    ctx.strokeStyle =
        "rgba(255, 247, 225, 0.18)";

    ctx.lineWidth = 3.5;

    ctx.stroke();

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth *
            0.30,
        geometry.bodyTop - 7
    );

    ctx.quadraticCurveTo(
        -geometry.bodyWidth *
            0.27,
        geometry.shoulderY + 1,
        -geometry.neckWidth *
            0.40,
        geometry.neckBottom + 5
    );

    ctx.strokeStyle =
        "rgba(255, 247, 225, 0.11)";

    ctx.lineWidth = 2.0;

    ctx.stroke();

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth *
            0.23,
        geometry.bodyBottom + 22
    );

    ctx.lineTo(
        -geometry.bodyWidth *
            0.20,
        geometry.bodyBottom + 54
    );

    ctx.strokeStyle =
        "rgba(255, 247, 225, 0.10)";

    ctx.lineWidth = 1.7;

    ctx.stroke();

    ctx.beginPath();

    ctx.moveTo(
        geometry.bodyWidth *
            0.25,
        geometry.bodyBottom + 18
    );

    ctx.lineTo(
        geometry.bodyWidth *
            0.22,
        geometry.bodyBottom + 38
    );

    ctx.strokeStyle =
        "rgba(255, 235, 202, 0.07)";

    ctx.lineWidth = 1.4;

    ctx.stroke();

    ctx.restore();

    const neckCollarY =
        geometry.neckTop - 3;

    const neckCollarHeight =
        4;

    const capWidth =
        geometry.mouthWidth + 2;

    const capBandHeight =
        7;

    const capBandY =
        geometry.neckTop - 1;

    const capTopY =
        capBandY +
        capBandHeight -
        1.4;

    ctx.beginPath();

    ctx.rect(
        -geometry.mouthWidth *
            0.40,
        neckCollarY,
        geometry.mouthWidth *
            0.80,
        neckCollarHeight
    );

    ctx.fillStyle =
        "rgba(91, 53, 28, 0.94)";

    ctx.fill();

    ctx.strokeStyle =
        "rgba(231, 204, 165, 0.34)";

    ctx.lineWidth = 0.9;

    ctx.stroke();

    ctx.beginPath();

    ctx.rect(
        -capWidth * 0.48,
        capBandY,
        capWidth * 0.96,
        capBandHeight
    );

    ctx.fillStyle =
        "rgba(166, 103, 47, 0.98)";

    ctx.fill();

    ctx.strokeStyle =
        "rgba(244, 223, 185, 0.54)";

    ctx.lineWidth = 1.1;

    ctx.stroke();

    ctx.beginPath();

    ctx.ellipse(
        0,
        capTopY,
        capWidth * 0.44,
        2.8,
        0,
        0,
        Math.PI * 2
    );

    ctx.fillStyle =
        "rgba(195, 132, 65, 0.98)";

    ctx.fill();

    ctx.strokeStyle =
        "rgba(249, 230, 193, 0.48)";

    ctx.lineWidth = 0.9;

    ctx.stroke();

    for (
        let index = 0;
        index < 8;
        index += 1
    ) {
        const ratio =
            index / 7;

        const x =
            -capWidth * 0.38 +
            capWidth * 0.76 * ratio;

        ctx.beginPath();

        ctx.moveTo(
            x,
            capBandY + 1
        );

        ctx.lineTo(
            x,
            capBandY +
                capBandHeight -
                1
        );

        ctx.strokeStyle =
            "rgba(100, 58, 29, 0.46)";

        ctx.lineWidth = 0.8;

        ctx.stroke();
    }

    ctx.restore();
}


function resetGlassTokenTransforms() {
    for (
        const token of
        gameState.glass.slots
    ) {
        delete token.drawX;
        delete token.drawY;
        delete token.rot;
    }
}

function shouldUseGlassTokenTransforms() {
    return (
        gameState.phase === "GLASS_FULL_WARNING" ||
        gameState.phase === "CAPACITY_SPILLING" ||
        gameState.phase === "ADDING_TOKEN" ||
        gameState.phase === "EVENT_WARNING" ||
        gameState.phase === "ANIMATING_EVENT" ||
        gameState.phase === "EVENT_FINISHED" ||
        gameState.phase === "BURST_WARNING" ||
        gameState.phase === "BURSTING" ||
        gameState.phase === "BURST_RESULT"
    );
}


function completeIngredientAddition(
    ingredientId
) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    gameState.landingPulse = 1;

    if (
        gameState.glass.slots.length >=
        CONFIG.glassCapacity
    ) {
        startCapacitySpillAndAdd(
            ingredientId
        );

        return;
    }

    gameState.flyingIngredient =
        null;

    addIngredientToken(
        ingredientId,
        false
    );
}


function startCapacitySpillAndAdd(ingredientId) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.capacitySpillFlow =
            null;

        gameState.ingredientFinishFlow =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    const slots =
        gameState.glass.slots;

    if (
        !slots ||
        slots.length <= 0
    ) {
        gameState.flyingIngredient =
            null;

        addIngredientToken(
            ingredientId,
            false
        );

        return;
    }

    if (
        !gameState.glass.spilledTokens
    ) {
        gameState.glass.spilledTokens =
            [];
    }

    const spilled =
        slots[0];

    if (!spilled) {
        gameState.flyingIngredient =
            null;

        addIngredientToken(
            ingredientId,
            false
        );

        return;
    }

    gameState.phase =
        "GLASS_FULL_WARNING";

    gameState.glassFullCount += 1;

    /*
     * 満杯であふれる前の一度だけ。
     * spill は結果、capacity_warning は「まだ間に合うが危険」の予告。
     */
    colaRollPlaySound(
        "capacity_warning",
        {
            volume: 0.34,
            cooldown: 0,
        }
    );

    gameState.ingredientFinishFlow =
        null;

    const startDrawY =
        getGlassSlotLocalY(
            0
        );

    for (
        let index = 0;
        index < slots.length;
        index += 1
    ) {
        const token =
            slots[index];

        token.drawX = 0;
        token.drawY =
            getGlassSlotLocalY(
                index
            );

        token.rot = 0;
    }

    const glassCenterX =
        layout.glass.x +
        layout.glass.w * 0.5;

    const spillDirection =
        glassCenterX <
        WIDTH * 0.5
            ? -1
            : 1;

    const effect =
        gameState.glassFullEffect;

    effect.visible = true;
    effect.text = "";
    effect.x = 0;
    effect.y = 0;
    effect.scale = 0.84;
    effect.alpha = 0;
    effect.ring = 0;

    gameState.glassPulse.scale =
        1;

    const flying =
        gameState.flyingIngredient;

    gameState.capacitySpillFlow = {
        active: true,
        stage: "warning",
        elapsed: 0,
        ingredientId: ingredientId,
        spilled: spilled,
        spilledUid:
            spilled.uid,
        spilledStartY:
            startDrawY,
        survivorTokens:
            slots.slice(1),
        spillDirection:
            spillDirection,
        spillDistance:
            Math.min(
                CONFIG.capacitySpillDistance,
                layout.glass.w * 0.88
            ),
        visualProgress: 0,
        flyingStartY:
            flying
                ? flying.y
                : 0,
        flyingStartScale:
            flying
                ? flying.scale
                : 1,
        flyingStartRotation:
            flying
                ? flying.rotation
                : 0,
        incoming: null,
        targetY: 0,
        warningDuration:
            CONFIG.glassFullWarningDuration ||
            0.42,
        spillDuration:
            CONFIG.capacitySpillDuration ||
            0.34,
        settleDuration:
            CONFIG.capacityIncomingSettleDuration ||
            0.28,
    };
}


function updateCapacitySpillFlow() {
    const flow =
        gameState.capacitySpillFlow;

    if (
        !flow ||
        !flow.active
    ) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            flow.ingredientId
        ];

    if (!ingredient) {
        gameState.capacitySpillFlow =
            null;
        gameState.flyingIngredient =
            null;
        settleTokensToCurrentSlots();
        gameState.phase =
            "WAIT_CAP_POWER";
        return;
    }

    if (
        !gameState.glass.spilledTokens
    ) {
        gameState.glass.spilledTokens =
            [];
    }

    flow.elapsed +=
        Math.max(
            0,
            DeltaTime
        );

    if (
        flow.stage ===
        "warning"
    ) {
        const duration =
            Math.max(
                0.01,
                flow.warningDuration
            );

        const rawT =
            Math.max(
                0,
                Math.min(
                    1,
                    flow.elapsed /
                        duration
                )
            );

        const t =
            1 -
            Math.pow(
                1 - rawT,
                2
            );

        gameState.phase =
            "GLASS_FULL_WARNING";

        const effect =
            gameState.glassFullEffect;

        effect.visible = true;
        effect.scale =
            0.84 +
            0.21 * t;
        effect.alpha =
            255 * t;
        effect.ring = t;

        gameState.glassPulse.scale =
            1 +
            0.05 *
                Math.sin(
                    rawT *
                    Math.PI
                );

        if (flow.spilled) {
            resetTokenVisualTransform(
                flow.spilled,
                flow.spilledStartY
            );

            const motion =
                ensureTokenLiquidMotion(
                    flow.spilled
                );

            motion.waveBoost =
                0.35 +
                rawT * 0.85;

            motion.stretchX =
                1 +
                rawT * 0.05;
        }

        for (
            let index = 0;
            index <
                flow.survivorTokens.length;
            index += 1
        ) {
            const token =
                flow.survivorTokens[
                    index
                ];

            resetTokenVisualTransform(
                token,
                getGlassSlotLocalY(
                    index + 1
                )
            );

            const motion =
                ensureTokenLiquidMotion(
                    token
                );

            motion.waveBoost =
                0.18 +
                rawT * 0.35;
            motion.stretchX =
                1 +
                rawT * 0.02;
        }

        if (
            rawT >= 1
        ) {
            flow.stage =
                "spilling";
            flow.elapsed = 0;
            gameState.phase =
                "CAPACITY_SPILLING";
        }

        return;
    }

    if (
        flow.stage ===
        "spilling"
    ) {
        const duration =
            Math.max(
                0.01,
                flow.spillDuration
            );

        const rawT =
            Math.max(
                0,
                Math.min(
                    1,
                    flow.elapsed /
                        duration
                )
            );

        const t =
            1 -
            Math.pow(
                1 - rawT,
                2
            );

        gameState.phase =
            "CAPACITY_SPILLING";

        const effect =
            gameState.glassFullEffect;

        effect.visible = true;
        effect.scale =
            1.05 -
            0.12 * t;
        effect.alpha =
            255 * (1 - t);
        effect.ring =
            1 + 0.65 * t;

        gameState.glassPulse.scale =
            1.05 -
            0.05 * t;

        const spilled =
            flow.spilled;

        if (spilled) {
            spilled.drawX =
                flow.spillDirection *
                22 * t;

            spilled.drawY =
                flow.spilledStartY +
                16 * t;

            spilled.rot =
                flow.spillDirection *
                8 * t;

            const motion =
                ensureTokenLiquidMotion(
                    spilled
                );

            motion.alpha =
                1 - t;
            motion.fillProgress =
                1 - 0.92 * t;
            motion.waveBoost =
                1.2 +
                0.8 * (1 - t);
            motion.surfaceLift =
                6 * t;
            motion.stretchX =
                1 +
                0.08 * t;
        }

        for (
            let index = 0;
            index <
                flow.survivorTokens.length;
            index += 1
        ) {
            const token =
                flow.survivorTokens[
                    index
                ];

            const startY =
                getGlassSlotLocalY(
                    index + 1
                );

            const targetY =
                getGlassSlotLocalY(
                    index
                );

            token.drawX =
                0;
            token.drawY =
                startY +
                (
                    targetY -
                    startY
                ) * t;
            token.rot = 0;

            const motion =
                ensureTokenLiquidMotion(
                    token
                );

            motion.waveBoost =
                0.55 *
                Math.sin(
                    rawT *
                    Math.PI
                );
            motion.stretchX =
                1 +
                0.03 *
                    Math.sin(
                        rawT *
                        Math.PI
                    );
        }

        if (
            rawT >= 1
        ) {
            if (spilled) {
                const currentIndex =
                    gameState.glass.slots.indexOf(
                        spilled
                    );

                if (
                    currentIndex >= 0
                ) {
                    gameState.glass.slots.splice(
                        currentIndex,
                        1
                    );
                }

                spilled.spillReason =
                    "capacity";

                clearTokenLiquidMotion(
                    spilled
                );
                delete spilled.drawX;
                delete spilled.drawY;
                delete spilled.rot;

                gameState.glass.spilledTokens.push(
                    spilled
                );
            }

            effect.visible = false;
            effect.alpha = 0;
            effect.ring = 0;

            gameState.capacitySpillFlow =
                null;

            settleTokensToCurrentSlots();
            gameState.flyingIngredient =
                null;
            gameState.glassPulse.scale =
                1;

            /*
             * あふれた後の新規追加は、
             * 既存の「下から満ちる」液体演出へつなぐ。
             */
            addIngredientToken(
                flow.ingredientId,
                false
            );
        }

        return;
    }

    gameState.capacitySpillFlow =
        null;
    gameState.flyingIngredient =
        null;
    settleTokensToCurrentSlots();
    gameState.phase =
        "WAIT_CAP_POWER";
}



function addIngredientToken(
    ingredientId,
    animateEntry
) {
    const ingredient =
        INGREDIENTS[
            ingredientId
        ];

    if (!ingredient) {
        gameState.flyingIngredient =
            null;

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    const slots =
        gameState.glass.slots;

    if (
        slots.length >=
        CONFIG.glassCapacity
    ) {
        startCapacitySpillAndAdd(
            ingredientId
        );

        return;
    }

    const token = {
        uid:
            gameState.nextTokenUid,

        ingredientId:
            ingredientId,

        bandReveal: {
            progress: 0,
        },
    };

    gameState.nextTokenUid += 1;

    slots.push(
        token
    );

    /* 瓶の素材帯が追加される、実際の瓶詰め開始。 */
    colaRollPlaySound(
        "ingredient_drop"
    );

    gameState.flyingIngredient =
        null;

    gameState.bottleIngredientEntry =
        null;

    gameState.softIngredientSettle =
        false;

    gameState.phase =
        "ADDING_TOKEN";

    const settleToken =
        function() {
            delete token.bandReveal;

            gameState.skipIngredientFinishPulse =
                true;

            finishIngredientAddition();
        };

    if (
        typeof tween === "undefined" ||
        !tween ||
        !tween.easing
    ) {
        gameState.glassPulse.scale =
            1;

        settleToken();
        return;
    }

    /*
     * 液面が上端へ達するタイミングと、
     * 瓶のふくらみの頂点をそろえる。
     */
    gameState.glassPulse.scale =
        0.996;

    tween(
        0.42,
        token.bandReveal,
        {
            progress: 1,
        },
        tween.easing.quadOut
    );

    tween(
        0.42,
        gameState.glassPulse,
        {
            scale: 1.026,
        },
        tween.easing.quadOut,
        function() {
            tween(
                0.18,
                gameState.glassPulse,
                {
                    scale: 1,
                },
                tween.easing.quadInOut,
                settleToken
            );
        }
    );
}


function finishIngredientAddition() {
    gameState.capacitySpillFlow =
        null;

    gameState.ingredientFinishFlow =
        null;

    gameState.phase =
        "ADDING_TOKEN";

    /*
     * 素材帯の出現アニメーションが、
     * すでに瓶のふくらみまで完了させた場合だけ、
     * 追加のバウンスを省き、余韻を残して戻る。
     *
     * 旧版ではこの分岐だけが finishIngredientAddition の
     * 後付けラッパーに置かれていた。現在の実行結果を
     * 変えず、本体の明示的な分岐として保持する。
     */
    const skipPulse =
        gameState.skipIngredientFinishPulse ===
        true;

    gameState.skipIngredientFinishPulse =
        false;

    if (skipPulse) {
        gameState.glassPulse.scale =
            1;

        const finish =
            function() {
                resetGlassTokenTransforms();

                gameState.phase =
                    "WAIT_CAP_POWER";
            };

        if (
            typeof tween === "undefined" ||
            !tween ||
            !tween.easing
        ) {
            finish();
            return;
        }

        const timer = {
            value: 0,
        };

        tween(
            CONFIG.ingredientResultHoldDuration,
            timer,
            {
                value: 1,
            },
            tween.easing.linear,
            finish
        );

        return;
    }

    const useSoftSettle =
        gameState.softIngredientSettle ===
        true;

    gameState.softIngredientSettle =
        false;

    if (
        typeof tween === "undefined" ||
        !tween ||
        !tween.easing
    ) {
        gameState.glassPulse.scale =
            1;

        resetGlassTokenTransforms();

        gameState.phase =
            "WAIT_CAP_POWER";

        return;
    }

    if (useSoftSettle) {
        gameState.glassPulse.scale =
            0.985;

        tween(
            0.10,
            gameState.glassPulse,
            {
                scale: 1.028,
            },
            tween.easing.quadOut,
            function() {
                tween(
                    0.18,
                    gameState.glassPulse,
                    {
                        scale: 1,
                    },
                    tween.easing.quadInOut,
                    function() {
                        const timer = {
                            value: 0,
                        };

                        tween(
                            CONFIG.ingredientResultHoldDuration,
                            timer,
                            {
                                value: 1,
                            },
                            tween.easing.linear,
                            function() {
                                resetGlassTokenTransforms();

                                gameState.phase =
                                    "WAIT_CAP_POWER";
                            }
                        );
                    }
                );
            }
        );

        return;
    }

    gameState.glassPulse.scale =
        0.88;

    tween(
        CONFIG.ingredientGlassBounceDuration,
        gameState.glassPulse,
        {
            scale: 1.14,
        },
        tween.easing.quadOut,
        function() {
            tween(
                CONFIG.ingredientGlassSettleDuration,
                gameState.glassPulse,
                {
                    scale: 1,
                },
                tween.easing.bounceOut,
                function() {
                    const timer = {
                        value: 0,
                    };

                    tween(
                        CONFIG.ingredientResultHoldDuration,
                        timer,
                        {
                            value: 1,
                        },
                        tween.easing.linear,
                        function() {
                            resetGlassTokenTransforms();

                            gameState.phase =
                                "WAIT_CAP_POWER";
                        }
                    );
                }
            );
        }
    );
}

