const COLA_HISTORY_KEY = "cola-roll-recent-bottles-v4";
const COLA_HISTORY_MAX = 12;

function colaHistoryNormalize(value) {
    const textValue = String(value === undefined || value === null ? "" : value);
    return typeof textValue.normalize === "function" ? textValue.normalize("NFC") : textValue;
}

function colaHistoryEntries() {
    if (!gameState) return [];

    /*
     * すでにメモリ上にある履歴は、従来どおりそのまま返す。
     * 保存済みタイトルの修復だけは、入口で必ず一度通す。
     */
    if (Array.isArray(gameState.recentBottleHistory)) {
        repairColaRollRecentBottleGarnishTitles(
            gameState.recentBottleHistory
        );

        return gameState.recentBottleHistory;
    }

    try {
        gameState.recentBottleHistory = JSON.parse(
            localStorage.getItem(COLA_HISTORY_KEY) || "[]"
        );
    } catch (error) {
        gameState.recentBottleHistory = [];
    }

    if (!Array.isArray(gameState.recentBottleHistory)) {
        gameState.recentBottleHistory = [];
    }

    /*
     * 初回ロード時だけ最大件数に整える。
     * ここは旧本体の挙動をそのまま残す。
     */
    gameState.recentBottleHistory =
        gameState.recentBottleHistory.slice(
            0,
            COLA_HISTORY_MAX
        );

    repairColaRollRecentBottleGarnishTitles(
        gameState.recentBottleHistory
    );

    return gameState.recentBottleHistory;
}

function colaHistorySave() {
    try {
        localStorage.setItem(
            COLA_HISTORY_KEY,
            JSON.stringify(
                colaHistoryEntries()
            )
        );
    } catch (error) {
    }
}


/*
 * ------------------------------------------------------------
 * ROAST SYRUP LEGACY CLEANUP
 *
 * thick_syrup を完全に旧IDとして扱う。
 * 新規プレイ、途中データ、過去の瓶詰め履歴を
 * roast_syrup へ安全に寄せる。
 * ------------------------------------------------------------
 */

function colaRollMigrateLegacyIngredientId(
    ingredientId
) {
    return ingredientId ===
        "thick_syrup"
        ? "roast_syrup"
        : ingredientId;
}

function colaRollMigrateLegacyResultData(
    result
) {
    if (
        !result ||
        typeof result !== "object"
    ) {
        return false;
    }

    let changed =
        false;

    const scalarKeys = [
        "topIngredientId",
        "singleIngredientId",
        "baseIngredientId",
        "aromaIngredientId",
    ];

    for (
        const key of scalarKeys
    ) {
        if (
            result[key] ===
            "thick_syrup"
        ) {
            result[key] =
                "roast_syrup";

            changed =
                true;
        }
    }

    if (
        Array.isArray(
            result.ingredientIds
        )
    ) {
        result.ingredientIds =
            result.ingredientIds.map(
                function(
                    ingredientId
                ) {
                    const migrated =
                        colaRollMigrateLegacyIngredientId(
                            ingredientId
                        );

                    if (
                        migrated !==
                        ingredientId
                    ) {
                        changed =
                            true;
                    }

                    return migrated;
                }
            );
    }

    if (
        Array.isArray(
            result.uniqueIngredientIds
        )
    ) {
        const migratedIds =
            [];

        for (
            const ingredientId of
            result.uniqueIngredientIds
        ) {
            const migrated =
                colaRollMigrateLegacyIngredientId(
                    ingredientId
                );

            if (
                migrated !==
                ingredientId
            ) {
                changed =
                    true;
            }

            if (
                migratedIds.indexOf(
                    migrated
                ) < 0
            ) {
                migratedIds.push(
                    migrated
                );
            }
        }

        result.uniqueIngredientIds =
            migratedIds;
    }

    const counts =
        result.ingredientCounts;

    if (
        counts &&
        counts.thick_syrup !==
            undefined
    ) {
        const legacyCount =
            Number(
                counts.thick_syrup
            ) || 0;

        counts.roast_syrup =
            (
                Number(
                    counts.roast_syrup
                ) || 0
            ) +
            legacyCount;

        delete counts.thick_syrup;

        changed =
            true;
    }

    if (
        Array.isArray(
            result.ingredientCountList
        )
    ) {
        const mergedList =
            [];

        const indexById =
            {};

        for (
            const item of
            result.ingredientCountList
        ) {
            if (
                !item ||
                !item.id
            ) {
                continue;
            }

            const migratedId =
                colaRollMigrateLegacyIngredientId(
                    item.id
                );

            if (
                migratedId !==
                item.id
            ) {
                changed =
                    true;
            }

            const count =
                Number(
                    item.count
                ) || 0;

            if (
                indexById[
                    migratedId
                ] === undefined
            ) {
                indexById[
                    migratedId
                ] =
                    mergedList.length;

                mergedList.push(
                    {
                        id: migratedId,
                        count: count,
                    }
                );
            } else {
                mergedList[
                    indexById[
                        migratedId
                    ]
                ].count +=
                    count;
            }
        }

        result.ingredientCountList =
            mergedList;
    }

    const roastCount =
        result.ingredientCounts &&
        result.ingredientCounts.roast_syrup
            ? result.ingredientCounts.roast_syrup
            : 0;

    result.roastCount =
        roastCount;

    result.hasRoast =
        roastCount > 0;

    return changed;
}

function colaRollNormalizeRoastSyrupData() {
    if (
        !INGREDIENTS ||
        !BOARD_NODES
    ) {
        return;
    }

    /*
     * 念のため素材辞書をここで確定。
     * 古い素材データが残っていても、
     * 起動後は必ず焙煎シロップだけになる。
     */
    if (
        !INGREDIENTS.roast_syrup
    ) {
        INGREDIENTS.roast_syrup = {
            id: "roast_syrup",
            ja: "焙煎シロップ",
            en: "Roast Syrup",
            color: color(
                72,
                37,
                20
            ),
            sweetness: 1,
            spice: 0,
            chill: 0,
            strange: 0,
        };
    }

    delete INGREDIENTS.thick_syrup;

    if (
        RESULT_WORDS &&
        RESULT_WORDS.ja &&
        RESULT_WORDS.ja.topFlavor
    ) {
        delete RESULT_WORDS.ja.topFlavor
            .thick_syrup;

        RESULT_WORDS.ja.topFlavor
            .roast_syrup =
            "焙煎香る";
    }

    if (
        RESULT_WORDS &&
        RESULT_WORDS.en &&
        RESULT_WORDS.en.topFlavor
    ) {
        delete RESULT_WORDS.en.topFlavor
            .thick_syrup;

        RESULT_WORDS.en.topFlavor
            .roast_syrup =
            "Roasted";
    }

    /*
     * 旧盤面データが残っていた場合も、
     * 最終的には sweet_roast に揃える。
     */
    if (
        BOARD_NODES.sweet_strong
    ) {
        const legacyNode =
            BOARD_NODES.sweet_strong;

        if (
            !BOARD_NODES.sweet_roast
        ) {
            legacyNode.id =
                "sweet_roast";

            BOARD_NODES.sweet_roast =
                legacyNode;
        }

        delete BOARD_NODES.sweet_strong;
    }

    for (
        const nodeId of
        Object.keys(
            BOARD_NODES
        )
    ) {
        const node =
            BOARD_NODES[nodeId];

        if (!node) {
            continue;
        }

        if (
            node.next ===
            "sweet_strong"
        ) {
            node.next =
                "sweet_roast";
        }

        if (
            node.effect &&
            node.effect.addIngredient ===
                "thick_syrup"
        ) {
            node.effect.addIngredient =
                "roast_syrup";
        }
    }

    if (
        gameState &&
        gameState.glass &&
        Array.isArray(
            gameState.glass.slots
        )
    ) {
        for (
            const token of
            gameState.glass.slots
        ) {
            if (
                token &&
                token.ingredientId ===
                    "thick_syrup"
            ) {
                token.ingredientId =
                    "roast_syrup";
            }
        }
    }

    if (
        gameState &&
        gameState.resultData
    ) {
        colaRollMigrateLegacyResultData(
            gameState.resultData
        );
    }
}


/*
 * initGameData / initGameState のあとに実行する。
 * 新規プレイは常に焙煎シロップ基準で開始する。
 */
const setupCoreBaseForRoastSyrupLegacyCleanup =
    setupCore;

setupCore = function() {
    const result =
        setupCoreBaseForRoastSyrupLegacyCleanup.apply(
            this,
            arguments
        );

    colaRollNormalizeRoastSyrupData();

    return result;
};


/*
 * 古い「最近の瓶詰め」を開いた時だけ、
 * 旧 thick_syrup の内部IDを roast_syrup へ移行する。
 *
 * 既に保存されている作品名そのものは、
 * 当時の記録として無理に書き換えない。
 */
const colaHistoryEntriesBaseForRoastSyrupLegacyCleanup =
    colaHistoryEntries;

colaHistoryEntries = function() {
    const entries =
        colaHistoryEntriesBaseForRoastSyrupLegacyCleanup.apply(
            this,
            arguments
        );

    let changed =
        false;

    for (
        const entry of
        entries
    ) {
        if (
            entry &&
            entry.result
        ) {
            if (
                colaRollMigrateLegacyResultData(
                    entry.result
                )
            ) {
                changed =
                    true;
            }
        }
    }

    if (
        changed &&
        typeof localStorage !==
            "undefined"
    ) {
        try {
            localStorage.setItem(
                COLA_HISTORY_KEY,
                JSON.stringify(
                    entries
                )
            );
        } catch (error) {
        }
    }

    return entries;
};

function colaHistoryCopyText(language) {
    const previousLanguage = gameState.language;
    gameState.language = language;
    const text = {
        name: colaHistoryNormalize(generateResultName()),
        description: colaHistoryNormalize(generateResultDescription()),
    };
    gameState.language = previousLanguage;
    return text;
}

function colaHistoryRecord() {
    if (!gameState || !gameState.resultData || gameState.recentBottleHistoryRecorded) return;
    const result = JSON.parse(JSON.stringify(gameState.resultData));
    const design = getResultBottleLabelDesign() || {};
    const entry = {
        createdAt: new Date().toISOString(),
        text: {
            ja: colaHistoryCopyText("ja"),
            en: colaHistoryCopyText("en"),
        },
        result: result,
        liquid: {
            r: Math.max(34, 56 + (result.sweetness || 0) * 5 - (result.maturity || 0) * 3),
            g: Math.max(16, 26 + (result.sweetness || 0) * 3 - (result.spice || 0) * 2),
            b: Math.max(7, 12 + (result.strange || 0) * 3),
        },
        label: {
            base: design.base || { r: 120, g: 72, b: 38 },
            light: design.light || design.base || { r: 180, g: 120, b: 64 },
            dark: design.dark || design.base || { r: 80, g: 42, b: 24 },
            rare: !!(design.rareColaId || result.rareColaId),
        },
    };
    const entries = colaHistoryEntries();
    entries.unshift(entry);
    entries.length = Math.min(entries.length, COLA_HISTORY_MAX);
    gameState.recentBottleHistoryRecorded = true;
    gameState.recentBottleHistoryNotice = true;
    colaHistorySave();
}

function colaHistoryWords(key) {
    const japanese = {
        title: "最近の瓶詰め", back: "もどる", saved: "最近の瓶詰めに追加しました",
        empty: "まだ瓶詰め記録はありません", aroma: "香り:", fizz: "炭酸:",
        chill: "冷たさ:", finish: "仕上げ:", none: "なし", light: "軽め",
        bold: "強め", still: "静か", cool: "ひんやり", cold: "よく冷えた",
        lemon: "レモン", cherry: "チェリー",
    };
    const english = {
        title: "RECENT BOTTLINGS", back: "BACK", saved: "SAVED TO RECENT BOTTLINGS",
        empty: "NO BOTTLES YET", aroma: "AROMA: ", fizz: "FIZZ: ",
        chill: "CHILL: ", finish: "FINISH: ", none: "NONE", light: "LIGHT",
        bold: "BOLD", still: "STILL", cool: "COOL", cold: "COLD",
        lemon: "LEMON", cherry: "CHERRY",
    };
    return (gameState.language === "en" ? english : japanese)[key] || "";
}

function colaHistoryTitleRect() {
    const width = Math.min(214, WIDTH * 0.64);
    return { x: WIDTH * 0.5 - width * 0.5, y: HEIGHT * 0.245 - 18, w: width, h: 36 };
}

function colaHistoryBackRect() {
    return { x: 12, y: HEIGHT - 43, w: 76, h: 26 };
}

function colaHistoryCell(index) {
    const width = (WIDTH - 30) / 4;
    const height = (HEIGHT - 137) / 3;
    return { x: 15 + width * (index % 4), y: HEIGHT - 86 - height * (Math.floor(index / 4) + 1), w: width, h: height };
}

function colaHistoryHit(touch, rect) {
    return touch.x >= rect.x && touch.x <= rect.x + rect.w && touch.y >= rect.y && touch.y <= rect.y + rect.h;
}

function colaHistoryName(entry, short) {
    const language = gameState.language === "en" ? "en" : "ja";
    const name = colaHistoryNormalize(entry.text[language].name);
    const limit = language === "en" ? 16 : 9;
    return short && name.length > limit ? name.slice(0, limit - 1) + "..." : name;
}

function colaHistoryTraits(entry) {
    const result = entry.result || {};
    const language = gameState.language === "en" ? "en" : "ja";
    const ingredient = typeof INGREDIENTS !== "undefined" ? INGREDIENTS[result.aromaIngredientId || result.topIngredientId] : null;
    const aroma = ingredient ? (ingredient[language] || ingredient.ja) : colaHistoryWords("none");
    const pressure = Number(result.pressure) || 0;
    const cooling = Number(result.coolingCount || result.iceCount || result.chill) || 0;
    const fizz = pressure >= 3 ? colaHistoryWords("bold") : pressure > 0 ? colaHistoryWords("light") : colaHistoryWords("still");
    const chill = cooling >= 2 ? colaHistoryWords("cold") : colaHistoryWords("cool");
    const finish = result.garnish === "lemon" ? colaHistoryWords("lemon") : result.garnish === "cherry" ? colaHistoryWords("cherry") : colaHistoryWords("none");
    return [
        colaHistoryWords("aroma") + aroma,
        colaHistoryWords("fizz") + fizz,
        colaHistoryWords("chill") + chill,
        colaHistoryWords("finish") + finish,
    ];
}

function colaHistoryHeader() {
    const palette = getGameVisualPalette();
    const back = colaHistoryBackRect();
    fill(palette.textSecondary.r, palette.textSecondary.g, palette.textSecondary.b, 255);
    fontSize(Math.min(17, WIDTH * 0.046));
    textAlign(CENTER);
    text(colaHistoryWords("title"), WIDTH * 0.5, HEIGHT - 34);
    fill(palette.textQuiet.r, palette.textQuiet.g, palette.textQuiet.b, 175);
    fontSize(10);
    text(String(colaHistoryEntries().length) + " / " + String(COLA_HISTORY_MAX), WIDTH * 0.5, HEIGHT - 54);
    rectMode(CORNER);
    fill(palette.panelRaised.r, palette.panelRaised.g, palette.panelRaised.b, 248);
    rect(back.x, back.y, back.w, back.h, 7);
    noFill();
    stroke(palette.panelLine.r, palette.panelLine.g, palette.panelLine.b, 230);
    strokeWidth(1.2);
    rect(back.x, back.y, back.w, back.h, 7);
    noStroke();
    fill(palette.textSecondary.r, palette.textSecondary.g, palette.textSecondary.b, 255);
    fontSize(11);
    text(colaHistoryWords("back"), back.x + back.w * 0.5, back.y + back.h * 0.5 - 1);
    drawLanguageButton();
}

function colaHistoryGrid() {
    const entries =
        colaHistoryEntries();

    const palette =
        getGameVisualPalette();

    rectMode(CORNER);
    noStroke();

    fill(
        24,
        14,
        10,
        232
    );

    rect(
        10,
        42,
        WIDTH - 20,
        HEIGHT - 96,
        14
    );

    for (
        let index = 0;
        index < COLA_HISTORY_MAX;
        index += 1
    ) {
        const cell =
            colaHistoryCell(
                index
            );

        const entry =
            entries[index];

        stroke(
            151,
            88,
            43,
            170
        );

        strokeWidth(1.5);

        line(
            cell.x + 5,
            cell.y +
                cell.h * 0.16,
            cell.x +
                cell.w -
                5,
            cell.y +
                cell.h * 0.16
        );

        noStroke();

        if (!entry) {
            noFill();

            stroke(
                210,
                177,
                132,
                42
            );

            strokeWidth(1);

            rect(
                cell.x + 3,
                cell.y + 3,
                cell.w - 6,
                cell.h - 6,
                8
            );

            noStroke();

            continue;
        }

        fill(
            palette.panelRaised.r,
            palette.panelRaised.g,
            palette.panelRaised.b,
            100
        );

        rect(
            cell.x + 3,
            cell.y + 3,
            cell.w - 6,
            cell.h - 6,
            8
        );

        const labelScale =
            Math.max(
                0.72,
                Math.min(
                    (cell.w - 16) / 68,
                    (cell.h - 58) / 79
                ) * 0.96
            );

        const labelX =
            cell.x +
            cell.w * 0.5;

        const labelY =
            cell.y +
            cell.h * 0.61;

        colaHistoryDrawShelfLabel(
            entry,
            labelX,
            labelY,
            labelScale,
            255
        );

        const nameLines =
            colaHistoryShelfNameLines(
                entry
            );

        setGameUIFont();

        fill(
            244,
            229,
            198,
            245
        );

        fontSize(
            Math.max(
                8.2,
                cell.w * 0.108
            )
        );

        textAlign(CENTER);

        const nameLineSpacing =
            11;

        const nameCenterY =
            cell.y +
            cell.h * 0.245;

        const firstLineY =
            nameCenterY +
            (
                (nameLines.length - 1) *
                nameLineSpacing
            ) * 0.5;

        for (
            let lineIndex = 0;
            lineIndex <
                nameLines.length;
            lineIndex += 1
        ) {
            text(
                nameLines[
                    lineIndex
                ],
                labelX,
                firstLineY -
                    lineIndex *
                        nameLineSpacing
            );
        }
    }

    if (
        entries.length <= 0
    ) {
        fill(
            palette.textQuiet.r,
            palette.textQuiet.g,
            palette.textQuiet.b,
            210
        );

        fontSize(12);
        textAlign(CENTER);

        text(
            colaHistoryWords(
                "empty"
            ),
            WIDTH * 0.5,
            HEIGHT * 0.5
        );
    }

    colaHistoryHeader();
}


function colaHistoryDate(entry) {
    const date = new Date(entry.createdAt);
    return gameState.language === "en"
        ? String(date.getMonth() + 1) + "/" + String(date.getDate()) + "/" + String(date.getFullYear())
        : String(date.getFullYear()) + "年" + String(date.getMonth() + 1) + "月" + String(date.getDate()) + "日";
}



function colaHistoryDrawReplayFooter() {
    const entry =
        gameState &&
        gameState.historyReplayEntry;

    if (!entry) {
        return;
    }

    const recordState =
        gameState &&
        gameState.resultRecord
            ? gameState.resultRecord
            : null;

    /*
     * 過去の瓶を画像保存する際は、
     * 戻るボタンと日付を共有画像から外す。
     */
    if (
        recordState &&
        recordState.captureMode
    ) {
        return;
    }

    const palette =
        getGameVisualPalette();

    const reveal =
        gameState.resultReveal;

    const alpha =
        reveal
            ? reveal.alpha
            : 255;

    /*
     * 通常結果の「補充する」と同じ位置・横幅を使う。
     * 右側には共通の記録スタンプが配置される。
     */
    const button =
        getResultRestartButtonRect();

    rectMode(CORNER);
    noStroke();

    fill(
        palette.panelRaised.r,
        palette.panelRaised.g,
        palette.panelRaised.b,
        alpha
    );

    rect(
        button.x,
        button.y,
        button.w,
        button.h,
        11
    );

    noFill();

    stroke(
        palette.actionLine.r,
        palette.actionLine.g,
        palette.actionLine.b,
        alpha
    );

    strokeWidth(2);

    rect(
        button.x,
        button.y,
        button.w,
        button.h,
        11
    );

    noStroke();

    if (
        typeof drawResultRestartButtonAccent ===
        "function"
    ) {
        drawResultRestartButtonAccent(
            button,
            alpha
        );
    }

    setGameUIFont();

    fill(
        palette.actionLight.r,
        palette.actionLight.g,
        palette.actionLight.b,
        alpha
    );

    fontSize(
        Math.min(
            18,
            WIDTH * 0.048
        )
    );

    textAlign(CENTER);

    text(
        colaHistoryWords("back"),
        button.x +
            button.w * 0.5,
        button.y +
            button.h * 0.5
    );

    fill(
        palette.textQuiet.r,
        palette.textQuiet.g,
        palette.textQuiet.b,
        alpha * 0.82
    );

    fontSize(
        Math.min(
            10.5,
            WIDTH * 0.028
        )
    );

    /*
     * 日付は戻るボタンの上に表示する。
     * 素材列は通常表示時だけ上へ移動するため、
     * 日付との重なりも避けられる。
     */
    text(
        colaHistoryDate(entry),
        button.x +
            button.w * 0.5,
        button.y +
            button.h +
            14
    );

    rectMode(CORNER);
    noStroke();
}


function colaHistoryReplayButtonHit(
    touch
) {
    const button =
        getResultRestartButtonRect();

    return touch.x >= button.x &&
        touch.x <= button.x + button.w &&
        touch.y >= button.y &&
        touch.y <= button.y + button.h;
}


function colaHistoryWithEntryResult(
    entry,
    callback
) {
    if (
        !gameState ||
        !entry ||
        !entry.result ||
        typeof callback !== "function"
    ) {
        return;
    }

    const previousResult =
        gameState.resultData;

    const previousReveal =
        gameState.resultReveal;

    const previousCrownReveal =
        gameState.resultCrownReveal;

    const previousPerfectGoalStop =
        gameState.perfectGoalStop;

    gameState.resultData =
        entry.result;

    gameState.resultReveal = {
        alpha: 255,
    };

    gameState.resultCrownReveal = {
        alpha: 255,
        rotation: 0,
        scale: 1,
        yOffset: 0,
        sparkAlpha: 0,
        sparkScale: 1,
        sparkRotation: 0,
    };

    gameState.perfectGoalStop =
        false;

    try {
        return callback();
    } finally {
        gameState.resultData =
            previousResult;

        gameState.resultReveal =
            previousReveal;

        gameState.resultCrownReveal =
            previousCrownReveal;

        gameState.perfectGoalStop =
            previousPerfectGoalStop;
    }
}

function colaHistoryShelfNameLines(
    entry
) {
    const name =
        colaHistoryName(
            entry,
            false
        );

    const japanese =
        gameState.language !==
        "en";

    if (!japanese) {
        const words =
            name.split(" ");

        const lines = [];
        let current = "";

        for (
            let index = 0;
            index < words.length;
            index += 1
        ) {
            const next =
                current
                    ? current +
                        " " +
                        words[index]
                    : words[index];

            if (
                current &&
                next.length > 13
            ) {
                lines.push(
                    current
                );

                current =
                    words[index];
            } else {
                current =
                    next;
            }
        }

        if (current) {
            lines.push(
                current
            );
        }

        if (lines.length <= 2) {
            return lines;
        }

        return [
            lines[0],
            lines
                .slice(1)
                .join(" ")
                .slice(0, 12) +
                "...",
        ];
    }

    const characters =
        Array.from(name);

    if (
        characters.length <= 9
    ) {
        return [
            name,
        ];
    }

    const firstLine =
        characters
            .slice(
                0,
                9
            )
            .join("");

    let secondLine =
        characters
            .slice(
                9,
                18
            )
            .join("");

    if (
        characters.length > 18
    ) {
        secondLine =
            secondLine.slice(
                0,
                8
            ) +
            "...";
    }

    return [
        firstLine,
        secondLine,
    ];
}

function colaHistoryDescriptionLines(
    entry
) {
    const language =
        gameState.language ===
        "en"
            ? "en"
            : "ja";

    const description =
        colaHistoryNormalize(
            entry.text[
                language
            ].description
        );

    if (!description) {
        return [];
    }

    if (
        language === "en"
    ) {
        const words =
            description.split(" ");

        const lines = [];
        let current = "";

        for (
            let index = 0;
            index < words.length;
            index += 1
        ) {
            const next =
                current
                    ? current +
                        " " +
                        words[index]
                    : words[index];

            if (
                current &&
                next.length > 29
            ) {
                lines.push(
                    current
                );

                current =
                    words[index];
            } else {
                current =
                    next;
            }
        }

        if (current) {
            lines.push(
                current
            );
        }

        if (lines.length <= 3) {
            return lines;
        }

        return [
            lines[0],
            lines[1],
            lines
                .slice(2)
                .join(" ")
                .slice(0, 27) +
                "...",
        ];
    }

    const characters =
        Array.from(
            description
        );

    const lines = [];

    for (
        let index = 0;
        index < characters.length;
        index += 16
    ) {
        lines.push(
            characters
                .slice(
                    index,
                    index + 16
                )
                .join("")
        );
    }

    if (
        lines.length <= 3
    ) {
        return lines;
    }

    const lastLine =
        lines[2];

    return [
        lines[0],
        lines[1],
        lastLine.slice(
            0,
            15
        ) + "...",
    ];
}

function colaHistoryDrawShelfLabel(
    entry,
    x,
    y,
    scaleValue,
    alpha
) {
    colaHistoryWithEntryResult(
        entry,
        function() {
            if (
                typeof drawResultBottleVisualCode !==
                "function"
            ) {
                return;
            }

            drawResultBottleVisualCode(
                x,
                y,
                scaleValue,
                alpha
            );
        }
    );
}

function colaHistoryDrawSavedProduct(
    entry,
    bottleX,
    bottleY,
    bottleScale,
    glassX,
    glassY,
    glassScale
) {
    colaHistoryWithEntryResult(
        entry,
        function() {
            if (
                typeof drawResultProductBottle ===
                "function"
            ) {
                drawResultProductBottle(
                    bottleX,
                    bottleY,
                    bottleScale,
                    255
                );
            }

            const result =
                entry.result || {};

            if (
                result.drinkType ===
                "soda"
            ) {
                if (
                    typeof drawFinishedSoda ===
                    "function"
                ) {
                    drawFinishedSoda(
                        glassX,
                        glassY,
                        glassScale,
                        255
                    );
                }

                return;
            }

            if (
                typeof drawFinishedCola ===
                "function"
            ) {
                drawFinishedCola(
                    glassX,
                    glassY,
                    glassScale,
                    255
                );
            }
        }
    );
}


