function startTitleTransition() {
    gameState.titleTransition = {
        active: true,
        elapsed: 0,

        titleFadeDuration: 0.44,
        fizzDuration: 0.92,

        /*
         * 盤面と瓶が見えてから、
         * 補充先カードまでの静かな間。
         *
         * 以前の 0.68 は少し長かったので、
         * 余韻だけ残る長さへ縮める。
         */
        settleDuration: 0.32,

        handoffDuration: 1.78,

        sceneSwitchTime: 0.44,

        sceneSwitched: false,

        bubbles:
            createTitleTransitionBubbles(),
    };

    gameState.phase =
        "TITLE_TRANSITION";

    colaRollPlaySound(
        "start"
    );

    gameState.nightDispatchPreHandoffShown =
        false;

    gameState.nightDispatchPreHandoffHold =
        false;
}


function createTitleTransitionBubbles() {
    const bubbles = [];
    const count =
        Math.max(
            54,
            Math.floor(
                WIDTH / 6
            )
        );

    for (
        let index = 0;
        index < count;
        index += 1
    ) {
        bubbles.push(
            {
                x:
                    WIDTH *
                    (
                        0.10 +
                        Math.random() * 0.80
                    ),

                startY:
                    -HEIGHT * 0.10 -
                    Math.random() *
                    HEIGHT *
                    0.18,

                travel:
                    HEIGHT *
                    (
                        0.98 +
                        Math.random() * 0.46
                    ),

                size:
                    2.2 +
                    Math.random() * 7.8,

                delay:
                    Math.random() * 0.20,

                life:
                    0.84 +
                    Math.random() * 0.58,

                wobble:
                    5 +
                    Math.random() * 18,

                wobbleSpeed:
                    5 +
                    Math.random() * 9,

                phase:
                    Math.random() *
                    Math.PI *
                    2,
            }
        );
    }

    return bubbles;
}


function updateTitleStartTransition() {
    const transition =
        gameState.titleTransition;

    if (
        !transition ||
        !transition.active
    ) {
        return;
    }

    /*
     * 補充先カードを読んでいる間だけ、
     * 導入タイムラインを止める。
     */
    if (
        gameState.nightDispatchPreHandoffHold
    ) {
        return;
    }

    const delta =
        Math.max(
            0,
            DeltaTime
        );

    const handoffStartTime =
        transition.fizzDuration +
        transition.settleDuration;

    const totalTime =
        handoffStartTime +
        transition.handoffDuration;

    transition.elapsed +=
        delta;

    /*
     * 盤面と瓶を先に出す。
     * この段階では補充先もプレートもまだ出さない。
     */
    if (
        !transition.sceneSwitched &&
        transition.elapsed >=
            transition.sceneSwitchTime
    ) {
        transition.sceneSwitched =
            true;

        gameState.phase =
            "INTRO_DISPATCH_WAIT";

        updateLayout(true);
    }

    /*
     * 泡が完全に消え、
     * さらに少し静かな時間が過ぎてから、
     * 初めて補充先カードを開く。
     */
    if (
        !gameState.nightDispatchPreHandoffShown &&
        transition.sceneSwitched &&
        gameState.phase ===
            "INTRO_DISPATCH_WAIT" &&
        transition.elapsed >=
            handoffStartTime
    ) {
        transition.elapsed =
            handoffStartTime;

        gameState.nightDispatchPreHandoffShown =
            true;

        gameState.nightDispatchPreHandoffHold =
            true;

        gameState.nightDispatchGatePending =
            false;

        colaRollDispatchOpenBeforeHandoff();

        return;
    }

    /*
     * カードを閉じた後だけ、
     * 機械の通電演出を進める。
     */
    if (
        transition.elapsed >=
        totalTime
    ) {
        transition.active =
            false;

        gameState.titleTransition =
            null;

        if (
            gameState.phase ===
            "INTRO_HANDOFF"
        ) {
            gameState.phase =
                "WAIT_CAP_POWER";
        }
    }
}


function clampShotGaugeStartup(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

function easeShotGaugeOut(
    value
) {
    const t =
        clampShotGaugeStartup(
            value
        );

    return 1 -
        Math.pow(
            1 - t,
            3
        );
}

function startShotGaugeStartup() {
    const initialPower =
        Math.max(
            0.04,
            Math.min(
                0.96,
                gameState.cap.power
            )
        );

    gameState.shotGaugeStartup = {
        active: true,
        elapsed: 0,
        duration: 0.56,

        /*
         * これは描画用の予備値として残すが、
         * 実際の針は通常の cap.power を使う。
         */
        needlePower: initialPower,

        tickProgress: 0,
        labelAlpha: 0,

        capScale: 1,
        capOffset: 0,
        capRotation: 0,

        ringAlpha: 0,
        ringProgress: 0,
    };

    /*
     * 左端ぴったりではなく、
     * 少しだけ動き始められる位置から開始する。
     */
    gameState.cap.power =
        initialPower;

    gameState.cap.powerDirection =
        1;
}



function updateShotGaugeStartup() {
    const startup =
        gameState.shotGaugeStartup;

    if (
        !startup ||
        !startup.active
    ) {
        return false;
    }

    startup.elapsed +=
        Math.max(
            0,
            DeltaTime
        );

    const progress =
        clampShotGaugeStartup(
            startup.elapsed /
                startup.duration
        );

    /*
     * 針・王冠はここで固定しない。
     * 起動演出は発光だけにする。
     */
    startup.tickProgress =
        easeShotGaugeOut(
            (
                progress - 0.03
            ) /
                0.34
        );

    startup.ringProgress =
        easeShotGaugeOut(
            (
                progress - 0.02
            ) /
                0.27
        );

    startup.ringAlpha =
        Math.sin(
            Math.min(
                1,
                progress * 3.25
            ) *
                Math.PI
        ) *
        0.78;

    startup.labelAlpha =
        easeShotGaugeOut(
            (
                progress - 0.38
            ) /
                0.22
        );

    if (progress < 1) {
        return true;
    }

    startup.active = false;

    return false;
}



const updateTitleStartTransitionBaseForShotGaugeStartup =
    updateTitleStartTransition;

updateTitleStartTransition = function() {
    const previousPhase =
        gameState.phase;

    updateTitleStartTransitionBaseForShotGaugeStartup();

    const reachedGauge =
        previousPhase ===
            "INTRO_HANDOFF" &&
        gameState.phase ===
            "WAIT_CAP_POWER";

    if (reachedGauge) {
        startShotGaugeStartup();
    }
};



function drawTitleStartTransition() {
    const transition =
        gameState &&
        gameState.titleTransition
            ? gameState.titleTransition
            : null;

    if (
        !transition ||
        !transition.active
    ) {
        return;
    }

    const elapsed =
        transition.elapsed;

    const titleFadeDuration =
        transition.titleFadeDuration;

    const fizzDuration =
        transition.fizzDuration;

    const settleDuration =
        transition.settleDuration;

    const handoffDuration =
        transition.handoffDuration;

    const fizzEndTime =
        fizzDuration;

    const handoffStartTime =
        fizzEndTime +
        settleDuration;

    let gradientAlpha =
        0;

    let bubbleAlpha =
        0;

    let bubbleElapsed =
        -1;

    let handoffProgress =
        0;

    if (
        elapsed <
        titleFadeDuration
    ) {
        const t =
            Math.max(
                0,
                Math.min(
                    1,
                    elapsed /
                        titleFadeDuration
                )
            );

        const easedFade =
            1 -
            Math.pow(
                1 - t,
                3
            );

        const bubbleFadeIn =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed +
                        0.04
                    ) /
                        0.18
                )
            );

        /*
         * 黒ではなく、注文先画面と同じ
         * コーラグラデーションへ沈んでいく。
         */
        gradientAlpha =
            255 * easedFade;

        bubbleAlpha =
            245 *
            bubbleFadeIn;

        bubbleElapsed =
            elapsed;
    } else if (
        elapsed <
        fizzEndTime
    ) {
        const bubbleFadeOut =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed -
                        (
                            fizzEndTime -
                            0.28
                        )
                    ) /
                        0.28
                )
            );

        /*
         * 泡が上がる間もグラデーションは残す。
         * 工房背景が途中で戻って見えないようにする。
         */
        gradientAlpha =
            255;

        bubbleAlpha =
            245 *
            (
                1 -
                Math.pow(
                    bubbleFadeOut,
                    1.35
                )
            );

        bubbleElapsed =
            elapsed;
    } else if (
        elapsed <
        handoffStartTime
    ) {
        gradientAlpha =
            255;

        bubbleAlpha =
            0;
    } else {
        gradientAlpha =
            255;

        handoffProgress =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed -
                        handoffStartTime
                    ) /
                        handoffDuration
                )
            );
    }

    if (gradientAlpha > 0) {
        drawColaRollDispatchGradient(
            gradientAlpha
        );
    }

    if (
        bubbleElapsed >= 0 &&
        bubbleAlpha > 0
    ) {
        const bubbles =
            transition.bubbles || [];

        for (
            let index = 0;
            index < bubbles.length;
            index += 1
        ) {
            const bubble =
                bubbles[index];

            const p =
                Math.max(
                    0,
                    Math.min(
                        1,
                        (
                            bubbleElapsed -
                            bubble.delay
                        ) /
                            bubble.life
                    )
                );

            if (
                bubbleElapsed <
                    bubble.delay ||
                p <= 0 ||
                p >= 1
            ) {
                continue;
            }

            const rise =
                p *
                bubble.travel;

            const bx =
                bubble.x +
                Math.sin(
                    p *
                        bubble.wobbleSpeed +
                        bubble.phase
                ) *
                    bubble.wobble;

            const by =
                bubble.startY +
                rise;

            const size =
                bubble.size *
                (
                    0.72 +
                    p * 0.58
                );

            const localAlpha =
                bubbleAlpha *
                Math.sin(
                    p * Math.PI
                );

            noFill();

            stroke(
                221,
                246,
                250,
                localAlpha * 0.86
            );

            strokeWidth(
                Math.max(
                    0.8,
                    size * 0.14
                )
            );

            ellipse(
                bx,
                by,
                size
            );

            stroke(
                255,
                239,
                198,
                localAlpha * 0.38
            );

            strokeWidth(
                Math.max(
                    0.6,
                    size * 0.075
                )
            );

            ellipse(
                bx -
                    size * 0.16,
                by +
                    size * 0.12,
                size * 0.42
            );

            noStroke();

            fill(
                255,
                247,
                224,
                localAlpha * 0.38
            );

            ellipse(
                bx -
                    size * 0.18,
                by +
                    size * 0.20,
                Math.max(
                    1.2,
                    size * 0.18
                )
            );
        }
    }

    if (
        transition.sceneSwitched &&
        handoffProgress > 0
    ) {
        drawTitlePressureHandoff(
            handoffProgress
        );
    }

    rectMode(CORNER);
    noStroke();
}


function getColaRollTitleForegroundFade() {
    const transition =
        gameState &&
        gameState.titleTransition;

    if (
        !transition ||
        !transition.active ||
        gameState.phase !==
            "TITLE_TRANSITION"
    ) {
        return 1;
    }

    /*
     * 盤面へ切り替わる直前まで、
     * タイトル前景をゆっくり消す。
     */
    const duration =
        Math.max(
            0.01,
            Math.min(
                transition.titleFadeDuration ||
                    0.44,
                transition.sceneSwitchTime ||
                    0.44
            )
        );

    const progress =
        Math.max(
            0,
            Math.min(
                1,
                transition.elapsed /
                    duration
            )
        );

    /*
     * 最初は少し残り、
     * 後半で静かに沈む。
     */
    const eased =
        progress *
        progress *
        (
            3 -
            2 * progress
        );

    return 1 - eased;
}

/*
 * TITLE_TRANSITION中も言語ボタンを描き続け、
 * タイトル全体のフェードに参加させる。
 */
const drawLanguageButtonBaseForTitleExitFade =
    drawLanguageButton;

drawLanguageButton = function() {
    const isTitleExit =
        gameState &&
        gameState.phase ===
            "TITLE_TRANSITION" &&
        gameState.titleTransition &&
        gameState.titleTransition.active;

    if (!isTitleExit) {
        return drawLanguageButtonBaseForTitleExitFade.apply(
            this,
            arguments
        );
    }

    /*
     * 既存の言語ボタン描画は TITLE 判定を持つため、
     * 描画中だけTITLEとして扱う。
     */
    const phaseBefore =
        gameState.phase;

    gameState.phase =
        "TITLE";

    try {
        return drawLanguageButtonBaseForTitleExitFade.apply(
            this,
            arguments
        );
    } finally {
        gameState.phase =
            phaseBefore;
    }
};

/*
 * タイトル前景全体に同じアルファを掛ける。
 *
 * 個々の文字色・ボタンの点滅・枠の濃淡は保ったまま、
 * 画面全体が一枚のまま沈んでいく。
 */
const drawTitleBaseForUnifiedExitFade =
    drawTitle;

drawTitle = function() {
    const context =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    if (!context) {
        return drawTitleBaseForUnifiedExitFade.apply(
            this,
            arguments
        );
    }

    const fade =
        getColaRollTitleForegroundFade();

    context.save();

    context.globalAlpha =
        context.globalAlpha *
        fade;

    try {
        return drawTitleBaseForUnifiedExitFade.apply(
            this,
            arguments
        );
    } finally {
        context.restore();
    }
};


/*
 * 工房背景の最終統一
 *
 * TITLE と TITLE_TRANSITION の両方で、
 * Canvasと同じ表示領域に合わせたDOM背景だけを使う。
 *
 * Canvas CSS背景は完全に無効化し、
 * 工房が泡の途中で下へずれる問題をなくす。
 */

const drawColaAmbientBackgroundBaseForStableWorkshopLayer =
    drawColaAmbientBackground;

function colaRollGetStableWorkshopCanvas() {
    if (
        typeof CodeaLite !== "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx &&
        CodeaLite.state.ctx.canvas
    ) {
        return CodeaLite.state.ctx.canvas;
    }

    if (typeof document !== "undefined") {
        return document.getElementById(
            "screen"
        );
    }

    return null;
}

function colaRollEnsureStableWorkshopLayer() {
    if (typeof document === "undefined") {
        return null;
    }

    let layer =
        document.getElementById(
            "colaRollTitleWorkshopBackdrop"
        );

    const canvas =
        colaRollGetStableWorkshopCanvas();

    if (!canvas || !canvas.parentNode) {
        return null;
    }

    if (!layer) {
        layer =
            document.createElement(
                "div"
            );

        layer.id =
            "colaRollTitleWorkshopBackdrop";

        layer.setAttribute(
            "aria-hidden",
            "true"
        );

        canvas.parentNode.insertBefore(
            layer,
            canvas
        );
    }

    layer.style.pointerEvents =
        "none";

    layer.style.zIndex =
        "0";

    layer.style.opacity =
        "0";

    layer.style.transition =
        "none";

    layer.style.backgroundColor =
        "rgb(24, 14, 10)";

    layer.style.backgroundImage =
        'linear-gradient(to bottom, rgba(13, 7, 5, 0.23) 0%, rgba(13, 7, 5, 0.07) 48%, rgba(13, 7, 5, 0.03) 100%), url("./cola-roll-title-workshop.png")';

    layer.style.backgroundRepeat =
        "no-repeat, no-repeat";

    layer.style.backgroundSize =
        "cover, cover";

    layer.style.backgroundPosition =
        "center center, center bottom";

    canvas.style.position =
        "relative";

    canvas.style.zIndex =
        "1";

    return layer;
}

function colaRollSyncStableWorkshopLayer() {
    const canvas =
        colaRollGetStableWorkshopCanvas();

    const layer =
        colaRollEnsureStableWorkshopLayer();

    if (!canvas || !layer) {
        return null;
    }

    const bounds =
        canvas.getBoundingClientRect();

    /*
     * fixed + Canvas実寸。
     *
     * 100vhではなくCanvasの実際の表示領域に合わせるため、
     * Safariの上部・下部バーの影響を受けない。
     */
    layer.style.position =
        "fixed";

    layer.style.left =
        String(bounds.left) + "px";

    layer.style.top =
        String(bounds.top) + "px";

    layer.style.width =
        String(bounds.width) + "px";

    layer.style.height =
        String(bounds.height) + "px";

    /*
     * 古いCanvas CSS背景は完全停止。
     * 工房画像はDOMレイヤーだけが担当する。
     */
    canvas.style.backgroundImage =
        "none";

    canvas.style.backgroundRepeat =
        "";

    canvas.style.backgroundSize =
        "";

    canvas.style.backgroundPosition =
        "";

    canvas.style.backgroundColor =
        "transparent";

    return layer;
}

function colaRollClearStableWorkshopCanvas() {
    const context =
        typeof CodeaLite !== "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    const canvas =
        context && context.canvas
            ? context.canvas
            : null;

    if (!context || !canvas) {
        return;
    }

    context.save();

    context.setTransform(
        1,
        0,
        0,
        1,
        0,
        0
    );

    context.clearRect(
        0,
        0,
        canvas.width,
        canvas.height
    );

    context.restore();
}

function colaRollIsStableWorkshopPhase() {
    return !!(
        gameState &&
        (
            gameState.phase === "TITLE" ||
            gameState.phase ===
                "TITLE_TRANSITION"
        )
    );
}

drawColaAmbientBackground = function() {
    const showWorkshop =
        colaRollIsStableWorkshopPhase();

    if (showWorkshop) {
        const layer =
            colaRollSyncStableWorkshopLayer();

        if (layer) {
            layer.style.opacity =
                "1";
        }

        /*
         * Canvasは文字・ボタン・泡だけ描く透明レイヤーにする。
         */
        colaRollClearStableWorkshopCanvas();

        return;
    }

    const layer =
        colaRollEnsureStableWorkshopLayer();

    if (layer) {
        layer.style.opacity =
            "0";
    }

    const canvas =
        colaRollGetStableWorkshopCanvas();

    if (canvas) {
        canvas.style.backgroundImage =
            "none";

        canvas.style.backgroundColor =
            "";
    }

    return drawColaAmbientBackgroundBaseForStableWorkshopLayer.apply(
        this,
        arguments
    );
};


/*
 * タイトル工房 → 泡遷移
 *
 * 工房画像を急に切らず、
 * 泡が消えるタイミングまで暗幕でゆっくり沈める。
 *
 * TITLE:
 *   工房背景をそのまま見せる。
 *
 * TITLE_TRANSITION:
 *   工房は残したまま、泡の進行に合わせて
 *   深いコーラ色の暗幕を重ねる。
 *
 * 泡が消える頃にだけ、画面が完全に暗くなる。
 */

const drawColaAmbientBackgroundBaseForWorkshopBubbleFade =
    drawColaAmbientBackground;

function colaRollWorkshopFadeClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

function colaRollWorkshopFadeClearCanvas() {
    const context =
        typeof CodeaLite !== "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    const canvas =
        context && context.canvas
            ? context.canvas
            : null;

    if (!context || !canvas) {
        return;
    }

    context.save();

    context.setTransform(
        1,
        0,
        0,
        1,
        0,
        0
    );

    context.clearRect(
        0,
        0,
        canvas.width,
        canvas.height
    );

    context.restore();
}

function colaRollWorkshopFadePrepareBackdrop(
    visible
) {
    const layer =
        typeof colaRollEnsureTitleWorkshopDomLayer ===
        "function"
            ? colaRollEnsureTitleWorkshopDomLayer()
            : null;

    const canvas =
        typeof colaRollGetMainCanvas ===
        "function"
            ? colaRollGetMainCanvas()
            : null;

    if (layer) {
        /*
         * CSS側の時間差は使わない。
         * 暗くする速度はCanvasの泡演出と
         * 同じタイムラインで制御する。
         */
        layer.style.transition =
            "none";

        layer.style.opacity =
            visible
                ? "1"
                : "0";
    }

    if (canvas) {
        /*
         * 以前のCanvas CSS背景を完全に外す。
         * 背景画像はDOMレイヤーだけが担当する。
         */
        canvas.style.backgroundImage =
            "none";

        canvas.style.backgroundRepeat =
            "";

        canvas.style.backgroundSize =
            "";

        canvas.style.backgroundPosition =
            "";

        canvas.style.backgroundColor =
            visible
                ? "transparent"
                : "";
    }
}

drawColaAmbientBackground = function() {
    const phase =
        gameState
            ? gameState.phase
            : "";

    const isTitle =
        phase === "TITLE";

    const isTitleTransition =
        phase === "TITLE_TRANSITION" &&
        gameState &&
        gameState.titleTransition &&
        gameState.titleTransition.active;

    if (
        isTitle ||
        isTitleTransition
    ) {
        /*
         * タイトルと泡のあいだは、
         * 工房背景をDOMレイヤーで維持する。
         */
        colaRollWorkshopFadePrepareBackdrop(
            true
        );

        colaRollWorkshopFadeClearCanvas();

        return;
    }

    /*
     * 注文先・ゲーム画面へ進んだら、
     * 工房背景はここで初めて完全に退場する。
     */
    colaRollWorkshopFadePrepareBackdrop(
        false
    );

    return drawColaAmbientBackgroundBaseForWorkshopBubbleFade.apply(
        this,
        arguments
    );
};

/*
 * 既存の泡描画を、
 * 工房がゆっくり暗くなる版へ置き換える。
 */
drawTitleStartTransition = function() {
    const transition =
        gameState &&
        gameState.titleTransition
            ? gameState.titleTransition
            : null;

    if (
        !transition ||
        !transition.active
    ) {
        return;
    }

    const elapsed =
        Math.max(
            0,
            transition.elapsed
        );

    const fizzDuration =
        Math.max(
            0.01,
            transition.fizzDuration ||
                0.92
        );

    const progress =
        colaRollWorkshopFadeClamp(
            elapsed /
                fizzDuration
        );

    /*
     * 前半は工房を少し残し、
     * 後半でゆっくり暗く沈める。
     *
     * 0.92秒の終端では必ず 1 になり、
     * 泡が消える頃に真っ暗へ到達する。
     */
    const darkProgress =
        Math.pow(
            progress,
            1.55
        );

    const darkAlpha =
        255 *
        darkProgress;

    const bubbleFadeIn =
        colaRollWorkshopFadeClamp(
            (
                elapsed +
                0.04
            ) /
            0.18
        );

    const bubbleFadeOut =
        colaRollWorkshopFadeClamp(
            (
                elapsed -
                (
                    fizzDuration -
                    0.28
                )
            ) /
            0.28
        );

    const bubbleAlpha =
        245 *
        bubbleFadeIn *
        (
            1 -
            Math.pow(
                bubbleFadeOut,
                1.35
            )
        );

    /*
     * 工房の上に暗幕を重ねる。
     * 泡はこのあとに描くので、
     * 暗くなっても最後まで見える。
     */
    if (darkAlpha > 0.5) {
        rectMode(CORNER);
        noStroke();

        fill(
            15,
            8,
            6,
            darkAlpha
        );

        rect(
            0,
            0,
            WIDTH,
            HEIGHT
        );
    }

    const bubbles =
        transition.bubbles || [];

    for (
        let index = 0;
        index < bubbles.length;
        index += 1
    ) {
        const bubble =
            bubbles[index];

        const bubbleProgress =
            (
                elapsed -
                bubble.delay
            ) /
            bubble.life;

        if (
            bubbleProgress <= 0 ||
            bubbleProgress >= 1
        ) {
            continue;
        }

        const bubbleX =
            bubble.x +
            Math.sin(
                bubbleProgress *
                    bubble.wobbleSpeed +
                bubble.phase
            ) *
            bubble.wobble;

        const bubbleY =
            bubble.startY +
            bubble.travel *
                bubbleProgress;

        const size =
            bubble.size *
            (
                0.76 +
                bubbleProgress * 0.42
            );

        const localAlpha =
            bubbleAlpha *
            Math.sin(
                bubbleProgress *
                    Math.PI
            );

        noFill();

        stroke(
            221,
            246,
            250,
            localAlpha * 0.88
        );

        strokeWidth(
            Math.max(
                0.8,
                size * 0.14
            )
        );

        ellipse(
            bubbleX,
            bubbleY,
            size
        );

        stroke(
            255,
            239,
            198,
            localAlpha * 0.38
        );

        strokeWidth(
            Math.max(
                0.6,
                size * 0.075
            )
        );

        ellipse(
            bubbleX -
                size * 0.16,
            bubbleY +
                size * 0.12,
            size * 0.42
        );

        noStroke();

        fill(
            255,
            247,
            224,
            localAlpha * 0.34
        );

        ellipse(
            bubbleX -
                size * 0.18,
            bubbleY +
                size * 0.20,
            Math.max(
                1.2,
                size * 0.18
            )
        );
    }

    /*
     * 最後の一瞬でDOM背景も退場させる。
     * すでに暗幕がほぼ完全なので、
     * 画像が切れた感じは出ない。
     */
    if (progress >= 0.995) {
        colaRollWorkshopFadePrepareBackdrop(
            false
        );
    }

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);
};


/*
 * 最近の瓶詰め:
 * 工房の瓶箱と重ならないよう、
 * 画面下端の記録欄としてもう一段下げる。
 */
colaHistoryTitleRect = function() {
    const portrait =
        HEIGHT >= WIDTH;

    const width =
        Math.min(
            portrait
                ? 196
                : 220,
            WIDTH * 0.52
        );

    const height =
        portrait
            ? 30
            : 28;

    const centerY =
        portrait
            ? HEIGHT * 0.085
            : HEIGHT * 0.11;

    return {
        x:
            WIDTH * 0.5 -
            width * 0.5,

        y:
            centerY -
            height * 0.5,

        w: width,
        h: height,
    };
};


function drawResultRestartTransition() {
    const transition =
        gameState.resultRestartTransition;

    if (
        !transition ||
        !transition.active
    ) {
        return;
    }

    const darkAlpha =
        Math.max(
            0,
            Math.min(
                255,
                transition.darkAlpha
            )
        );

    const bubbleAlpha =
        Math.max(
            0,
            Math.min(
                255,
                transition.bubbleAlpha
            )
        );

    const elapsed =
        Math.max(
            0,
            ElapsedTime -
                transition.startedAt
        );

    if (
        darkAlpha > 0
    ) {
        rectMode(CORNER);
        noStroke();

        fill(
            15,
            10,
            9,
            darkAlpha
        );

        rect(
            0,
            0,
            WIDTH,
            HEIGHT
        );
    }

    if (
        bubbleAlpha <= 0
    ) {
        rectMode(CORNER);
        noStroke();
        return;
    }

    const bubbles =
        transition.bubbles || [];

    for (
        let index = 0;
        index < bubbles.length;
        index += 1
    ) {
        const bubble =
            bubbles[index];

        const progress =
            (
                elapsed -
                bubble.delay
            ) /
            bubble.life;

        if (
            progress <= 0 ||
            progress >= 1
        ) {
            continue;
        }

        const bubbleX =
            bubble.x +
            Math.sin(
                progress *
                    bubble.wobbleSpeed +
                bubble.phase
            ) *
                bubble.wobble;

        const bubbleY =
            bubble.startY +
            bubble.travel *
                progress;

        const size =
            bubble.size *
            (
                0.76 +
                progress * 0.42
            );

        const localAlpha =
            bubbleAlpha *
            Math.sin(
                progress *
                Math.PI
            );

        noFill();

        stroke(
            221,
            246,
            250,
            localAlpha * 0.88
        );

        strokeWidth(
            Math.max(
                0.8,
                size * 0.14
            )
        );

        ellipse(
            bubbleX,
            bubbleY,
            size
        );

        stroke(
            255,
            239,
            198,
            localAlpha * 0.38
        );

        strokeWidth(
            Math.max(
                0.6,
                size * 0.075
            )
        );

        ellipse(
            bubbleX -
                size * 0.16,
            bubbleY +
                size * 0.12,
            size * 0.42
        );

        noStroke();

        fill(
            255,
            247,
            224,
            localAlpha * 0.34
        );

        ellipse(
            bubbleX -
                size * 0.18,
            bubbleY +
                size * 0.20,
            Math.max(
                1.2,
                size * 0.18
            )
        );
    }

    rectMode(CORNER);
    noStroke();
}

const drawTitleStartTransitionBaseForResultRestart =
    drawTitleStartTransition;

drawTitleStartTransition = function() {
    drawTitleStartTransitionBaseForResultRestart();
    drawResultRestartTransition();
};


function drawTitlePressureHandoff(
    progress
) {
    if (
        !layout ||
        !layout.board ||
        !layout.cap
    ) {
        return;
    }

    const capPanel =
        layout.cap;

    const gauge =
        getMainGaugeLayout(
            capPanel
        );

    const startPosition =
        typeof getBoardNodeScreenPosition ===
        "function"
            ? getBoardNodeScreenPosition(
                "start"
            )
            : {
                x:
                    layout.board.x +
                    layout.board.w * 0.50,
                y:
                    layout.board.y +
                    layout.board.h * 0.50,
            };

    const sourceX =
        startPosition.x;

    const sourceY =
        startPosition.y;

    const targetX =
        capPanel.x +
        gauge.centerX;

    const targetY =
        capPanel.y +
        gauge.centerY;

    const travelProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    progress -
                    0.10
                ) /
                    0.34
            )
        );

    const retractProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    progress -
                    0.44
                ) /
                    0.20
            )
        );

    const easedRetract =
        1 -
        Math.pow(
            1 -
                retractProgress,
            2
        );

    const beamHeadProgress =
        travelProgress;

    const beamTailProgress =
        travelProgress < 1
            ? 0
            : easedRetract;

    const meterProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    progress -
                    0.62
                ) /
                    0.34
            )
        );

    const beamFadeOut =
        Math.max(
            0,
            Math.min(
                1,
                (
                    1 -
                    progress
                ) /
                    0.12
            )
        );

    const beamLength =
        Math.max(
            0,
            beamHeadProgress -
                beamTailProgress
        );

    const beamStartX =
        sourceX +
        (
            targetX -
            sourceX
        ) *
            beamTailProgress;

    const beamStartY =
        sourceY +
        (
            targetY -
            sourceY
        ) *
            beamTailProgress;

    const beamHeadX =
        sourceX +
        (
            targetX -
            sourceX
        ) *
            beamHeadProgress;

    const beamHeadY =
        sourceY +
        (
            targetY -
            sourceY
        ) *
            beamHeadProgress;

    const beamAlpha =
        (
            34 +
            travelProgress * 108
        ) *
        beamFadeOut;

    if (
        beamLength > 0.012
    ) {
        noFill();

        stroke(
            234,
            176,
            94,
            beamAlpha * 0.18
        );

        strokeWidth(4);

        line(
            beamStartX,
            beamStartY,
            beamHeadX,
            beamHeadY
        );

        stroke(
            255,
            230,
            177,
            beamAlpha * 0.72
        );

        strokeWidth(1.2);

        line(
            beamStartX,
            beamStartY,
            beamHeadX,
            beamHeadY
        );

        noStroke();

        const tailDotCount =
            4;

        for (
            let index = 0;
            index < tailDotCount;
            index += 1
        ) {
            const ratio =
                (
                    index + 1
                ) /
                (
                    tailDotCount + 1
                );

            const dotProgress =
                beamHeadProgress -
                beamLength * ratio;

            const dotX =
                sourceX +
                (
                    targetX -
                    sourceX
                ) *
                    dotProgress;

            const dotY =
                sourceY +
                (
                    targetY -
                    sourceY
                ) *
                    dotProgress;

            fill(
                255,
                220,
                149,
                beamAlpha *
                    (
                        0.22 -
                        index * 0.035
                    )
            );

            ellipse(
                dotX,
                dotY,
                3.8 -
                    index * 0.42
            );
        }
    }

    if (
        beamHeadProgress > 0 &&
        beamLength > 0.012
    ) {
        const headGlow =
            beamAlpha *
            (
                0.70 +
                (
                    1 -
                    beamLength
                ) *
                    0.30
            );

        noFill();

        stroke(
            255,
            238,
            192,
            headGlow
        );

        strokeWidth(2);

        ellipse(
            beamHeadX,
            beamHeadY,
            12 +
                Math.sin(
                    beamHeadProgress *
                        Math.PI
                ) *
                    4
        );

        noStroke();

        fill(
            255,
            226,
            154,
            headGlow
        );

        ellipse(
            beamHeadX,
            beamHeadY,
            5
        );
    }

    if (
        travelProgress >= 1 &&
        retractProgress > 0 &&
        retractProgress < 1
    ) {
        const collapseGlow =
            Math.sin(
                retractProgress *
                    Math.PI
            );

        noFill();

        stroke(
            255,
            232,
            174,
            150 *
                collapseGlow *
                beamFadeOut
        );

        strokeWidth(1.4);

        ellipse(
            targetX,
            targetY,
            gauge.radius *
                (
                    0.24 +
                    collapseGlow *
                        0.22
                )
        );

        noStroke();

        fill(
            255,
            226,
            154,
            130 *
                collapseGlow *
                beamFadeOut
        );

        ellipse(
            targetX,
            targetY,
            gauge.radius *
                (
                    0.09 +
                    collapseGlow *
                        0.04
                )
        );
    }

    drawTitleGaugeStartupLights(
        targetX,
        targetY,
        gauge.radius,
        meterProgress,
        1
    );

    noStroke();
}

function colaRollEnsureTitleDispatchUnderlay() {
    if (
        typeof document ===
        "undefined"
    ) {
        return null;
    }

    let layer =
        document.getElementById(
            "colaRollTitleDispatchUnderlay"
        );

    if (layer) {
        return layer;
    }

    const workshopLayer =
        typeof colaRollEnsureTitleWorkshopDomLayer ===
        "function"
            ? colaRollEnsureTitleWorkshopDomLayer()
            : null;

    if (
        !workshopLayer ||
        !workshopLayer.parentNode
    ) {
        return null;
    }

    layer =
        document.createElement(
            "div"
        );

    layer.id =
        "colaRollTitleDispatchUnderlay";

    layer.setAttribute(
        "aria-hidden",
        "true"
    );

    layer.style.position =
        "fixed";

    layer.style.left =
        "0";

    layer.style.top =
        "0";

    layer.style.width =
        "100vw";

    layer.style.height =
        "100vh";

    layer.style.pointerEvents =
        "none";

    /*
     * 工房画像と同じ z-index にして、
     * DOMの並び順だけで必ず画像の下に置く。
     */
    layer.style.zIndex =
        "0";

    layer.style.opacity =
        "0";

    layer.style.transition =
        "none";

    /*
     * 注文先画面と同じ背景構成。
     *
     * 上: 明るめのコーラ茶
     * 中: 暗い茶
     * 下: 黒に近い茶
     *
     * 中央下寄りの暖色帯と全体の暗幕も、
     * 注文先画面に合わせて重ねる。
     */
    layer.style.background =
        "linear-gradient(" +
            "to bottom, " +
            "rgba(15, 10, 9, 0.1883) 0%, " +
            "rgba(15, 10, 9, 0.1883) 100%" +
        "), " +
        "linear-gradient(" +
            "to bottom, " +
            "rgba(73, 34, 20, 0) 0%, " +
            "rgba(73, 34, 20, 0) 52%, " +
            "rgba(73, 34, 20, 0.1255) 52%, " +
            "rgba(73, 34, 20, 0.1255) 82%, " +
            "rgba(73, 34, 20, 0) 82%, " +
            "rgba(73, 34, 20, 0) 100%" +
        "), " +
        "linear-gradient(" +
            "to bottom, " +
            "rgb(53, 29, 18) 0%, " +
            "rgb(34, 22, 18) 44%, " +
            "rgb(22, 18, 18) 100%" +
        ")";

    workshopLayer.parentNode.insertBefore(
        layer,
        workshopLayer
    );

    return layer;
}


/*
 * 工房画像と、その下の注文先背景を別々に制御する。
 *
 * TITLE:
 *   工房だけ見せる。
 *
 * TITLE_TRANSITION:
 *   注文先背景を下に置き、
 *   工房画像だけを泡の時間に合わせて薄くする。
 *
 * それ以外:
 *   DOMレイヤーは退場し、通常のCanvas描画へ戻る。
 */
colaRollWorkshopFadePrepareBackdrop =
    function(
        visible
    ) {
        const workshopLayer =
            typeof colaRollEnsureTitleWorkshopDomLayer ===
            "function"
                ? colaRollEnsureTitleWorkshopDomLayer()
                : null;

        const dispatchLayer =
            colaRollEnsureTitleDispatchUnderlay();

        const canvas =
            typeof colaRollGetMainCanvas ===
            "function"
                ? colaRollGetMainCanvas()
                : null;

        const transition =
            gameState &&
            gameState.titleTransition
                ? gameState.titleTransition
                : null;

        const isTransition =
            !!(
                visible &&
                gameState &&
                gameState.phase ===
                    "TITLE_TRANSITION" &&
                transition &&
                transition.active
            );

        let workshopAlpha =
            visible
                ? 1
                : 0;

        let dispatchAlpha =
            0;

        if (isTransition) {
            const fizzDuration =
                Math.max(
                    0.01,
                    transition.fizzDuration ||
                        0.92
                );

            const progress =
                Math.max(
                    0,
                    Math.min(
                        1,
                        transition.elapsed /
                            fizzDuration
                    )
                );

            /*
             * これまで黒幕が暗くしていたカーブを、
             * 今度は工房画像自身の透明度に使う。
             */
            const imageFade =
                Math.pow(
                    progress,
                    1.55
                );

            workshopAlpha =
                1 - imageFade;

            dispatchAlpha =
                1;
        }

        if (workshopLayer) {
            workshopLayer.style.transition =
                "none";

            workshopLayer.style.opacity =
                String(
                    workshopAlpha
                );
        }

        if (dispatchLayer) {
            dispatchLayer.style.transition =
                "none";

            dispatchLayer.style.opacity =
                String(
                    dispatchAlpha
                );
        }

        if (canvas) {
            canvas.style.backgroundImage =
                "none";

            canvas.style.backgroundRepeat =
                "";

            canvas.style.backgroundSize =
                "";

            canvas.style.backgroundPosition =
                "";

            /*
             * タイトル中はCanvasを透明にし、
             * 下の2レイヤーをそのまま見せる。
             */
            canvas.style.backgroundColor =
                visible
                    ? "transparent"
                    : "";
        }
    };


/*
 * 古い黒幕つき泡フェードを、泡だけの描画に差し替える。
 *
 * 工房画像のフェードは上のDOMレイヤーが担当するため、
 * ここでは全面を暗く塗らない。
 */
drawTitleStartTransition = function() {
    const transition =
        gameState &&
        gameState.titleTransition
            ? gameState.titleTransition
            : null;

    if (
        transition &&
        transition.active
    ) {
        const elapsed =
            Math.max(
                0,
                transition.elapsed
            );

        const fizzDuration =
            Math.max(
                0.01,
                transition.fizzDuration ||
                    0.92
            );

        const bubbleFadeIn =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed +
                        0.04
                    ) /
                        0.18
                )
            );

        const bubbleFadeOut =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        elapsed -
                        (
                            fizzDuration -
                            0.28
                        )
                    ) /
                        0.28
                )
            );

        const bubbleAlpha =
            245 *
            bubbleFadeIn *
            (
                1 -
                Math.pow(
                    bubbleFadeOut,
                    1.35
                )
            );

        const bubbles =
            transition.bubbles || [];

        for (
            let index = 0;
            index < bubbles.length;
            index += 1
        ) {
            const bubble =
                bubbles[index];

            const bubbleProgress =
                (
                    elapsed -
                    bubble.delay
                ) /
                bubble.life;

            if (
                bubbleProgress <= 0 ||
                bubbleProgress >= 1
            ) {
                continue;
            }

            const bubbleX =
                bubble.x +
                Math.sin(
                    bubbleProgress *
                        bubble.wobbleSpeed +
                    bubble.phase
                ) *
                bubble.wobble;

            const bubbleY =
                bubble.startY +
                bubble.travel *
                bubbleProgress;

            const size =
                bubble.size *
                (
                    0.76 +
                    bubbleProgress *
                        0.42
                );

            const localAlpha =
                bubbleAlpha *
                Math.sin(
                    bubbleProgress *
                    Math.PI
                );

            noFill();

            stroke(
                221,
                246,
                250,
                localAlpha * 0.88
            );

            strokeWidth(
                Math.max(
                    0.8,
                    size * 0.14
                )
            );

            ellipse(
                bubbleX,
                bubbleY,
                size
            );

            stroke(
                255,
                239,
                198,
                localAlpha * 0.38
            );

            strokeWidth(
                Math.max(
                    0.6,
                    size * 0.075
                )
            );

            ellipse(
                bubbleX -
                    size * 0.16,
                bubbleY +
                    size * 0.12,
                size * 0.42
            );

            noStroke();

            fill(
                255,
                247,
                224,
                localAlpha * 0.34
            );

            ellipse(
                bubbleX -
                    size * 0.18,
                bubbleY +
                    size * 0.20,
                Math.max(
                    1.2,
                    size * 0.18
                )
            );
        }
    }

    /*
     * 結果画面からタイトルへ戻る演出は保つ。
     */
    if (
        typeof drawResultRestartTransition ===
        "function"
    ) {
        drawResultRestartTransition();
    }

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);
};



function drawTitleGaugeStartupLights(
    centerX,
    centerY,
    radius,
    progress,
    fadeOut
) {
    if (
        progress <= 0 ||
        fadeOut <= 0
    ) {
        return;
    }

    const startAngle =
        205;

    const endAngle =
        -25;

    const zones = [
        {
            start: 0,
            end:
                CONFIG.capPowerZone1End,
            color: {
                r: 166,
                g: 184,
                b: 104,
            },
        },
        {
            start:
                CONFIG.capPowerZone1End,
            end:
                CONFIG.capPowerZone2End,
            color: {
                r: 224,
                g: 176,
                b: 85,
            },
        },
        {
            start:
                CONFIG.capPowerZone2End,
            end:
                CONFIG.capPowerZone3End,
            color: {
                r: 229,
                g: 126,
                b: 64,
            },
        },
        {
            start:
                CONFIG.capPowerZone3End,
            end: 1,
            color: {
                r: 235,
                g: 88,
                b: 76,
            },
        },
    ];

    const sequenceEnd =
        0.66;

    const allFlashStart =
        0.72;

    const allFlashEnd =
        0.98;

    const sequenceProgress =
        Math.max(
            0,
            Math.min(
                1,
                progress /
                    sequenceEnd
            )
        );

    for (
        let index = 0;
        index < zones.length;
        index += 1
    ) {
        const zone =
            zones[index];

        const stepStart =
            index /
            zones.length;

        const stepEnd =
            (
                index + 1
            ) /
            zones.length;

        const localProgress =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        sequenceProgress -
                        stepStart
                    ) /
                        (
                            stepEnd -
                            stepStart
                        )
                )
            );

        if (
            sequenceProgress <
                stepStart ||
            sequenceProgress >
                stepEnd
        ) {
            continue;
        }

        const flash =
            Math.sin(
                localProgress *
                    Math.PI
            );

        if (
            flash <= 0
        ) {
            continue;
        }

        drawTitleGaugeLightArc(
            centerX,
            centerY,
            radius,
            startAngle,
            endAngle,
            zone.start,
            zone.end,
            zone.color,
            flash,
            fadeOut
        );
    }

    const allFlashProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    progress -
                    allFlashStart
                ) /
                    (
                        allFlashEnd -
                        allFlashStart
                    )
            )
        );

    if (
        progress <
        allFlashStart
    ) {
        return;
    }

    let allFlash =
        0;

    if (
        allFlashProgress <
        0.24
    ) {
        const t =
            allFlashProgress /
            0.24;

        allFlash =
            1 -
            Math.pow(
                1 - t,
                3
            );
    } else if (
        allFlashProgress <
        0.64
    ) {
        allFlash =
            1;
    } else {
        const t =
            (
                allFlashProgress -
                0.64
            ) /
            0.36;

        allFlash =
            Math.max(
                0,
                1 -
                    t
            );
    }

    for (
        let index = 0;
        index < zones.length;
        index += 1
    ) {
        const zone =
            zones[index];

        drawTitleGaugeLightArc(
            centerX,
            centerY,
            radius,
            startAngle,
            endAngle,
            zone.start,
            zone.end,
            zone.color,
            allFlash,
            fadeOut
        );
    }
}


function drawTitleGaugeLightArc(
    centerX,
    centerY,
    radius,
    startAngle,
    endAngle,
    rangeStart,
    rangeEnd,
    lightColor,
    flash,
    fadeOut
) {
    const arcRadius =
        radius * 0.96;

    const segmentCount =
        7;

    const glowAlpha =
        170 *
        flash *
        fadeOut;

    const coreAlpha =
        255 *
        flash *
        fadeOut;

    for (
        let index = 0;
        index < segmentCount;
        index += 1
    ) {
        const ratio1 =
            rangeStart +
            (
                rangeEnd -
                rangeStart
            ) *
                (
                    index /
                    segmentCount
                );

        const ratio2 =
            rangeStart +
            (
                rangeEnd -
                rangeStart
            ) *
                (
                    (
                        index + 1
                    ) /
                    segmentCount
                );

        const angle1 =
            (
                startAngle +
                (
                    endAngle -
                    startAngle
                ) *
                ratio1
            ) *
            Math.PI /
            180;

        const angle2 =
            (
                startAngle +
                (
                    endAngle -
                    startAngle
                ) *
                ratio2
            ) *
            Math.PI /
            180;

        const x1 =
            centerX +
            Math.cos(
                angle1
            ) *
                arcRadius;

        const y1 =
            centerY +
            Math.sin(
                angle1
            ) *
                arcRadius;

        const x2 =
            centerX +
            Math.cos(
                angle2
            ) *
                arcRadius;

        const y2 =
            centerY +
            Math.sin(
                angle2
            ) *
                arcRadius;

        stroke(
            lightColor.r,
            lightColor.g,
            lightColor.b,
            glowAlpha * 0.24
        );

        strokeWidth(9);

        line(
            x1,
            y1,
            x2,
            y2
        );

        stroke(
            255,
            240,
            190,
            glowAlpha * 0.48
        );

        strokeWidth(5);

        line(
            x1,
            y1,
            x2,
            y2
        );

        stroke(
            lightColor.r,
            lightColor.g,
            lightColor.b,
            coreAlpha
        );

        strokeWidth(3.4);

        line(
            x1,
            y1,
            x2,
            y2
        );
    }

    noStroke();
}


function drawPreviewScreen() {
    /*
     * カウンターは本当に最背面。
     * 盤面・ゲージ・瓶より先に描く。
     */
    if (
        typeof drawGameplayBackCounter ===
        "function"
    ) {
        drawGameplayBackCounter();
    }

    drawBoardPanel();
    drawBoardStationActivation();
    drawExactStopEffect();

    const capPanelHidden =
        gameState.phase === "MOVING" ||
        gameState.phase === "MOVE_COUNT_TICK" ||
        gameState.phase === "MOVE_COUNT_ZERO" ||
        gameState.phase === "LANDING";

    if (!capPanelHidden) {
        drawCapPanel();
    }

    const storedGarnish =
        gameState.glass.garnish;

    gameState.previewGarnishTray =
        storedGarnish;

    gameState.glass.garnish =
        null;

    drawBottleInspectionPanel();

    gameState.glass.garnish =
        storedGarnish;

    gameState.previewGarnishTray =
        null;

    drawCapacitySpillTokenOverlay();
    drawBottleShakeRig();
    drawBottleChillIndicator();

    if (
        typeof drawBottleCoolingFog ===
        "function"
    ) {
        drawBottleCoolingFog();
    }

    drawBottleCoolingEffect();
    drawLandingIngredientSource();
    drawFlyingIngredient();
    drawBurstFlash();
    drawCarbonationParticles();
    drawBurstToken();
    drawSpilledTokens();
    drawGlassFullMessage();
    drawMoveCounter();
    drawCapSnapEffect();
    drawLanguageButton();
    drawIngredientGetBackdrop();
    drawIngredientGetEffect();

    if (isEventRoulettePhase()) {
        drawEventRouletteOverlay();
    }

    if (isEventActionPhase()) {
        drawEventActionOverlay();
    }

    if (isMysteryPhase()) {
        drawMysteryOverlay();
    }

    if (
        gameState.phase ===
        "GOAL_ARRIVAL"
    ) {
        drawGoalArrivalOverlay();
    }
}


function drawCapSnapEffect() {
    const effect =
        gameState.capSnapEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const cap =
        gameState.cap;

    const panel =
        layout.cap;

    const x =
        panel.x +
        cap.x;

    const y =
        panel.y +
        cap.y;

    const baseSize =
        Math.min(
            CONFIG.capSize,
            panel.h * 0.15
        );

    const ringSize =
        baseSize *
        (
            1.35 +
            effect.ring * 1.4
        );

    noFill();

    stroke(
        255,
        235,
        185,
        effect.alpha *
            0.78
    );

    strokeWidth(
        3 +
        effect.ring * 2
    );

    ellipse(
        x,
        y,
        ringSize
    );

    stroke(
        255,
        255,
        235,
        effect.alpha *
            0.34
    );

    strokeWidth(2);

    ellipse(
        x,
        y,
        ringSize * 1.28
    );

    const sparkRadius =
        baseSize * 0.72;

    const sparkLength =
        6 +
        effect.spark * 18;

    stroke(
        255,
        226,
        155,
        effect.alpha
    );

    strokeWidth(3);

    for (
        let index = 0;
        index < 8;
        index += 1
    ) {
        const angle =
            index *
            Math.PI /
            4;

        const innerX =
            x +
            Math.cos(angle) *
                sparkRadius;

        const innerY =
            y +
            Math.sin(angle) *
                sparkRadius;

        const outerX =
            x +
            Math.cos(angle) *
                (
                    sparkRadius +
                    sparkLength
                );

        const outerY =
            y +
            Math.sin(angle) *
                (
                    sparkRadius +
                    sparkLength
                );

        line(
            innerX,
            innerY,
            outerX,
            outerY
        );
    }

    noStroke();

    fill(
        255,
        245,
        205,
        effect.alpha *
            0.85
    );

    const flashSize =
        3 +
        effect.spark * 5;

    ellipse(
        x -
            baseSize * 0.62,
        y +
            baseSize * 0.48,
        flashSize
    );

    ellipse(
        x +
            baseSize * 0.66,
        y +
            baseSize * 0.30,
        flashSize * 0.72
    );
}



function drawGoalArrivalOverlay() {
    const effect =
        gameState.goalEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const goalPosition =
        getBoardNodeScreenPosition(
            "goal"
        );

    const bottleCenterX =
        goalPosition.x;

    const bottleCenterY =
        goalPosition.y +
        CONFIG.boardBottleRailOffset -
        (
            CONFIG.boardBottleScreenLift ||
            0
        );

    const mouthPosition =
        getBoardBottleMouthScreenPosition(
            "goal"
        );

    fill(
        5,
        3,
        3,
        effect.alpha * 0.42
    );

    noStroke();

    rectMode(CORNER);

    rect(
        0,
        0,
        WIDTH,
        HEIGHT
    );

    const ringSize =
        46 +
        effect.ring * 68;

    noFill();

    stroke(
        255,
        220,
        125,
        effect.alpha *
        (
            0.45 +
            effect.complete * 0.45
        )
    );

    strokeWidth(
        2.5 +
        effect.complete * 2
    );

    ellipse(
        bottleCenterX,
        bottleCenterY,
        ringSize
    );

    stroke(
        255,
        245,
        205,
        effect.alpha *
        (
            0.18 +
            effect.complete * 0.34
        )
    );

    strokeWidth(2);

    ellipse(
        bottleCenterX,
        bottleCenterY,
        ringSize * 1.42
    );

    noStroke();

    drawBoardBottleToken(
        goalPosition.x,
        goalPosition.y,
        1 +
        effect.press * 0.04 +
        effect.complete * 0.08,
        0,
        effect.alpha
    );

    const capX =
        mouthPosition.x;

    const capY =
        mouthPosition.y +
        (
            1 -
            effect.capProgress
        ) *
        CONFIG.goalCapStartOffset -
        effect.press * 3;

    const pressStemTop =
        capY +
        CONFIG.goalPressStemLength +
        13;

    stroke(
        24,
        15,
        12,
        effect.alpha * 0.90
    );

    strokeWidth(10);

    line(
        capX,
        pressStemTop,
        capX,
        capY + 14
    );

    stroke(
        167,
        109,
        59,
        effect.alpha
    );

    strokeWidth(6);

    line(
        capX,
        pressStemTop,
        capX,
        capY + 14
    );

    stroke(
        239,
        191,
        117,
        effect.alpha * 0.62
    );

    strokeWidth(1.5);

    line(
        capX - 2,
        pressStemTop,
        capX - 2,
        capY + 14
    );

    noStroke();

    rectMode(CENTER);

    fill(
        40,
        26,
        21,
        effect.alpha
    );

    rect(
        capX,
        capY + 17,
        CONFIG.goalPressHeadWidth + 5,
        CONFIG.goalPressHeadHeight + 4,
        4
    );

    fill(
        157,
        101,
        55,
        effect.alpha
    );

    rect(
        capX,
        capY + 17,
        CONFIG.goalPressHeadWidth,
        CONFIG.goalPressHeadHeight,
        3
    );

    fill(
        235,
        183,
        107,
        effect.alpha * 0.68
    );

    rect(
        capX,
        capY + 19,
        CONFIG.goalPressHeadWidth - 8,
        2,
        1
    );

    rectMode(CORNER);

    drawCap(
        capX,
        capY,
        effect.capRotation,
        CONFIG.goalCapSize *
        (
            0.84 +
            effect.capProgress * 0.16 +
            effect.press * 0.10
        )
    );

    if (
        effect.press > 0.18
    ) {
        const sparkAlpha =
            effect.alpha *
            effect.press;

        stroke(
            255,
            224,
            142,
            sparkAlpha
        );

        strokeWidth(2);

        for (
            let index = 0;
            index < 8;
            index += 1
        ) {
            const angle =
                index *
                Math.PI /
                4;

            const innerRadius =
                11;

            const outerRadius =
                16 +
                effect.press * 10;

            line(
                capX +
                Math.cos(
                    angle
                ) *
                innerRadius,
                mouthPosition.y +
                Math.sin(
                    angle
                ) *
                innerRadius,
                capX +
                Math.cos(
                    angle
                ) *
                outerRadius,
                mouthPosition.y +
                Math.sin(
                    angle
                ) *
                outerRadius
            );
        }

        noStroke();
    }

    if (
        effect.labelProgress > 0
    ) {
        const labelAlpha =
            effect.alpha *
            effect.labelProgress;

        const labelX =
            bottleCenterX +
            (
                1 -
                effect.labelProgress
            ) *
            CONFIG.goalLabelStartOffset;

        const labelY =
            bottleCenterY - 3;

        pushMatrix();

        translate(
            labelX,
            labelY
        );

        rotate(
            (
                1 -
                effect.labelProgress
            ) *
            24
        );

        scale(
            0.72 +
            effect.labelProgress * 0.28,
            0.72 +
            effect.labelProgress * 0.28
        );

        rectMode(CENTER);

        fill(
            24,
            15,
            12,
            labelAlpha * 0.42
        );

        rect(
            2,
            -2,
            CONFIG.goalLabelWidth + 5,
            CONFIG.goalLabelHeight + 5,
            4
        );

        fill(
            238,
            216,
            178,
            labelAlpha
        );

        rect(
            0,
            0,
            CONFIG.goalLabelWidth,
            CONFIG.goalLabelHeight,
            3
        );

        fill(
            151,
            55,
            43,
            labelAlpha
        );

        ellipse(
            0,
            0,
            6
        );

        fill(
            244,
            208,
            133,
            labelAlpha
        );

        ellipse(
            0,
            0,
            2.5
        );

        rectMode(CORNER);

        popMatrix();
    }

    rectMode(CORNER);
    noStroke();
}

function drawGoalResultProductLabel(
    effect,
    bottleCenterX,
    bottleCenterY
) {
    if (
        !effect ||
        effect.labelProgress <= 0 ||
        typeof getResultBottleLabelDesign !==
            "function"
    ) {
        return;
    }

    const design =
        getResultBottleLabelDesign();

    if (!design) {
        return;
    }

    const labelAlpha =
        effect.alpha *
        effect.labelProgress;

    const labelX =
        bottleCenterX +
        (
            1 -
            effect.labelProgress
        ) *
        CONFIG.goalLabelStartOffset;

    const labelY =
        bottleCenterY - 3;

    const labelW =
        CONFIG.goalLabelWidth;

    const labelH =
        CONFIG.goalLabelHeight;

    const base =
        design.base;

    const light =
        design.light;

    const dark =
        design.dark;

    pushMatrix();

    translate(
        labelX,
        labelY
    );

    rotate(
        (
            1 -
            effect.labelProgress
        ) * 24
    );

    scale(
        0.72 +
        effect.labelProgress * 0.28,
        0.72 +
        effect.labelProgress * 0.28
    );

    rectMode(CENTER);
    ellipseMode(CENTER);
    noStroke();

    fill(
        24,
        15,
        12,
        labelAlpha * 0.42
    );

    rect(
        2,
        -2,
        labelW + 5,
        labelH + 5,
        4
    );

    fill(
        238,
        216,
        178,
        labelAlpha
    );

    rect(
        0,
        0,
        labelW,
        labelH,
        3
    );

    fill(
        base.r,
        base.g,
        base.b,
        labelAlpha * 0.96
    );

    rect(
        0,
        0,
        labelW - 2.2,
        labelH - 2.2,
        2
    );

    if (
        design.pattern ===
        "spice"
    ) {
        stroke(
            dark.r,
            dark.g,
            dark.b,
            labelAlpha * 0.68
        );

        strokeWidth(0.75);

        line(
            -labelW * 0.34,
            labelH * 0.22,
            -labelW * 0.16,
            labelH * 0.04
        );

        line(
            labelW * 0.16,
            -labelH * 0.04,
            labelW * 0.34,
            -labelH * 0.22
        );

        noStroke();
    } else if (
        design.pattern ===
        "fresh"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            labelAlpha * 0.48
        );

        ellipse(
            -labelW * 0.30,
            labelH * 0.22,
            1.8
        );

        ellipse(
            labelW * 0.30,
            -labelH * 0.22,
            1.5
        );
    } else if (
        design.pattern ===
        "mystery"
    ) {
        pushMatrix();

        translate(
            labelW * 0.30,
            labelH * 0.18
        );

        rotate(45);

        fill(
            light.r,
            light.g,
            light.b,
            labelAlpha * 0.54
        );

        rect(
            0,
            0,
            2.1,
            2.1,
            0.4
        );

        popMatrix();
    } else if (
        design.pattern ===
        "heavy"
    ) {
        fill(
            dark.r,
            dark.g,
            dark.b,
            labelAlpha * 0.38
        );

        rect(
            0,
            labelH * 0.28,
            labelW * 0.58,
            1.25,
            0.6
        );
    } else if (
        design.pattern ===
        "drop"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            labelAlpha * 0.52
        );

        ellipse(
            -labelW * 0.31,
            labelH * 0.20,
            1.7,
            2.3
        );

        ellipse(
            labelW * 0.31,
            -labelH * 0.20,
            1.4,
            2.0
        );
    } else {
        noFill();

        stroke(
            light.r,
            light.g,
            light.b,
            labelAlpha * 0.45
        );

        strokeWidth(0.65);

        ellipse(
            -labelW * 0.30,
            labelH * 0.20,
            2.2
        );

        ellipse(
            labelW * 0.30,
            -labelH * 0.20,
            1.9
        );

        noStroke();
    }

    noFill();

    stroke(
        dark.r,
        dark.g,
        dark.b,
        labelAlpha * 0.86
    );

    strokeWidth(0.9);

    rect(
        0,
        0,
        labelW - 0.7,
        labelH - 0.7,
        3
    );

    noStroke();

    pushMatrix();

    scale(
        0.17,
        0.17
    );

    drawResultLabelMainMark(
        design,
        labelAlpha
    );

    popMatrix();

    rectMode(CORNER);
    ellipseMode(CENTER);
    noStroke();

    popMatrix();
}

const drawGoalArrivalOverlayBaseForProductLabel =
    drawGoalArrivalOverlay;

drawGoalArrivalOverlay = function() {
    drawGoalArrivalOverlayBaseForProductLabel();

    const effect =
        gameState &&
        gameState.goalEffect;

    if (
        !effect ||
        !effect.visible ||
        effect.labelProgress <= 0
    ) {
        return;
    }

    const goalPosition =
        getBoardNodeScreenPosition(
            "goal"
        );

    const bottleCenterY =
        goalPosition.y +
        CONFIG.boardBottleRailOffset -
        (
            CONFIG.boardBottleScreenLift ||
            0
        );

    drawGoalResultProductLabel(
        effect,
        goalPosition.x,
        bottleCenterY
    );
};


function drawResultScreenCore() {
    setGameUIFont();

    const palette =
        getGameVisualPalette();

    const type =
        getGameTypeScale();
    const reveal =
        gameState.resultReveal;

    const alpha =
        reveal
            ? reveal.alpha
            : 255;

    const scaleValue =
        reveal
            ? reveal.scale
            : 1;

    const portrait =
        HEIGHT > WIDTH;

    const resultGlassKind =
        getResultGlassDrinkKind();

    const resultVisualSetOffsetXPortrait =
        14;

    const resultVisualSetOffsetYPortrait =
        18;

    const resultVisualSetOffsetXLandscape =
        0;

    const resultVisualSetOffsetYLandscape =
        0;

    const resultVisualSetOffsetX =
        portrait
            ? resultVisualSetOffsetXPortrait
            : resultVisualSetOffsetXLandscape;

    const resultVisualSetOffsetY =
        portrait
            ? resultVisualSetOffsetYPortrait
            : resultVisualSetOffsetYLandscape;

    const noGlassVisualShiftX =
        resultGlassKind === "none"
            ? (
                portrait
                    ? WIDTH * 0.12
                    : WIDTH * 0.075
            )
            : 0;

    drawResultCardFrame(
        alpha
    );

    drawResultSparkles(
        alpha
    );

    pushMatrix();

    translate(
        WIDTH * 0.5,
        HEIGHT * 0.5
    );

    scale(
        scaleValue,
        scaleValue
    );

    translate(
        -WIDTH * 0.5,
        -HEIGHT * 0.5
    );

    const headerY =
        HEIGHT - 43;

    fill(
        palette.action.r,
        palette.action.g,
        palette.action.b,
        alpha
    );

    noStroke();

    fontSize(
        Math.min(
            type.sectionLabelMax,
            WIDTH *
                type.sectionLabelWidthRatio
        )
    );

    textAlign(CENTER);

    text(
        "MIDNIGHT COLA",
        WIDTH * 0.5,
        headerY
    );

    const headerLineW =
        Math.min(
            128,
            WIDTH * 0.28
        );

    stroke(
        174,
        101,
        45,
        alpha * 0.75
    );

    strokeWidth(2);

    line(
        WIDTH * 0.5 -
            headerLineW -
            30,
        headerY,
        WIDTH * 0.5 -
            30,
        headerY
    );

    line(
        WIDTH * 0.5 +
            30,
        headerY,
        WIDTH * 0.5 +
            headerLineW +
            30,
        headerY
    );

    noStroke();

    let bottleX;
    let bottleY;
    let bottleScale;
    let tastingGlassX;
    let tastingGlassY;
    let tastingGlassScale;
    let crownX;
    let crownY;
    let crownSize;
    let textX;
    let nameY;
    let ingredientY;
    let contentWidth;

    if (portrait) {
        bottleX =
            WIDTH * 0.35;

        bottleY =
            HEIGHT * 0.605;

        bottleScale =
            Math.min(
                0.78,
                WIDTH / 490
            );

        tastingGlassX =
            WIDTH * 0.615;

        tastingGlassScale =
            Math.min(
                0.34,
                WIDTH / 1080
            );

        const resultBottleLocalBottom =
            -CONFIG.inspectionBottleBodyHeight *
                0.5 -
            18;

        const resultBottleBottomY =
            bottleY +
            resultBottleLocalBottom *
                bottleScale;

        tastingGlassY =
            resultBottleBottomY +
            115 *
                tastingGlassScale;

        crownX =
            bottleX +
            60 * bottleScale;

        crownY =
            bottleY +
            117 * bottleScale;

        crownSize =
            Math.min(
                28,
                WIDTH * 0.070
            );

        textX =
            WIDTH * 0.5;

        nameY =
            HEIGHT * 0.365;

        /*
         * 操作ボタンがある通常表示では、
         * 素材列を上へ移して専用の操作領域を確保する。
         *
         * 保存時は、現在完成している共有用配置へ戻す。
         */
        const resultRecordState =
            gameState &&
            gameState.resultRecord
                ? gameState.resultRecord
                : null;

        ingredientY =
            HEIGHT *
            (
                resultRecordState &&
                resultRecordState.captureMode
                    ? 0.105
                    : 0.145
            );

        contentWidth =
            WIDTH - 54;
    } else {
        bottleX =
            WIDTH * 0.27;

        bottleY =
            HEIGHT * 0.55;

        bottleScale =
            Math.min(
                0.78,
                HEIGHT / 520
            );

        tastingGlassX =
            WIDTH * 0.43;

        tastingGlassScale =
            Math.min(
                0.31,
                HEIGHT / 820
            );

        const resultBottleLocalBottom =
            -CONFIG.inspectionBottleBodyHeight *
                0.5 -
            18;

        const resultBottleBottomY =
            bottleY +
            resultBottleLocalBottom *
                bottleScale;

        tastingGlassY =
            resultBottleBottomY +
            115 *
                tastingGlassScale;

        crownX =
            bottleX +
            60 * bottleScale;

        crownY =
            bottleY +
            114 * bottleScale;

        crownSize =
            Math.min(
                29,
                HEIGHT * 0.070
            );

        textX =
            WIDTH * 0.72;

        nameY =
            HEIGHT * 0.66;

        ingredientY =
            HEIGHT * 0.255;

        contentWidth =
            WIDTH * 0.48;
    }

    bottleX +=
        resultVisualSetOffsetX +
        noGlassVisualShiftX;

    bottleY +=
        resultVisualSetOffsetY;

    tastingGlassX +=
        resultVisualSetOffsetX +
        noGlassVisualShiftX;

    tastingGlassY +=
        resultVisualSetOffsetY;

    crownX +=
        resultVisualSetOffsetX +
        noGlassVisualShiftX;

    crownY +=
        resultVisualSetOffsetY;

    noFill();

    stroke(
        199,
        121,
        45,
        alpha * 0.16
    );

    strokeWidth(7);

    ellipse(
        bottleX,
        bottleY,
        176 *
            bottleScale +
            Math.sin(
                ElapsedTime * 2.4
            ) *
            4
    );

    stroke(
        235,
        169,
        70,
        alpha * 0.27
    );

    strokeWidth(2);

    ellipse(
        bottleX,
        bottleY,
        198 *
            bottleScale
    );

    noStroke();

    drawResultProductBottle(
        bottleX,
        bottleY,
        bottleScale,
        alpha
    );

    drawResultBottleVisualCode(
        bottleX,
        bottleY,
        bottleScale,
        alpha
    );

    drawResultTastingSet(
        tastingGlassX,
        tastingGlassY,
        tastingGlassScale,
        crownX,
        crownY,
        crownSize,
        alpha
    );

    const resultName =
        generateResultName();

    const nameLines =
        splitResultName(
            resultName
        );

    const nameGap =
        portrait
            ? 26
            : 31;

    const nameStartY =
        nameY +
        (
            nameLines.length -
            1
        ) *
        nameGap *
        0.5;

    setGameTitleFont();

    fill(
        palette.actionLight.r,
        palette.actionLight.g,
        palette.actionLight.b,
        alpha
    );

    fontSize(
        portrait
            ? Math.min(
                27,
                WIDTH * 0.066
            )
            : Math.min(
                34,
                WIDTH * 0.041
            )
    );

    textAlign(CENTER);

    for (
        let index = 0;
        index <
            nameLines.length;
        index += 1
    ) {
        text(
            nameLines[
                index
            ],
            textX,
            nameStartY -
                index *
                nameGap
        );
    }

    setGameUIFont();

    const descriptionLines =
        splitResultDescription(
            generateResultDescription(),
            portrait
                ? 25
                : 38
        );

    fill(
        palette.textQuiet.r,
        palette.textQuiet.g,
        palette.textQuiet.b,
        alpha * 0.92
    );

    fontSize(
        portrait
            ? Math.min(
                12.5,
                WIDTH * 0.031
            )
            : Math.min(
                15,
                WIDTH * 0.020
            )
    );

    const descriptionGap =
        portrait
            ? 17
            : 18;

    const extraNameLines =
        Math.max(
            0,
            nameLines.length - 1
        );

    const descriptionBaseY =
        portrait
            ? HEIGHT * 0.242
            : HEIGHT * 0.454;

    const descriptionY =
        descriptionBaseY -
        extraNameLines *
            (
                portrait
                    ? 12
                    : 10
            );

    const descriptionStartY =
        descriptionY +
        (
            descriptionLines.length -
            1
        ) *
        descriptionGap *
        0.5;

    textAlign(CENTER);

    for (
        let index = 0;
        index <
            descriptionLines.length;
        index += 1
    ) {
        text(
            descriptionLines[
                index
            ],
            textX,
            descriptionStartY -
                index *
                descriptionGap
        );
    }

    drawResultIngredientRibbon(
        textX,
        ingredientY,
        contentWidth,
        alpha
    );

    const button =
        getResultRestartButtonRect();

    fill(
        palette.panelRaised.r,
        palette.panelRaised.g,
        palette.panelRaised.b,
        alpha
    );

    rectMode(CORNER);

    rect(
        button.x,
        button.y,
        button.w,
        button.h,
        11
    );

    noFill();

    stroke(
        palette.actionLine.r,
        palette.actionLine.g,
        palette.actionLine.b,
        alpha
    );

    strokeWidth(2);

    rect(
        button.x,
        button.y,
        button.w,
        button.h,
        11
    );

    noStroke();

    fill(
        palette.actionLight.r,
        palette.actionLight.g,
        palette.actionLight.b,
        alpha
    );

    fontSize(
        Math.min(
            type.actionMax,
            WIDTH *
                type.actionWidthRatio
        )
    );

    textAlign(CENTER);

    text(
        getGameUIText(
            "restart"
        ),
        button.x +
            button.w * 0.5,
        button.y +
            button.h * 0.5
    );

    popMatrix();

    drawLanguageButton();
    setGameUIFont();
}


function drawResultNameOrnaments(
    textX,
    nameY,
    portrait,
    nameLines,
    alpha
) {
    const nameGap =
        portrait
            ? 26
            : 31;

    const nameStartY =
        nameY +
        (
            nameLines.length -
            1
        ) *
        nameGap *
        0.5;

    const nameTopY =
        nameStartY;

    const nameBottomY =
        nameStartY -
        (
            nameLines.length -
            1
        ) *
            nameGap;

    const extraLines =
        Math.max(
            0,
            nameLines.length - 1
        );

    const bottomGap =
        (
            portrait
                ? 26
                : 30
        ) +
        extraLines *
            (
                portrait
                    ? 3
                    : 3
            );

    const topOpticalCompensation =
        portrait
            ? 11
            : 13;

    const topGap =
        bottomGap +
        topOpticalCompensation;

    const topY =
        nameTopY +
        topGap;

    const bottomY =
        nameBottomY -
        bottomGap;

    const topHalfWidth =
        portrait
            ? 48
            : 58;

    const bottomHalfWidth =
        portrait
            ? 86
            : 104;

    noFill();

    stroke(
        214,
        142,
        68,
        alpha * 0.38
    );

    strokeWidth(1.2);

    line(
        textX -
            topHalfWidth,
        topY,
        textX - 10,
        topY
    );

    line(
        textX + 10,
        topY,
        textX +
            topHalfWidth,
        topY
    );

    line(
        textX -
            bottomHalfWidth,
        bottomY,
        textX +
            bottomHalfWidth,
        bottomY
    );

    noStroke();

    fill(
        238,
        186,
        98,
        alpha * 0.48
    );

    pushMatrix();

    translate(
        textX,
        topY
    );

    rotate(45);

    rectMode(CENTER);

    rect(
        0,
        0,
        5,
        5,
        1
    );

    popMatrix();

    fill(
        238,
        186,
        98,
        alpha * 0.28
    );

    ellipse(
        textX -
            bottomHalfWidth -
            10,
        bottomY,
        2.6
    );

    ellipse(
        textX +
            bottomHalfWidth +
            10,
        bottomY,
        2.6
    );

    rectMode(CORNER);
}

function drawResultLetterpressText(
    value,
    x,
    y,
    alpha
) {
    textAlign(CENTER);

    fill(
        40,
        19,
        11,
        alpha * 0.78
    );

    text(
        value,
        x + 0.9,
        y - 1.15
    );

    fill(
        255,
        246,
        220,
        alpha * 0.20
    );

    text(
        value,
        x - 0.55,
        y + 0.72
    );

    fill(
        255,
        225,
        165,
        alpha
    );

    text(
        value,
        x,
        y
    );
}


function drawResultRestartButtonAccent(
    button,
    alpha
) {
    noFill();

    stroke(
        233,
        178,
        104,
        alpha * 0.34
    );

    strokeWidth(1.2);

    rect(
        button.x + 6,
        button.y + 6,
        button.w - 12,
        button.h - 12,
        8
    );

    stroke(
        255,
        225,
        176,
        alpha * 0.22
    );

    strokeWidth(1);

    line(
        button.x + 16,
        button.y +
            button.h - 11,
        button.x +
            button.w - 16,
        button.y +
            button.h - 11
    );

    noStroke();

    fill(
        246,
        197,
        126,
        alpha * 0.24
    );

    ellipse(
        button.x + 15,
        button.y +
            button.h * 0.5,
        3
    );

    ellipse(
        button.x +
            button.w - 15,
        button.y +
            button.h * 0.5,
        3
    );
}

function drawResultHeaderClean(
    alpha
) {
    /*
     * 上端とタイトルの間に少し余白を作り、
     * 結果カードのロゴとして控えめな大きさにする。
     */
    const headerY =
        HEIGHT - 52;

    const headerFontSize =
        Math.min(
            17,
            WIDTH * 0.043
        );

    const cardMargin =
        14;

    const maskX =
        cardMargin + 9;

    const maskW =
        WIDTH -
        (
            cardMargin +
            9
        ) *
            2;

    rectMode(CORNER);
    noStroke();

    /*
     * 元の大きな見出しと横線を覆う範囲。
     */
    fill(
        35,
        18,
        12,
        alpha
    );

    rect(
        maskX,
        headerY - 25,
        maskW,
        50,
        4
    );

    if (
        typeof setGameTitleFont ===
        "function"
    ) {
        setGameTitleFont();
    }

    const centerX =
        WIDTH * 0.5;

    const titleHalfWidth =
        headerFontSize *
        3.45;

    const titleGap =
        11;

    /*
     * ロゴ縮小に合わせて横線も短くする。
     */
    const lineWidth =
        Math.min(
            58,
            WIDTH * 0.135
        );

    const leftLineEnd =
        centerX -
        titleHalfWidth -
        titleGap;

    const rightLineStart =
        centerX +
        titleHalfWidth +
        titleGap;

    const leftLineStart =
        Math.max(
            cardMargin + 54,
            leftLineEnd -
                lineWidth
        );

    const rightLineEnd =
        Math.min(
            WIDTH -
                cardMargin -
                54,
            rightLineStart +
                lineWidth
        );

    stroke(
        174,
        101,
        45,
        alpha * 0.68
    );

    strokeWidth(1.4);

    if (
        leftLineEnd >
        leftLineStart
    ) {
        line(
            leftLineStart,
            headerY,
            leftLineEnd,
            headerY
        );
    }

    if (
        rightLineEnd >
        rightLineStart
    ) {
        line(
            rightLineStart,
            headerY,
            rightLineEnd,
            headerY
        );
    }

    noStroke();

    fill(
        232,
        167,
        73,
        alpha * 0.92
    );

    fontSize(
        headerFontSize
    );

    textAlign(CENTER);

    text(
        "MIDNIGHT COLA",
        centerX,
        headerY
    );

    rectMode(CORNER);
}



function drawResultScreenRefinements() {
    const reveal =
        gameState.resultReveal;

    const alpha =
        reveal
            ? reveal.alpha
            : 255;

    const scaleValue =
        reveal
            ? reveal.scale
            : 1;

    const portrait =
        HEIGHT > WIDTH;

    let textX;
    let nameY;
    let nameMaskW;

    if (portrait) {
        textX =
            WIDTH * 0.5;

        nameY =
            HEIGHT * 0.365;

        nameMaskW =
            WIDTH - 58;
    } else {
        textX =
            WIDTH * 0.72;

        nameY =
            HEIGHT * 0.66;

        nameMaskW =
            WIDTH * 0.46;
    }

    const resultName =
        generateResultName();

    const nameLines =
        splitResultName(
            resultName
        );

    const nameGap =
        portrait
            ? 26
            : 31;

    const nameFontSize =
        portrait
            ? Math.min(
                27,
                WIDTH * 0.066
            )
            : Math.min(
                34,
                WIDTH * 0.041
            );

    const nameStartY =
        nameY +
        (
            nameLines.length -
            1
        ) *
        nameGap *
        0.5;

    const nameMaskH =
        nameFontSize +
        (
            nameLines.length -
            1
        ) *
            nameGap +
        22;

    const button =
        getResultRestartButtonRect();

    pushMatrix();

    translate(
        WIDTH * 0.5,
        HEIGHT * 0.5
    );

    scale(
        scaleValue,
        scaleValue
    );

    translate(
        -WIDTH * 0.5,
        -HEIGHT * 0.5
    );

    /*
     * 上部見出しだけ整える。
     * 結果名に別の札や枠は付けない。
     */
    drawResultHeaderClean(
        alpha
    );

    /*
     * 上側のコーナー装飾は、
     * 見出しを整える背景マスクによって
     * 縦線部分が隠れ、短い横線だけが残っていた。
     *
     * 下側と同じ模様を、見出しの描画後に
     * 上下反転して描き直す。
     */
    const resultCardCornerMargin =
        14;

    drawResultCornerMark(
        resultCardCornerMargin + 11,
        HEIGHT -
            resultCardCornerMargin -
            11,
        1,
        -1,
        alpha
    );

    drawResultCornerMark(
        WIDTH -
            resultCardCornerMargin -
            11,
        HEIGHT -
            resultCardCornerMargin -
            11,
        -1,
        -1,
        alpha
    );

    /*
     * 既存の文字を静かに消すための
     * 最小限の背景マスク。
     */
    rectMode(CENTER);
    noStroke();

    fill(
        35,
        18,
        12,
        alpha
    );

    rect(
        textX,
        nameY,
        nameMaskW,
        nameMaskH,
        4
    );

    /*
     * 結果名は文字そのものを主役にする。
     */
    drawResultNameOrnaments(
        textX,
        nameY,
        portrait,
        nameLines,
        alpha
    );

    setGameTitleFont();

    fontSize(
        nameFontSize
    );

    textAlign(CENTER);

    for (
        let index = 0;
        index <
            nameLines.length;
        index += 1
    ) {
        drawResultLetterpressText(
            nameLines[
                index
            ],
            textX,
            nameStartY -
                index *
                    nameGap,
            alpha
        );
    }

    /*
     * ボタンは既存のまま、
     * 内側の細い線だけ活かす。
     */
    drawResultRestartButtonAccent(
        button,
        alpha
    );

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);

    popMatrix();
}


/*
 * 結果画面の後付け表示を受けるための拡張口。
 *
 * 初期状態では何も描かない。
 * 補充完了など、結果画面の外側にある機能だけが
 * ここへ必要な表示を追加する。
 */
function drawResultScreenPostDraw() {
    /*
     * 結果画面の共有用UI。
     * captureMode中は内部で自動的に非表示になる。
     */
    colaRollDrawResultRecordUI();
}


/*
 * ============================================================
 * 結果記録スタンプ
 * ============================================================
 *
 * 結果画面の右下に小さな記録スタンプを置く。
 *
 * タップ:
 *   COPY  /  SHARE  /  SAVE
 *
 * 画像生成時だけこのUIを隠し、
 * 現在の結果画面CanvasをそのままPNG化する。
 */

function colaRollEnsureResultRecordState() {
    if (!gameState) {
        return null;
    }

    if (!gameState.resultRecord) {
        gameState.resultRecord = {
            open: false,
            captureMode: false,

            stampPulse: 0,
            stampPressedAt: -999,

            status: "",
            statusUntil: 0,

            busy: false,
        };
    }

    return gameState.resultRecord;
}


function colaRollResultRecordNow() {
    return typeof ElapsedTime ===
        "number"
        ? ElapsedTime
        : Date.now() / 1000;
}


function colaRollResultRecordHit(
    touch,
    rect
) {
    return !!(
        touch &&
        rect &&
        touch.x >= rect.x &&
        touch.x <= rect.x + rect.w &&
        touch.y >= rect.y &&
        touch.y <= rect.y + rect.h
    );
}


function colaRollGetResultRecordStampRect() {
    const button =
        getResultRestartButtonRect();

    const availableRight =
        WIDTH -
        (
            button.x +
            button.w
        );

    const size =
        Math.min(
            42,
            Math.max(
                34,
                availableRight - 18
            )
        );

    /*
     * 縦画面では「補充する」の右側。
     * 右側が狭い横画面では左側へ回す。
     */
    const useRight =
        availableRight >=
        size + 14;

    return {
        x:
            useRight
                ? button.x +
                    button.w +
                    8
                : button.x -
                    size -
                    8,

        y:
            button.y +
            (
                button.h -
                size
            ) *
                0.5,

        w:
            size,

        h:
            size,
    };
}


function colaRollGetResultRecordMenuRect() {
    const button =
        getResultRestartButtonRect();

    const width =
        Math.min(
            button.w,
            260
        );

    return {
        x:
            WIDTH * 0.5 -
            width * 0.5,

        y:
            button.y +
            button.h +
            12,

        w:
            width,

        h:
            42,
    };
}


function colaRollGetResultRecordActionRects() {
    const menu =
        colaRollGetResultRecordMenuRect();

    const gap =
        4;

    const itemWidth =
        (
            menu.w -
            gap * 2
        ) /
        3;

    return {
        copy: {
            x:
                menu.x,

            y:
                menu.y,

            w:
                itemWidth,

            h:
                menu.h,
        },

        share: {
            x:
                menu.x +
                itemWidth +
                gap,

            y:
                menu.y,

            w:
                itemWidth,

            h:
                menu.h,
        },

        save: {
            x:
                menu.x +
                (
                    itemWidth +
                    gap
                ) *
                    2,

            y:
                menu.y,

            w:
                itemWidth,

            h:
                menu.h,
        },
    };
}


function colaRollResultRecordWords(
    key
) {
    const english =
        gameState &&
        gameState.language === "en";

    const ja = {
        stamp: "記録",
        copy: "コピー",
        share: "共有",
        save: "保存",

        copied: "記録をコピーしました",
        shared: "共有画面を開きました",
        saved: "画像を保存しました",
        failed: "記録できませんでした",
        preparing: "記録を準備しています",
    };

    const en = {
        stamp: "LOG",
        copy: "COPY",
        share: "SHARE",
        save: "SAVE",

        copied: "RECORD COPIED",
        shared: "SHARE SHEET OPENED",
        saved: "IMAGE SAVED",
        failed: "COULD NOT RECORD",
        preparing: "PREPARING RECORD",
    };

    return (
        english
            ? en[key]
            : ja[key]
    ) || "";
}


function colaRollShowResultRecordStatus(
    status,
    duration
) {
    const state =
        colaRollEnsureResultRecordState();

    if (!state) {
        return;
    }

    state.status =
        status || "";

    state.statusUntil =
        colaRollResultRecordNow() +
        (
            typeof duration ===
            "number"
                ? duration
                : 1.4
        );
}


function colaRollBuildResultShareText() {
    const name =
        typeof generateResultName ===
            "function"
            ? String(
                generateResultName() ||
                ""
            ).trim()
            : "";

    const description =
        typeof generateResultDescription ===
            "function"
            ? String(
                generateResultDescription() ||
                ""
            ).trim()
            : "";

    if (
        gameState &&
        gameState.language === "en"
    ) {
        return (
            name +
            (
                description
                    ? "\n" +
                        description
                    : ""
            ) +
            "\n\n#MidnightCola"
        );
    }

    return (
        "『" +
        name +
        "』" +
        (
            description
                ? "\n" +
                    description
                : ""
        ) +
        "\n\n#真夜中コーラ"
    );
}


function colaRollFallbackCopyText(
    value
) {
    if (
        typeof document ===
        "undefined"
    ) {
        return false;
    }

    const area =
        document.createElement(
            "textarea"
        );

    area.value =
        value;

    area.setAttribute(
        "readonly",
        ""
    );

    area.style.position =
        "fixed";

    area.style.left =
        "-9999px";

    area.style.top =
        "0";

    document.body.appendChild(
        area
    );

    area.focus();
    area.select();

    let copied =
        false;

    try {
        copied =
            document.execCommand(
                "copy"
            );
    } catch (error) {
        copied =
            false;
    }

    document.body.removeChild(
        area
    );

    return copied;
}


function colaRollCopyResultRecord() {
    const value =
        colaRollBuildResultShareText();

    if (
        typeof navigator !==
            "undefined" &&
        navigator.clipboard &&
        typeof navigator.clipboard.writeText ===
            "function"
    ) {
        navigator.clipboard.writeText(
            value
        ).then(
            function() {
                colaRollShowResultRecordStatus(
                    colaRollResultRecordWords(
                        "copied"
                    )
                );
            }
        ).catch(
            function() {
                const copied =
                    colaRollFallbackCopyText(
                        value
                    );

                colaRollShowResultRecordStatus(
                    colaRollResultRecordWords(
                        copied
                            ? "copied"
                            : "failed"
                    )
                );
            }
        );

        return;
    }

    const copied =
        colaRollFallbackCopyText(
            value
        );

    colaRollShowResultRecordStatus(
        colaRollResultRecordWords(
            copied
                ? "copied"
                : "failed"
        )
    );
}


function colaRollGetMainResultCanvas() {
    if (
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx &&
        CodeaLite.state.ctx.canvas
    ) {
        return CodeaLite.state.ctx.canvas;
    }

    if (
        typeof document !==
        "undefined"
    ) {
        return (
            document.getElementById(
                "screen"
            ) ||
            document.querySelector(
                "canvas"
            )
        );
    }

    return null;
}


function colaRollRenderCleanResultForCapture() {
    const state =
        colaRollEnsureResultRecordState();

    if (!state) {
        return;
    }

    state.captureMode =
        true;

    /*
     * 結果画面だけを同じCanvasへ描き直す。
     * captureMode中は記録UIを描かない。
     */
    if (
        typeof drawResultScreen ===
        "function"
    ) {
        drawResultScreen();
    }
}


function colaRollRestoreResultAfterCapture() {
    const state =
        colaRollEnsureResultRecordState();

    if (!state) {
        return;
    }

    state.captureMode =
        false;

    if (
        typeof drawResultScreen ===
        "function"
    ) {
        drawResultScreen();
    }
}


function colaRollDataUrlToBlob(
    dataUrl
) {
    const parts =
        String(
            dataUrl || ""
        ).split(
            ","
        );

    if (parts.length < 2) {
        return null;
    }

    const mimeMatch =
        parts[0].match(
            /data:([^;]+)/
        );

    const mime =
        mimeMatch
            ? mimeMatch[1]
            : "image/png";

    const binary =
        atob(
            parts[1]
        );

    const bytes =
        new Uint8Array(
            binary.length
        );

    for (
        let index = 0;
        index < binary.length;
        index += 1
    ) {
        bytes[index] =
            binary.charCodeAt(
                index
            );
    }

    return new Blob(
        [bytes],
        {
            type: mime,
        }
    );
}

/*
 * 工房側へ到着する空瓶を描く。
 *
 * 本編の検品ボトルと同じ座標・形状へ着地するため、
 * 演出終了時に既存の瓶と完全に重なる。
 */
function colaRollDrawFactoryLiftBottle(
    fade,
    progress
) {
    if (
        !fade ||
        typeof getBottleInspectionGeometry !==
            "function"
    ) {
        return;
    }

    const geometry =
        getBottleInspectionGeometry();

    const context =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    if (!context) {
        return;
    }

    /*
     * 暗転中に床下から上がり始め、
     * 画面が見えるころには台の近くへ到着する。
     */
    const riseRaw =
        colaRollDispatchClamp(
            (
                progress -
                0.08
            ) /
                0.70
        );

    const riseEase =
        1 -
        Math.pow(
            1 - riseRaw,
            3
        );

    fade.bottleRiseProgress =
        riseEase;

    const startOffset =
        Math.max(
            geometry.panel.h * 0.72,
            190
        );

    /*
     * 目標位置を少しだけ上へ通り越し、
     * そのあと下へ戻って「コツン」と着地する。
     *
     * Codea座標では +Y が上なので、
     * 前半は正方向へオーバーシュートさせる。
     */
    let landingOffset =
        0;

    if (riseRaw > 0.72) {
        const local =
            colaRollDispatchClamp(
                (
                    riseRaw -
                    0.72
                ) /
                    0.28
            );

        if (local < 0.58) {
            /*
             * 少し上へ行きすぎる。
             */
            const upProgress =
                local / 0.58;

            landingOffset =
                Math.sin(
                    upProgress *
                    Math.PI *
                    0.5
                ) *
                4.2;
        } else {
            /*
             * 行きすぎた位置から、
             * 台へ向かって下へ戻る。
             */
            const downProgress =
                (
                    local -
                    0.58
                ) /
                0.42;

            landingOffset =
                4.2 *
                (
                    1 -
                    downProgress
                );
        }
    }

    const bottleY =
        geometry.centerY -
        startOffset *
            (
                1 -
                riseEase
            ) +
        landingOffset;

    /*
     * 暗転が濃い間から瓶だけが少し見え、
     * 上昇するにつれて輪郭が現れる。
     */
    const bottleAlpha =
        colaRollDispatchClamp(
            riseRaw / 0.28
        );

    /*
     * 到着時の接地影。
     */
    const contactProgress =
        colaRollDispatchClamp(
            (
                riseRaw -
                0.66
            ) /
                0.34
        );

    context.save();

    context.translate(
        geometry.centerX,
        geometry.centerY +
        (
            geometry.bodyBottom -
            1
        ) *
            geometry.scale
    );

    context.scale(
        1,
        0.18
    );

    context.beginPath();

    context.arc(
        0,
        0,
        geometry.bodyWidth *
            geometry.scale *
            (
                0.28 +
                contactProgress *
                    0.22
            ),
        0,
        Math.PI * 2
    );

    context.fillStyle =
        "rgba(3, 2, 2, " +
        String(
            0.58 *
            contactProgress
        ) +
        ")";

    context.fill();

    context.restore();

    /*
     * 上昇中の空瓶。
     */
    context.save();

    context.translate(
        geometry.centerX,
        bottleY
    );

    context.scale(
        geometry.scale,
        geometry.scale
    );

    context.globalAlpha *=
        bottleAlpha;

    context.save();

    traceInspectionBottleVectorPath(
        context,
        geometry,
        -4
    );

    context.translate(
        5,
        -8
    );

    context.fillStyle =
        "rgba(5, 3, 2, 0.42)";

    context.fill();

    context.restore();

    context.save();

    traceInspectionBottleVectorPath(
        context,
        geometry,
        0
    );

    context.fillStyle =
        "rgba(32, 20, 14, 0.94)";

    context.strokeStyle =
        "rgba(225, 207, 174, 0.58)";

    context.lineWidth =
        3;

    context.fill();
    context.stroke();

    context.restore();

    context.save();

    traceInspectionBottleVectorPath(
        context,
        geometry,
        6
    );

    context.fillStyle =
        "rgba(92, 57, 31, 0.38)";

    context.fill();

    context.restore();

    drawInspectionBottleVectorHighlights(
        context,
        geometry
    );

    /*
     * 着地直前だけ輪郭を静かに光らせる。
     */
    if (contactProgress > 0.001) {
        context.save();

        traceInspectionBottleVectorPath(
            context,
            geometry,
            1
        );

        context.strokeStyle =
            "rgba(255, 222, 157, " +
            String(
                0.26 *
                Math.sin(
                    contactProgress *
                    Math.PI
                )
            ) +
            ")";

        context.lineWidth =
            3.4;

        context.shadowColor =
            "rgba(255, 184, 92, 0.34)";

        context.shadowBlur =
            9;

        context.stroke();

        context.restore();
    }

    context.restore();

    /*
     * 一度だけ小さな着地音。
     */
    if (
        riseRaw >= 0.82 &&
        !fade.landingSoundPlayed
    ) {
        fade.landingSoundPlayed =
            true;

        if (
            typeof colaRollPlaySound ===
                "function"
        ) {
            colaRollPlaySound(
                "delivery_setdown",
                {
                    volume: 0.22,
                    playbackRate: 0.92,
                    cooldown: 0,
                }
            );
        }
    }
}



function colaRollCreateResultImageFile() {
    const canvas =
        colaRollGetMainResultCanvas();

    if (!canvas) {
        return null;
    }

    const state =
        colaRollEnsureResultRecordState();

    if (!state) {
        return null;
    }

    const wasOpen =
        state.open;

    /*
     * メニューとスタンプを隠した状態で
     * Canvasを同期的に取り込む。
     */
    colaRollRenderCleanResultForCapture();

    let dataUrl =
        "";

    try {
        dataUrl =
            canvas.toDataURL(
                "image/png"
            );
    } catch (error) {
        dataUrl =
            "";
    }

    colaRollRestoreResultAfterCapture();

    state.open =
        wasOpen;

    if (!dataUrl) {
        return null;
    }

    const blob =
        colaRollDataUrlToBlob(
            dataUrl
        );

    if (!blob) {
        return null;
    }

    const date =
        new Date();

    const pad =
        function(value) {
            return String(
                value
            ).padStart(
                2,
                "0"
            );
        };

    const fileName =
        "midnight-cola-" +
        String(
            date.getFullYear()
        ) +
        pad(
            date.getMonth() + 1
        ) +
        pad(
            date.getDate()
        ) +
        "-" +
        pad(
            date.getHours()
        ) +
        pad(
            date.getMinutes()
        ) +
        ".png";

    if (
        typeof File ===
        "function"
    ) {
        return new File(
            [blob],
            fileName,
            {
                type: "image/png",
            }
        );
    }

    blob.name =
        fileName;

    return blob;
}


function colaRollSaveResultImage() {
    const state =
        colaRollEnsureResultRecordState();

    if (
        !state ||
        state.busy
    ) {
        return;
    }

    state.busy =
        true;

    colaRollShowResultRecordStatus(
        colaRollResultRecordWords(
            "preparing"
        ),
        1
    );

    const file =
        colaRollCreateResultImageFile();

    state.busy =
        false;

    if (
        !file ||
        typeof document ===
            "undefined" ||
        typeof URL ===
            "undefined"
    ) {
        colaRollShowResultRecordStatus(
            colaRollResultRecordWords(
                "failed"
            )
        );

        return;
    }

    const url =
        URL.createObjectURL(
            file
        );

    const anchor =
        document.createElement(
            "a"
        );

    anchor.href =
        url;

    anchor.download =
        file.name ||
        "midnight-cola.png";

    anchor.rel =
        "noopener";

    document.body.appendChild(
        anchor
    );

    anchor.click();

    document.body.removeChild(
        anchor
    );

    setTimeout(
        function() {
            URL.revokeObjectURL(
                url
            );
        },
        1200
    );

    colaRollShowResultRecordStatus(
        colaRollResultRecordWords(
            "saved"
        )
    );
}


function colaRollShareResultRecord() {
    const state =
        colaRollEnsureResultRecordState();

    if (
        !state ||
        state.busy
    ) {
        return;
    }

    state.busy =
        true;

    const shareText =
        colaRollBuildResultShareText();

    const file =
        colaRollCreateResultImageFile();

    const shareData = {
        text:
            shareText,
    };

    let canShareFile =
        false;

    if (
        file &&
        typeof navigator !==
            "undefined" &&
        typeof navigator.canShare ===
            "function"
    ) {
        try {
            canShareFile =
                navigator.canShare(
                    {
                        files: [file],
                    }
                );
        } catch (error) {
            canShareFile =
                false;
        }
    }

    if (canShareFile) {
        shareData.files =
            [file];
    }

    if (
        typeof navigator !==
            "undefined" &&
        typeof navigator.share ===
            "function"
    ) {
        /*
         * ユーザー操作の同一イベント内で
         * share()を呼び出す。
         */
        navigator.share(
            shareData
        ).then(
            function() {
                state.busy =
                    false;

                colaRollShowResultRecordStatus(
                    colaRollResultRecordWords(
                        "shared"
                    )
                );
            }
        ).catch(
            function(error) {
                state.busy =
                    false;

                /*
                 * 共有画面を閉じただけなら、
                 * エラー表示は出さない。
                 */
                if (
                    error &&
                    error.name ===
                        "AbortError"
                ) {
                    return;
                }

                colaRollCopyResultRecord();
            }
        );

        return;
    }

    state.busy =
        false;

    /*
     * Web Share APIがない場合は、
     * テキストコピーへ切り替える。
     */
    colaRollCopyResultRecord();
}


function colaRollPlayResultStampSound() {
    if (
        typeof colaRollPlaySound ===
        "function"
    ) {
        colaRollPlaySound(
            "delivery_setdown",
            {
                volume: 0.28,
                playbackRate: 1.08,
                cooldown: 0,
            }
        );
    }
}


function colaRollDrawResultRecordStamp() {
    if (
        !gameState ||
        gameState.phase !== "RESULT"
    ) {
        return;
    }

    const state =
        colaRollEnsureResultRecordState();

    if (
        !state ||
        state.captureMode
    ) {
        return;
    }

    /*
     * 描画関数 rect() と衝突しないよう、
     * 当たり判定用の矩形は stampRect とする。
     */
    const stampRect =
        colaRollGetResultRecordStampRect();

    const now =
        colaRollResultRecordNow();

    const pressedElapsed =
        Math.max(
            0,
            now -
            state.stampPressedAt
        );

    const press =
        Math.max(
            0,
            1 -
            pressedElapsed /
                0.24
        );

    const pulse =
        0.5 +
        Math.sin(
            now * 2.8
        ) *
            0.5;

    pushMatrix();

    translate(
        stampRect.x +
            stampRect.w * 0.5,
        stampRect.y +
            stampRect.h * 0.5
    );

    scale(
        1 -
            press * 0.08,
        1 -
            press * 0.08
    );

    rectMode(CENTER);

    noStroke();

    fill(
        28,
        15,
        11,
        226
    );

    rect(
        0,
        -2,
        stampRect.w,
        stampRect.h,
        7
    );

    noFill();

    stroke(
        state.open
            ? 230
            : 167,
        state.open
            ? 153
            : 101,
        state.open
            ? 72
            : 53,
        state.open
            ? 240
            : 178 +
                pulse * 22
    );

    strokeWidth(
        state.open
            ? 2
            : 1.25
    );

    rect(
        0,
        0,
        stampRect.w - 2,
        stampRect.h - 2,
        7
    );

    /*
     * 少しかすれた二重枠で
     * ゴム印らしさを出す。
     */
    stroke(
        205,
        126,
        59,
        state.open
            ? 180
            : 92
    );

    strokeWidth(0.8);

    rect(
        0,
        0,
        stampRect.w - 9,
        stampRect.h - 9,
        4
    );

    noStroke();

    setGameUIFont();

    fill(
        state.open
            ? 244
            : 206,
        state.open
            ? 183
            : 137,
        state.open
            ? 105
            : 76,
        235
    );

    fontSize(
        Math.min(
            10.5,
            stampRect.w * 0.27
        )
    );

    textAlign(CENTER);

    text(
        colaRollResultRecordWords(
            "stamp"
        ),
        0,
        -0.5
    );

    popMatrix();

    rectMode(CORNER);
    noStroke();
}



function colaRollDrawResultRecordMenu() {
    const state =
        colaRollEnsureResultRecordState();

    if (
        !state ||
        !state.open ||
        state.captureMode
    ) {
        return;
    }

    const actions =
        colaRollGetResultRecordActionRects();

    const items = [
        {
            rect:
                actions.copy,

            key:
                "copy",
        },
        {
            rect:
                actions.share,

            key:
                "share",
        },
        {
            rect:
                actions.save,

            key:
                "save",
        },
    ];

    rectMode(CORNER);
    setGameUIFont();
    textAlign(CENTER);

    for (
        const item of items
    ) {
        noStroke();

        fill(
            38,
            21,
            15,
            238
        );

        rect(
            item.rect.x,
            item.rect.y,
            item.rect.w,
            item.rect.h,
            7
        );

        noFill();

        stroke(
            151,
            93,
            52,
            195
        );

        strokeWidth(1);

        rect(
            item.rect.x + 0.5,
            item.rect.y + 0.5,
            item.rect.w - 1,
            item.rect.h - 1,
            7
        );

        noStroke();

        fill(
            230,
            184,
            119,
            235
        );

        fontSize(
            Math.min(
                10.5,
                item.rect.w * 0.18
            )
        );

        text(
            colaRollResultRecordWords(
                item.key
            ),
            item.rect.x +
                item.rect.w * 0.5,
            item.rect.y +
                item.rect.h * 0.5 -
                0.5
        );
    }

    const now =
        colaRollResultRecordNow();

    if (
        state.status &&
        now <
            state.statusUntil
    ) {
        const menu =
            colaRollGetResultRecordMenuRect();

        fill(
            223,
            190,
            145,
            218
        );

        fontSize(
            Math.min(
                10,
                WIDTH * 0.027
            )
        );

        text(
            state.status,
            menu.x +
                menu.w * 0.5,
            menu.y +
                menu.h +
                15
        );
    }

    noStroke();
    rectMode(CORNER);
}


function colaRollDrawResultRecordUI() {
    const state =
        colaRollEnsureResultRecordState();

    if (
        !state ||
        state.captureMode
    ) {
        return;
    }

    colaRollDrawResultRecordStamp();
    colaRollDrawResultRecordMenu();
}


function colaRollHandleResultRecordTouch(
    touch
) {
    if (
        !gameState ||
        gameState.phase !== "RESULT" ||
        !touch ||
        touch.state !== ENDED
    ) {
        return false;
    }

    const state =
        colaRollEnsureResultRecordState();

    if (!state) {
        return false;
    }

    const stamp =
        colaRollGetResultRecordStampRect();

    if (
        colaRollResultRecordHit(
            touch,
            stamp
        )
    ) {
        state.open =
            !state.open;

        state.stampPressedAt =
            colaRollResultRecordNow();

        colaRollPlayResultStampSound();

        return true;
    }

    if (!state.open) {
        return false;
    }

    const actions =
        colaRollGetResultRecordActionRects();

    if (
        colaRollResultRecordHit(
            touch,
            actions.copy
        )
    ) {
        state.stampPressedAt =
            colaRollResultRecordNow();

        colaRollPlayResultStampSound();
        colaRollCopyResultRecord();

        return true;
    }

    if (
        colaRollResultRecordHit(
            touch,
            actions.share
        )
    ) {
        state.stampPressedAt =
            colaRollResultRecordNow();

        colaRollPlayResultStampSound();
        colaRollShareResultRecord();

        return true;
    }

    if (
        colaRollResultRecordHit(
            touch,
            actions.save
        )
    ) {
        state.stampPressedAt =
            colaRollResultRecordNow();

        colaRollPlayResultStampSound();
        colaRollSaveResultImage();

        return true;
    }

    /*
     * メニュー外を押した場合は閉じる。
     * 背後の結果画面には入力を渡さない。
     */
    state.open =
        false;

    return true;
}




/*
 * ------------------------------------------------------------
 * 工房メモ
 * ------------------------------------------------------------
 *
 * 結果画面の下端から、古いメモ用紙の端を少しだけ見せる。
 * タップすると今回の仕込みに関係する短いメモが開く。
 */

function colaRollEnsureWorkshopMemoState() {
    if (!gameState) {
        return null;
    }

    const result =
        gameState.resultData || null;

    if (!gameState.workshopMemo) {
        gameState.workshopMemo = {
            open: false,
            progress: 0,
            targetProgress: 0,
            sourceResult: result,
            memoKey: "",
        };
    }

    const memo =
        gameState.workshopMemo;

    /*
     * 別の一本の結果へ移った場合は、
     * 閉じた状態から始める。
     */
    if (
        memo.sourceResult !==
        result
    ) {
        memo.open = false;
        memo.progress = 0;
        memo.targetProgress = 0;
        memo.sourceResult = result;
        memo.memoKey = "";
    }

    return memo;
}


function colaRollWorkshopMemoClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}


function colaRollWorkshopMemoEase(
    value
) {
    const t =
        colaRollWorkshopMemoClamp(
            value
        );

    return (
        t *
        t *
        (
            3 -
            2 * t
        )
    );
}


function colaRollUpdateWorkshopMemo() {
    const memo =
        colaRollEnsureWorkshopMemoState();

    if (!memo) {
        return;
    }

    /*
     * 紙が少し重さを持って動く程度の、
     * 穏やかな追従。
     */
    const speed =
        memo.targetProgress >
        memo.progress
            ? 7.8
            : 9.2;

    const difference =
        memo.targetProgress -
        memo.progress;

    memo.progress +=
        difference *
        Math.min(
            1,
            DeltaTime * speed
        );

    if (
        Math.abs(
            difference
        ) < 0.002
    ) {
        memo.progress =
            memo.targetProgress;
    }
}


function colaRollGetWorkshopMemoLayout() {
    const portrait =
        HEIGHT >= WIDTH;

    const historyLink =
        typeof deliveryHistoryLinkRect ===
        "function"
            ? deliveryHistoryLinkRect()
            : {
                x: WIDTH * 0.25,
                y: 76,
                w: WIDTH * 0.5,
                h: 30,
            };

    const paperWidth =
        Math.min(
            portrait
                ? WIDTH * 0.78
                : WIDTH * 0.46,
            390
        );

    const paperHeight =
        portrait
            ? Math.min(
                142,
                HEIGHT * 0.18
            )
            : Math.min(
                126,
                HEIGHT * 0.27
            );

    const tabHeight =
        25;

    /*
     * 説明文と「最近の瓶詰めを見る」の間に、
     * 紙の上端だけを見せる。
     */
    const tabBottomY =
        historyLink.y +
        historyLink.h +
        8;

    /*
     * 閉じた状態では上端25pxだけ表示。
     */
    const closedY =
        tabBottomY -
        paperHeight +
        tabHeight;

    /*
     * 開くと、その場所を起点に上へ紙が現れる。
     */
    const openY =
        tabBottomY;

    return {
        x:
            WIDTH * 0.5 -
            paperWidth * 0.5,

        closedY:
            closedY,

        openY:
            openY,

        w:
            paperWidth,

        h:
            paperHeight,

        tabH:
            tabHeight,
    };
}



function colaRollWorkshopMemoHit(
    touch,
    rect
) {
    return !!(
        touch &&
        rect &&
        touch.x >= rect.x &&
        touch.x <=
            rect.x + rect.w &&
        touch.y >= rect.y &&
        touch.y <=
            rect.y + rect.h
    );
}


function colaRollGetWorkshopMemoText() {
    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : {};

    const language =
        gameState &&
        gameState.language === "en"
            ? "en"
            : "ja";

    function ingredientName(
        ingredientId
    ) {
        const ingredient =
            ingredientId &&
            INGREDIENTS
                ? INGREDIENTS[
                    ingredientId
                ]
                : null;

        if (!ingredient) {
            return language === "en"
                ? "the main ingredient"
                : "主な材料";
        }

        if (language === "en") {
            return (
                ingredient.en ||
                ingredient.ja ||
                "the main ingredient"
            );
        }

        return (
            ingredient.ja ||
            ingredient.en ||
            "主な材料"
        );
    }

    function getLastIngredientId() {
        const ids =
            Array.isArray(
                result.ingredientIds
            )
                ? result.ingredientIds
                : [];

        for (
            let index =
                ids.length - 1;
            index >= 0;
            index -= 1
        ) {
            const ingredientId =
                ids[index];

            if (
                ingredientId &&
                ingredientId !== "ice" &&
                ingredientId !==
                    "carbonation"
            ) {
                return ingredientId;
            }
        }

        return null;
    }

    const topIngredientId =
        result.topIngredientId ||
        null;

    const topName =
        ingredientName(
            topIngredientId
        );

    const lastIngredientId =
        getLastIngredientId();

    const lastName =
        ingredientName(
            lastIngredientId
        );

    const spilledCount =
        Number(
            result.spilledCount || 0
        );

    const merged =
        !!result.hasMergedBand ||
        Number(
            result.mergedBandCount || 0
        ) > 0 ||
        Number(
            result.stirCount || 0
        ) > 0;

    const carbonation =
        Number(
            result.carbonation || 0
        );

    const chill =
        Math.max(
            Number(
                result.chill || 0
            ),
            Number(
                result.chillCount || 0
            )
        );

    const sweetness =
        Number(
            result.sweetness || 0
        );

    const spice =
        Number(
            result.spice || 0
        );

    let body;

    /*
     * 1行目：今回起きたこと
     * 2行目：結果への影響
     *
     * 補充先の雰囲気文は入れず、
     * 仕込み結果だけを説明する。
     */
    if (spilledCount > 0) {
        body =
            language === "en"
                ? (
                    "Some of the upper ingredients spilled out.\n" +
                    "The remaining balance changed, making " +
                    topName +
                    " stand out more."
                )
                : (
                    "上にあった材料が少しこぼれた。\n" +
                    "残った材料の比率が変わり、" +
                    topName +
                    "が強く出ている。"
                );
    } else if (merged) {
        body =
            language === "en"
                ? (
                    topName +
                    " blended with a neighboring layer.\n" +
                    "That combination remains in the name and aroma."
                )
                : (
                    topName +
                    "が、隣り合う材料と混ざった。\n" +
                    "その組み合わせが、名前と香りに残っている。"
                );
    } else if (carbonation <= 0) {
        body =
            language === "en"
                ? (
                    "Almost no carbonation was added this time.\n" +
                    "The sweetness and ingredient flavors come forward instead."
                )
                : (
                    "今回は炭酸がほとんど加わらなかった。\n" +
                    "そのぶん、甘さと材料の味が前に出ている。"
                );
    } else if (carbonation >= 3) {
        body =
            language === "en"
                ? (
                    "This bottle received a strong amount of carbonation.\n" +
                    "The bubbles lift the aroma and make the finish feel lighter."
                )
                : (
                    "今回は炭酸が強く入った。\n" +
                    "泡が香りを持ち上げ、後味を軽くしている。"
                );
    } else if (chill >= 2) {
        body =
            language === "en"
                ? (
                    "Plenty of ice made this a well-chilled bottle.\n" +
                    "The cold makes the sweetness feel quieter."
                )
                : (
                    "氷が多く入り、よく冷えた一本になった。\n" +
                    "冷たさによって、甘さが少し静かに感じられる。"
                );
    } else if (spice >= 3) {
        body =
            language === "en"
                ? (
                    "The spice became one of the strongest parts of this bottle.\n" +
                    "It leaves a clearer aroma and a sharper finish."
                )
                : (
                    "今回はスパイスが強く出た。\n" +
                    "香りの輪郭がはっきりし、後味にも残っている。"
                );
    } else if (sweetness >= 4) {
        body =
            language === "en"
                ? (
                    "This bottle finished with a strong sweetness.\n" +
                    topName +
                    " remains underneath it as the main aroma."
                )
                : (
                    "今回は甘さの強い一本になった。\n" +
                    "その奥に、" +
                    topName +
                    "の香りが残っている。"
                );
    } else if (
        lastIngredientId &&
        lastIngredientId !==
            topIngredientId
    ) {
        body =
            language === "en"
                ? (
                    lastName +
                    " was the final ingredient added.\n" +
                    "Its position at the top changed the first aroma of the bottle."
                )
                : (
                    "最後に加わった材料は" +
                    lastName +
                    "。\n" +
                    "一番上に入ったことで、最初に感じる香りを変えている。"
                );
    } else if (topIngredientId) {
        body =
            language === "en"
                ? (
                    topName +
                    " appeared more often than any other ingredient.\n" +
                    "That is why it remains at the center of the name and aroma."
                )
                : (
                    "今回もっとも多かった材料は" +
                    topName +
                    "。\n" +
                    "そのため、名前と香りの中心にも残っている。"
                );
    } else {
        body =
            language === "en"
                ? (
                    "No single ingredient became dominant this time.\n" +
                    "The bottle finished with a relatively balanced character."
                )
                : (
                    "今回は、特に突出した材料がなかった。\n" +
                    "全体のバランスが近い一本に仕上がっている。"
                );
    }

    return {
        title:
            language === "en"
                ? "WORKSHOP NOTE"
                : "工房メモ",

        body:
            body,
    };
}




function colaRollDrawWorkshopMemoPaperTexture(
    x,
    y,
    width,
    height,
    alpha
) {
    /*
     * 紙の繊維に見える、ごく薄い横線。
     */
    stroke(
        107,
        77,
        47,
        alpha * 0.10
    );

    strokeWidth(0.7);

    for (
        let lineY = y + 18;
        lineY <
            y + height - 12;
        lineY += 11
    ) {
        line(
            x + 13,
            lineY,
            x + width - 13,
            lineY
        );
    }

    noStroke();
}

function colaRollWorkshopMemoWrapLines(
    value,
    language
) {
    const sourceLines =
        String(
            value || ""
        ).split(
            "\n"
        );

    const wrapped = [];

    /*
     * 紙の横幅にはまだ余裕があるため、
     * 日本語は一行27文字前後まで使用する。
     *
     * 以前の20文字では早く折り返しすぎて、
     * 4行制限による省略が発生していた。
     */
    const maxLength =
        language === "en"
            ? 48
            : 27;

    for (
        const sourceLine of
        sourceLines
    ) {
        const normalizedLine =
            String(
                sourceLine || ""
            ).trim();

        if (!normalizedLine) {
            continue;
        }

        if (
            typeof splitResultDescription ===
            "function"
        ) {
            const lines =
                splitResultDescription(
                    normalizedLine,
                    maxLength
                );

            for (
                const line of lines
            ) {
                const normalized =
                    String(
                        line || ""
                    ).trim();

                if (normalized) {
                    wrapped.push(
                        normalized
                    );
                }
            }

            continue;
        }

        let remaining =
            normalizedLine;

        while (
            remaining.length >
            maxLength
        ) {
            wrapped.push(
                remaining.slice(
                    0,
                    maxLength
                )
            );

            remaining =
                remaining.slice(
                    maxLength
                );
        }

        if (remaining) {
            wrapped.push(
                remaining
            );
        }
    }

    /*
     * 今回は紙の横幅を活かすため、
     * 最大5行まで表示する。
     *
     * 5行を超える非常に長い文だけ、
     * 最終行を省略する。
     */
    if (
        wrapped.length >
        5
    ) {
        const limited =
            wrapped.slice(
                0,
                5
            );

        const lastIndex =
            limited.length - 1;

        limited[lastIndex] =
            limited[lastIndex].replace(
                /[。、,.!?！？」』]*$/,
                ""
            ) + "…";

        return limited;
    }

    return wrapped;
}




function colaRollDrawWorkshopMemo() {
    if (
        !gameState ||
        gameState.phase !==
            "DELIVERY_COMPLETE"
    ) {
        return;
    }

    const memo =
        colaRollEnsureWorkshopMemoState();

    if (!memo) {
        return;
    }

    colaRollUpdateWorkshopMemo();

    const layout =
        colaRollGetWorkshopMemoLayout();

    const eased =
        colaRollWorkshopMemoEase(
            memo.progress
        );

    const paperY =
        layout.closedY +
        (
            layout.openY -
            layout.closedY
        ) *
            eased;

    const reveal =
        gameState.resultReveal;

    const resultAlpha =
        reveal
            ? Math.max(
                0,
                Math.min(
                    1,
                    reveal.alpha /
                        255
                )
            )
            : 1;

    if (resultAlpha <= 0.001) {
        return;
    }

    const alpha =
        255 *
        resultAlpha;

    /*
     * 開いたときだけ、
     * 背景へ薄い暗幕を置く。
     */
    if (memo.progress > 0.02) {
        noStroke();

        fill(
            12,
            7,
            5,
            96 *
                eased *
                resultAlpha
        );

        rectMode(CORNER);

        rect(
            0,
            0,
            WIDTH,
            HEIGHT
        );
    }

    pushMatrix();

    /*
     * 紙の下に落ちる影。
     */
    noStroke();

    fill(
        5,
        3,
        2,
        alpha * 0.38
    );

    rectMode(CORNER);

    rect(
        layout.x + 5,
        paperY - 6,
        layout.w,
        layout.h,
        7
    );

    /*
     * 古いメモ用紙。
     */
    fill(
        219,
        198,
        158,
        alpha * 0.98
    );

    rect(
        layout.x,
        paperY,
        layout.w,
        layout.h,
        5
    );

    /*
     * 紙の上辺だけ少し明るくする。
     */
    fill(
        243,
        224,
        184,
        alpha * 0.74
    );

    rect(
        layout.x + 5,
        paperY +
            layout.h - 4,
        layout.w - 10,
        2,
        1
    );

    /*
     * 左右の古びた色むら。
     */
    fill(
        117,
        76,
        42,
        alpha * 0.08
    );

    rect(
        layout.x,
        paperY,
        12,
        layout.h,
        5
    );

    rect(
        layout.x +
            layout.w - 10,
        paperY,
        10,
        layout.h,
        5
    );

    colaRollDrawWorkshopMemoPaperTexture(
        layout.x,
        paperY,
        layout.w,
        layout.h,
        alpha
    );

    const words =
        colaRollGetWorkshopMemoText();

    setGameUIFont();
    textAlign(CENTER);

    /*
     * 閉じている間も見える見出し。
     */
    fill(
        92,
        58,
        34,
        alpha * 0.94
    );

    fontSize(
        Math.min(
            11,
            WIDTH * 0.030
        )
    );

    text(
        words.title,
        layout.x +
            layout.w * 0.5,
        paperY +
            layout.h -
            13
    );

    /*
     * 紙を引き出すための小さな印。
     */
    stroke(
        107,
        68,
        39,
        alpha * 0.55
    );

    strokeWidth(1.1);

    line(
        layout.x +
            layout.w * 0.5 -
            12,
        paperY +
            layout.h -
            4,
        layout.x +
            layout.w * 0.5 +
            12,
        paperY +
            layout.h -
            4
    );

    noStroke();

    /*
     * 本文は紙がほぼ開いてから現れる。
     */
    const bodyReveal =
        colaRollWorkshopMemoClamp(
            (
                memo.progress -
                0.38
            ) /
                0.62
        );

    if (bodyReveal > 0.001) {
        fill(
            67,
            43,
            29,
            alpha *
                bodyReveal *
                0.96
        );

        fontSize(
            Math.min(
                13,
                WIDTH * 0.034
            )
        );

        const language =
            gameState &&
            gameState.language === "en"
                ? "en"
                : "ja";

        const lines =
            colaRollWorkshopMemoWrapLines(
                words.body,
                language
            );

        /*
         * 行数に応じて文字サイズを少し縮める。
         */
        const bodyFontSize =
            lines.length >= 5
                ? Math.min(
                    10.4,
                    WIDTH * 0.027
                )
                : lines.length === 4
                    ? Math.min(
                        11.1,
                        WIDTH * 0.029
                    )
                    : lines.length === 3
                        ? Math.min(
                            11.9,
                            WIDTH * 0.031
                        )
                        : Math.min(
                            13,
                            WIDTH * 0.034
                        );

        fontSize(
            bodyFontSize
        );

        const lineGap =
            lines.length >= 5
                ? Math.min(
                    15.5,
                    layout.h * 0.108
                )
                : lines.length === 4
                    ? Math.min(
                        17.5,
                        layout.h * 0.122
                    )
                    : Math.min(
                        21,
                        layout.h * 0.145
                    );

        /*
         * 見出しと上下の余白を避けた中央へ配置。
         */
        const centerY =
            paperY +
            layout.h * 0.46;

        for (
            let index = 0;
            index < lines.length;
            index += 1
        ) {
            const offset =
                (
                    index -
                    (
                        lines.length -
                        1
                    ) *
                        0.5
                ) *
                lineGap;

            text(
                lines[index],
                layout.x +
                    layout.w * 0.5,
                centerY -
                    offset
            );
        }

        /*
         * 紙を閉じる操作を、
         * 文字ではなく短い横線で示す。
         */
        stroke(
            105,
            69,
            42,
            alpha *
                bodyReveal *
                0.38
        );

        strokeWidth(1);

        line(
            layout.x +
                layout.w * 0.5 -
                18,
            paperY + 15,
            layout.x +
                layout.w * 0.5 +
                18,
            paperY + 15
        );

        noStroke();
    }

    popMatrix();

    rectMode(CORNER);
    textAlign(CENTER);
    noStroke();
}


function colaRollHandleWorkshopMemoTouch(
    touch
) {
    if (
        !gameState ||
        gameState.phase !==
            "DELIVERY_COMPLETE" ||
        !touch ||
        touch.state !== ENDED
    ) {
        return false;
    }

    const memo =
        colaRollEnsureWorkshopMemoState();

    if (!memo) {
        return false;
    }

    const layout =
        colaRollGetWorkshopMemoLayout();

    const eased =
        colaRollWorkshopMemoEase(
            memo.progress
        );

    const paperY =
        layout.closedY +
        (
            layout.openY -
            layout.closedY
        ) *
            eased;

    const visibleRect = {
        x:
            layout.x,

        y:
            memo.open
                ? paperY
                : paperY +
                    layout.h -
                    layout.tabH -
                    8,

        w:
            layout.w,

        h:
            memo.open
                ? layout.h
                : layout.tabH +
                    16,
    };

    /*
     * 開いている間は、紙の外をタップしても閉じる。
     * 背後の結果ボタンへ入力を渡さない。
     */
    if (memo.open) {
        memo.open = false;
        memo.targetProgress = 0;

        if (
            typeof colaRollPlayCriticalSound ===
            "function"
        ) {
            colaRollPlayCriticalSound(
                "paper",
                {
                    volume: 0.14,
                    playbackRate: 0.94,
                    cooldown: 0,
                }
            );
        }

        return true;
    }

    if (
        colaRollWorkshopMemoHit(
            touch,
            visibleRect
        )
    ) {
        memo.open = true;
        memo.targetProgress = 1;

        if (
            typeof colaRollPlayCriticalSound ===
            "function"
        ) {
            colaRollPlayCriticalSound(
                "paper",
                {
                    volume: 0.16,
                    playbackRate: 1.02,
                    cooldown: 0,
                }
            );
        }

        return true;
    }

    return false;
}


function drawResultScreen() {
    drawResultScreenCore();

    /*
     * 履歴詳細では、再生画面用の戻るボタン。
     * 通常の結果では何も描かない。
     */
    colaHistoryDrawReplayFooter();

    /*
     * 新しい瓶を履歴に保存したことを知らせる短い文。
     */
    colaHistorySavedNote();

    /*
     * 結果画面の見出し・名前・ボタン装飾。
     */
    drawResultScreenRefinements();

    /*
     * 補充完了など、外部機能の結果画面上の表示。
     */
    drawResultScreenPostDraw();
}



function drawResultBottleVisualCodeCore(
    x,
    y,
    scaleValue,
    alpha
) {
    const design =
        getResultBottleLabelDesign();

    const base =
        design.base;

    const light =
        design.light;

    const dark =
        design.dark;

    const labelW =
        68;

    const labelH =
        79;

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    ellipseMode(CENTER);
    noStroke();

    fill(
        18,
        10,
        8,
        alpha * 0.42
    );

    rect(
        2,
        -2,
        labelW + 9,
        labelH + 9,
        11
    );

    fill(
        246,
        220,
        160,
        alpha * 0.92
    );

    rect(
        0,
        0,
        labelW,
        labelH,
        10
    );

    fill(
        base.r,
        base.g,
        base.b,
        alpha * 0.90
    );

    rect(
        0,
        0,
        labelW - 8,
        labelH - 8,
        8
    );

    fill(
        255,
        236,
        185,
        alpha * 0.16
    );

    rect(
        0,
        16,
        labelW - 15,
        18,
        5
    );

    noFill();

    stroke(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.78
    );

    strokeWidth(2);

    rect(
        0,
        0,
        labelW,
        labelH,
        10
    );

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.72
    );

    strokeWidth(1.2);

    rect(
        0,
        0,
        labelW - 13,
        labelH - 13,
        7
    );

    noStroke();

    if (
        design.pattern ===
        "spice"
    ) {
        stroke(
            dark.r,
            dark.g,
            dark.b,
            alpha * 0.42
        );

        strokeWidth(1.6);

        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            const lineY =
                27 -
                index * 17;

            line(
                -28,
                lineY - 6,
                -19,
                lineY + 3
            );

            line(
                19,
                lineY + 3,
                28,
                lineY - 6
            );
        }

        noStroke();
    } else if (
        design.pattern ===
        "fresh"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            alpha * 0.30
        );

        ellipse(
            -23,
            25,
            7
        );

        ellipse(
            24,
            16,
            5
        );

        ellipse(
            -25,
            -22,
            5
        );
    } else if (
        design.pattern ===
        "mystery"
    ) {
        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            pushMatrix();

            translate(
                index % 2 === 0
                    ? -24
                    : 24,
                24 -
                    index * 16
            );

            rotate(45);

            rectMode(CENTER);

            fill(
                light.r,
                light.g,
                light.b,
                alpha * 0.26
            );

            rect(
                0,
                0,
                6,
                6,
                1
            );

            popMatrix();
        }
    } else if (
        design.pattern ===
        "heavy"
    ) {
        fill(
            dark.r,
            dark.g,
            dark.b,
            alpha * 0.28
        );

        rect(
            0,
            25,
            labelW - 18,
            5,
            2
        );

        rect(
            0,
            -25,
            labelW - 18,
            5,
            2
        );
    } else if (
        design.pattern ===
        "drop"
    ) {
        fill(
            light.r,
            light.g,
            light.b,
            alpha * 0.28
        );

        ellipse(
            -23,
            23,
            7,
            10
        );

        ellipse(
            24,
            -20,
            6,
            9
        );
    } else {
        noFill();

        stroke(
            light.r,
            light.g,
            light.b,
            alpha * 0.36
        );

        strokeWidth(1.5);

        ellipse(
            -24,
            20,
            8
        );

        ellipse(
            23,
            -20,
            7
        );

        noStroke();
    }

    fill(
        21,
        12,
        10,
        alpha * 0.32
    );

    ellipse(
        0,
        1,
        34,
        34
    );

    drawResultLabelMainMark(
        design,
        alpha
    );

    if (
        design.stillFinish
    ) {
        stroke(
            255,
            236,
            188,
            alpha * 0.62
        );

        strokeWidth(1.6);

        line(
            -22,
            -29,
            22,
            -29
        );

        line(
            -17,
            -24,
            17,
            -24
        );

        noStroke();

        fill(
            255,
            236,
            188,
            alpha * 0.26
        );

        rect(
            0,
            30,
            25,
            4,
            2
        );
    } else {
        const bubbleCount =
            Math.max(
                2,
                Math.min(
                    8,
                    design.carbonationGets +
                    design.pressure +
                    (
                        design.burstCount > 0
                            ? 2
                            : 0
                    )
                )
            );

        for (
            let index = 0;
            index < bubbleCount;
            index += 1
        ) {
            const bubbleX =
                -27 +
                (
                    index % 4
                ) *
                18;

            const bubbleY =
                -28 +
                Math.floor(
                    index / 4
                ) *
                12 +
                (
                    index % 2
                ) *
                3;

            noFill();

            stroke(
                217,
                241,
                247,
                alpha *
                (
                    design.burstCount > 0
                        ? 0.74
                        : 0.54
                )
            );

            strokeWidth(1.2);

            ellipse(
                bubbleX,
                bubbleY,
                4 +
                (
                    index % 3
                )
            );

            noStroke();
        }
    }

    if (
        design.coolingCount > 0
    ) {
        stroke(
            207,
            239,
            247,
            alpha *
            (
                0.44 +
                design.coolingCount * 0.10
            )
        );

        strokeWidth(
            1.2 +
            design.coolingCount * 0.22
        );

        line(
            -25,
            35,
            -13,
            35
        );

        line(
            -19,
            29,
            -19,
            41
        );

        line(
            13,
            35,
            25,
            35
        );

        line(
            19,
            29,
            19,
            41
        );

        noStroke();

        fill(
            210,
            244,
            255,
            alpha * 0.40
        );

        ellipse(
            -28,
            -2,
            4,
            7
        );

        ellipse(
            29,
            12,
            3,
            6
        );
    }

    if (
        design.hasSecret &&
        design.symbol !==
            "diamond"
    ) {
        pushMatrix();

        translate(
            0,
            -31
        );

        rotate(45);

        rectMode(CENTER);

        fill(
            94,
            45,
            119,
            alpha * 0.86
        );

        rect(
            0,
            0,
            8,
            8,
            2
        );

        fill(
            223,
            169,
            236,
            alpha * 0.52
        );

        rect(
            0,
            0,
            3,
            3,
            1
        );

        popMatrix();
    }

    if (
        design.garnish
    ) {
        const markX =
            design.garnish === "cherry"
                ? -25
                : 25;

        const markY =
            -31;

        if (
            design.garnish ===
            "cherry"
        ) {
            fill(
                204,
                56,
                54,
                alpha
            );

            ellipse(
                markX,
                markY,
                8
            );

            fill(
                255,
                158,
                143,
                alpha * 0.72
            );

            ellipse(
                markX - 2,
                markY + 2,
                2.5
            );
        } else {
            noFill();

            stroke(
                227,
                218,
                70,
                alpha
            );

            strokeWidth(2.5);

            ellipse(
                markX,
                markY,
                9
            );

            stroke(
                88,
                130,
                65,
                alpha
            );

            strokeWidth(1.4);

            line(
                markX - 4,
                markY,
                markX + 4,
                markY
            );

            noStroke();
        }
    }

    if (
        design.perfectStopCount > 0
    ) {
        noFill();

        stroke(
            247,
            204,
            104,
            alpha *
            (
                design.perfectGoal
                    ? 0.95
                    : 0.70
            )
        );

        strokeWidth(
            design.perfectGoal
                ? 2.5
                : 1.6
        );

        rect(
            0,
            0,
            labelW - 5,
            labelH - 5,
            8
        );

        if (
            design.perfectGoal
        ) {
            rect(
                0,
                0,
                labelW - 12,
                labelH - 12,
                6
            );
        }

        noStroke();

        const studPositions = [
            {
                x: -28,
                y: 33,
            },
            {
                x: 28,
                y: 33,
            },
            {
                x: -28,
                y: -33,
            },
            {
                x: 28,
                y: -33,
            },
        ];

        for (
            const stud of
            studPositions
        ) {
            fill(
                249,
                214,
                126,
                alpha *
                (
                    design.perfectGoal
                        ? 0.95
                        : 0.72
                )
            );

            ellipse(
                stud.x,
                stud.y,
                design.perfectGoal
                    ? 5
                    : 3.5
            );
        }
    }

    fill(
        18,
        10,
        8,
        alpha * 0.32
    );

    rect(
        0,
        126,
        38,
        13,
        4
    );

    fill(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.90
    );

    rect(
        0,
        126,
        34,
        9,
        3
    );

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.78
    );

    strokeWidth(1.4);

    line(
        -14,
        128,
        14,
        128
    );

    rectMode(CORNER);

    popMatrix();

    noStroke();
}


function drawResultBottleLabelRefinement(
    x,
    y,
    scaleValue,
    alpha
) {
    const result =
        gameState.resultData || {};

    const design =
        getResultBottleLabelDesign();

    const rareCola =
        typeof getRareColaRecipe ===
        "function"
            ? getRareColaRecipe(
                result
            )
            : null;

    const base =
        design.base;

    const light =
        design.light;

    const dark =
        design.dark;

    const labelW =
        66;

    const labelH =
        86;

    const rareTitle =
        rareCola
            ? (
                rareCola.title[
                    gameState.language
                ] ||
                rareCola.title.ja
            )
            : "";

    const outerInset =
        3;

    const innerInset =
        8;

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    ellipseMode(CENTER);
    textAlign(CENTER);

    noStroke();

    fill(
        11,
        7,
        6,
        alpha * 0.42
    );

    rect(
        2,
        -3,
        labelW + 8,
        labelH + 8,
        11
    );

    fill(
        238,
        213,
        158,
        alpha * 0.96
    );

    rect(
        0,
        0,
        labelW,
        labelH,
        10
    );

    fill(
        base.r,
        base.g,
        base.b,
        alpha * 0.94
    );

    rect(
        0,
        0,
        labelW -
            outerInset * 2,
        labelH -
            outerInset * 2,
        8
    );

    fill(
        255,
        240,
        190,
        alpha * 0.09
    );

    rect(
        0,
        23,
        labelW -
            12,
        21,
        5
    );

    noFill();

    stroke(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.90
    );

    strokeWidth(2.1);

    rect(
        0,
        0,
        labelW -
            1,
        labelH -
            1,
        10
    );

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.78
    );

    strokeWidth(1.05);

    rect(
        0,
        0,
        labelW -
            innerInset * 2,
        labelH -
            innerInset * 2,
        6
    );

    const cornerPositions = [
        {
            x:
                -labelW *
                0.5 +
                8,
            y:
                labelH *
                0.5 -
                8,
        },
        {
            x:
                labelW *
                0.5 -
                8,
            y:
                labelH *
                0.5 -
                8,
        },
        {
            x:
                -labelW *
                0.5 +
                8,
            y:
                -labelH *
                0.5 +
                8,
        },
        {
            x:
                labelW *
                0.5 -
                8,
            y:
                -labelH *
                0.5 +
                8,
        },
    ];

    for (
        const corner of
        cornerPositions
    ) {
        noStroke();

        fill(
            light.r,
            light.g,
            light.b,
            alpha * 0.72
        );

        ellipse(
            corner.x,
            corner.y,
            3.4
        );

        fill(
            dark.r,
            dark.g,
            dark.b,
            alpha * 0.72
        );

        ellipse(
            corner.x,
            corner.y,
            1.5
        );
    }

    const topDividerY =
        18;

    const bottomDividerY =
        rareCola
            ? -17
            : -22;

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.66
    );

    strokeWidth(1.15);

    line(
        -21,
        topDividerY,
        -5,
        topDividerY
    );

    line(
        5,
        topDividerY,
        21,
        topDividerY
    );

    line(
        -21,
        bottomDividerY,
        -5,
        bottomDividerY
    );

    line(
        5,
        bottomDividerY,
        21,
        bottomDividerY
    );

    noStroke();

    fill(
        light.r,
        light.g,
        light.b,
        alpha * 0.82
    );

    pushMatrix();
    translate(0, topDividerY);
    rotate(45);
    rectMode(CENTER);
    rect(0, 0, 4, 4, 1);
    popMatrix();

    pushMatrix();
    translate(0, bottomDividerY);
    rotate(45);
    rectMode(CENTER);
    rect(0, 0, 4, 4, 1);
    popMatrix();

    fill(
        18,
        10,
        8,
        alpha * 0.32
    );

    ellipse(
        0,
        1,
        38,
        38
    );

    noFill();

    stroke(
        light.r,
        light.g,
        light.b,
        alpha * 0.58
    );

    strokeWidth(1.2);

    ellipse(
        0,
        1,
        35
    );

    stroke(
        dark.r,
        dark.g,
        dark.b,
        alpha * 0.72
    );

    strokeWidth(1.0);

    ellipse(
        0,
        1,
        29
    );

    noStroke();

    drawResultLabelMainMark(
        design,
        alpha
    );

    if (rareCola) {
        fill(
            255,
            236,
            190,
            alpha * 0.78
        );

        fontSize(5.8);

        text(
            "NIGHT BATCH",
            0,
            34
        );
    }

    if (
        typeof setGameTitleFont ===
        "function"
    ) {
        setGameTitleFont();
    }

    fill(
        255,
        244,
        214,
        alpha * 0.98
    );

    fontSize(13.2);

    text(
        "COLA",
        0,
        25
    );

    if (
        typeof setGameUIFont ===
        "function"
    ) {
        setGameUIFont();
    }

    if (rareTitle) {
        fill(
            255,
            240,
            199,
            alpha * 0.95
        );

        fontSize(
            gameState.language ===
            "ja"
                ? 10
                : 8.2
        );

        text(
            rareTitle,
            0,
            -31
        );
    }

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);

    popMatrix();

    if (
        typeof setGameUIFont ===
        "function"
    ) {
        setGameUIFont();
    }
}




function drawResultProductBottleCore(
    x,
    y,
    scaleValue,
    alpha
) {
    const result =
        gameState.resultData || {};

    const pressure =
        result.pressure ===
        undefined
            ? gameState.glass.pressure
            : result.pressure;

    const pressureRatio =
        CONFIG.pressureMax > 0
            ? Math.max(
                0,
                Math.min(
                    1,
                    pressure /
                    CONFIG.pressureMax
                )
            )
            : 0;

    const sweetness =
        result.sweetness || 0;

    const spice =
        result.spice || 0;

    const strange =
        result.strange || 0;

    const coolingCount =
        result.coolingCount ||
        result.iceCount ||
        0;

    const alphaRatio =
        Math.max(
            0,
            Math.min(
                1,
                alpha / 255
            )
        );

    const geometry = {
        bodyWidth:
            CONFIG.inspectionBottleBodyWidth,
        bodyHeight:
            CONFIG.inspectionBottleBodyHeight,
        neckWidth:
            CONFIG.inspectionBottleNeckWidth,
        neckHeight:
            CONFIG.inspectionBottleNeckHeight,
        mouthWidth:
            CONFIG.inspectionBottleMouthWidth,
        mouthHeight:
            CONFIG.inspectionBottleMouthHeight
    };

    geometry.bodyBottom =
        -geometry.bodyHeight * 0.5 -
        18;

    geometry.bodyTop =
        geometry.bodyHeight * 0.5 -
        18;

    geometry.shoulderY =
        geometry.bodyTop + 7;

    geometry.neckBottom =
        geometry.bodyTop + 17;

    geometry.neckTop =
        geometry.neckBottom +
        geometry.neckHeight;

    const colaR =
        Math.max(
            40,
            Math.min(
                98,
                56 +
                sweetness * 5 +
                strange * 3
            )
        );

    const colaG =
        Math.max(
            20,
            Math.min(
                60,
                26 +
                sweetness * 3 -
                spice * 2
            )
        );

    const colaB =
        Math.max(
            8,
            Math.min(
                30,
                12 +
                strange * 3
            )
        );

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    ellipseMode(CENTER);
    noStroke();

    fill(
        8,
        5,
        4,
        alpha * 0.38
    );

    ellipse(
        4,
        geometry.bodyBottom - 12,
        geometry.bodyWidth *
            1.32,
        16
    );

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        popMatrix();
        return;
    }

    const ctx =
        nativeContext;

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        -4
    );

    ctx.fillStyle =
        "rgba(5, 3, 2, " +
        String(
            0.36 * alphaRatio
        ) +
        ")";

    ctx.translate(
        5,
        -8
    );

    ctx.fill();

    ctx.restore();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        0
    );

    ctx.fillStyle =
        "rgba(31, 20, 14, " +
        String(
            0.94 * alphaRatio
        ) +
        ")";

    ctx.strokeStyle =
        "rgba(229, 210, 177, " +
        String(
            0.54 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 2.8;

    ctx.fill();
    ctx.stroke();

    ctx.restore();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        6
    );

    ctx.fillStyle =
        "rgba(92, 57, 31, " +
        String(
            0.28 * alphaRatio
        ) +
        ")";

    ctx.fill();
    ctx.clip();

    const liquidBottom =
        geometry.bodyBottom + 2;

    const liquidTop =
        geometry.neckTop - 18;

    const liquidGradient =
        ctx.createLinearGradient(
            0,
            liquidBottom,
            0,
            liquidTop
        );

    liquidGradient.addColorStop(
        0,
        "rgba(" +
        String(
            Math.max(
                18,
                colaR - 16
            )
        ) +
        "," +
        String(
            Math.max(
                10,
                colaG - 10
            )
        ) +
        "," +
        String(
            Math.max(
                5,
                colaB - 5
            )
        ) +
        "," +
        String(
            0.98 * alphaRatio
        ) +
        ")"
    );

    liquidGradient.addColorStop(
        0.55,
        "rgba(" +
        String(
            colaR
        ) +
        "," +
        String(
            colaG
        ) +
        "," +
        String(
            colaB
        ) +
        "," +
        String(
            0.97 * alphaRatio
        ) +
        ")"
    );

    liquidGradient.addColorStop(
        1,
        "rgba(" +
        String(
            Math.min(
                140,
                colaR + 16
            )
        ) +
        "," +
        String(
            Math.min(
                90,
                colaG + 10
            )
        ) +
        "," +
        String(
            Math.min(
                45,
                colaB + 6
            )
        ) +
        "," +
        String(
            0.92 * alphaRatio
        ) +
        ")"
    );

    ctx.fillStyle =
        liquidGradient;

    ctx.fillRect(
        -geometry.bodyWidth,
        liquidBottom - 6,
        geometry.bodyWidth * 2,
        liquidTop -
            liquidBottom +
            12
    );

    ctx.fillStyle =
        "rgba(255, 243, 216, " +
        String(
            0.08 * alphaRatio
        ) +
        ")";

    ctx.fillRect(
        -geometry.bodyWidth *
            0.35,
        liquidBottom + 8,
        geometry.bodyWidth *
            0.14,
        liquidTop -
            liquidBottom -
            26
    );

    const wave =
        Math.sin(
            ElapsedTime * 2.6
        ) * 2.0;

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth,
        liquidTop
    );

    ctx.bezierCurveTo(
        -geometry.bodyWidth *
            0.36,
        liquidTop + wave,
        geometry.bodyWidth *
            0.36,
        liquidTop - wave,
        geometry.bodyWidth,
        liquidTop
    );

    ctx.strokeStyle =
        "rgba(255, 224, 174, " +
        String(
            0.34 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 1.4;

    ctx.stroke();

    if (pressure > 0) {
        const bubbleCount =
            Math.min(
                16,
                Math.max(
                    4,
                    pressure * 4
                )
            );

        for (
            let index = 0;
            index < bubbleCount;
            index += 1
        ) {
            const bubbleX =
                Math.sin(
                    index * 6.1
                ) *
                geometry.bodyWidth *
                0.26;

            const travel =
                (
                    ElapsedTime * 15 +
                    index * 18
                ) %
                (
                    liquidTop -
                    liquidBottom - 10
                );

            const bubbleY =
                liquidBottom +
                6 +
                travel;

            const bubbleSize =
                2.2 +
                (
                    index % 4
                ) *
                0.75;

            ctx.beginPath();

            ctx.ellipse(
                bubbleX,
                bubbleY,
                bubbleSize * 0.5,
                bubbleSize * 0.5,
                0,
                0,
                Math.PI * 2
            );

            ctx.strokeStyle =
                "rgba(222, 244, 249, " +
                String(
                    (
                        0.34 +
                        pressureRatio *
                            0.28
                    ) *
                        alphaRatio
                ) +
                ")";

            ctx.lineWidth = 1;

            ctx.stroke();
        }
    }

    ctx.restore();

    ctx.save();

    const amberOverlay =
        ctx.createLinearGradient(
            -geometry.bodyWidth *
                0.5,
            0,
            geometry.bodyWidth *
                0.5,
            0
        );

    amberOverlay.addColorStop(
        0,
        "rgba(25, 12, 7, " +
        String(
            0.22 * alphaRatio
        ) +
        ")"
    );

    amberOverlay.addColorStop(
        0.28,
        "rgba(214, 145, 74, " +
        String(
            0.06 * alphaRatio
        ) +
        ")"
    );

    amberOverlay.addColorStop(
        0.72,
        "rgba(90, 43, 20, " +
        String(
            0.04 * alphaRatio
        ) +
        ")"
    );

    amberOverlay.addColorStop(
        1,
        "rgba(17, 8, 5, " +
        String(
            0.30 * alphaRatio
        ) +
        ")"
    );

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        7
    );

    ctx.fillStyle =
        amberOverlay;

    ctx.fill();

    ctx.restore();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        0
    );

    ctx.strokeStyle =
        "rgba(233, 222, 199, " +
        String(
            0.60 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 2.4;

    ctx.stroke();

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        3
    );

    ctx.clip();

    ctx.lineCap =
        "round";

    ctx.lineJoin =
        "round";

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth *
            0.34,
        geometry.bodyBottom + 24
    );

    ctx.lineTo(
        -geometry.bodyWidth *
            0.31,
        geometry.bodyTop - 28
    );

    ctx.strokeStyle =
        "rgba(255, 247, 225, " +
        String(
            0.20 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 3.8;

    ctx.stroke();

    ctx.beginPath();

    ctx.moveTo(
        -geometry.bodyWidth *
            0.23,
        geometry.bodyBottom + 46
    );

    ctx.lineTo(
        -geometry.bodyWidth *
            0.22,
        geometry.bodyTop + 6
    );

    ctx.strokeStyle =
        "rgba(255, 247, 225, " +
        String(
            0.10 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 1.8;

    ctx.stroke();

    ctx.beginPath();

    ctx.moveTo(
        geometry.bodyWidth *
            0.24,
        geometry.bodyBottom + 18
    );

    ctx.lineTo(
        geometry.bodyWidth *
            0.21,
        geometry.bodyBottom + 58
    );

    ctx.strokeStyle =
        "rgba(255, 235, 202, " +
        String(
            0.07 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 1.5;

    ctx.stroke();

    ctx.restore();

    ctx.beginPath();

    ctx.ellipse(
        0,
        geometry.neckTop + 7,
        geometry.mouthWidth *
            0.5,
        geometry.mouthHeight *
            0.52,
        0,
        0,
        Math.PI * 2
    );

    ctx.fillStyle =
        "rgba(233, 210, 174, " +
        String(
            0.92 * alphaRatio
        ) +
        ")";

    ctx.fill();

    ctx.strokeStyle =
        "rgba(247, 230, 196, " +
        String(
            0.48 * alphaRatio
        ) +
        ")";

    ctx.lineWidth = 1.2;

    ctx.stroke();

    ctx.beginPath();

    ctx.ellipse(
        0,
        geometry.neckTop + 6.5,
        geometry.mouthWidth *
            0.34,
        geometry.mouthHeight *
            0.24,
        0,
        0,
        Math.PI * 2
    );

    ctx.fillStyle =
        "rgba(21, 12, 9, " +
        String(
            0.90 * alphaRatio
        ) +
        ")";

    ctx.fill();

    if (coolingCount > 0) {
        ctx.save();

        traceInspectionBottleVectorPath(
            ctx,
            geometry,
            1
        );

        ctx.clip();

        ctx.strokeStyle =
            "rgba(211, 239, 247, " +
            String(
                (
                    0.22 +
                    coolingCount * 0.10
                ) * alphaRatio
            ) +
            ")";

        ctx.lineWidth =
            1 +
            coolingCount * 0.28;

        for (
            let index = 0;
            index < 4;
            index += 1
        ) {
            const side =
                index % 2 === 0
                    ? -1
                    : 1;

            const frostX =
                side *
                geometry.bodyWidth *
                0.40;

            const frostY =
                geometry.bodyBottom +
                44 +
                index * 22;

            ctx.beginPath();

            ctx.moveTo(
                frostX - 4,
                frostY
            );

            ctx.lineTo(
                frostX + 4,
                frostY
            );

            ctx.moveTo(
                frostX,
                frostY - 4
            );

            ctx.lineTo(
                frostX,
                frostY + 4
            );

            ctx.stroke();
        }

        ctx.restore();
    }

    ctx.restore();

    rectMode(CORNER);

    popMatrix();
}

function drawResultBottlePresentationBase(
    x,
    y,
    scaleValue,
    alpha
) {
    const bodyWidth =
        CONFIG.inspectionBottleBodyWidth;

    const bodyHeight =
        CONFIG.inspectionBottleBodyHeight;

    const outerSize =
        208 *
        scaleValue;

    const innerSize =
        176 *
        scaleValue;

    const baseY =
        y +
        (
            -bodyHeight * 0.5 -
            26
        ) *
            scaleValue;

    ellipseMode(CENTER);

    noStroke();

    fill(
        35,
        18,
        12,
        alpha * 0.90
    );

    ellipse(
        x,
        y,
        outerSize + 12
    );

    noFill();

    stroke(
        133,
        78,
        35,
        alpha * 0.34
    );

    strokeWidth(2.4);

    ellipse(
        x,
        y,
        outerSize
    );

    stroke(
        226,
        157,
        68,
        alpha * 0.20
    );

    strokeWidth(1.25);

    ellipse(
        x,
        y,
        innerSize
    );

    noStroke();

    fill(
        10,
        6,
        5,
        alpha * 0.34
    );

    ellipse(
        x +
            3 *
                scaleValue,
        baseY -
            2 *
                scaleValue,
        bodyWidth *
            1.72 *
            scaleValue,
        16 *
            scaleValue
    );

    noFill();

    stroke(
        143,
        86,
        41,
        alpha * 0.30
    );

    strokeWidth(1.4);

    ellipse(
        x,
        baseY,
        bodyWidth *
            1.52 *
            scaleValue,
        10 *
            scaleValue
    );

    stroke(
        239,
        181,
        94,
        alpha * 0.16
    );

    strokeWidth(0.9);

    line(
        x -
            bodyWidth *
                0.42 *
                scaleValue,
        baseY +
            1.2 *
                scaleValue,
        x +
            bodyWidth *
                0.42 *
                scaleValue,
        baseY +
            1.2 *
                scaleValue
    );

    noStroke();
}




function drawResultTastingSetCore(
    glassX,
    glassY,
    glassScale,
    crownX,
    crownY,
    crownSize,
    alpha
) {
    const glassKind =
        getResultGlassDrinkKind();

    if (
        glassKind !==
        "none"
    ) {
        fill(
            8,
            5,
            4,
            alpha * 0.34
        );

        noStroke();

        ellipse(
            glassX + 3,
            glassY -
                116 * glassScale,
            116 * glassScale,
            20 * glassScale
        );

        if (
            glassKind ===
            "soda"
        ) {
            drawFinishedSoda(
                glassX,
                glassY,
                glassScale,
                alpha
            );
        } else {
            drawFinishedCola(
                glassX,
                glassY,
                glassScale,
                alpha
            );
        }
    }

    const crownReveal =
        gameState.resultCrownReveal || {
            alpha: 255,
            rotation: 0,
            scale: 1,
            yOffset: 0,
            sparkAlpha: 0,
            sparkScale: 1,
            sparkRotation: 0,
        };

    const crownOpacity =
        Math.max(
            0,
            Math.min(
                1,
                (
                    crownReveal.alpha ||
                    0
                ) / 255
            )
        );

    if (
        crownOpacity <= 0.002
    ) {
        return;
    }

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        if (
            crownOpacity <
            0.98
        ) {
            return;
        }
    } else {
        nativeContext.save();

        nativeContext.globalAlpha =
            crownOpacity;
    }

    drawResultCrownArrivalSparkles(
        crownX,
        crownY,
        crownSize,
        crownReveal,
        alpha
    );

    pushMatrix();

    translate(
        crownX,
        crownY +
            (
                crownReveal.yOffset || 0
            )
    );

    rotate(
        crownReveal.rotation || 0
    );

    scale(
        crownReveal.scale || 1,
        crownReveal.scale || 1
    );

    translate(
        -crownX,
        -crownY
    );

    if (
        gameState.perfectGoalStop
    ) {
        noFill();

        stroke(
            255,
            215,
            112,
            alpha * 0.58
        );

        strokeWidth(2.2);

        ellipse(
            crownX,
            crownY,
            crownSize * 1.26
        );

        noStroke();
    }

    fill(
        7,
        4,
        3,
        alpha * 0.40
    );

    ellipse(
        crownX + 3,
        crownY -
            crownSize * 0.55,
        crownSize * 1.28,
        crownSize * 0.38
    );

    drawCap(
        crownX,
        crownY,
        -12,
        crownSize
    );

    drawResultCrownSeal(
        crownX,
        crownY,
        crownSize,
        alpha
    );

    popMatrix();

    if (nativeContext) {
        nativeContext.restore();
    }

    noStroke();
}

function drawResultStillGarnishTray(
    glassX,
    glassY,
    glassScale,
    alpha
) {
    const result =
        gameState.resultData || {};

    if (
        !result.garnish ||
        getResultGlassDrinkKind() !==
            "none"
    ) {
        return;
    }

    const portrait =
        HEIGHT > WIDTH;

    const bottleToGlassDistance =
        portrait
            ? WIDTH * 0.265
            : WIDTH * 0.16;

    const bottleX =
        glassX -
        bottleToGlassDistance;

    const bottleScale =
        portrait
            ? Math.min(
                0.78,
                WIDTH / 490
            )
            : Math.min(
                0.78,
                HEIGHT / 520
            );

    const bottleBottomY =
        glassY -
        115 *
            glassScale;

    const dishW =
        Math.max(
            32,
            54 * bottleScale
        );

    const dishH =
        Math.max(
            8,
            12 * bottleScale
        );

    const dishX =
        bottleX -
        50 * bottleScale;

    const dishY =
        bottleBottomY +
        dishH * 0.5;

    const garnishSize =
        result.garnish ===
        "cherry"
            ? 13 * bottleScale
            : 14 * bottleScale;

    noStroke();

    fill(
        8,
        5,
        4,
        alpha * 0.30
    );

    ellipse(
        dishX + 2,
        dishY -
            dishH * 0.54,
        dishW * 0.92,
        dishH * 0.74
    );

    fill(
        36,
        23,
        16,
        alpha * 0.96
    );

    ellipse(
        dishX,
        dishY,
        dishW,
        dishH
    );

    noFill();

    stroke(
        227,
        179,
        105,
        alpha * 0.76
    );

    strokeWidth(
        Math.max(
            1,
            1.35 * bottleScale
        )
    );

    ellipse(
        dishX,
        dishY,
        dishW,
        dishH
    );

    noStroke();

    fill(
        255,
        237,
        198,
        alpha * 0.16
    );

    ellipse(
        dishX -
            dishW * 0.08,
        dishY +
            dishH * 0.12,
        dishW * 0.58,
        dishH * 0.34
    );

    drawGarnishSymbol(
        result.garnish,
        dishX,
        dishY +
            dishH * 0.42,
        garnishSize,
        alpha,
        result.garnish === "cherry"
            ? -16
            : 10
    );

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);
}




function drawResultCrownArrivalSparkles(
    crownX,
    crownY,
    crownSize,
    crownReveal,
    alpha
) {
    const sparkAlpha =
        Math.max(
            0,
            Math.min(
                255,
                crownReveal.sparkAlpha || 0
            )
        );

    if (sparkAlpha <= 0.5) {
        return;
    }

    const sparkleScale =
        crownReveal.sparkScale ===
        undefined
            ? 1
            : crownReveal.sparkScale;

    const sparkleRotation =
        crownReveal.sparkRotation || 0;

    const centerY =
        crownY +
        (
            crownReveal.yOffset || 0
        );

    pushMatrix();

    translate(
        crownX,
        centerY
    );

    rotate(
        sparkleRotation
    );

    scale(
        sparkleScale,
        sparkleScale
    );

    noFill();

    stroke(
        255,
        223,
        154,
        Math.min(
            alpha,
            sparkAlpha
        ) * 0.32
    );

    strokeWidth(1.5);

    ellipse(
        0,
        0,
        crownSize * 1.42
    );

    for (
        let index = 0;
        index < 6;
        index += 1
    ) {
        pushMatrix();

        rotate(index * 60);

        stroke(
            255,
            231,
            182,
            Math.min(
                alpha,
                sparkAlpha
            ) * 0.82
        );

        strokeWidth(
            index % 2 === 0
                ? 2.2
                : 1.5
        );

        line(
            crownSize * 0.78,
            0,
            crownSize * 1.05,
            0
        );

        popMatrix();
    }

    noStroke();

    fill(
        255,
        236,
        190,
        Math.min(
            alpha,
            sparkAlpha
        ) * 0.86
    );

    ellipse(
        0,
        crownSize * 1.03,
        4
    );

    ellipse(
        crownSize * 0.95,
        -crownSize * 0.35,
        3.2
    );

    ellipse(
        -crownSize * 0.92,
        -crownSize * 0.18,
        2.8
    );

    popMatrix();
}



function getResultCrownSealType() {
    const result =
        gameState.resultData || {};

    if (
        gameState.perfectGoalStop ===
        true
    ) {
        return "star";
    }

    if (
        (
            result.mysteryCount ||
            0
        ) > 0
    ) {
        return "mystery";
    }

    if (
        (
            result.glassFullCount ||
            0
        ) > 0
    ) {
        return "scuff";
    }

    return "none";
}

function drawResultCrownSeal(
    crownX,
    crownY,
    crownSize,
    alpha
) {
    const sealType =
        getResultCrownSealType();

    if (
        sealType ===
        "none"
    ) {
        return;
    }

    const sealRadius =
        crownSize * 0.145;

    pushMatrix();

    translate(
        crownX,
        crownY
    );

    rotate(-12);

    if (
        sealType ===
        "star"
    ) {
        stroke(
            88,
            42,
            25,
            alpha * 0.92
        );

        strokeWidth(
            Math.max(
                1,
                crownSize * 0.042
            )
        );

        for (
            let index = 0;
            index < 5;
            index += 1
        ) {
            const angleA =
                (
                    index * 72 -
                    90
                ) *
                Math.PI /
                180;

            const angleB =
                (
                    (
                        (
                            index +
                            2
                        ) %
                        5
                    ) *
                    72 -
                    90
                ) *
                Math.PI /
                180;

            line(
                Math.cos(
                    angleA
                ) *
                    sealRadius,
                Math.sin(
                    angleA
                ) *
                    sealRadius,
                Math.cos(
                    angleB
                ) *
                    sealRadius,
                Math.sin(
                    angleB
                ) *
                    sealRadius
            );
        }

        stroke(
            255,
            224,
            147,
            alpha * 0.70
        );

        strokeWidth(
            Math.max(
                0.7,
                crownSize * 0.020
            )
        );

        line(
            0,
            -sealRadius * 0.78,
            0,
            sealRadius * 0.78
        );

        line(
            -sealRadius * 0.72,
            0,
            sealRadius * 0.72,
            0
        );
    } else if (
        sealType ===
        "mystery"
    ) {
        let previousX = 0;
        let previousY = 0;

        stroke(
            74,
            39,
            78,
            alpha * 0.92
        );

        strokeWidth(
            Math.max(
                1,
                crownSize * 0.038
            )
        );

        for (
            let index = 0;
            index <= 12;
            index += 1
        ) {
            const ratio =
                index / 12;

            const angle =
                ratio *
                Math.PI *
                2.18;

            const radius =
                sealRadius *
                (
                    0.10 +
                    ratio * 0.96
                );

            const currentX =
                Math.cos(
                    angle
                ) *
                radius;

            const currentY =
                Math.sin(
                    angle
                ) *
                radius;

            if (index > 0) {
                line(
                    previousX,
                    previousY,
                    currentX,
                    currentY
                );
            }

            previousX =
                currentX;

            previousY =
                currentY;
        }

        noStroke();

        fill(
            216,
            165,
            219,
            alpha * 0.56
        );

        ellipse(
            0,
            0,
            Math.max(
                1.4,
                crownSize * 0.052
            )
        );
    } else if (
        sealType ===
        "scuff"
    ) {
        stroke(
            83,
            40,
            24,
            alpha * 0.90
        );

        strokeWidth(
            Math.max(
                1,
                crownSize * 0.050
            )
        );

        line(
            crownSize * 0.16,
            -crownSize * 0.30,
            crownSize * 0.37,
            -crownSize * 0.16
        );

        line(
            crownSize * 0.19,
            -crownSize * 0.18,
            crownSize * 0.39,
            -crownSize * 0.04
        );

        stroke(
            239,
            185,
            103,
            alpha * 0.42
        );

        strokeWidth(
            Math.max(
                0.7,
                crownSize * 0.020
            )
        );

        line(
            crownSize * 0.18,
            -crownSize * 0.32,
            crownSize * 0.35,
            -crownSize * 0.20
        );
    }

    noStroke();

    popMatrix();
}


function getResultGlassDrinkKind() {
    const result =
        gameState.resultData || {};

    const hasFizz =
        result.hasFizz === undefined
            ? (
                (
                    result.pressure || 0
                ) > 0 ||
                (
                    result.carbonationGets || 0
                ) > 0
            )
            : result.hasFizz;

    if (!hasFizz) {
        return "none";
    }

    const drinkType =
        result.drinkType || "cola";

    if (
        drinkType === "plain_soda" ||
        drinkType === "single_soda"
    ) {
        return "soda";
    }

    if (
        drinkType === "scrap" &&
        result.hasColaBase === false
    ) {
        return "soda";
    }

    if (
        drinkType !== "cola" &&
        result.hasColaBase === false
    ) {
        return "soda";
    }

    return "cola";
}


function drawFinishedCola(
    x,
    y,
    scaleValue,
    alpha
) {
    const result =
        gameState.resultData || {};

    const glassH = 230;
    const topW = 130;
    const bottomW = 98;

    const liquidBottom =
        -glassH * 0.44;

    const liquidTop =
        glassH * 0.27;

    const liquidHeight =
        liquidTop -
        liquidBottom;

    const pressure =
        result.pressure ===
        undefined
            ? gameState.glass.pressure
            : result.pressure;

    const pressureRatio =
        CONFIG.pressureMax > 0
            ? Math.max(
                0,
                Math.min(
                    1,
                    pressure /
                        CONFIG.pressureMax
                )
            )
            : 0;

    const iceCount =
        result.iceCount || 0;

    const coldLevel =
        result.chillLevel ===
            "high" ||
        iceCount >= 2
            ? 1
            : iceCount > 0
                ? 0.55
                : 0.25;

    const featureIds =
        getFinishedColaFeatureIds();

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    rectMode(CENTER);
    noStroke();

    fill(
        17,
        9,
        7,
        alpha * 0.42
    );

    rect(
        0,
        -2,
        topW * 0.82,
        glassH * 0.92,
        16
    );

    const bandCount = 18;

    const bandHeight =
        liquidHeight /
        bandCount +
        1.2;

    for (
        let index = 0;
        index < bandCount;
        index += 1
    ) {
        const ratio =
            (
                index +
                0.5
            ) /
            bandCount;

        const bandY =
            liquidBottom +
            liquidHeight *
                ratio;

        const glassRatio =
            (
                bandY +
                glassH * 0.5
            ) /
            glassH;

        const bandW =
            bottomW +
            (
                topW -
                bottomW
            ) *
                glassRatio -
            12;

        fill(
            45 +
                ratio * 36,
            19 +
                ratio * 23,
            8 +
                ratio * 8,
            alpha * 0.98
        );

        rect(
            0,
            bandY,
            bandW,
            bandHeight,
            3
        );

        fill(
            19,
            8,
            5,
            alpha * 0.22
        );

        rect(
            -bandW * 0.30,
            bandY,
            bandW * 0.22,
            bandHeight,
            2
        );

        fill(
            205,
            112,
            31,
            alpha *
                (
                    0.04 +
                    ratio * 0.08
                )
        );

        rect(
            bandW * 0.27,
            bandY,
            bandW * 0.14,
            bandHeight,
            2
        );
    }

    drawFinishedColaBubbles(
        liquidBottom,
        liquidTop,
        topW,
        bottomW,
        glassH,
        pressureRatio,
        alpha
    );

    drawFinishedColaIce(
        liquidTop,
        iceCount,
        coldLevel,
        alpha
    );

    fill(
        128,
        71,
        23,
        alpha * 0.98
    );

    ellipse(
        0,
        liquidTop,
        topW * 0.84,
        17
    );

    fill(
        63,
        30,
        12,
        alpha * 0.92
    );

    ellipse(
        0,
        liquidTop + 1,
        topW * 0.70,
        10
    );

    drawFinishedColaFoam(
        liquidTop,
        pressureRatio,
        alpha
    );

    for (
        let index = 0;
        index <
            featureIds.length;
        index += 1
    ) {
        drawFinishedColaFeature(
            featureIds[index],
            index,
            liquidTop,
            topW,
            glassH,
            alpha
        );
    }

    stroke(
        245,
        238,
        228,
        alpha * 0.52
    );

    strokeWidth(4);

    line(
        -topW * 0.5,
        glassH * 0.5,
        -bottomW * 0.5,
        -glassH * 0.5
    );

    line(
        topW * 0.5,
        glassH * 0.5,
        bottomW * 0.5,
        -glassH * 0.5
    );

    line(
        -bottomW * 0.5,
        -glassH * 0.5,
        bottomW * 0.5,
        -glassH * 0.5
    );

    noFill();

    stroke(
        255,
        248,
        235,
        alpha * 0.24
    );

    strokeWidth(2);

    ellipse(
        0,
        glassH * 0.5,
        topW,
        14
    );

    stroke(
        255,
        255,
        255,
        alpha * 0.17
    );

    strokeWidth(3);

    line(
        -topW * 0.27,
        glassH * 0.40,
        -bottomW * 0.20,
        -glassH * 0.37
    );

    stroke(
        255,
        255,
        255,
        alpha * 0.08
    );

    strokeWidth(2);

    line(
        -topW * 0.18,
        glassH * 0.30,
        -bottomW * 0.12,
        -glassH * 0.25
    );

    noStroke();

    drawFinishedColaCondensation(
        coldLevel,
        glassH,
        topW,
        alpha
    );

    rectMode(CORNER);
    popMatrix();
}

