function drawResultBackgroundVignette(
    alpha
) {
    const outerInset =
        23;

    const layerCount =
        5;

    rectMode(CORNER);
    ellipseMode(CENTER);
    noStroke();

    fill(
        104,
        55,
        26,
        alpha * 0.028
    );

    ellipse(
        WIDTH * 0.5,
        HEIGHT * 0.56,
        WIDTH * 0.54,
        HEIGHT * 0.62
    );

    noFill();

    for (
        let index = 0;
        index < layerCount;
        index += 1
    ) {
        const inset =
            outerInset +
            index * 8;

        const strength =
            (
                layerCount -
                index
            ) /
            layerCount;

        stroke(
            9,
            5,
            4,
            alpha *
                (
                    0.025 +
                    strength * 0.052
                )
        );

        strokeWidth(
            13 -
            index * 1.2
        );

        rect(
            inset,
            inset,
            WIDTH -
                inset * 2,
            HEIGHT -
                inset * 2,
            12
        );
    }

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);
}


function splitResultName(name) {
    setGameTitleFont();

    if (
        gameState.language === "ja"
    ) {
        if (
            name.length <= 13
        ) {
            return [
                name,
            ];
        }

        /*
         * まず「完成品の種類」を末尾として確保する。
         * 例:
         * 生姜香るひんやり / コーラの素
         * レモンピール香る / 強炭酸コーラ
         */
        const suffixes = [
            "限界炭酸コーラ",
            "強炭酸コーラ",
            "ひんやりコーラの素",
            "濃厚コーラの素",
            "泡待ちシロップ",
            "静かな秘伝シロップ",
            "コーラの素",
            "炭酸水",
            "コーラ",
            "ソーダ",
            "シロップ",
        ];

        let suffix =
            "";

        for (
            const candidate of
            suffixes
        ) {
            if (
                name.endsWith(
                    candidate
                )
            ) {
                suffix =
                    candidate;

                break;
            }
        }

        if (suffix !== "") {
            const prefix =
                name.slice(
                    0,
                    name.length -
                        suffix.length
                );

            if (prefix === "") {
                return [
                    suffix,
                ];
            }

            /*
             * ほとんどの名前は、
             * 味の説明 / 飲み物名
             * の二行で終える。
             */
            if (
                prefix.length <= 12
            ) {
                return [
                    prefix,
                    suffix,
                ];
            }

            /*
             * チェリー系は、
             * 味 / チェリー / 飲み物名
             * に分けると読みやすい。
             */
            const cherryIndex =
                prefix.indexOf(
                    "チェリー"
                );

            if (
                cherryIndex > 0
            ) {
                const before =
                    prefix.slice(
                        0,
                        cherryIndex
                    );

                const after =
                    prefix.slice(
                        cherryIndex
                    );

                if (
                    before.length <= 12 &&
                    after.length <= 12
                ) {
                    return [
                        before,
                        after,
                        suffix,
                    ];
                }
            }

            /*
             * レモン添えも同様に、
             * 味 / レモン添え / 飲み物名
             * の順にする。
             */
            const lemonIndex =
                prefix.indexOf(
                    "レモン添えの"
                );

            if (
                lemonIndex > 0
            ) {
                const before =
                    prefix.slice(
                        0,
                        lemonIndex
                    );

                const after =
                    prefix.slice(
                        lemonIndex
                    );

                if (
                    before.length <= 12 &&
                    after.length <= 12
                ) {
                    return [
                        before,
                        after,
                        suffix,
                    ];
                }
            }

            /*
             * 「香る」の直後は、
             * 日本語の結果名として比較的自然な切れ目。
             */
            const flavorEnd =
                prefix.lastIndexOf(
                    "香る"
                );

            if (
                flavorEnd > 0
            ) {
                const cutIndex =
                    flavorEnd + 2;

                const before =
                    prefix.slice(
                        0,
                        cutIndex
                    );

                const after =
                    prefix.slice(
                        cutIndex
                    );

                if (
                    after !== "" &&
                    before.length <= 12 &&
                    after.length <= 12
                ) {
                    return [
                        before,
                        after,
                        suffix,
                    ];
                }
            }

            /*
             * 意味の区切りが取れない時だけ、
             * 真ん中付近で三行に分ける。
             */
            let middle =
                Math.ceil(
                    prefix.length *
                    0.5
                );

            if (
                prefix.charAt(
                    middle
                ) === "の"
            ) {
                middle += 1;
            }

            let first =
                prefix.slice(
                    0,
                    middle
                );

            let second =
                prefix.slice(
                    middle
                );

            if (
                second.charAt(
                    0
                ) === "の"
            ) {
                first +=
                    "の";

                second =
                    second.slice(
                        1
                    );
            }

            if (second === "") {
                return [
                    first,
                    suffix,
                ];
            }

            return [
                first,
                second,
                suffix,
            ];
        }

        /*
         * 飲み物名の型が不明な時だけ、
         * 中央で二行に分ける。
         */
        let middle =
            Math.ceil(
                name.length *
                0.5
            );

        if (
            name.charAt(
                middle
            ) === "の"
        ) {
            middle += 1;
        }

        let first =
            name.slice(
                0,
                middle
            );

        let second =
            name.slice(
                middle
            );

        if (
            second.charAt(
                0
            ) === "の"
        ) {
            first +=
                "の";

            second =
                second.slice(
                    1
                );
        }

        return [
            first,
            second,
        ];
    }

    if (
        name.length <= 24
    ) {
        return [
            name,
        ];
    }

    const words =
        name.split(
            " "
        );

    const lines = [
        "",
        "",
    ];

    for (
        const word of
        words
    ) {
        const targetIndex =
            lines[0].length <=
            lines[1].length
                ? 0
                : 1;

        lines[
            targetIndex
        ] +=
            (
                lines[
                    targetIndex
                ] === ""
                    ? ""
                    : " "
            ) +
            word;
    }

    return lines;
}



function drawGlassFullMessage() {
    const effect =
        gameState.glassFullEffect;

    if (
        !effect ||
        !effect.visible
    ) {
        return;
    }

    const geometry =
        getBottleInspectionGeometry();

    const mouthX =
        geometry.centerX;

    const mouthY =
        geometry.centerY +
        (
            geometry.neckTop + 6
        ) *
            geometry.scale;

    const shoulderY =
        geometry.centerY +
        geometry.shoulderY *
            geometry.scale;

    const neckWidth =
        geometry.mouthWidth *
        geometry.scale *
        0.92;

    const ringW =
        neckWidth * 1.16 +
        effect.ring * 18;

    const ringH =
        11 *
            geometry.scale +
        effect.ring * 6;

    const surge =
        effect.scale;

    const wave =
        Math.sin(
            ElapsedTime * 10
        ) *
        1.6 *
        surge;

    noFill();

    stroke(
        255,
        221,
        151,
        effect.alpha * 0.55
    );

    strokeWidth(2.2);

    ellipse(
        mouthX,
        mouthY + 1,
        ringW,
        ringH
    );

    stroke(
        255,
        239,
        194,
        effect.alpha * 0.22
    );

    strokeWidth(1.4);

    ellipse(
        mouthX,
        mouthY + 1,
        ringW * 1.34,
        ringH * 1.55
    );

    noStroke();

    fill(
        101,
        54,
        24,
        effect.alpha * 0.88
    );

    ellipse(
        mouthX,
        mouthY - 1 +
            wave * 0.2,
        neckWidth * 1.08 +
            effect.ring * 12,
        9 *
            geometry.scale +
            surge * 1.5
    );

    fill(
        136,
        74,
        31,
        effect.alpha * 0.92
    );

    ellipse(
        mouthX,
        mouthY +
            0.8 +
            wave * 0.15,
        neckWidth * 0.95 +
            effect.ring * 9,
        5.5 *
            geometry.scale +
            surge
    );

    fill(
        223,
        158,
        78,
        effect.alpha * 0.34
    );

    ellipse(
        mouthX - neckWidth * 0.14,
        mouthY + 1.6,
        neckWidth * 0.38,
        2.8 *
            geometry.scale
    );

    strokeCap(ROUND);

    stroke(
        105,
        55,
        25,
        effect.alpha * 0.86
    );

    strokeWidth(
        4.4 *
            geometry.scale
    );

    line(
        mouthX - neckWidth * 0.28,
        mouthY - 1,
        mouthX - neckWidth * 0.36,
        mouthY -
            16 *
                surge
    );

    line(
        mouthX,
        mouthY - 1,
        mouthX - 1,
        mouthY -
            12 *
                surge
    );

    line(
        mouthX + neckWidth * 0.30,
        mouthY - 1,
        mouthX + neckWidth * 0.39,
        mouthY -
            18 *
                surge
    );

    stroke(
        232,
        173,
        95,
        effect.alpha * 0.34
    );

    strokeWidth(
        1.4 *
            geometry.scale
    );

    line(
        mouthX - neckWidth * 0.31,
        mouthY + 0.5,
        mouthX - neckWidth * 0.37,
        mouthY -
            13 *
                surge
    );

    line(
        mouthX + neckWidth * 0.29,
        mouthY + 0.5,
        mouthX + neckWidth * 0.35,
        mouthY -
            15 *
                surge
    );

    noStroke();

    fill(
        119,
        62,
        28,
        effect.alpha * 0.84
    );

    ellipse(
        mouthX - neckWidth * 0.45,
        shoulderY - 12,
        7.5 *
            geometry.scale
    );

    ellipse(
        mouthX + neckWidth * 0.47,
        shoulderY - 16,
        9 *
            geometry.scale
    );

    fill(
        240,
        178,
        97,
        effect.alpha * 0.28
    );

    ellipse(
        mouthX - neckWidth * 0.47,
        shoulderY - 10.5,
        3 *
            geometry.scale
    );

    ellipse(
        mouthX + neckWidth * 0.44,
        shoulderY - 13.5,
        3.2 *
            geometry.scale
    );

    for (
        let index = 0;
        index < 6;
        index += 1
    ) {
        const rise =
            (
                (
                    ElapsedTime * 1.8 +
                    index * 0.19
                ) %
                1
            );

        const bubbleX =
            mouthX +
            Math.sin(
                rise * 8 +
                index * 1.7
            ) *
            neckWidth *
            0.22;

        const bubbleY =
            mouthY +
            6 *
                geometry.scale +
            rise *
                30 *
                geometry.scale;

        const bubbleSize =
            (
                3.4 +
                (
                    index % 3
                ) *
                    1.1
            ) *
            (
                0.82 +
                effect.ring * 0.20
            );

        noFill();

        stroke(
            225,
            245,
            249,
            effect.alpha *
                (
                    0.26 +
                    0.34 * rise
                )
        );

        strokeWidth(1.1);

        ellipse(
            bubbleX,
            bubbleY,
            bubbleSize
        );
    }

    noStroke();
}


function isMysteryPhase() {
    return (
        gameState.phase ===
            "WAIT_MYSTERY_ROLL" ||
        gameState.phase ===
            "MYSTERY_ROLLING" ||
        gameState.phase ===
            "MYSTERY_RESULT"
    );
}


function drawMysteryOverlay() {
    const mystery =
        gameState.mystery;

    if (
        !mystery ||
        !mystery.visible
    ) {
        return;
    }

    const rouletteLayout =
        getSharedRoulettePanelLayout();

    const panel =
        rouletteLayout.panel;

    const waiting =
        gameState.phase ===
        "WAIT_MYSTERY_ROLL";

    const rolling =
        gameState.phase ===
        "MYSTERY_ROLLING";

    const result =
        gameState.phase ===
        "MYSTERY_RESULT";

    const mode =
        waiting
            ? "waiting"
            : rolling
                ? "rolling"
                : "result";

    const ingredient =
        mystery.ingredientId
            ? INGREDIENTS[
                mystery.ingredientId
            ]
            : null;

    const mysteryAccent = {
        r: 194,
        g: 142,
        b: 207,
    };

    let accent = {
        r: mysteryAccent.r,
        g: mysteryAccent.g,
        b: mysteryAccent.b,
    };

    if (
        result &&
        ingredient &&
        ingredient.color
    ) {
        accent = {
            r: Math.round(
                mysteryAccent.r *
                    0.38 +
                ingredient.color.r *
                    0.62
            ),

            g: Math.round(
                mysteryAccent.g *
                    0.38 +
                ingredient.color.g *
                    0.62
            ),

            b: Math.round(
                mysteryAccent.b *
                    0.38 +
                ingredient.color.b *
                    0.62
            ),
        };
    }

    pushMatrix();

    translate(
        panel.x,
        panel.y
    );

    drawSharedRoulettePanelBase(
        rouletteLayout,
        accent,
        gameState.language === "ja"
            ? "特殊素材"
            : "SPECIAL"
    );

    drawSharedRouletteRing(
        rouletteLayout,
        accent,
        mode,
        mystery.ringRotation || 0
    );

    if (waiting) {
        fill(
            225,
            197,
            232,
            225
        );

        noStroke();

        fontSize(
            rouletteLayout.iconSize *
            0.80
        );

        textAlign(CENTER);

        text(
            "?",
            rouletteLayout.centerX,
            rouletteLayout.centerY
        );

        drawSharedRouletteStatusText(
            rouletteLayout,
            "TAP",
            170 +
                Math.sin(
                    ElapsedTime * 7
                ) *
                45
        );

        rectMode(CORNER);
        popMatrix();
        return;
    }

    if (!ingredient) {
        rectMode(CORNER);
        popMatrix();
        return;
    }

    const rollingPulse =
        rolling
            ? 1 +
                Math.sin(
                    ElapsedTime * 21
                ) *
                0.025
            : 1;

    const iconScale =
        (
            mystery.scale ||
            1
        ) *
        rollingPulse;

    const iconSize =
        rouletteLayout.iconSize *
        iconScale;

    if (result) {
        noFill();

        stroke(
            accent.r,
            accent.g,
            accent.b,
            76
        );

        strokeWidth(4);

        ellipse(
            rouletteLayout.centerX,
            rouletteLayout.centerY,
            iconSize * 1.33
        );

        stroke(
            255,
            246,
            222,
            92
        );

        strokeWidth(1.3);

        ellipse(
            rouletteLayout.centerX,
            rouletteLayout.centerY,
            iconSize * 1.22
        );
    }

    fill(
        ingredient.color.r,
        ingredient.color.g,
        ingredient.color.b,
        rolling
            ? 190
            : 235
    );

    noStroke();

    ellipse(
        rouletteLayout.centerX,
        rouletteLayout.centerY,
        iconSize
    );

    noFill();

    stroke(
        255,
        241,
        214,
        rolling
            ? 120
            : 215
    );

    strokeWidth(
        result
            ? 2.5
            : 1.8
    );

    ellipse(
        rouletteLayout.centerX,
        rouletteLayout.centerY,
        iconSize * 1.08
    );

    noStroke();

    drawIngredientIcon(
        mystery.ingredientId,
        rouletteLayout.centerX,
        rouletteLayout.centerY,
        iconSize * 0.55,
        255
    );

    if (result) {
        stroke(
            accent.r,
            accent.g,
            accent.b,
            225
        );

        strokeWidth(2.2);

        line(
            rouletteLayout.centerX -
                iconSize * 0.34,
            rouletteLayout.centerY -
                iconSize * 0.72,
            rouletteLayout.centerX +
                iconSize * 0.34,
            rouletteLayout.centerY -
                iconSize * 0.72
        );

        noStroke();
    }

    if (rolling) {
        drawSharedRouletteStatusText(
            rouletteLayout,
            "•••",
            145
        );
    } else if (result) {
        drawSharedRouletteStatusText(
            rouletteLayout,
            ingredient[
                gameState.language
            ],
            230
        );
    }

    rectMode(CORNER);
    popMatrix();
}



function isEventRoulettePhase() {
    return (
        gameState.phase ===
            "WAIT_EVENT_ROLL" ||
        gameState.phase ===
            "EVENT_ROLLING" ||
        gameState.phase ===
            "SHOWING_EVENT_RESULT"
    );
}

function getSharedRoulettePanelLayout() {
    const panel =
        layout.cap;

    return {
        panel: panel,

        centerX:
            panel.w * 0.5,

        centerY:
            panel.h * 0.43,

        titleY:
            panel.h * 0.86,

        dividerY:
            panel.h * 0.76,

        footerY:
            panel.h * 0.12,

        iconSize:
            Math.min(
                64,
                panel.w * 0.21,
                panel.h * 0.25
            ),

        ringRadius:
            Math.min(
                54,
                panel.w * 0.18,
                panel.h * 0.21
            ),
    };
}

function drawSharedRoulettePanelBase(
    rouletteLayout,
    accent,
    title
) {
    const panel =
        rouletteLayout.panel;

    const palette =
        getGameVisualPalette();

    const type =
        getGameTypeScale();

    rectMode(CORNER);
    noStroke();

    fill(
        palette.panel.r,
        palette.panel.g,
        palette.panel.b,
        248
    );

    rect(
        4,
        4,
        panel.w - 8,
        panel.h - 8,
        13
    );

    fill(
        accent.r,
        accent.g,
        accent.b,
        24
    );

    rect(
        8,
        panel.h * 0.71,
        panel.w - 16,
        panel.h * 0.23,
        10
    );

    stroke(
        accent.r,
        accent.g,
        accent.b,
        84
    );

    strokeWidth(1.3);

    line(
        panel.w * 0.14,
        rouletteLayout.dividerY,
        panel.w * 0.86,
        rouletteLayout.dividerY
    );

    noStroke();
    setGameUIFont();

    fill(
        palette.textSecondary.r,
        palette.textSecondary.g,
        palette.textSecondary.b,
        182
    );

    fontSize(
        Math.min(
            type.sectionLabelMax,
            panel.h *
                type.sectionLabelPanelRatio
        )
    );

    textAlign(CENTER);

    text(
        title,
        rouletteLayout.centerX,
        rouletteLayout.titleY
    );
}


function drawSharedRouletteRing(
    rouletteLayout,
    accent,
    mode,
    stepRotation
) {
    const waiting =
        mode === "waiting";

    const rolling =
        mode === "rolling";

    const result =
        mode === "result";

    const hasStepRotation =
        typeof stepRotation ===
        "number";

    const pulse =
        waiting
            ? 1 +
                Math.sin(
                    ElapsedTime * 6
                ) *
                0.05
            : result
                ? 1 +
                    Math.sin(
                        ElapsedTime * 8
                    ) *
                    0.025
                : 1;

    pushMatrix();

    translate(
        rouletteLayout.centerX,
        rouletteLayout.centerY
    );

    if (hasStepRotation) {
        rotate(
            stepRotation
        );
    } else if (rolling) {
        rotate(
            ElapsedTime * 150
        );
    }

    noFill();

    stroke(
        accent.r,
        accent.g,
        accent.b,
        rolling
            ? 150
            : result
                ? 220
                : 125
    );

    strokeWidth(
        result
            ? 3
            : 2
    );

    ellipse(
        0,
        0,
        rouletteLayout.ringRadius *
            2 *
            pulse
    );

    stroke(
        255,
        238,
        205,
        rolling
            ? 105
            : result
                ? 170
                : 70
    );

    strokeWidth(1.5);

    for (
        let index = 0;
        index < 10;
        index += 1
    ) {
        const inner =
            rouletteLayout.ringRadius *
            0.82;

        const outer =
            rouletteLayout.ringRadius *
            (
                rolling
                    ? 1.02
                    : 0.96
            );

        line(
            0,
            inner,
            0,
            outer
        );

        rotate(36);
    }

    noStroke();

    popMatrix();
}


function drawSharedRouletteStatusText(
    rouletteLayout,
    value,
    alpha
) {
    const palette =
        getGameVisualPalette();

    const type =
        getGameTypeScale();

    setGameUIFont();
    noStroke();

    fill(
        palette.actionLight.r,
        palette.actionLight.g,
        palette.actionLight.b,
        alpha
    );

    fontSize(
        Math.min(
            type.helperMax,
            rouletteLayout.panel.h *
                type.helperPanelRatio
        )
    );

    textAlign(CENTER);

    text(
        value,
        rouletteLayout.centerX,
        rouletteLayout.footerY
    );
}

const drawSharedRoulettePanelBaseForBoardTerminology =
    drawSharedRoulettePanelBase;

drawSharedRoulettePanelBase = function(
    rouletteLayout,
    accent,
    title
) {
    const language =
        gameState &&
        gameState.language === "en"
            ? "en"
            : "ja";

    if (
        title === "\u7279\u6b8a\u7d20\u6750" ||
        title === "SPECIAL"
    ) {
        title =
            language === "ja"
                ? "\u8ffd\u52a0\u7d20\u6750"
                : "EXTRA INGREDIENT";
    }

    if (
        title === "\u30b9\u30c6\u30a2" ||
        title === "STIR"
    ) {
        title =
            language === "ja"
                ? "\u64b9\u62cc"
                : "MIXING";
    }

    return drawSharedRoulettePanelBaseForBoardTerminology(
        rouletteLayout,
        accent,
        title
    );
};




function isEventActionPhase() {
    return (
        gameState.phase ===
            "EVENT_WARNING" ||
        gameState.phase ===
            "ANIMATING_EVENT" ||
        gameState.phase ===
            "EVENT_FINISHED"
    );
}

function drawEventRouletteOverlay() {
    const rouletteLayout =
        getSharedRoulettePanelLayout();

    const panel =
        rouletteLayout.panel;

    const waiting =
        gameState.phase ===
        "WAIT_EVENT_ROLL";

    const rolling =
        gameState.phase ===
        "EVENT_ROLLING";

    const result =
        gameState.phase ===
        "SHOWING_EVENT_RESULT";

    const mode =
        waiting
            ? "waiting"
            : rolling
                ? "rolling"
                : "result";

    const accent = {
        r: 208,
        g: 145,
        b: 78,
    };

    pushMatrix();

    translate(
        panel.x,
        panel.y
    );

    drawSharedRoulettePanelBase(
        rouletteLayout,
        accent,
        gameState.language === "ja"
            ? "ステア"
            : "STIR"
    );

    drawSharedRouletteRing(
        rouletteLayout,
        accent,
        mode
    );

    if (waiting) {
        drawEventIcon(
            "swap",
            rouletteLayout.centerX,
            rouletteLayout.centerY,
            rouletteLayout.iconSize *
                0.88,
            235
        );

        drawSharedRouletteStatusText(
            rouletteLayout,
            "TAP",
            170 +
                Math.sin(
                    ElapsedTime * 7
                ) *
                45
        );

        rectMode(CORNER);
        popMatrix();
        return;
    }

    if (
        !gameState.eventResultData
    ) {
        rectMode(CORNER);
        popMatrix();
        return;
    }

    const eventId =
        gameState.eventResultData.id;

    const iconPulse =
        rolling
            ? 1 +
                Math.sin(
                    ElapsedTime * 22
                ) *
                0.07
            : 1.08;

    drawEventIcon(
        eventId,
        rouletteLayout.centerX,
        rouletteLayout.centerY,
        rouletteLayout.iconSize *
            iconPulse,
        255
    );

    if (rolling) {
        drawSharedRouletteStatusText(
            rouletteLayout,
            "•••",
            145
        );
    } else if (result) {
        const display =
            getEventDisplayText(
                eventId
            );

        drawSharedRouletteStatusText(
            rouletteLayout,
            display.title,
            230
        );
    }

    rectMode(CORNER);
    popMatrix();
}


function drawEventActionOverlay() {
    const eventAnim =
        gameState.eventAnim;

    if (!eventAnim) {
        return;
    }

    fill(
        0,
        0,
        0,
        eventAnim.panelMaskAlpha
    );

    noStroke();

    rectMode(CORNER);

    rect(
        layout.board.x,
        layout.board.y,
        layout.board.w,
        layout.board.h
    );

    rect(
        layout.cap.x,
        layout.cap.y,
        layout.cap.w,
        layout.cap.h
    );

    if (
        gameState.eventResultData
    ) {
        drawEventIcon(
            gameState.eventResultData.id,
            eventAnim.iconX,
            eventAnim.iconY,
            eventAnim.iconSize,
            eventAnim.iconAlpha
        );
    }
}

function getEventDisplayText(eventId) {
    const language =
        gameState &&
        gameState.language === "en"
            ? "en"
            : "ja";

    if (eventId === "flip") {
        return {
            title:
                language === "ja"
                    ? "\u3072\u3063\u304f\u308a\u8fd4\u3059"
                    : "FLIP",
            description:
                language === "ja"
                    ? "\u3072\u3063\u304f\u308a\u8fd4\u3059"
                    : "FLIP",
        };
    }

    if (eventId === "swap") {
        return {
            title:
                language === "ja"
                    ? "\u307e\u305c\u308b"
                    : "MIX",
            description:
                language === "ja"
                    ? "\u307e\u305c\u308b"
                    : "MIX",
        };
    }

    return {
        title:
            language === "ja"
                ? "\u3053\u307c\u308c"
                : "SPILL",
        description:
            language === "ja"
                ? "\u3053\u307c\u308c"
                : "SPILL",
    };
}




function drawCarbonationParticles() {
    noStroke();

    for (
        const particle of
        gameState.carbonationParticles
    ) {
        const ratio =
            Math.max(
                0,
                particle.life /
                    particle.maxLife
            );

        if (particle.burst) {
            fill(
                215,
                245,
                255,
                ratio * 230
            );
        } else {
            fill(
                220,
                248,
                255,
                ratio * 150
            );
        }

        ellipse(
            particle.x,
            particle.y,
            particle.size *
                (
                    0.65 +
                    ratio * 0.55
                )
        );
    }
}

function drawBurstFlash() {
    const burst =
        gameState.burstState;

    if (!burst) {
        return;
    }

    const geometry =
        getGlassScreenGeometry();

    const pulse =
        1 +
        Math.sin(
            ElapsedTime * 20
        ) *
            0.08;

    noFill();

    stroke(
        220,
        248,
        255,
        burst.flash * 220
    );

    strokeWidth(
        3 +
        burst.flash * 5
    );

    ellipse(
        geometry.centerX,
        geometry.centerY,
        geometry.topW *
            geometry.scale *
            1.55 *
            pulse
    );

    stroke(
        255,
        245,
        220,
        burst.flash * 120
    );

    strokeWidth(2);

    ellipse(
        geometry.centerX,
        geometry.centerY,
        geometry.topW *
            geometry.scale *
            2.1 *
            pulse
    );

    noStroke();
}

function drawBurstToken() {
    const token =
        gameState.burstToken;

    if (!token) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            token.ingredientId
        ];

    if (!ingredient) {
        return;
    }

    pushMatrix();

    translate(
        token.x,
        token.y
    );

    rotate(
        token.rotation
    );

    scale(
        token.scale,
        token.scale
    );

    fill(
        ingredient.color.r,
        ingredient.color.g,
        ingredient.color.b,
        token.alpha
    );

    noStroke();

    rectMode(CENTER);

    rect(
        0,
        0,
        42,
        18,
        4
    );

    drawIngredientIcon(
        token.ingredientId,
        0,
        0,
        15,
        token.alpha
    );

    rectMode(CORNER);

    popMatrix();
}

function drawSpilledTokens() {
    drawEventSpillDrops();

    const tokens =
        gameState.glass.spilledTokens;

    if (
        !tokens ||
        tokens.length === 0
    ) {
        return;
    }

    const panel =
        layout.glass;

    const startIndex =
        Math.max(
            0,
            tokens.length - 3
        );

    for (
        let index = startIndex;
        index < tokens.length;
        index += 1
    ) {
        const token =
            tokens[index];

        const offset =
            index -
            startIndex;

        const x =
            panel.x +
            panel.w -
            18 -
            offset * 8;

        const y =
            panel.y +
            22 +
            offset * 15;

        pushMatrix();

        translate(
            x,
            y
        );

        rotate(
            35 +
            index * 18
        );

        fill(
            INGREDIENTS[
                token.ingredientId
            ].color
        );

        rectMode(CENTER);

        rect(
            0,
            0,
            24,
            9,
            2
        );

        drawIngredientIcon(
            token.ingredientId,
            0,
            0,
            9,
            255
        );

        rectMode(CORNER);

        popMatrix();
    }
}


function drawEventSpillDrops() {
    const presentation =
        gameState.eventSpillPresentation;

    if (
        !presentation ||
        !presentation.active ||
        !presentation.startedAt
    ) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            presentation.ingredientId
        ];

    if (!ingredient) {
        presentation.active = false;
        return;
    }

    const now =
        typeof ElapsedTime !==
            "undefined"
            ? ElapsedTime
            : presentation.startedAt;

    const elapsed =
        Math.max(
            0,
            now -
                presentation.startedAt
        );

    const duration =
        Math.max(
            0.01,
            presentation.duration ||
                0.46
        );

    if (
        elapsed >
        duration + 0.22
    ) {
        presentation.active = false;
        return;
    }

    const progress =
        Math.max(
            0,
            Math.min(
                1,
                elapsed / duration
            )
        );

    const geometry =
        getBottleInspectionGeometry();

    const direction =
        presentation.direction || 1;

    const mouthX =
        geometry.centerX +
        direction *
            geometry.mouthWidth *
            geometry.scale *
            0.34;

    const mouthY =
        geometry.centerY +
        (
            geometry.neckTop -
            7
        ) *
            geometry.scale;

    noStroke();
    ellipseMode(CENTER);

    for (
        let index = 0;
        index < 3;
        index += 1
    ) {
        const delay =
            index * 0.13;

        const localProgress =
            Math.max(
                0,
                Math.min(
                    1,
                    (
                        progress -
                        delay
                    ) /
                    Math.max(
                        0.01,
                        1 - delay
                    )
                )
            );

        if (localProgress <= 0) {
            continue;
        }

        const dropX =
            mouthX +
            direction *
                (
                    9 +
                    28 * localProgress +
                    index * 5
                );

        const dropY =
            mouthY -
            8 -
            42 * localProgress -
            19 *
                localProgress *
                localProgress +
            Math.sin(
                ElapsedTime * 15 +
                index * 2.1
            ) *
                1.5;

        const dropSize =
            6 -
            index * 0.8 +
            Math.sin(
                localProgress *
                Math.PI
            ) *
                1.8;

        const dropAlpha =
            205 *
            (
                1 -
                localProgress * 0.48
            ) *
            Math.min(
                1,
                localProgress * 5
            );

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            dropAlpha * 0.30
        );

        ellipse(
            dropX +
                direction * 1.5,
            dropY - 1.5,
            dropSize * 1.65
        );

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            dropAlpha
        );

        ellipse(
            dropX,
            dropY,
            dropSize
        );

        fill(
            255,
            239,
            205,
            dropAlpha * 0.48
        );

        ellipse(
            dropX -
                direction *
                    dropSize * 0.18,
            dropY +
                dropSize * 0.18,
            Math.max(
                1.2,
                dropSize * 0.28
            )
        );
    }

    noStroke();
}


function drawCapacitySpillTokenOverlay() {
    const flow =
        gameState.capacitySpillFlow;

    if (
        !flow ||
        !flow.active ||
        flow.stage !== "spilling" ||
        !flow.spilled
    ) {
        return;
    }

    const ingredient =
        INGREDIENTS[
            flow.spilled.ingredientId
        ];

    if (!ingredient) {
        return;
    }

    const rawProgress =
        Math.max(
            0,
            Math.min(
                1,
                flow.visualProgress || 0
            )
        );

    const visibleProgress =
        Math.max(
            0,
            Math.min(
                1,
                (
                    rawProgress -
                    0.10
                ) /
                    0.90
            )
        );

    if (
        visibleProgress <= 0
    ) {
        return;
    }

    const t =
        1 -
        Math.pow(
            1 - visibleProgress,
            2
        );

    const geometry =
        getBottleInspectionGeometry();

    const startY =
        geometry.centerY +
        getGlassSlotLocalY(
            0
        ) *
            geometry.scale;

    const bottleEdgeX =
        geometry.centerX +
        flow.spillDirection *
            geometry.bodyWidth *
            geometry.scale *
            0.34;

    const travelDistance =
        Math.min(
            94,
            layout.glass.w *
                0.52
        );

    const x =
        bottleEdgeX +
        flow.spillDirection *
            (
                8 +
                travelDistance *
                    t
            );

    const y =
        startY -
        8 -
        26 *
            t +
        20 *
            t *
            t;

    const alpha =
        255 *
        Math.min(
            1,
            visibleProgress *
                4
        ) *
        (
            1 -
            t * 0.14
        );

    pushMatrix();

    translate(
        x,
        y
    );

    rotate(
        flow.spillDirection *
            (
                18 +
                42 * t
            )
    );

    scale(
        0.86 +
            0.10 *
                Math.sin(
                    t *
                    Math.PI
                )
    );

    noStroke();

    fill(
        8,
        5,
        3,
        alpha * 0.28
    );

    ellipse(
        5,
        -12,
        43,
        11
    );

    fill(
        ingredient.color.r,
        ingredient.color.g,
        ingredient.color.b,
        alpha
    );

    rectMode(CENTER);

    rect(
        0,
        0,
        42,
        18,
        4
    );

    noFill();

    stroke(
        255,
        228,
        174,
        alpha * 0.68
    );

    strokeWidth(1.3);

    rect(
        0,
        0,
        42,
        18,
        4
    );

    noStroke();

    drawIngredientIcon(
        flow.spilled.ingredientId,
        0,
        0,
        15,
        alpha
    );

    rectMode(CORNER);

    popMatrix();

    const trailCount =
        3;

    for (
        let index = 0;
        index < trailCount;
        index += 1
    ) {
        const trailRatio =
            (
                index + 1
            ) /
            (
                trailCount + 1
            );

        const trailX =
            bottleEdgeX +
            flow.spillDirection *
                (
                    8 +
                    travelDistance *
                        t *
                        trailRatio
                );

        const trailY =
            startY -
            8 -
            26 *
                t *
                trailRatio;

        fill(
            ingredient.color.r,
            ingredient.color.g,
            ingredient.color.b,
            alpha *
                (
                    0.22 -
                    index * 0.05
                )
        );

        noStroke();

        ellipse(
            trailX,
            trailY,
            4 -
                index * 0.7
        );
    }

    noStroke();
}


