function drawCapShotResultBadge(
    panel,
    board,
    cap,
    physics,
    branchRelevant,
    branchIndex
) {
    const badgeW =
        Math.min(
            board.radius *
                1.12,
            86
        );

    const badgeH =
        Math.min(
            board.radius *
                0.44,
            42
        );

    const badgeX =
        board.centerX;

    const stopFlash =
        physics &&
        physics.stopFlash !==
            undefined
            ? Math.max(
                0,
                Math.min(
                    1,
                    physics.stopFlash
                )
            )
            : 0;

    const stopRing =
        physics &&
        physics.stopRing !==
            undefined
            ? Math.max(
                0,
                Math.min(
                    1,
                    physics.stopRing
                )
            )
            : 1;

    const introMotion =
        Math.max(
            stopFlash,
            1 - stopRing
        );

    const badgeScale =
        1 -
        introMotion * 0.055;

    const badgeYOffset =
        introMotion * 6;

    const badgeY =
        panel.h * 0.14 +
        badgeYOffset;

    const badgeAlpha =
        224 +
        (
            1 -
            introMotion
        ) *
            12;

    rectMode(CENTER);

    fill(
        21,
        15,
        14,
        badgeAlpha
    );

    rect(
        badgeX,
        badgeY,
        badgeW *
            badgeScale,
        badgeH *
            badgeScale,
        badgeH *
            0.40
    );

    noFill();

    stroke(
        244,
        198,
        112,
        214 +
            (
                1 -
                introMotion
            ) *
                20
    );

    strokeWidth(
        2.2 -
        introMotion * 0.3
    );

    rect(
        badgeX,
        badgeY,
        badgeW *
            badgeScale,
        badgeH *
            badgeScale,
        badgeH *
            0.40
    );

    noStroke();

    fontSize(
        badgeH *
            0.64
    );

    let directionResult =
        String(
            cap.distance
        );

    if (branchRelevant) {
        directionResult =
            branchIndex === 0
                ? "← " +
                    String(
                        cap.distance
                    )
                : String(
                    cap.distance
                ) +
                    " →";
    }

    drawStrongNumberText(
        directionResult,
        badgeX,
        badgeY,
        255,
        238,
        198,
        255,
        96,
        0.84
    );

    rectMode(CORNER);
}


function drawCapPressureGauge(
    panel,
    power,
    locked,
    sliding
) {
    const gaugeLayout =
        getMainGaugeLayout(
            panel
        );

    const centerX =
        gaugeLayout.centerX;

    const centerY =
        gaugeLayout.centerY;

    const radius =
        gaugeLayout.radius;

    const gaugeFrameCenterY =
        centerY +
        radius * 0.20;

    const gaugeFrameHeight =
        radius * 1.78;

    const startAngle = 205;
    const endAngle = -25;

    const language =
        gameState &&
        gameState.language === "en"
            ? "en"
            : "ja";

    rectMode(CORNER);
    noStroke();

    fill(
        31,
        23,
        21,
        248
    );

    rect(
        4,
        4,
        panel.w - 8,
        panel.h - 8,
        13
    );

    fill(
        208,
        145,
        78,
        20
    );

    rect(
        8,
        panel.h * 0.71,
        panel.w - 16,
        panel.h * 0.23,
        10
    );

    noStroke();

    if (
        typeof setGameUIFont ===
        "function"
    ) {
        setGameUIFont();
    }

    fill(
        235,
        217,
        190,
        178
    );

    fontSize(
        Math.min(
            13,
            panel.h * 0.052
        )
    );

    textAlign(CENTER);

    text(
        language === "ja"
            ? "å§å"
            : "STARTING PRESSURE",
        panel.w * 0.5,
        panel.h * 0.86
    );

    noStroke();

    fill(
        12,
        9,
        9,
        122
    );

    rectMode(CENTER);

    rect(
        centerX,
        gaugeFrameCenterY,
        radius * 2.42,
        gaugeFrameHeight,
        16
    );

    noFill();

    stroke(
        106,
        82,
        67,
        140
    );

    strokeWidth(2);

    rect(
        centerX,
        gaugeFrameCenterY,
        radius * 2.42,
        gaugeFrameHeight,
        16
    );

    const zones = [
        {
            start: 0,
            end:
                CONFIG.capPowerZone1End,
            color:
                color(
                    114,
                    118,
                    76
                ),
        },
        {
            start:
                CONFIG.capPowerZone1End,
            end:
                CONFIG.capPowerZone2End,
            color:
                color(
                    183,
                    133,
                    61
                ),
        },
        {
            start:
                CONFIG.capPowerZone2End,
            end:
                CONFIG.capPowerZone3End,
            color:
                color(
                    200,
                    105,
                    54
                ),
        },
        {
            start:
                CONFIG.capPowerZone3End,
            end: 1,
            color:
                color(
                    216,
                    72,
                    62
                ),
        },
    ];

    for (
        let index = 0;
        index < zones.length;
        index += 1
    ) {
        const zone =
            zones[index];

        drawCapPressureArc(
            centerX,
            centerY,
            radius,
            startAngle,
            endAngle,
            zone.start,
            zone.end,
            zone.color,
            power >= zone.start &&
                power < zone.end
        );
    }

    for (
        let index = 0;
        index <= 16;
        index += 1
    ) {
        const ratio =
            index / 16;

        const angle =
            startAngle +
            (
                endAngle -
                startAngle
            ) *
            ratio;

        const radians =
            angle *
            Math.PI /
            180;

        const major =
            index % 4 === 0;

        const innerRadius =
            radius *
            (
                major
                    ? 0.69
                    : 0.78
            );

        const outerRadius =
            radius * 0.91;

        stroke(
            232,
            214,
            184,
            major
                ? 150
                : 62
        );

        strokeWidth(
            major
                ? 3
                : 1.2
        );

        line(
            centerX +
                Math.cos(
                    radians
                ) *
                innerRadius,
            centerY +
                Math.sin(
                    radians
                ) *
                innerRadius,
            centerX +
                Math.cos(
                    radians
                ) *
                outerRadius,
            centerY +
                Math.sin(
                    radians
                ) *
                outerRadius
        );
    }

    const baseAngle =
        startAngle +
        (
            endAngle -
            startAngle
        ) *
        power;

    let jitter = 0;

    if (sliding) {
        jitter =
            Math.sin(
                ElapsedTime * 48
            ) *
            2.0;
    } else if (
        power >=
        CONFIG.capPowerZone3End
    ) {
        jitter =
            Math.sin(
                ElapsedTime * 34
            ) *
                1.1;
    }

    const needleAngle =
        (
            baseAngle +
            jitter
        ) *
        Math.PI /
        180;

    const needleLength =
        radius * 0.68;

    stroke(
        20,
        13,
        12,
        170
    );

    strokeWidth(7);

    line(
        centerX + 2,
        centerY - 2,
        centerX +
            Math.cos(
                needleAngle
            ) *
            needleLength +
            2,
        centerY +
            Math.sin(
                needleAngle
            ) *
            needleLength -
            2
    );

    if (
        power >=
        CONFIG.capPowerZone3End
    ) {
        stroke(
            236,
            82,
            70,
            245
        );
    } else if (locked) {
        stroke(
            255,
            220,
            145,
            245
        );
    } else {
        stroke(
            238,
            222,
            188,
            235
        );
    }

    strokeWidth(3.2);

    line(
        centerX,
        centerY,
        centerX +
            Math.cos(
                needleAngle
            ) *
            needleLength,
        centerY +
            Math.sin(
                needleAngle
            ) *
            needleLength
    );

    noStroke();

    fill(
        35,
        27,
        24,
        255
    );

    ellipse(
        centerX,
        centerY,
        radius * 0.25
    );

    fill(
        205,
        180,
        144,
        255
    );

    ellipse(
        centerX,
        centerY,
        radius * 0.12
    );

    fill(
        224,
        198,
        152,
        145
    );

    fontSize(
        Math.min(
            12,
            panel.h * 0.045
        )
    );

    textAlign(CENTER);

    text(
        sliding
            ? (
                language === "ja"
                    ? "ã­ãã¯"
                    : "LOCK"
            )
            : (
                language === "ja"
                    ? "ã¿ãã"
                    : "TAP"
            ),
        centerX,
        panel.h * 0.14
    );

    rectMode(CORNER);
}

var colaRollDrawCapPressureGaugeBase =
    drawCapPressureGauge;

drawCapPressureGauge = function(
    panel,
    power,
    locked,
    sliding
) {
    if (
        !gameState ||
        gameState.language === "en"
    ) {
        return colaRollDrawCapPressureGaugeBase(
            panel,
            power,
            locked,
            sliding
        );
    }

    var originalText = text;
    var japaneseLabelIndex = 0;

    text = function(
        value,
        x,
        y
    ) {
        if (
            typeof value === "string" &&
            /[^\x00-\x7f]/.test(value)
        ) {
            if (japaneseLabelIndex === 0) {
                value = "\u5727\u529b";
            } else if (japaneseLabelIndex === 1) {
                value = sliding
                    ? "\u30ed\u30c3\u30af"
                    : "\u30bf\u30c3\u30d7";
            }

            japaneseLabelIndex += 1;
        }

        return originalText(
            value,
            x,
            y
        );
    };

    try {
        return colaRollDrawCapPressureGaugeBase(
            panel,
            power,
            locked,
            sliding
        );
    } finally {
        text = originalText;
    }
};




function drawCapPressureArc(
    centerX,
    centerY,
    radius,
    startAngle,
    endAngle,
    rangeStart,
    rangeEnd,
    zoneColor,
    active
) {
    const segmentCount =
        Math.max(
            1,
            Math.ceil(
                (
                    rangeEnd -
                    rangeStart
                ) *
                12
            )
        );

    const arcRadius =
        radius * 0.96;

    stroke(
        zoneColor.r,
        zoneColor.g,
        zoneColor.b,
        active
            ? 218
            : 92
    );

    strokeWidth(
        active
            ? 5
            : 3.2
    );

    for (
        let index = 0;
        index <
        segmentCount;
        index += 1
    ) {
        const ratio1 =
            rangeStart +
            (
                rangeEnd -
                rangeStart
            ) *
            (
                index /
                segmentCount
            );

        const ratio2 =
            rangeStart +
            (
                rangeEnd -
                rangeStart
            ) *
            (
                (
                    index +
                    1
                ) /
                segmentCount
            );

        const angle1 =
            (
                startAngle +
                (
                    endAngle -
                    startAngle
                ) *
                ratio1
            ) *
            Math.PI /
            180;

        const angle2 =
            (
                startAngle +
                (
                    endAngle -
                    startAngle
                ) *
                ratio2
            ) *
            Math.PI /
            180;

        line(
            centerX +
                Math.cos(
                    angle1
                ) *
                arcRadius,
            centerY +
                Math.sin(
                    angle1
                ) *
                arcRadius,
            centerX +
                Math.cos(
                    angle2
                ) *
                arcRadius,
            centerY +
                Math.sin(
                    angle2
                ) *
                arcRadius
        );
    }

    noStroke();
}


function normalizeMultipleGarnishList(
    values,
    fallback
) {
    const allowed = {
        lemon: true,
        cherry: true,
    };

    const seen = {};

    const add =
        function(value) {
            if (
                allowed[value]
            ) {
                seen[value] =
                    true;
            }
        };

    if (
        Array.isArray(
            values
        )
    ) {
        for (
            const value of
            values
        ) {
            add(value);
        }
    } else if (
        values &&
        typeof values === "object"
    ) {
        for (
            const value of
            Object.keys(values)
        ) {
            if (values[value]) {
                add(value);
            }
        }
    } else {
        add(values);
    }

    add(fallback);

    const result = [];

    if (seen.lemon) {
        result.push(
            "lemon"
        );
    }

    if (seen.cherry) {
        result.push(
            "cherry"
        );
    }

    return result;
}

function getCollectedGarnishes() {
    if (
        !gameState ||
        !gameState.glass
    ) {
        return [];
    }

    return normalizeMultipleGarnishList(
        gameState.glass.garnishes,
        gameState.glass.garnish
    );
}

function getResultGarnishes(
    result
) {
    const source =
        result ||
        gameState.resultData ||
        {};

    return normalizeMultipleGarnishList(
        source.garnishes,
        source.garnish
    );
}

function getPrimaryGarnish(
    garnishes
) {
    if (
        garnishes.indexOf(
            "cherry"
        ) >= 0
    ) {
        return "cherry";
    }

    if (
        garnishes.indexOf(
            "lemon"
        ) >= 0
    ) {
        return "lemon";
    }

    return null;
}

function addCollectedGarnish(
    garnish
) {
    if (
        !gameState ||
        !gameState.glass ||
        (
            garnish !== "lemon" &&
            garnish !== "cherry"
        )
    ) {
        return;
    }

    const current =
        getCollectedGarnishes();

    if (
        current.indexOf(
            garnish
        ) < 0
    ) {
        current.push(
            garnish
        );
    }

    gameState.glass.garnishes = {
        lemon:
            current.indexOf(
                "lemon"
            ) >= 0,

        cherry:
            current.indexOf(
                "cherry"
            ) >= 0,
    };

    gameState.glass.garnish =
        garnish;
}

function getVisibleBottleGarnishes() {
    const preview =
        normalizeMultipleGarnishList(
            gameState.previewGarnishes,
            gameState.previewGarnishTray
        );

    const collected =
        getCollectedGarnishes();

    const merged =
        normalizeMultipleGarnishList(
            preview.concat(
                collected
            ),
            null
        );

    const effect =
        gameState.ingredientGetEffect;

    if (
        effect &&
        effect.visible &&
        effect.kind === "garnish" &&
        effect.garnish &&
        !effect.hideTrayPreview
    ) {
        return normalizeMultipleGarnishList(
            merged.concat(
                [
                    effect.garnish,
                ]
            ),
            null
        );
    }

    return merged;
}


function startGarnishTrayReaction(
    garnish,
    fromArrival
) {
    const arrivalSync =
        gameState.garnishTrayArrivalSync;

    if (
        !fromArrival &&
        arrivalSync &&
        arrivalSync.garnish ===
            garnish &&
        ElapsedTime <
            arrivalSync.blockUntil
    ) {
        return;
    }

    if (
        !gameState.garnishTrayReaction
    ) {
        gameState.garnishTrayReaction = {
            active: false,
            garnish: null,
            scale: 1,
            lift: 0,
            glow: 0,
        };
    }

    if (fromArrival) {
        gameState.garnishTrayArrivalSync = {
            garnish: garnish,
            blockUntil:
                ElapsedTime + 1.4,
        };
    }

    const reaction =
        gameState.garnishTrayReaction;

    reaction.active = true;
    reaction.garnish = garnish;
    reaction.scale = 0.62;
    reaction.lift = 0;
    reaction.glow = 0;

    if (
        typeof tween === "undefined" ||
        !tween ||
        !tween.easing
    ) {
        reaction.active = false;
        reaction.garnish = null;
        reaction.scale = 1;
        reaction.lift = 0;
        reaction.glow = 0;
        return;
    }

    tween(
        0.14,
        reaction,
        {
            scale: 1.12,
            lift: 2,
            glow: 1,
        },
        tween.easing.quadOut,
        function() {
            tween(
                0.20,
                reaction,
                {
                    scale: 1,
                    lift: 0,
                    glow: 0,
                },
                tween.easing.bounceOut,
                function() {
                    reaction.active = false;
                    reaction.garnish = null;
                    reaction.scale = 1;
                    reaction.lift = 0;
                    reaction.glow = 0;
                }
            );
        }
    );
}



const startGarnishGetEffectBaseForMultipleGarnishes =
    startGarnishGetEffect;



const showGarnishRevealBaseForMultipleGarnishes =
    showGarnishReveal;

showGarnishReveal = function(
    garnish,
    onComplete
) {
    showGarnishRevealBaseForMultipleGarnishes(
        garnish,
        function() {
            addCollectedGarnish(
                garnish
            );

            if (onComplete) {
                onComplete();
            }
        }
    );
};

const drawBottleInspectionPanelBaseForMultipleGarnishes =
    drawBottleInspectionPanel;

drawBottleInspectionPanel = function() {
    const glass =
        gameState &&
        gameState.glass
            ? gameState.glass
            : null;

    const storedGarnish =
        glass
            ? glass.garnish
            : null;

    const storedPreviewGarnishes =
        gameState.previewGarnishes;

    if (glass) {
        gameState.previewGarnishes =
            getCollectedGarnishes();

        glass.garnish =
            null;
    }

    drawBottleInspectionPanelBaseForMultipleGarnishes();

    if (glass) {
        glass.garnish =
            storedGarnish;

        gameState.previewGarnishes =
            storedPreviewGarnishes;
    }
};



getFinishedColaFeatureIds = function() {
    const result =
        gameState.resultData || {};

    const features =
        getResultGarnishes(
            result
        );

    const counts =
        result.ingredientCounts ||
        {};

    const candidates = [
        "secret_syrup",
        "lemon_peel",
        "herb",
        "cinnamon",
        "ginger",
        "vanilla",
        "caramel",
        "brown_sugar",
        "thick_syrup",
    ];

    candidates.sort(
        function(a, b) {
            const countA =
                counts[a] || 0;

            const countB =
                counts[b] || 0;

            if (
                countA !==
                countB
            ) {
                return (
                    countB -
                    countA
                );
            }

            return 0;
        }
    );

    for (
        const candidate of
        candidates
    ) {
        if (
            features.length >= 2
        ) {
            break;
        }

        if (
            (
                counts[candidate] ||
                0
            ) <= 0
        ) {
            continue;
        }

        if (
            candidate ===
                "lemon_peel" &&
            features.indexOf(
                "lemon"
            ) >= 0
        ) {
            continue;
        }

        features.push(
            candidate
        );
    }

    if (
        features.length === 0 &&
        result.topIngredientId &&
        result.topIngredientId !==
            "base_syrup" &&
        result.topIngredientId !==
            "ice"
    ) {
        features.push(
            result.topIngredientId
        );
    }

    return features.slice(
        0,
        2
    );
};

drawResultStillGarnishTray = function(
    glassX,
    glassY,
    glassScale,
    alpha
) {
    const result =
        gameState.resultData || {};

    const garnishes =
        getResultGarnishes(
            result
        );

    if (
        garnishes.length <= 0 ||
        getResultGlassDrinkKind() !==
            "none"
    ) {
        return;
    }

    const portrait =
        HEIGHT > WIDTH;

    const bottleToGlassDistance =
        portrait
            ? WIDTH * 0.265
            : WIDTH * 0.16;

    const bottleX =
        glassX -
        bottleToGlassDistance;

    const bottleScale =
        portrait
            ? Math.min(
                0.78,
                WIDTH / 490
            )
            : Math.min(
                0.78,
                HEIGHT / 520
            );

    const bottleBottomY =
        glassY -
        115 *
            glassScale;

    const isDouble =
        garnishes.length >= 2;

    const dishW =
        (
            isDouble
                ? 66
                : 54
        ) *
        bottleScale;

    const dishH =
        (
            isDouble
                ? 14
                : 12
        ) *
        bottleScale;

    const dishX =
        bottleX -
        (
            isDouble
                ? 47
                : 43
        ) *
        bottleScale;

    const dishY =
        bottleBottomY +
        dishH * 0.5;

    noStroke();

    fill(
        8,
        5,
        4,
        alpha * 0.30
    );

    ellipse(
        dishX + 2,
        dishY -
            dishH * 0.58,
        dishW * 0.92,
        dishH * 0.74
    );

    fill(
        36,
        23,
        16,
        alpha * 0.96
    );

    ellipse(
        dishX,
        dishY,
        dishW,
        dishH
    );

    noFill();

    stroke(
        227,
        179,
        105,
        alpha * 0.76
    );

    strokeWidth(
        Math.max(
            1,
            1.35 * bottleScale
        )
    );

    ellipse(
        dishX,
        dishY,
        dishW,
        dishH
    );

    noStroke();

    fill(
        255,
        237,
        198,
        alpha * 0.16
    );

    ellipse(
        dishX -
            dishW * 0.08,
        dishY +
            dishH * 0.12,
        dishW * 0.58,
        dishH * 0.34
    );

    const itemOffsets =
        isDouble
            ? [
                -dishW * 0.21,
                dishW * 0.21,
            ]
            : [0];

    for (
        let index = 0;
        index < garnishes.length;
        index += 1
    ) {
        const garnish =
            garnishes[index];

        const garnishSize =
            (
                garnish === "cherry"
                    ? 13
                    : 14
            ) *
            bottleScale;

        drawGarnishSymbol(
            garnish,
            dishX +
                itemOffsets[index],
            dishY +
                dishH * 0.42,
            garnishSize,
            alpha,
            garnish === "cherry"
                ? -16
                : 10
        );
    }

    noStroke();
    rectMode(CORNER);
    ellipseMode(CENTER);
};

function drawGlass(x, y, s) {
    pushMatrix();
    translate(x, y);
    scale(s);

    const slotH = 45;

    const glassH =
        slotH *
            CONFIG.glassCapacity +
        10;

    const topW = 130;
    const bottomW = 100;

    const pressureRatio =
        CONFIG.pressureMax > 0
            ? gameState.glass.pressure /
                CONFIG.pressureMax
            : 0;

    const eventAction =
        isEventActionPhase();

    const useAnimatedTransforms =
        shouldUseGlassTokenTransforms();

    rectMode(CENTER);
    noStroke();

    fill(
        255,
        244,
        232,
        8
    );

    rect(
        0,
        0,
        topW * 0.93,
        glassH * 0.95,
        12
    );

    fill(
        80,
        38,
        20,
        28
    );

    rect(
        0,
        -glassH * 0.03,
        topW * 0.80,
        glassH * 0.88,
        12
    );

    for (
        let index = 0;
        index <
            gameState.glass.slots.length;
        index += 1
    ) {
        const token =
            gameState.glass.slots[
                index
            ];

        const baseY =
            getGlassSlotLocalY(
                index
            );

        const tokenY =
            useAnimatedTransforms &&
            token.drawY !== undefined
                ? token.drawY
                : baseY;

        const tokenX =
            useAnimatedTransforms &&
            token.drawX !== undefined
                ? token.drawX
                : 0;

        const tokenRotation =
            useAnimatedTransforms &&
            token.rot !== undefined
                ? token.rot
                : 0;

        const rawRatio =
            (
                tokenY +
                glassH / 2
            ) /
            glassH;

        const ratio =
            Math.max(
                0,
                Math.min(
                    1,
                    rawRatio
                )
            );

        const currentW =
            bottomW +
            (
                topW -
                bottomW
            ) *
                ratio -
            10;

        const isTop =
            index ===
            gameState.glass.slots.length -
                1;

        let isEventTarget =
            false;

        let isEventDimmed =
            false;

        if (
            eventAction &&
            gameState.eventResultData
        ) {
            const eventId =
                gameState.eventResultData.id;

            if (eventId === "flip") {
                if (
                    index === 0 ||
                    index ===
                        gameState.glass.slots.length -
                            1
                ) {
                    isEventTarget =
                        true;
                }
            } else if (
                eventId === "swap"
            ) {
                if (
                    token ===
                        gameState.eventTarget1 ||
                    token ===
                        gameState.eventTarget2
                ) {
                    isEventTarget =
                        true;
                } else {
                    isEventDimmed =
                        true;
                }
            } else if (
                eventId === "spill"
            ) {
                if (
                    token ===
                    gameState.eventTarget1
                ) {
                    isEventTarget =
                        true;
                } else {
                    isEventDimmed =
                        true;
                }
            }
        }

        const alpha =
            isEventDimmed
                ? 92
                : 255;

        const layerHeight =
            slotH - 6;

        pushMatrix();

        translate(
            tokenX,
            tokenY
        );

        rotate(
            tokenRotation
        );

        rectMode(CENTER);

        drawColaLayer(
            token.ingredientId,
            currentW,
            layerHeight,
            alpha,
            isTop,
            index,
            pressureRatio
        );

        if (
            isTop &&
            !eventAction
        ) {
            noFill();

            stroke(
                255,
                247,
                220,
                90 +
                    Math.sin(
                        ElapsedTime * 8
                    ) *
                        25
            );

            strokeWidth(2);

            ellipse(
                0,
                layerHeight * 0.36,
                currentW * 0.94,
                Math.max(
                    8,
                    layerHeight * 0.26
                )
            );

            noStroke();
        }

        if (
            isEventTarget &&
            (
                gameState.phase ===
                    "EVENT_WARNING" ||
                gameState.phase ===
                    "EVENT_FINISHED"
            )
        ) {
            noFill();

            stroke(
                255,
                245,
                185,
                190 +
                    Math.sin(
                        ElapsedTime * 15
                    ) *
                        40
            );

            strokeWidth(3);

            rect(
                0,
                0,
                currentW + 4,
                layerHeight + 4,
                7
            );

            noStroke();
        }

        let iconSize = 19;

        if (
            isTop &&
            !eventAction
        ) {
            iconSize +=
                Math.sin(
                    ElapsedTime * 4
                ) *
                1.5;
        }

        if (isEventTarget) {
            iconSize *= 1.08;
        }

        drawIngredientIcon(
            token.ingredientId,
            0,
            -1,
            iconSize,
            alpha * 0.88
        );

        popMatrix();
    }

    stroke(
        245,
        238,
        228,
        125
    );

    strokeWidth(4);

    line(
        -topW / 2,
        glassH / 2,
        -bottomW / 2,
        -glassH / 2
    );

    line(
        topW / 2,
        glassH / 2,
        bottomW / 2,
        -glassH / 2
    );

    line(
        -bottomW / 2,
        -glassH / 2,
        bottomW / 2,
        -glassH / 2
    );

    stroke(
        255,
        248,
        235,
        42
    );

    strokeWidth(2);

    line(
        -topW * 0.24,
        glassH * 0.44,
        -bottomW * 0.18,
        -glassH * 0.40
    );

    stroke(
        255,
        248,
        235,
        20
    );

    line(
        -topW * 0.18,
        glassH * 0.36,
        -bottomW * 0.12,
        -glassH * 0.34
    );

    stroke(
        255,
        255,
        255,
        14
    );

    line(
        topW * 0.20,
        glassH * 0.28,
        bottomW * 0.12,
        -glassH * 0.24
    );

    stroke(
        245,
        238,
        228,
        18
    );

    strokeWidth(2);

    for (
        let index = 1;
        index <
            CONFIG.glassCapacity;
        index += 1
    ) {
        const slotY =
            -glassH / 2 +
            5 +
            index * slotH;

        const ratio =
            index /
            CONFIG.glassCapacity;

        const currentW =
            bottomW +
            (
                topW -
                bottomW
            ) *
                ratio;

        line(
            -currentW / 2,
            slotY,
            currentW / 2,
            slotY
        );
    }

    noStroke();

    fill(
        255,
        255,
        255,
        10
    );

    ellipse(
        0,
        glassH / 2 + 4,
        topW * 0.78,
        12
    );

    const pressureY =
        -glassH / 2 -
        20;

    for (
        let index = 1;
        index <=
            CONFIG.pressureMax;
        index += 1
    ) {
        if (
            index <=
            gameState.glass.pressure
        ) {
            fill(
                170,
                224,
                245,
                210
            );
        } else {
            fill(
                105,
                96,
                92,
                72
            );
        }

        ellipse(
            -30 +
                index * 12,
            pressureY,
            6
        );
    }

    rectMode(CORNER);
    popMatrix();
}

function drawGameplayCounterBehindAll() {
    const geometry =
        getBottleInspectionGeometry();

    const bottleBottomY =
        geometry.centerY +
        geometry.bodyBottom *
            geometry.scale;

    const left = 10;
    const right =
        WIDTH - 10;

    const counterW =
        right - left;

    /*
     * 瓶の足元に合わせたカウンター上面。
     * これは背景なので、この後に描かれる
     * 瓶・ゲージ・盤面より必ず後ろになる。
     */
    const topY =
        bottleBottomY - 8;

    const topH = 20;
    const frontH =
        Math.max(
            24,
            topY - 4
        );

    rectMode(CORNER);
    noStroke();

    /*
     * 前面
     */
    fill(
        52,
        30,
        18,
        248
    );

    rect(
        left,
        0,
        counterW,
        frontH,
        12
    );

    /*
     * 上面
     */
    fill(
        116,
        69,
        40,
        252
    );

    rect(
        left,
        topY - 2,
        counterW,
        topH,
        12
    );

    /*
     * 上面の奥側。
     * 上面と前面を分けて立体感を出す。
     */
    fill(
        70,
        41,
        25,
        72
    );

    rect(
        left,
        topY - 1,
        counterW,
        6,
        4
    );

    /*
     * 上面の反射
     */
    fill(
        255,
        226,
        180,
        32
    );

    rect(
        left +
            counterW * 0.06,
        topY +
            topH * 0.55,
        counterW * 0.35,
        2.5,
        2
    );

    fill(
        255,
        226,
        180,
        17
    );

    rect(
        left +
            counterW * 0.55,
        topY +
            topH * 0.55,
        counterW * 0.22,
        2,
        2
    );

    /*
     * 前面の薄い木目
     */
    stroke(
        27,
        15,
        9,
        28
    );

    strokeWidth(1);

    line(
        left +
            counterW * 0.07,
        frontH * 0.58,
        left +
            counterW * 0.25,
        frontH * 0.58
    );

    line(
        left +
            counterW * 0.34,
        frontH * 0.36,
        left +
            counterW * 0.56,
        frontH * 0.36
    );

    line(
        left +
            counterW * 0.67,
        frontH * 0.52,
        left +
            counterW * 0.88,
        frontH * 0.52
    );

    rectMode(CORNER);
    noStroke();
}


/*
 * これまでの途中版の机描画経路を止める。
 * drawPreviewScreen や瓶パネル内から呼ばれても
 * もう何も描かない。
 */
drawGameplayBackCounter =
    function() {};

drawBottleWorktable =
    function() {};

drawCapPanelCounterMask =
    function() {};


/*
 * 机を後から描いてしまう古い preview 側の経路を切る。
 */
drawPreviewScreen = function() {
    drawBoardPanel();
    drawBoardStationActivation();
    drawExactStopEffect();

    const capPanelHidden =
        gameState.phase === "MOVING" ||
        gameState.phase ===
            "MOVE_COUNT_TICK" ||
        gameState.phase ===
            "MOVE_COUNT_ZERO" ||
        gameState.phase === "LANDING";

    if (!capPanelHidden) {
        drawCapPanel();
    }

    const storedGarnish =
        gameState.glass.garnish;

    gameState.previewGarnishTray =
        storedGarnish;

    gameState.glass.garnish =
        null;

    drawBottleInspectionPanel();

    gameState.glass.garnish =
        storedGarnish;

    gameState.previewGarnishTray =
        null;

    drawCapacitySpillTokenOverlay();
    drawBottleShakeRig();
    drawBottleChillIndicator();

    if (
        typeof drawBottleCoolingFog ===
        "function"
    ) {
        drawBottleCoolingFog();
    }

    drawBottleCoolingEffect();
    drawLandingIngredientSource();
    drawFlyingIngredient();
    drawBurstFlash();
    drawCarbonationParticles();
    drawBurstToken();
    drawSpilledTokens();
    drawGlassFullMessage();
    drawMoveCounter();
    drawCapSnapEffect();
    drawLanguageButton();
    drawIngredientGetBackdrop();
    drawIngredientGetEffect();

    if (isEventRoulettePhase()) {
        drawEventRouletteOverlay();
    }

    if (isEventActionPhase()) {
        drawEventActionOverlay();
    }

    if (isMysteryPhase()) {
        drawMysteryOverlay();
    }

    if (
        gameState.phase ===
        "GOAL_ARRIVAL"
    ) {
        drawGoalArrivalOverlay();
    }
};



