function getRareColaTopFlavorIngredientId(
    result
) {
    if (
        !result ||
        !result.ingredientIds ||
        result.ingredientIds.length <= 0
    ) {
        return null;
    }

    const structuralIngredientIds = [
        "ice",
        "base_syrup",
        "thick_syrup",
    ];

    for (
        let index =
            result.ingredientIds.length - 1;
        index >= 0;
        index -= 1
    ) {
        const ingredientId =
            result.ingredientIds[
                index
            ];

        if (
            structuralIngredientIds.indexOf(
                ingredientId
            ) >= 0
        ) {
            continue;
        }

        return ingredientId;
    }

    return null;
}


function hasColaMaturityBase() {
    if (
        !gameState ||
        !gameState.glass ||
        !gameState.glass.slots
    ) {
        return false;
    }

    const baseIds = [
        "base_syrup",
        "thick_syrup",
        "brown_sugar",
        "secret_syrup",
        "caramel",
    ];

    for (
        const token of
        gameState.glass.slots
    ) {
        if (
            token &&
            baseIds.indexOf(
                token.ingredientId
            ) >= 0
        ) {
            return true;
        }
    }

    return false;
}

function advanceColaMaturityForShot() {
    if (
        !gameState ||
        !hasColaMaturityBase()
    ) {
        return;
    }

    if (
        typeof gameState.maturity !==
        "number"
    ) {
        gameState.maturity =
            0;
    }

    if (
        typeof gameState.maturityTurns !==
        "number"
    ) {
        gameState.maturityTurns =
            0;
    }

    gameState.maturityTurns +=
        1;

    gameState.maturity =
        Math.min(
            COLA_MATURITY_MAX,
            gameState.maturity + 1
        );

    gameState.maturityPulse =
        1;

    tween(
        0.28,
        gameState,
        {
            maturityPulse: 0,
        },
        tween.easing.quadOut
    );
}

function getBaseRareColaRecipe(
    result
) {
    if (!result) {
        return null;
    }

    const ingredientIds =
        result.uniqueIngredientIds ||
        result.ingredientIds ||
        [];

    const maturity =
        typeof result.maturity ===
        "number"
            ? result.maturity
            : 0;

    const chill =
        result.coolingCount ||
        result.iceCount ||
        0;

    const burstCount =
        result.burstCount ||
        0;

    const carbonationGets =
        result.carbonationGets ||
        0;

    const spilledCount =
        result.spilledCount ||
        0;

    const topFlavorIngredientId =
        getRareColaTopFlavorIngredientId(
            result
        );

    for (
        const recipeId of
        Object.keys(
            RARE_COLAS
        )
    ) {
        const recipe =
            RARE_COLAS[
                recipeId
            ];

        const finishRequirement =
            RARE_COLA_FINISH_REQUIREMENTS[
                recipeId
            ] ||
            {};

        if (
            recipe.requiresFizz &&
            !result.hasFizz
        ) {
            continue;
        }

        if (
            recipe.requiresColaBase &&
            !result.hasColaBase
        ) {
            continue;
        }

        if (
            recipe.requiredPrimaryRoute &&
            result.routePrimary !==
                recipe.requiredPrimaryRoute
        ) {
            continue;
        }

        if (
            recipe.requiredFinalRoute &&
            result.routeFinal !==
                recipe.requiredFinalRoute
        ) {
            continue;
        }

        if (
            recipe.minMaturity !==
                undefined &&
            maturity <
                recipe.minMaturity
        ) {
            continue;
        }

        if (
            recipe.maxMaturity !==
                undefined &&
            maturity >
                recipe.maxMaturity
        ) {
            continue;
        }

        if (
            recipe.minChill !==
                undefined &&
            chill <
                recipe.minChill
        ) {
            continue;
        }

        if (
            recipe.minCarbonationGets !==
                undefined &&
            carbonationGets <
                recipe.minCarbonationGets
        ) {
            continue;
        }

        if (
            recipe.maxBurstCount !==
                undefined &&
            burstCount >
                recipe.maxBurstCount
        ) {
            continue;
        }

        if (
            finishRequirement.requiresNoSpill &&
            spilledCount > 0
        ) {
            continue;
        }

        if (
            finishRequirement.forbiddenIngredientId &&
            ingredientIds.indexOf(
                finishRequirement
                    .forbiddenIngredientId
            ) >= 0
        ) {
            continue;
        }

        if (
            finishRequirement
                .requiredTopFlavorIngredient &&
            topFlavorIngredientId !==
                finishRequirement
                    .requiredTopFlavorIngredient
        ) {
            continue;
        }

        let hasAllIngredients =
            true;

        for (
            const ingredientId of
            recipe.requiredIngredients
        ) {
            if (
                ingredientIds.indexOf(
                    ingredientId
                ) < 0
            ) {
                hasAllIngredients =
                    false;

                break;
            }
        }

        if (!hasAllIngredients) {
            continue;
        }

        let hasForbiddenIngredient =
            false;

        for (
            const ingredientId of
            recipe.forbiddenIngredients ||
            []
        ) {
            if (
                ingredientIds.indexOf(
                    ingredientId
                ) >= 0
            ) {
                hasForbiddenIngredient =
                    true;

                break;
            }
        }

        if (
            hasForbiddenIngredient
        ) {
            continue;
        }

        return recipe;
    }

    return null;
}


