const getResultBottleLabelDesignBaseForRareCola =
    getResultBottleLabelDesign;

getResultBottleLabelDesign = function() {
    const result =
        gameState.resultData || {};

    const defaultDesign =
        getResultBottleLabelDesignBaseForRareCola();

    const rareCola =
        getRareColaRecipe(
            result
        );

    if (!rareCola) {
        return defaultDesign;
    }

    return {
        mainId:
            defaultDesign.mainId,

        base:
            rareCola.label.base,

        light:
            rareCola.label.light,

        dark:
            rareCola.label.dark,

        symbol:
            rareCola.label.symbol,

        pattern:
            rareCola.label.pattern,

        carbonationGets:
            defaultDesign.carbonationGets,

        pressure:
            defaultDesign.pressure,

        stillFinish:
            defaultDesign.stillFinish,

        coolingCount:
            defaultDesign.coolingCount,

        garnish:
            defaultDesign.garnish,

        hasSecret:
            defaultDesign.hasSecret,

        burstCount:
            defaultDesign.burstCount,

        perfectStopCount:
            defaultDesign.perfectStopCount,

        perfectGoal:
            defaultDesign.perfectGoal,

        rareColaId:
            rareCola.id,

        maturity:
            result.maturity || 0,
    };
};

function drawResultMaturityAndRareLiquidOverlay(
    x,
    y,
    scaleValue,
    alpha
) {
    const result =
        gameState.resultData || {};

    const maturity =
        Math.max(
            0,
            Math.min(
                COLA_MATURITY_MAX,
                result.maturity || 0
            )
        );

    const rareCola =
        getRareColaRecipe(
            result
        );

    if (
        maturity <= 0 &&
        !rareCola
    ) {
        return;
    }

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        return;
    }

    const alphaRatio =
        Math.max(
            0,
            Math.min(
                1,
                alpha / 255
            )
        );

    const geometry = {
        bodyWidth:
            CONFIG.inspectionBottleBodyWidth,
        bodyHeight:
            CONFIG.inspectionBottleBodyHeight,
        neckWidth:
            CONFIG.inspectionBottleNeckWidth,
        neckHeight:
            CONFIG.inspectionBottleNeckHeight,
        mouthWidth:
            CONFIG.inspectionBottleMouthWidth,
        mouthHeight:
            CONFIG.inspectionBottleMouthHeight,
    };

    geometry.bodyBottom =
        -geometry.bodyHeight * 0.5 -
        18;

    geometry.bodyTop =
        geometry.bodyHeight * 0.5 -
        18;

    geometry.shoulderY =
        geometry.bodyTop + 7;

    geometry.neckBottom =
        geometry.bodyTop + 17;

    geometry.neckTop =
        geometry.neckBottom +
        geometry.neckHeight;

    const liquidBottom =
        geometry.bodyBottom + 2;

    const liquidTop =
        geometry.neckTop - 18;

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    const ctx =
        nativeContext;

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        6
    );

    ctx.clip();

    const maturityAlpha =
        Math.min(
            0.24,
            maturity * 0.075
        ) *
        alphaRatio;

    ctx.fillStyle =
        "rgba(31, 14, 7, " +
        String(
            maturityAlpha
        ) +
        ")";

    ctx.fillRect(
        -geometry.bodyWidth,
        liquidBottom - 4,
        geometry.bodyWidth * 2,
        liquidTop -
            liquidBottom +
            8
    );

    if (rareCola) {
        const liquid =
            rareCola.liquid;

        const rareGradient =
            ctx.createLinearGradient(
                0,
                liquidBottom,
                0,
                liquidTop
            );

        rareGradient.addColorStop(
            0,
            "rgba(" +
            String(
                Math.max(
                    0,
                    liquid.r - 24
                )
            ) +
            "," +
            String(
                Math.max(
                    0,
                    liquid.g - 18
                )
            ) +
            "," +
            String(
                Math.max(
                    0,
                    liquid.b - 10
                )
            ) +
            "," +
            String(
                0.34 * alphaRatio
            ) +
            ")"
        );

        rareGradient.addColorStop(
            0.58,
            "rgba(" +
            String(
                liquid.r
            ) +
            "," +
            String(
                liquid.g
            ) +
            "," +
            String(
                liquid.b
            ) +
            "," +
            String(
                0.25 * alphaRatio
            ) +
            ")"
        );

        rareGradient.addColorStop(
            1,
            "rgba(" +
            String(
                Math.min(
                    255,
                    liquid.r + 38
                )
            ) +
            "," +
            String(
                Math.min(
                    255,
                    liquid.g + 30
                )
            ) +
            "," +
            String(
                Math.min(
                    255,
                    liquid.b + 20
                )
            ) +
            "," +
            String(
                0.18 * alphaRatio
            ) +
            ")"
        );

        ctx.fillStyle =
            rareGradient;

        ctx.fillRect(
            -geometry.bodyWidth,
            liquidBottom - 4,
            geometry.bodyWidth * 2,
            liquidTop -
                liquidBottom +
                8
        );

        for (
            let index = 0;
            index < 5;
            index += 1
        ) {
            const bubbleX =
                Math.sin(
                    index * 5.7
                ) *
                geometry.bodyWidth *
                0.25;

            const bubbleY =
                liquidBottom +
                28 +
                (
                    (
                        ElapsedTime * 13 +
                        index * 31
                    ) %
                    Math.max(
                        18,
                        liquidTop -
                            liquidBottom -
                            42
                    )
                );

            const bubbleSize =
                1.8 +
                (
                    index % 2
                ) *
                    0.9;

            ctx.beginPath();

            ctx.ellipse(
                bubbleX,
                bubbleY,
                bubbleSize,
                bubbleSize,
                0,
                0,
                Math.PI * 2
            );

            ctx.strokeStyle =
                "rgba(" +
                String(
                    rareCola.label.light.r
                ) +
                "," +
                String(
                    rareCola.label.light.g
                ) +
                "," +
                String(
                    rareCola.label.light.b
                ) +
                "," +
                String(
                    0.62 * alphaRatio
                ) +
                ")";

            ctx.lineWidth =
                0.85;

            ctx.stroke();
        }
    }

    ctx.restore();

    popMatrix();
}

function drawResultBottleCoolingMistOverlay(
    x,
    y,
    scaleValue,
    alpha
) {
    const result =
        gameState.resultData || {};

    const coolingCount =
        result.coolingCount ||
        result.iceCount ||
        0;

    if (coolingCount <= 0) {
        return;
    }

    const nativeContext =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state
            ? CodeaLite.state.ctx
            : null;

    if (!nativeContext) {
        return;
    }

    const alphaRatio =
        Math.max(
            0,
            Math.min(
                1,
                alpha / 255
            )
        );

    const geometry = {
        bodyWidth:
            CONFIG.inspectionBottleBodyWidth,
        bodyHeight:
            CONFIG.inspectionBottleBodyHeight,
        neckWidth:
            CONFIG.inspectionBottleNeckWidth,
        neckHeight:
            CONFIG.inspectionBottleNeckHeight,
        mouthWidth:
            CONFIG.inspectionBottleMouthWidth,
        mouthHeight:
            CONFIG.inspectionBottleMouthHeight,
    };

    geometry.bodyBottom =
        -geometry.bodyHeight * 0.5 -
        18;

    geometry.bodyTop =
        geometry.bodyHeight * 0.5 -
        18;

    geometry.shoulderY =
        geometry.bodyTop + 7;

    geometry.neckBottom =
        geometry.bodyTop + 17;

    geometry.neckTop =
        geometry.neckBottom +
        geometry.neckHeight;

    pushMatrix();

    translate(
        x,
        y
    );

    scale(
        scaleValue,
        scaleValue
    );

    const ctx =
        nativeContext;

    ctx.save();

    traceInspectionBottleVectorPath(
        ctx,
        geometry,
        3
    );

    ctx.clip();

    const sideMistAlpha =
        (
            0.14 +
            coolingCount * 0.05
        ) * alphaRatio;

    const centerMistAlpha =
        (
            0.06 +
            coolingCount * 0.03
        ) * alphaRatio;

    const condenseAlpha =
        (
            0.22 +
            coolingCount * 0.06
        ) * alphaRatio;

    function fillMistEllipse(
        cx,
        cy,
        rx,
        ry,
        r,
        g,
        b,
        a
    ) {
        ctx.beginPath();
        ctx.ellipse(
            cx,
            cy,
            rx,
            ry,
            0,
            0,
            Math.PI * 2
        );
        ctx.fillStyle =
            "rgba(" +
            String(r) +
            "," +
            String(g) +
            "," +
            String(b) +
            "," +
            String(a) +
            ")";
        ctx.fill();
    }

    /*
     * 既存の十字表現が出ていた位置を、
     * 曇りガラスのようなミストで柔らかく覆う
     */
    fillMistEllipse(
        -geometry.bodyWidth * 0.36,
        geometry.bodyBottom + 48,
        12,
        10,
        235,
        243,
        245,
        sideMistAlpha
    );

    fillMistEllipse(
        geometry.bodyWidth * 0.36,
        geometry.bodyBottom + 68,
        13,
        10,
        235,
        243,
        245,
        sideMistAlpha
    );

    fillMistEllipse(
        -geometry.bodyWidth * 0.36,
        geometry.bodyBottom + 92,
        12,
        10,
        235,
        243,
        245,
        sideMistAlpha * 0.94
    );

    fillMistEllipse(
        geometry.bodyWidth * 0.36,
        geometry.bodyBottom + 114,
        12,
        10,
        235,
        243,
        245,
        sideMistAlpha * 0.92
    );

    /*
     * 全体のうっすらした曇り
     */
    fillMistEllipse(
        -geometry.bodyWidth * 0.18,
        geometry.bodyBottom + 74,
        16,
        44,
        240,
        247,
        248,
        centerMistAlpha
    );

    fillMistEllipse(
        geometry.bodyWidth * 0.16,
        geometry.bodyBottom + 86,
        14,
        38,
        240,
        247,
        248,
        centerMistAlpha * 0.92
    );

    fillMistEllipse(
        0,
        geometry.neckBottom + 18,
        geometry.neckWidth * 0.64,
        18,
        242,
        248,
        249,
        centerMistAlpha * 0.88
    );

    /*
     * 冷えた結露の細い筋
     */
    ctx.lineCap =
        "round";

    ctx.beginPath();
    ctx.moveTo(
        -geometry.bodyWidth * 0.33,
        geometry.bodyBottom + 24
    );
    ctx.lineTo(
        -geometry.bodyWidth * 0.31,
        geometry.bodyBottom + 56
    );
    ctx.moveTo(
        geometry.bodyWidth * 0.28,
        geometry.bodyBottom + 42
    );
    ctx.lineTo(
        geometry.bodyWidth * 0.29,
        geometry.bodyBottom + 72
    );
    ctx.moveTo(
        -geometry.bodyWidth * 0.08,
        geometry.bodyBottom + 88
    );
    ctx.lineTo(
        -geometry.bodyWidth * 0.06,
        geometry.bodyBottom + 108
    );

    ctx.strokeStyle =
        "rgba(232,242,246," +
        String(
            condenseAlpha * 0.72
        ) +
        ")";
    ctx.lineWidth =
        1.2 +
        coolingCount * 0.16;
    ctx.stroke();

    /*
     * 小さな結露粒
     */
    const droplets = [
        {
            x:
                -geometry.bodyWidth * 0.27,
            y:
                geometry.bodyBottom + 36,
            w: 3.8,
            h: 5.4,
        },
        {
            x:
                geometry.bodyWidth * 0.18,
            y:
                geometry.bodyBottom + 58,
            w: 3.4,
            h: 4.8,
        },
        {
            x:
                -geometry.bodyWidth * 0.05,
            y:
                geometry.bodyBottom + 104,
            w: 3.2,
            h: 4.5,
        },
        {
            x:
                geometry.bodyWidth * 0.31,
            y:
                geometry.bodyBottom + 96,
            w: 3.6,
            h: 5.0,
        },
        {
            x:
                -geometry.bodyWidth * 0.24,
            y:
                geometry.neckBottom + 15,
            w: 2.8,
            h: 4.0,
        },
    ];

    for (
        const droplet of
        droplets
    ) {
        ctx.beginPath();
        ctx.ellipse(
            droplet.x,
            droplet.y,
            droplet.w,
            droplet.h,
            0,
            0,
            Math.PI * 2
        );
        ctx.fillStyle =
            "rgba(241,248,250," +
            String(
                condenseAlpha * 0.82
            ) +
            ")";
        ctx.fill();

        ctx.beginPath();
        ctx.ellipse(
            droplet.x - 0.6,
            droplet.y + 0.7,
            Math.max(
                0.7,
                droplet.w * 0.28
            ),
            Math.max(
                0.9,
                droplet.h * 0.26
            ),
            0,
            0,
            Math.PI * 2
        );
        ctx.fillStyle =
            "rgba(255,255,255," +
            String(
                condenseAlpha * 0.42
            ) +
            ")";
        ctx.fill();
    }

    /*
     * 口元のひんやりした白い曇り
     */
    fillMistEllipse(
        0,
        geometry.neckTop + 4,
        geometry.mouthWidth * 0.30,
        geometry.mouthHeight * 0.18,
        246,
        250,
        250,
        (0.12 + coolingCount * 0.03) * alphaRatio
    );

    ctx.restore();

    popMatrix();
}




function drawRareColaCrownAccent(
    x,
    y,
    size,
    alpha
) {
    const rareCola =
        getRareColaRecipe(
            gameState.resultData || {}
        );

    if (!rareCola) {
        return;
    }

    const crown =
        rareCola.crown;

    noFill();

    stroke(
        crown.r,
        crown.g,
        crown.b,
        alpha * 0.82
    );

    strokeWidth(2);

    ellipse(
        x,
        y,
        size * 1.22
    );

    stroke(
        255,
        238,
        190,
        alpha * 0.42
    );

    strokeWidth(0.9);

    ellipse(
        x,
        y,
        size * 0.82
    );

    noStroke();
}


const drawPreviewScreenBaseForMaturityIndicator =
    drawPreviewScreen;

function drawRareColaCrownSealMark(
    crownX,
    crownY,
    crownSize,
    alpha
) {
    const rareCola =
        getRareColaRecipe(
            gameState.resultData || {}
        );

    if (!rareCola) {
        return;
    }

    const crown =
        rareCola.crown;

    const seal =
        rareCola.seal ||
        "";

    pushMatrix();

    translate(
        crownX,
        crownY
    );

    rotate(-12);

    noStroke();

    fill(
        46,
        28,
        17,
        alpha * 0.82
    );

    ellipse(
        0,
        0,
        crownSize * 0.19
    );

    if (seal === "moon") {
        fill(
            crown.r,
            crown.g,
            crown.b,
            alpha * 0.96
        );

        ellipse(
            -crownSize * 0.012,
            0,
            crownSize * 0.112
        );

        fill(
            59,
            37,
            20,
            alpha * 0.96
        );

        ellipse(
            crownSize * 0.023,
            crownSize * 0.006,
            crownSize * 0.086
        );
    } else if (seal === "leaf") {
        fill(
            crown.r,
            crown.g,
            crown.b,
            alpha * 0.96
        );

        pushMatrix();

        rotate(-28);

        ellipse(
            0,
            0,
            crownSize * 0.135,
            crownSize * 0.078
        );

        popMatrix();

        stroke(
            56,
            39,
            21,
            alpha * 0.80
        );

        strokeWidth(
            Math.max(
                0.7,
                crownSize * 0.011
            )
        );

        line(
            -crownSize * 0.034,
            -crownSize * 0.020,
            crownSize * 0.036,
            crownSize * 0.026
        );
    } else if (seal === "ring") {
        noFill();

        stroke(
            crown.r,
            crown.g,
            crown.b,
            alpha * 0.98
        );

        strokeWidth(
            Math.max(
                1,
                crownSize * 0.019
            )
        );

        ellipse(
            0,
            0,
            crownSize * 0.115
        );

        stroke(
            61,
            35,
            20,
            alpha * 0.82
        );

        strokeWidth(
            Math.max(
                0.7,
                crownSize * 0.010
            )
        );

        ellipse(
            0,
            0,
            crownSize * 0.052
        );
    }

    noStroke();

    popMatrix();
}

/*
 * Tasting set rendering pipeline.
 *
 * Keep the exact historical layer order:
 * base tasting set -> still garnish tray -> rare crown accent -> rare seal.
 */
function drawResultTastingSet(
    glassX,
    glassY,
    glassScale,
    crownX,
    crownY,
    crownSize,
    alpha
) {
    drawResultTastingSetCore(
        glassX,
        glassY,
        glassScale,
        crownX,
        crownY,
        crownSize,
        alpha
    );

    drawResultStillGarnishTray(
        glassX,
        glassY,
        glassScale,
        alpha
    );

    drawRareColaCrownAccent(
        crownX,
        crownY,
        crownSize,
        alpha
    );

    drawRareColaCrownSealMark(
        crownX,
        crownY,
        crownSize,
        alpha
    );
}


