function colaRollDispatchClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

function colaRollDispatchDelta() {
    return Math.max(
        0,
        Math.min(
            0.05,
            typeof DeltaTime === "number"
                ? DeltaTime
                : 0.016
        )
    );
}

function colaRollDispatchNow() {
    return typeof ElapsedTime === "number"
        ? ElapsedTime
        : Date.now() / 1000;
}

function colaRollDispatchHit(
    touch,
    rect
) {
    return (
        touch.x >= rect.x &&
        touch.x <= rect.x + rect.w &&
        touch.y >= rect.y &&
        touch.y <= rect.y + rect.h
    );
}

function colaRollDispatchDrawBackdrop(
    options
) {
    const settings =
        options || {};

    const opacity =
        Math.max(
            0,
            Math.min(
                1,
                typeof settings.alpha ===
                    "number"
                    ? settings.alpha
                    : 1
            )
        );

    const drawFrame =
        settings.drawFrame !==
        false;

    if (opacity <= 0) {
        return;
    }

    const context =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    if (context) {
        context.save();

        context.globalAlpha =
            context.globalAlpha *
            opacity;
    }

    try {
        const stripeCount =
            44;

        const topColor = {
            r: 22,
            g: 18,
            b: 18,
        };

        const middleColor = {
            r: 34,
            g: 22,
            b: 18,
        };

        const bottomColor = {
            r: 53,
            g: 29,
            b: 18,
        };

        rectMode(CORNER);
        noStroke();

        for (
            let index = 0;
            index < stripeCount;
            index += 1
        ) {
            const startRatio =
                index /
                stripeCount;

            const endRatio =
                (
                    index + 1
                ) /
                stripeCount;

            const ratio =
                (
                    startRatio +
                    endRatio
                ) *
                0.5;

            let red;
            let green;
            let blue;

            if (
                ratio < 0.56
            ) {
                const localRatio =
                    ratio /
                    0.56;

                red =
                    topColor.r +
                    (
                        middleColor.r -
                        topColor.r
                    ) *
                        localRatio;

                green =
                    topColor.g +
                    (
                        middleColor.g -
                        topColor.g
                    ) *
                        localRatio;

                blue =
                    topColor.b +
                    (
                        middleColor.b -
                        topColor.b
                    ) *
                        localRatio;
            } else {
                const localRatio =
                    (
                        ratio -
                        0.56
                    ) /
                    0.44;

                red =
                    middleColor.r +
                    (
                        bottomColor.r -
                        middleColor.r
                    ) *
                        localRatio;

                green =
                    middleColor.g +
                    (
                        bottomColor.g -
                        middleColor.g
                    ) *
                        localRatio;

                blue =
                    middleColor.b +
                    (
                        bottomColor.b -
                        middleColor.b
                    ) *
                        localRatio;
            }

            fill(
                red,
                green,
                blue
            );

            rect(
                0,
                HEIGHT * startRatio,
                WIDTH,
                HEIGHT *
                    (
                        endRatio -
                        startRatio
                    ) +
                    1
            );
        }

        fill(
            73,
            34,
            20,
            32
        );

        rect(
            0,
            HEIGHT * 0.18,
            WIDTH,
            HEIGHT * 0.30
        );

        fill(
            15,
            10,
            9,
            48
        );

        rect(
            0,
            0,
            WIDTH,
            HEIGHT
        );

        /*
         * タイトルからの遷移中は背景だけ共有し、
         * 注文先画面に入ってから外枠を出す。
         */
        if (!drawFrame) {
            noStroke();
            rectMode(CORNER);
            return;
        }

        noFill();

        stroke(
            79,
            47,
            30,
            155
        );

        strokeWidth(2);

        rect(
            14,
            14,
            WIDTH - 28,
            HEIGHT - 28,
            18
        );

        stroke(
            161,
            101,
            50,
            70
        );

        strokeWidth(1);

        rect(
            22,
            22,
            WIDTH - 44,
            HEIGHT - 44,
            14
        );

        noStroke();
        rectMode(CORNER);
    } finally {
        if (context) {
            context.restore();
        }
    }
}



function drawColaRollDispatchGradient(
    alpha
) {
    const opacity =
        Math.max(
            0,
            Math.min(
                255,
                alpha
            )
        );

    if (opacity <= 0) {
        return;
    }

    /*
     * 遷移専用の似た背景は作らない。
     * 注文先画面と同じ背景本体を、
     * 外枠なし・透過つきでそのまま使う。
     */
    colaRollDispatchDrawBackdrop(
        {
            alpha:
                opacity / 255,

            drawFrame:
                false,
        }
    );
}

const drawColaRollDispatchGradientBaseForTitleUnderlay =
    drawColaRollDispatchGradient;

drawColaRollDispatchGradient = function(
    alpha
) {
    /*
     * TITLE_TRANSITION中は、
     * 背景がすでにタイトル画像の下にある。
     *
     * ここで再度グラデーションを上から重ねると、
     * また画像が「覆われて消える」動きに戻るため、
     * この場面だけは何もしない。
     */
    if (
        gameState &&
        gameState.phase ===
            "TITLE_TRANSITION"
    ) {
        return;
    }

    return drawColaRollDispatchGradientBaseForTitleUnderlay(
        alpha
    );
};


const colaRollDispatchDrawBackdropBaseForHandoff =
    colaRollDispatchDrawBackdrop;

colaRollDispatchDrawBackdrop = function(
    options
) {
    const settings =
        options || {};

    const opacity =
        Math.max(
            0,
            Math.min(
                1,
                typeof settings.alpha ===
                    "number"
                    ? settings.alpha
                    : 1
            )
        );

    const drawFrame =
        settings.drawFrame !==
        false;

    /*
     * 背景本体は常に既存の注文先背景を使う。
     * タイトル遷移中は drawFrame:false なので、
     * 背景だけがそのまま共有される。
     */
    colaRollDispatchDrawBackdropBaseForHandoff(
        {
            alpha:
                opacity,

            drawFrame:
                false,
        }
    );

    if (
        !drawFrame ||
        opacity <= 0
    ) {
        return;
    }

    const screen =
        gameState &&
        gameState.dispatchScreen
            ? gameState.dispatchScreen
            : null;

    const rawFrameArrival =
        typeof settings.frameAlpha ===
            "number"
            ? Math.max(
                0,
                Math.min(
                    1,
                    settings.frameAlpha
                )
            )
            : (
                screen
                    ? colaRollDispatchClamp(
                        screen.alpha
                    )
                    : 1
            );

    /*
     * 背景は最初から完成状態。
     * 外枠だけを注文票と同じ速度で浮かせる。
     */
    const frameArrival =
        rawFrameArrival *
        rawFrameArrival *
        (
            3 -
            2 * rawFrameArrival
        );

    if (frameArrival <= 0.001) {
        return;
    }

    const context =
        typeof CodeaLite !==
            "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
            ? CodeaLite.state.ctx
            : null;

    if (context) {
        context.save();

        context.globalAlpha =
            context.globalAlpha *
            opacity *
            frameArrival;
    }

    try {
        rectMode(CORNER);
        noFill();

        stroke(
            79,
            47,
            30,
            155
        );

        strokeWidth(2);

        rect(
            14,
            14,
            WIDTH - 28,
            HEIGHT - 28,
            18
        );

        stroke(
            161,
            101,
            50,
            70
        );

        strokeWidth(1);

        rect(
            22,
            22,
            WIDTH - 44,
            HEIGHT - 44,
            14
        );

        noStroke();
        rectMode(CORNER);
    } finally {
        if (context) {
            context.restore();
        }
    }
};





