function getKnownFlavorPrefixes(
        language,
        currentTopIngredientId
    ) {
        const prefixes =
            [];

        const current =
            getTopFlavorText(
                language,
                currentTopIngredientId
            );

        if (current) {
            prefixes.push(
                current
            );
        }

        const words =
            RESULT_WORDS &&
            RESULT_WORDS[language] &&
            RESULT_WORDS[language].topFlavor
                ? RESULT_WORDS[
                    language
                ].topFlavor
                : {};

        for (
            const id of
            Object.keys(
                words
            )
        ) {
            const value =
                words[id];

            if (
                value &&
                prefixes.indexOf(
                    value
                ) < 0
            ) {
                prefixes.push(
                    value
                );
            }
        }

        prefixes.sort(
            function(a, b) {
                return (
                    b.length -
                    a.length
                );
            }
        );

        return prefixes;
    }

function splitJapaneseColaTitle(
    name,
    result
) {
    const normalizedName =
        normalizeColaRollResultText(
            name
        );

    const suffixes = [
        "限界炭酸コーラ",
        "強炭酸コーラ",
        "コーラ",
    ];

    let suffix =
        "";

    for (
        const candidate of
        suffixes
    ) {
        const normalizedCandidate =
            normalizeColaRollResultText(
                candidate
            );

        if (
            normalizedName.endsWith(
                normalizedCandidate
            )
        ) {
            suffix =
                normalizedCandidate;
            break;
        }
    }

    if (!suffix) {
        return null;
    }

    let prefix =
        normalizedName.slice(
            0,
            normalizedName.length -
                suffix.length
        );

    /*
     * 結合帯では「香り + 古い味の前置き + 新しい結合帯名」
     * になっていた履歴がある。
     *
     * 前置きは一度だけでなく、連続している分をすべて外す。
     * 例:
     * バニラ香る + 素朴なシロップの + 濃い仕込みのコーラ
     *       ↓
     * バニラ香る濃い仕込みのコーラ
     */
    const flavorPrefixes =
        getKnownFlavorPrefixes(
            "ja",
            result.topIngredientId
        ).map(
            function(value) {
                return normalizeColaRollResultText(
                    value
                );
            }
        ).filter(
            function(value) {
                return !!value;
            }
        );

    let removedFlavor =
        false;

    let removedOne =
        true;

    while (removedOne) {
        removedOne =
            false;

        for (
            const flavorPrefix of
            flavorPrefixes
        ) {
            if (
                prefix.indexOf(
                    flavorPrefix
                ) === 0
            ) {
                prefix =
                    prefix.slice(
                        flavorPrefix.length
                    );

                removedFlavor =
                    true;

                removedOne =
                    true;

                break;
            }
        }
    }

    /*
     * 既存の表にない香り名でも、
     * 「香る」までを旧来の前置きとして外す。
     */
    if (!removedFlavor) {
        const aromaEnd =
            prefix.indexOf(
                normalizeColaRollResultText(
                    "香る"
                )
            );

        if (
            aromaEnd >= 0 &&
            aromaEnd <= 16
        ) {
            prefix =
                prefix.slice(
                    aromaEnd + 2
                );
        }
    }

    const garnishCandidates = [
        "チェリー浮かぶレモン添えの",
        "レモンとチェリー添えの",
        "チェリー添えの",
        "レモン添えの",
        "チェリー浮かぶ",
    ].map(
        function(value) {
            return normalizeColaRollResultText(
                value
            );
        }
    );

    let garnish =
        "";

    for (
        const candidate of
        garnishCandidates
    ) {
        if (
            prefix.indexOf(
                candidate
            ) === 0
        ) {
            garnish =
                candidate;

            prefix =
                prefix.slice(
                    candidate.length
                );

            break;
        }
    }

    return {
        suffix:
            suffix,

        garnish:
            garnish,

        extraPrefix:
            prefix,
    };
}


function splitEnglishColaTitle(
        name,
        result
    ) {
        const suffixes = [
            "Limit Fizz Cola",
            "Extra Fizzy Cola",
            "Cola",
        ];

        let suffix =
            "";

        for (
            const candidate of
            suffixes
        ) {
            if (
                name.endsWith(
                    candidate
                )
            ) {
                suffix =
                    candidate;
                break;
            }
        }

        if (!suffix) {
            return null;
        }

        let prefix =
            name.slice(
                0,
                name.length -
                    suffix.length
            ).trim();

        const flavorPrefixes =
            getKnownFlavorPrefixes(
                "en",
                result.topIngredientId
            );

        for (
            const flavorPrefix of
            flavorPrefixes
        ) {
            if (
                prefix.indexOf(
                    flavorPrefix
                ) === 0
            ) {
                prefix =
                    prefix.slice(
                        flavorPrefix.length
                    ).trim();

                break;
            }
        }

        const garnishCandidates = [
            "Cherry & Lemon",
            "Cherry",
            "Lemon",
        ];

        let garnish =
            "";

        for (
            const candidate of
            garnishCandidates
        ) {
            if (
                prefix.indexOf(
                    candidate
                ) === 0
            ) {
                garnish =
                    candidate;

                prefix =
                    prefix.slice(
                        candidate.length
                    ).trim();

                break;
            }
        }

        return {
            suffix:
                suffix,

            garnish:
                garnish,

            extraPrefix:
                prefix,
        };
    }

function getResultCompositionLanguage() {
    return gameState && gameState.language === "en"
        ? "en"
        : "ja";
}

function getResultHistoryText(
    key
) {
    const entry =
        gameState &&
        gameState.historyReplayEntry;

    if (
        !entry ||
        !entry.text
    ) {
        return "";
    }

    const language =
        getResultCompositionLanguage();

    const savedText =
        entry.text[language] &&
        entry.text[language][key];

    return savedText
        ? colaHistoryNormalize(
            savedText
        )
        : "";
}

function applyStillCherryGarnishTitle(
    name,
    result
) {
    if (
        gameState.language === "ja" &&
        result.garnish === "cherry" &&
        getResultGlassDrinkKind() ===
            "none"
    ) {
        return name.replace(
            "チェリー浮かぶ",
            "チェリー添えの"
        );
    }

    return name;
}


/*
 * English result names use the same data as Japanese names, but they are
 * assembled from components rather than rewritten with string replacements.
 *
 * This prevents a saved name such as "... Cherry & Lemon Cola" from being
 * modified again when it is opened from Recent Bottlings.
 */
function getEnglishResultGarnishTitle(
    result
) {
    const garnishes =
        getResultGarnishes(
            result
        );

    const hasLemon =
        garnishes.indexOf(
            "lemon"
        ) >= 0;

    const hasCherry =
        garnishes.indexOf(
            "cherry"
        ) >= 0;

    if (
        hasCherry &&
        hasLemon
    ) {
        return "Cherry & Lemon";
    }

    if (hasCherry) {
        return "Cherry";
    }

    if (hasLemon) {
        return "Lemon";
    }

    return "";
}

function getEnglishColaBaseTitle(
    result
) {
    if (
        result.burstCount > 0 ||
        result.pressure >=
            CONFIG.pressureMax
    ) {
        return "Limit Fizz Cola";
    }

    if (result.pressure >= 3) {
        return "Extra Fizzy Cola";
    }

    return "Cola";
}

function buildCanonicalEnglishResultTitle(
    result,
    baseTitle
) {
    const flavor =
        getEnglishResultFlavorTitle(
            result
        );

    const garnish =
        getEnglishResultGarnishTitle(
            result
        );

    /*
     * lemon_peel とレモン添えが重なる時だけ、
     * 同じ Lemon を機械的に二度並べない。
     */
    if (
        flavor === "Lemon" &&
        garnish === "Lemon"
    ) {
        return [
            "Lemon Peel",
            baseTitle,
            "with Lemon",
        ].filter(
            function(part) {
                return !!part;
            }
        ).join(" ");
    }

    return [
        flavor,
        garnish,
        baseTitle,
    ].filter(
        function(part) {
            return !!part;
        }
    ).join(" ");
}

function getEnglishSyrupBaseTitle(
    result
) {
    if (
        result.sweetness >= 4
    ) {
        return "Rich Cola Base";
    }

    if (
        result.strange > 0
    ) {
        return "Quiet Secret Syrup";
    }

    if (
        result.chill >= 2
    ) {
        return "Chilled Cola Base";
    }

    return "Waiting-for-Fizz Syrup";
}

function buildCanonicalEnglishSyrupTitle(
    result
) {
    return buildCanonicalEnglishResultTitle(
        result,
        getEnglishSyrupBaseTitle(
            result
        )
    );
}


function getEnglishResultFlavorTitle(
    result
) {
    const flavor =
        getTopFlavorText(
            "en",
            result.topIngredientId
        );

    return flavor ||
        "Mysterious";
}

function buildCanonicalEnglishColaTitle(
    result
) {
    return buildCanonicalEnglishResultTitle(
        result,
        getEnglishColaBaseTitle(
            result
        )
    );
}


function buildCanonicalEnglishMergedBandColaTitle(
    result
) {
    const baseText =
        getBaseBandTitleText(
            "en",
            result.baseIngredientId
        );

    if (!baseText) {
        return buildCanonicalEnglishColaTitle(
            result
        );
    }

    const aromaId =
        result.aromaIngredientId;

    const aromaText =
        aromaId &&
        aromaId !==
            result.baseIngredientId
            ? getTopFlavorText(
                "en",
                aromaId
            )
            : "";

    const parts = [];

    if (aromaText) {
        parts.push(
            aromaText +
                "-Led"
        );
    }

    const garnishText =
        getEnglishResultGarnishTitle(
            result
        );

    if (garnishText) {
        parts.push(
            garnishText
        );
    }

    parts.push(
        baseText
    );

    parts.push(
        getEnglishColaBaseTitle(
            result
        )
    );

    return parts.join(" ");
}

function getCanonicalEnglishStoredColaTitle(
    result
) {
    if (
        !result ||
        getRareColaRecipe(
            result
        )
    ) {
        return "";
    }

    if (
        result.drinkType ===
        "cola"
    ) {
        if (result.baseIngredientId) {
            return buildCanonicalEnglishMergedBandColaTitle(
                result
            );
        }

        return buildCanonicalEnglishColaTitle(
            result
        );
    }

    /*
     * 既存の履歴に残っているシロップ系も、
     * 新規作成時と同じ日英ルールで修復する。
     */
    if (
        result.drinkType ===
        "syrup"
    ) {
        return buildCanonicalEnglishSyrupTitle(
            result
        );
    }

    return "";
}


function applyMultipleGarnishTitle(
    name,
    result,
    language
) {
    const garnishes =
        getResultGarnishes(
            result
        );

    if (
        garnishes.length <= 0
    ) {
        return name;
    }

    const stillFinish =
        getResultGlassDrinkKind() ===
        "none";

    if (language === "ja") {
        let garnishText =
            "";

        if (
            garnishes.length >= 2
        ) {
            garnishText =
                stillFinish
                    ? "レモンとチェリー添えの"
                    : "チェリー浮かぶレモン添えの";
        } else if (
            garnishes[0] ===
            "cherry"
        ) {
            garnishText =
                stillFinish
                    ? "チェリー添えの"
                    : "チェリー浮かぶ";
        } else {
            garnishText =
                "レモン添えの";
        }

        const oldTexts = [
            "チェリー浮かぶ",
            "チェリー添えの",
            "レモン添えの",
        ];

        for (
            const oldText of
            oldTexts
        ) {
            if (
                name.indexOf(
                    oldText
                ) >= 0
            ) {
                return name.replace(
                    oldText,
                    garnishText
                );
            }
        }

        return name;
    }

    if (
        language === "en" &&
        result
    ) {
        if (
            result.drinkType ===
            "cola"
        ) {
            return buildCanonicalEnglishColaTitle(
                result
            );
        }

        if (
            result.drinkType ===
            "syrup"
        ) {
            return buildCanonicalEnglishSyrupTitle(
                result
            );
        }
    }

    return name;
}


function getRareColaRecipe(
    result
) {
    const recipe =
        getBaseRareColaRecipe(
            result
        );

    if (!recipe) {
        return null;
    }

    const fallbackHeading =
        typeof recipe.labelHeading ===
            "string" &&
        recipe.labelHeading.length > 0
            ? recipe.labelHeading
            : "NIGHT BATCH";

    if (
        !recipe.heading ||
        typeof recipe.heading !==
            "object"
    ) {
        recipe.heading = {
            ja:
                fallbackHeading,

            en:
                fallbackHeading,
        };
    } else {
        if (
            !recipe.heading.ja
        ) {
            recipe.heading.ja =
                fallbackHeading;
        }

        if (
            !recipe.heading.en
        ) {
            recipe.heading.en =
                fallbackHeading;
        }
    }

    return recipe;
}

function applyResultGarnishData(
    result
) {
    const garnishes =
        getCollectedGarnishes();

    result.garnishes =
        garnishes.slice();

    result.garnish =
        getPrimaryGarnish(
            garnishes
        );
}

function applyResultMaturityAndRareData(
    result
) {
    const maturity =
        Math.max(
            0,
            Math.min(
                COLA_MATURITY_MAX,
                gameState.maturity || 0
            )
        );

    result.maturity =
        maturity;

    result.maturityTurns =
        gameState.maturityTurns || 0;

    const rareCola =
        getRareColaRecipe(
            result
        );

    result.rareColaId =
        rareCola
            ? rareCola.id
            : null;
}

function applyResultMergedBandData(
    result
) {
    const mergedBand =
        getLargestMergedBandForResult();

    result.aromaIngredientId =
        getResultAromaIngredientId();

    result.baseIngredientId =
        mergedBand
            ? mergedBand.ingredientId
            : null;

    result.baseIngredientStrength =
        mergedBand
            ? mergedBand.count
            : 0;

    result.baseIngredientSlotIndex =
        mergedBand
            ? mergedBand.start
            : -1;
}

function createResultData() {
    createBaseResultData();

    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : null;

    if (!result) {
        return;
    }

    /*
     * 旧チェーンと同じ順：
     * 基本データ → ガーニッシュ → 熟成・レア → 結合帯。
     */
    applyResultGarnishData(
        result
    );

    applyResultMaturityAndRareData(
        result
    );

    applyResultMergedBandData(
        result
    );
}

function getBaseResultNameWithStillGarnish(
    result
) {
    return applyStillCherryGarnishTitle(
        generateBaseResultName(),
        result
    );
}

function getStandardResultName() {
    const result =
        gameState.resultData || {};

    const language =
        getResultCompositionLanguage();

    const rareCola =
        getRareColaRecipe(
            result
        );

    let name =
        "";

    if (rareCola) {
        name =
            rareCola.title[
                gameState.language
            ] ||
            rareCola.title.ja;
    } else {
        const savedName =
            getResultHistoryText(
                "name"
            );

        /*
         * Recent Bottlings already stores a completed title in each language.
         * It must be shown as saved, not sent through garnish composition a
         * second time.
         */
        if (savedName) {
            name =
                savedName;
        } else {
            name =
                applyMultipleGarnishTitle(
                    getBaseResultNameWithStillGarnish(
                        result
                    ),
                    result,
                    language
                );
        }
    }

    name =
        normalizeColaRollResultText(
            name
        );

    if (
        gameState &&
        gameState.language !== "en"
    ) {
        name =
            colaRollCanonicalizeJapaneseGarnishTitle(
                name,
                result
            );
    }

    return name;
}

function getMergedBandResultName(
    result,
    originalName
) {
    const language =
        getResultCompositionLanguage();

    const baseText =
        getBaseBandTitleText(
            language,
            result.baseIngredientId
        );

    if (!baseText) {
        return originalName;
    }

    const aromaId =
        result.aromaIngredientId;

    const aromaText =
        aromaId &&
        aromaId !==
            result.baseIngredientId
            ? getTopFlavorText(
                language,
                aromaId
            )
            : "";

    if (language === "ja") {
        const parts =
            splitJapaneseColaTitle(
                originalName,
                result
            );

        if (!parts) {
            return originalName;
        }

        return (
            aromaText +
            parts.extraPrefix +
            parts.garnish +
            baseText +
            parts.suffix
        );
    }

    const parts =
        splitEnglishColaTitle(
            originalName,
            result
        );

    if (!parts) {
        return originalName;
    }

    const nameParts =
        [];

    if (aromaText) {
        nameParts.push(
            aromaText +
                "-Led"
        );
    }

    if (parts.extraPrefix) {
        nameParts.push(
            parts.extraPrefix
        );
    }

    if (parts.garnish) {
        nameParts.push(
            parts.garnish
        );
    }

    nameParts.push(
        baseText
    );

    nameParts.push(
        parts.suffix
    );

    return nameParts.join(
        " "
    );
}

function generateResultName() {
    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : {};

    /*
     * レモンピール単体ソーダは、旧チェーンでも最外層で確定していた。
     */
    if (
        result.drinkType ===
            "single_soda" &&
        result.singleIngredientId ===
            "lemon_peel"
    ) {
        return gameState.language === "ja"
            ? "レモンピールソーダ"
            : "Lemon Peel Soda";
    }

    const isMergedBandCola =
        result.drinkType ===
            "cola" &&
        result.baseIngredientId;

    if (isMergedBandCola) {
        const rareCola =
            getRareColaRecipe(
                result
            );

        if (rareCola) {
            return getStandardResultName();
        }

        return getMergedBandResultName(
            result,
            getStandardResultName()
        );
    }

    return getStandardResultName();
}

function getBaseResultDescriptionWithSpillMemory() {
    return appendResultSpillMemory(
        generateBaseResultDescription()
    );
}

function getStandardResultDescription() {
    const result =
        gameState.resultData || {};

    const rareCola =
        getRareColaRecipe(
            result
        );

    let description =
        "";

    if (rareCola) {
        description =
            rareCola.description[
                gameState.language
            ] ||
            rareCola.description.ja;
    } else {
        const savedDescription =
            getResultHistoryText(
                "description"
            );

        description =
            savedDescription ||
            getBaseResultDescriptionWithSpillMemory();
    }

    return normalizeColaRollResultText(
        description
    );
}

function generateResultDescription() {
    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : {};

    /*
     * レモンピール単体ソーダは、旧チェーンでも最外層で確定していた。
     */
    if (
        result.drinkType ===
            "single_soda" &&
        result.singleIngredientId ===
            "lemon_peel"
    ) {
        return gameState.language === "ja"
            ? "レモンピールの香りと炭酸だけで、思ったよりちゃんと爽やかです。"
            : "Lemon peel and bubbles only. Somehow, that is enough.";
    }

    const isMergedBandCola =
        result.drinkType ===
            "cola" &&
        result.baseIngredientId &&
        result.baseIngredientStrength >=
            2;

    if (isMergedBandCola) {
        const rareCola =
            getRareColaRecipe(
                result
            );

        if (!rareCola) {
            return appendResultSpillMemory(
                getMergedBandDescription(
                    result,
                    getResultCompositionLanguage()
                )
            );
        }
    }

    return getStandardResultDescription();
}

function appendRoastSyrupAftertasteToFinalDescription(
    description,
    result,
    language
) {
    const counts =
        result &&
        result.ingredientCounts
            ? result.ingredientCounts
            : {};

    const hasRoast =
        (counts.roast_syrup || 0) > 0;

    if (!hasRoast) {
        return description;
    }

    const textValue =
        String(
            description || ""
        );

    const normalized =
        textValue.toLowerCase();

    /*
     * すでに焙煎について書かれている結果には、
     * 同じ後味を二重に足さない。
     */
    const alreadyMentionsRoast =
        language === "ja"
            ? textValue.indexOf(
                "焙煎"
            ) >= 0
            : (
                normalized.indexOf(
                    "roast"
                ) >= 0 ||
                normalized.indexOf(
                    "bittersweet"
                ) >= 0
            );

    if (alreadyMentionsRoast) {
        return description;
    }

    const hasBrownSugar =
        (counts.brown_sugar || 0) > 0;

    let aftertaste =
        "";

    if (language === "ja") {
        aftertaste =
            hasBrownSugar
                ? "黒糖の深い甘みの奥に、焙煎のほろ苦い香りが静かに重なっています。"
                : "その奥に、焙煎のほろ苦い香りが静かに残ります。";
    } else {
        aftertaste =
            hasBrownSugar
                ? "Brown sugar leaves a deep sweetness, with a quiet roasted bitterness underneath."
                : "A quiet roasted bitterness lingers underneath.";
    }

    if (textValue === "") {
        return aftertaste;
    }

    return (
        textValue +
        " " +
        aftertaste
    );
}


const generateResultDescriptionBaseForRoastFinalAftertaste =
    generateResultDescription;

generateResultDescription = function() {
    const description =
        generateResultDescriptionBaseForRoastFinalAftertaste.apply(
            this,
            arguments
        );

    const result =
        gameState &&
        gameState.resultData
            ? gameState.resultData
            : null;

    if (!result) {
        return description;
    }

    /*
     * レアレシピは固有の完成文を持つため、
     * 後味を自動で足さず、そのまま見せる。
     */
    const rareCola =
        typeof getRareColaRecipe ===
            "function"
            ? getRareColaRecipe(
                result
            )
            : null;

    if (rareCola) {
        return description;
    }

    const language =
        gameState &&
        gameState.language === "en"
            ? "en"
            : "ja";

    return appendRoastSyrupAftertasteToFinalDescription(
        description,
        result,
        language
    );
};




/*
 * ------------------------------------------------------------
 * BOTTLE LIQUID BAND RENDERING PIPELINE
 * ------------------------------------------------------------
 *
 * 以前は、結合帯・最上段の香り・熟成色・結合モーション・
 * 結合帯全体の香り発光が、drawInspectionBottleLiquidBand を
 * 順に上書きしていた。
 *
 * ここでは描画順をそのまま明示する。
 *
 *   base liquid
 *   → merged band
 *   → top aroma focus
 *   → maturity color / aroma glow
 *   → merge motion
 *   → merged-top aroma glow
 */

function clampColaRollBottleBandValue(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

function drawColaRollBottleMergeRichness(
    ctx,
    geometry,
    ingredient,
    mergedHeight,
    count,
    flash
) {
    const bandWidth =
        geometry.bodyWidth +
        28;

    const halfHeight =
        mergedHeight * 0.43;

    const density =
        Math.min(
            0.17,
            0.075 +
            (
                count - 2
            ) *
                0.028
        );

    ctx.save();

    ctx.fillStyle =
        "rgba(" +
        String(
            ingredient.color.r
        ) +
        "," +
        String(
            ingredient.color.g
        ) +
        "," +
        String(
            ingredient.color.b
        ) +
        "," +
        String(
            density
        ) +
        ")";

    ctx.fillRect(
        -bandWidth,
        -halfHeight,
        bandWidth * 2,
        halfHeight * 2
    );

    if (flash > 0) {
        ctx.fillStyle =
            "rgba(255,245,215," +
            String(
                flash * 0.18
            ) +
            ")";

        ctx.fillRect(
            -bandWidth * 0.76,
            -halfHeight + 2,
            bandWidth * 1.52,
            Math.max(
                1.1,
                mergedHeight * 0.055
            )
        );
    }

    ctx.restore();
}

function getColaRollCurrentTopAromaSlot() {
    const slots =
        getColaRollGlassSlots();

    const structuralIds = [
        "ice",
        "base_syrup",
        "thick_syrup",
    ];

    for (
        let index =
            slots.length - 1;
        index >= 0;
        index -= 1
    ) {
        const token =
            slots[index];

        if (
            !token ||
            structuralIds.indexOf(
                token.ingredientId
            ) >= 0
        ) {
            continue;
        }

        return {
            token: token,
            index: index,
        };
    }

    return null;
}

function getColaRollMergedTopAromaGlowRun() {
    const focus =
        gameState &&
        gameState.topAromaFocus;

    const slots =
        getColaRollGlassSlots();

    if (
        !focus ||
        !focus.token ||
        slots.length <= 0
    ) {
        return null;
    }

    const focusIndex =
        slots.indexOf(
            focus.token
        );

    if (focusIndex < 0) {
        return null;
    }

    const run =
        getColaRollMergeRunAtIndex(
            focusIndex
        );

    /*
     * 香り札が結合帯の一番上でなければ、
     * 従来どおり単独の光に任せる。
     */
    if (
        !run ||
        run.end !== focusIndex
    ) {
        return null;
    }

    return {
        start: run.start,
        end: run.end,
        count: run.count,
        focus: focus,
        visual:
            run.visual || {
                progress: 1,
            },
    };
}

function drawInspectionBottleLiquidBandWithMerge(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    if (
        !gameState ||
        !gameState.glass
    ) {
        return drawInspectionBottleLiquidBandBase(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );
    }

    gameState.bottleMergeIconInstruction =
        null;

    const run =
        getColaRollMergeRunAtIndex(
            index
        );

    if (!run) {
        return drawInspectionBottleLiquidBandBase(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );
    }

    const visual =
        run.visual || {};

    const progress =
        clampColaRollBottleBandValue(
            visual.progress ===
                undefined
                ? 1
                : visual.progress
        );

    const normalAlpha =
        1 -
        progress;

    const isLeader =
        index === run.start;

    /*
     * 結合途中だけ、もとの小カードを薄く残す。
     */
    if (normalAlpha > 0.01) {
        ctx.save();

        ctx.globalAlpha *=
            normalAlpha;

        drawInspectionBottleLiquidBandBase(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );

        ctx.restore();
    }

    /*
     * 先頭カードだけが、複数スロットを占める大カードを描く。
     */
    if (
        isLeader &&
        progress > 0.01
    ) {
        const mergedHeight =
            layerHeight *
            run.count;

        const centerOffset =
            layerHeight *
            (
                run.count - 1
            ) *
            0.5;

        ctx.save();

        ctx.translate(
            0,
            centerOffset
        );

        ctx.globalAlpha *=
            progress;

        drawInspectionBottleLiquidBandBase(
            ctx,
            geometry,
            ingredient,
            mergedHeight,
            index
        );

        drawColaRollBottleMergeRichness(
            ctx,
            geometry,
            ingredient,
            mergedHeight,
            run.count,
            clampColaRollBottleBandValue(
                visual.flash || 0
            )
        );

        ctx.restore();

        gameState.bottleMergeIconInstruction =
            {
                kind: "crossfade",
                ingredientId:
                    run.ingredientId,
                normalAlpha:
                    normalAlpha,
                mergedAlpha:
                    progress,
                mergedOffset:
                    centerOffset,
                mergedScale:
                    1 +
                    Math.min(
                        0.46,
                        0.22 *
                        (
                            run.count - 1
                        )
                    ),
            };

        return;
    }

    /*
     * 結合帯の二枚目以降は、結合の進行に合わせて消える。
     */
    gameState.bottleMergeIconInstruction =
        normalAlpha > 0.01
            ? {
                kind: "normal",
                ingredientId:
                    run.ingredientId,
                normalAlpha:
                    normalAlpha,
            }
            : {
                kind: "hide",
                ingredientId:
                    run.ingredientId,
            };
}

function drawInspectionBottleLiquidBandWithTopAromaFocus(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    drawInspectionBottleLiquidBandWithMerge(
        ctx,
        geometry,
        ingredient,
        layerHeight,
        index
    );

    const focus =
        gameState &&
        gameState.topAromaFocus;

    if (!focus) {
        return;
    }

    const currentTop =
        getColaRollCurrentTopAromaSlot();

    /*
     * 新しい香味が上に来たら、前の札の明るさは残さない。
     */
    if (
        !currentTop ||
        currentTop.token !==
            focus.token
    ) {
        gameState.topAromaFocus =
            null;
        return;
    }

    const slots =
        getColaRollGlassSlots();

    const token =
        slots[index];

    if (
        token !== focus.token
    ) {
        return;
    }

    const now =
        typeof ElapsedTime !==
            "undefined"
            ? ElapsedTime
            : focus.startedAt;

    const elapsed =
        Math.max(
            0,
            now - focus.startedAt
        );

    /*
     * 0.75秒だけ淡い発光。
     * その後も通常より一段だけ明るく残す。
     */
    const flash =
        Math.max(
            0,
            1 - elapsed / 0.75
        );

    const bandWidth =
        geometry.bodyWidth + 28;

    const halfHeight =
        layerHeight * 0.43;

    ctx.save();

    /*
     * 常時はごく薄く。
     * シェイク直後だけ、少しだけ明るくなる。
     */
    ctx.fillStyle =
        "rgba(255, 242, 210, " +
        String(
            0.105 +
            flash * 0.145
        ) +
        ")";

    ctx.fillRect(
        -bandWidth,
        -halfHeight,
        bandWidth * 2,
        halfHeight * 2
    );

    /*
     * 発光の最初だけ、液面に細い反射を一度だけ通す。
     */
    if (flash > 0) {
        ctx.fillStyle =
            "rgba(255, 250, 226, " +
            String(
                flash * 0.12
            ) +
            ")";

        ctx.fillRect(
            -bandWidth,
            -halfHeight + 1.5,
            bandWidth * 2,
            Math.max(
                1.2,
                layerHeight * 0.09
            )
        );
    }

    ctx.restore();
}

function drawInspectionBottleLiquidBandWithMaturity(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    const maturityRatio =
        getColaRollLiveMaturityRatio();

    let maturedIngredient =
        ingredient;

    if (
        ingredient &&
        ingredient.color
    ) {
        maturedIngredient =
            Object.assign(
                {},
                ingredient,
                {
                    color:
                        getColaRollMaturedLiquidColor(
                            ingredient.color,
                            maturityRatio
                        ),
                }
            );
    }

    drawInspectionBottleLiquidBandWithTopAromaFocus(
        ctx,
        geometry,
        maturedIngredient,
        layerHeight,
        index
    );

    drawColaRollAromaGlowOnBand(
        ctx,
        geometry,
        layerHeight,
        index,
        maturityRatio
    );
}

function drawInspectionBottleLiquidBandWithMergeMotion(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    const run =
        getColaRollMergeRunAtIndex(
            index
        );

    if (
        !run ||
        index !==
            run.start
    ) {
        return drawInspectionBottleLiquidBandWithMaturity(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );
    }

    const motion =
        colaRollStartMergeMotion(
            run.visual
        );

    if (!motion) {
        return drawInspectionBottleLiquidBandWithMaturity(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );
    }

    const popProgress =
        colaRollMergeMotionClamp(
            (
                motion.elapsed -
                0.22
            ) /
            0.26
        );

    const pop =
        Math.sin(
            popProgress *
            Math.PI
        );

    const gatherProgress =
        colaRollMergeMotionClamp(
            motion.elapsed /
                0.24
        );

    const gather =
        Math.sin(
            gatherProgress *
            Math.PI
        );

    const strength =
        Math.min(
            1.24,
            0.90 +
            (
                run.count - 2
            ) *
            0.14
        );

    const centerOffset =
        layerHeight *
        (
            run.count - 1
        ) *
        0.5;

    /*
     * 前半は少し締まり、結合した瞬間に横へ「むにっ」と広がる。
     */
    const scaleX =
        1 -
        gather * 0.026 +
        pop * 0.068 *
            strength;

    const scaleY =
        1 +
        gather * 0.012 -
        pop * 0.032 *
            strength;

    ctx.save();

    ctx.translate(
        0,
        centerOffset
    );

    ctx.scale(
        scaleX,
        scaleY
    );

    ctx.translate(
        0,
        -centerOffset
    );

    const result =
        drawInspectionBottleLiquidBandWithMaturity(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );

    ctx.restore();

    colaRollDrawMergeMotionOverlay(
        ctx,
        geometry,
        layerHeight,
        run,
        motion
    );

    return result;
}

function drawInspectionBottleLiquidBandWithMergedTopAromaGlow(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    const mergeRun =
        getColaRollMergedTopAromaGlowRun();

    const isInsideFocusedMergeRun =
        mergeRun &&
        index >=
            mergeRun.start &&
        index <=
            mergeRun.end;

    /*
     * 既存の「最上段一枚だけ」の光を、
     * 結合帯の描画中だけ止める。
     */
    const savedFocus =
        isInsideFocusedMergeRun
            ? gameState.topAromaFocus
            : null;

    if (isInsideFocusedMergeRun) {
        gameState.topAromaFocus =
            null;
    }

    try {
        drawInspectionBottleLiquidBandWithMergeMotion(
            ctx,
            geometry,
            ingredient,
            layerHeight,
            index
        );
    } finally {
        if (isInsideFocusedMergeRun) {
            gameState.topAromaFocus =
                savedFocus;
        }
    }

    /*
     * 結合帯の先頭だけが、帯全体をまとめて光らせる。
     */
    if (
        !mergeRun ||
        index !==
            mergeRun.start
    ) {
        return;
    }

    const progress =
        clampColaRollBottleBandValue(
            mergeRun.visual &&
            mergeRun.visual.progress !==
                undefined
                ? mergeRun.visual.progress
                : 1
        );

    if (progress <= 0.01) {
        return;
    }

    const now =
        typeof ElapsedTime !==
            "undefined"
            ? ElapsedTime
            : mergeRun.focus.startedAt;

    const elapsed =
        Math.max(
            0,
            now -
                mergeRun.focus.startedAt
    );

    /*
     * シェイク直後だけ少したけ明るい。
     * その後も「香りとして立っている」ことが分かる程度に淡く残す。
     */
    const flash =
        Math.max(
            0,
            1 -
                elapsed /
                    0.75
        );

    const mergedHeight =
        layerHeight *
        mergeRun.count;

    const centerOffset =
        layerHeight *
        (
            mergeRun.count - 1
        ) *
        0.5;

    const bandWidth =
        geometry.bodyWidth +
        28;

    const halfHeight =
        mergedHeight * 0.43;

    ctx.save();

    ctx.translate(
        0,
        centerOffset
    );

    ctx.globalAlpha *=
        progress;

    ctx.fillStyle =
        "rgba(255, 242, 210, " +
        String(
            0.07 +
            flash * 0.12
        ) +
        ")";

    ctx.fillRect(
        -bandWidth,
        -halfHeight,
        bandWidth * 2,
        halfHeight * 2
    );

    if (flash > 0.01) {
        ctx.fillStyle =
            "rgba(255, 250, 226, " +
            String(
                flash * 0.08
            ) +
            ")";

        ctx.fillRect(
            -bandWidth * 0.76,
            -1.1,
            bandWidth * 1.52,
            2.2
        );
    }

    ctx.restore();
}

/*
 * 瓶の一枚の液体帯を描く唯一の公開入口。
 *
 * 描画順：
 * base → merge → top aroma → maturity → merge motion → merged-top glow
 */
function drawInspectionBottleLiquidBand(
    ctx,
    geometry,
    ingredient,
    layerHeight,
    index
) {
    return drawInspectionBottleLiquidBandWithMergedTopAromaGlow(
        ctx,
        geometry,
        ingredient,
        layerHeight,
        index
    );
}


/*
 * TITLE CANVAS SCENE — clean reset
 *
 * Title background rendering is rebuilt from scratch.
 *
 * Ownership:
 * - Draw title images directly inside the same canvas as the UI.
 * - Do not use CSS background-image.
 * - Do not use DOM image layers.
 * - Do not draw bokeh, glow, or particles in this first reset.
 *
 * Behaviour:
 * - deterministic 1 -> 2 -> 3 -> 1 loop
 * - 4.0s hold
 * - 1.0s crossfade
 * - title transition freezes the current image
 */

var colaRollTitleCanvasBaseAmbient =
    drawColaAmbientBackground;

var colaRollTitleCanvasScene = {
    initialized: false,
    images: [],
    currentIndex: 0,
    nextIndex: 1,
    phase: "idle",
    fadeStartedAt: 0,
    nextChangeAt: 0,
    holdDuration: 4.0,
    fadeDuration: 1.0,
};

var colaRollTitleCanvasPaths = [
    "./cola-roll-title-workshop-1.jpg",
    "./cola-roll-title-workshop-2.jpg",
    "./cola-roll-title-workshop-3.jpg",
];

function colaRollTitleCanvasNow() {
    return typeof ElapsedTime ===
        "number"
            ? ElapsedTime
            : Date.now() / 1000;
}

function colaRollTitleCanvasClamp(
    value
) {
    return Math.max(
        0,
        Math.min(
            1,
            value
        )
    );
}

var colaRollTitleCanvasParticles =
    null;

var colaRollTitleCanvasAtmosphereLastDrawAt =
    -999;

function colaRollTitleCanvasGetAtmosphereFade() {
    var now =
        colaRollTitleCanvasNow();

    /*
     * 現在は背景Canvas内と通常draw内の両方から
     * 空気演出が呼ばれる。
     * 同じフレーム内の二重描画だけ止める。
     */
    if (
        now -
            colaRollTitleCanvasAtmosphereLastDrawAt <
        0.004
    ) {
        return 0;
    }

    colaRollTitleCanvasAtmosphereLastDrawAt =
        now;

    if (!gameState) {
        return 0;
    }

    if (
        gameState.phase === "TITLE"
    ) {
        return 1;
    }

    if (
        gameState.phase ===
            "TITLE_TRANSITION" &&
        gameState.titleTransition &&
        gameState.titleTransition.active
    ) {
        var duration =
            Math.max(
                0.01,
                gameState.titleTransition.fizzDuration ||
                    0.92
            );

        var progress =
            colaRollTitleCanvasClamp(
                gameState.titleTransition.elapsed /
                    duration
            );

        return 1 - progress * 0.60;
    }

    return 0;
}

function colaRollTitleCanvasEnsureParticles() {
    if (
        colaRollTitleCanvasParticles
    ) {
        return colaRollTitleCanvasParticles;
    }

    colaRollTitleCanvasParticles =
        [];

    /*
     * 上空の粒子。
     * 少し小さめにして、
     * ホコリ感を弱める。
     */
    for (
        var upperIndex = 0;
        upperIndex < 8;
        upperIndex += 1
    ) {
        colaRollTitleCanvasParticles.push({
            baseX:
                0.10 +
                Math.random() * 0.78,

            baseY:
                0.56 +
                Math.random() * 0.22,

            rise:
                0.10 +
                Math.random() * 0.13,

            sway:
                0.008 +
                Math.random() * 0.012,

            swaySpeed:
                0.42 +
                Math.random() * 0.58,

            speed:
                0.018 +
                Math.random() * 0.026,

            size:
                1.4 +
                Math.random() * 1.2,

            alpha:
                42 +
                Math.random() * 20,

            phase:
                Math.random() *
                Math.PI * 2,

            warm:
                Math.random() < 0.82,
        });
    }

    /*
     * 工房と店先のあたり。
     * 下側も少し小さくする。
     */
    for (
        var lowerIndex = 0;
        lowerIndex < 7;
        lowerIndex += 1
    ) {
        colaRollTitleCanvasParticles.push({
            baseX:
                0.16 +
                Math.random() * 0.68,

            baseY:
                0.13 +
                Math.random() * 0.28,

            rise:
                0.08 +
                Math.random() * 0.11,

            sway:
                0.010 +
                Math.random() * 0.016,

            swaySpeed:
                0.50 +
                Math.random() * 0.68,

            speed:
                0.014 +
                Math.random() * 0.022,

            size:
                1.6 +
                Math.random() * 1.4,

            alpha:
                38 +
                Math.random() * 22,

            phase:
                Math.random() *
                Math.PI * 2,

            warm:
                Math.random() < 0.90,
        });
    }

    return colaRollTitleCanvasParticles;
}


function colaRollTitleCanvasDrawBokeh(
    x,
    y,
    size,
    alpha
) {
    if (
        alpha <= 0
    ) {
        return;
    }

    noStroke();

    fill(
        255,
        194,
        118,
        alpha * 0.16
    );

    ellipse(
        x,
        y,
        size * 2.1
    );

    fill(
        255,
        214,
        158,
        alpha * 0.52
    );

    ellipse(
        x,
        y,
        size
    );

    fill(
        255,
        242,
        210,
        alpha * 0.92
    );

    ellipse(
        x -
            size * 0.10,
        y +
            size * 0.08,
        size * 0.26
    );
}


function colaRollTitleCanvasGetContext() {
    if (
        typeof CodeaLite !== "undefined" &&
        CodeaLite.state &&
        CodeaLite.state.ctx
    ) {
        return CodeaLite.state.ctx;
    }

    if (
        typeof document !== "undefined"
    ) {
        var canvas =
            document.querySelector(
                "canvas"
            );

        return canvas
            ? canvas.getContext(
                "2d"
            )
            : null;
    }

    return null;
}

function colaRollTitleCanvasImageReady(
    image
) {
    return !!(
        image &&
        image.complete &&
        image.naturalWidth > 0 &&
        image.naturalHeight > 0
    );
}

function colaRollTitleCanvasHideLegacyLayers() {
    if (
        typeof document === "undefined"
    ) {
        return;
    }

    var ids = [
        "colaRollTitleWorkshopBackdrop",
        "colaRollTitleWorkshopStage",
        "colaRollTitleWorkshopStageV2",
    ];

    for (
        var index = 0;
        index < ids.length;
        index += 1
    ) {
        var layer =
            document.getElementById(
                ids[index]
            );

        if (!layer) {
            continue;
        }

        layer.style.display =
            "none";

        layer.style.opacity =
            "0";
    }
}

function colaRollTitleCanvasInitialize() {
    var scene =
        colaRollTitleCanvasScene;

    if (
        scene.initialized
    ) {
        return;
    }

    scene.initialized =
        true;

    scene.images =
        [];

    for (
        var index = 0;
        index <
        colaRollTitleCanvasPaths.length;
        index += 1
    ) {
        var image =
            new Image();

        image.decoding =
            "async";

        image.loading =
            "eager";

        image.src =
            colaRollTitleCanvasPaths[
                index
            ];

        scene.images.push(
            image
        );
    }

    scene.currentIndex =
        0;

    scene.nextIndex =
        1;

    scene.phase =
        "idle";

    scene.nextChangeAt =
        colaRollTitleCanvasNow() +
        scene.holdDuration;
}

function colaRollTitleCanvasDrawCoverImage(
    context,
    image,
    canvasWidth,
    canvasHeight,
    alpha
) {
    if (
        !colaRollTitleCanvasImageReady(
            image
        ) ||
        alpha <= 0
    ) {
        return false;
    }

    var imageWidth =
        image.naturalWidth;

    var imageHeight =
        image.naturalHeight;

    var scale =
        Math.max(
            canvasWidth /
                imageWidth,
            canvasHeight /
                imageHeight
        );

    var drawWidth =
        imageWidth * scale;

    var drawHeight =
        imageHeight * scale;

    var drawX =
        (
            canvasWidth -
            drawWidth
        ) *
        0.5;

    var drawY =
        canvasHeight -
        drawHeight;

    context.globalAlpha =
        alpha;

    context.drawImage(
        image,
        drawX,
        drawY,
        drawWidth,
        drawHeight
    );

    return true;
}

function colaRollTitleCanvasUpdateCycle() {
    var scene =
        colaRollTitleCanvasScene;

    var now =
        colaRollTitleCanvasNow();

    if (
        scene.phase === "idle" &&
        now >= scene.nextChangeAt
    ) {
        var targetImage =
            scene.images[
                scene.nextIndex
            ];

        if (
            colaRollTitleCanvasImageReady(
                targetImage
            )
        ) {
            scene.phase =
                "fading";

            scene.fadeStartedAt =
                now;
        }

        return;
    }

    if (
        scene.phase !== "fading"
    ) {
        return;
    }

    var progress =
        colaRollTitleCanvasClamp(
            (
                now -
                scene.fadeStartedAt
            ) /
            scene.fadeDuration
        );

    if (progress < 1) {
        return;
    }

    scene.currentIndex =
        scene.nextIndex;

    scene.nextIndex =
        (
            scene.currentIndex + 1
        ) %
        scene.images.length;

    scene.phase =
        "idle";

    scene.nextChangeAt =
        now + scene.holdDuration;
}

function colaRollTitleCanvasDrawVeil(
    context,
    canvasWidth,
    canvasHeight,
    alpha
) {
    const opacity =
        typeof alpha === "number"
            ? Math.max(
                0,
                Math.min(
                    1,
                    alpha
                )
            )
            : 1;

    if (opacity <= 0) {
        return;
    }

    const veil =
        context.createLinearGradient(
            0,
            0,
            0,
            canvasHeight
        );

    veil.addColorStop(
        0,
        "rgba(13, 7, 5, 0.23)"
    );

    veil.addColorStop(
        0.48,
        "rgba(13, 7, 5, 0.07)"
    );

    veil.addColorStop(
        1,
        "rgba(13, 7, 5, 0.03)"
    );

    context.globalAlpha =
        opacity;

    context.fillStyle =
        veil;

    context.fillRect(
        0,
        0,
        canvasWidth,
        canvasHeight
    );
}

function colaRollTitleCanvasDrawDispatchBase(
    context,
    canvasWidth,
    canvasHeight
) {
    /*
     * 注文先画面の背景と同じ配色を、
     * Canvasの物理座標（上が0）で描く。
     *
     * Codea側のY座標は下が0なので、
     * 上下の色順は注文先背景と同じ見え方になるよう
     * 反転している。
     */
    const gradient =
        context.createLinearGradient(
            0,
            0,
            0,
            canvasHeight
        );

    gradient.addColorStop(
        0,
        "rgb(53, 29, 18)"
    );

    gradient.addColorStop(
        0.44,
        "rgb(34, 22, 18)"
    );

    gradient.addColorStop(
        1,
        "rgb(22, 18, 18)"
    );

    context.globalAlpha =
        1;

    context.fillStyle =
        gradient;

    context.fillRect(
        0,
        0,
        canvasWidth,
        canvasHeight
    );

    /*
     * 注文先画面にある中央寄りのコーラ色。
     * Canvas座標へ合わせて上下を反転している。
     */
    context.fillStyle =
        "rgba(73, 34, 20, 0.1255)";

    context.fillRect(
        0,
        canvasHeight * 0.52,
        canvasWidth,
        canvasHeight * 0.30
    );

    /*
     * 注文先画面全体の暗幕。
     */
    context.fillStyle =
        "rgba(15, 10, 9, 0.1883)";

    context.fillRect(
        0,
        0,
        canvasWidth,
        canvasHeight
    );
}

function colaRollTitleCanvasGetImageAlpha() {
    if (
        !gameState ||
        gameState.phase !==
            "TITLE_TRANSITION" ||
        !gameState.titleTransition ||
        !gameState.titleTransition.active
    ) {
        return 1;
    }

    const transition =
        gameState.titleTransition;

    const duration =
        Math.max(
            0.01,
            transition.titleFadeDuration ||
                0.44
        );

    const progress =
        colaRollTitleCanvasClamp(
            transition.elapsed /
                duration
        );

    /*
     * 以前、注文先背景を上から重ねていた時と
     * 同じカーブで、今度は画像自身を薄くする。
     */
    const eased =
        1 -
        Math.pow(
            1 - progress,
            3
        );

    return 1 - eased;
}



function drawColaRollTitleCanvasScene() {
    colaRollTitleCanvasHideLegacyLayers();
    colaRollTitleCanvasInitialize();

    const context =
        colaRollTitleCanvasGetContext();

    if (
        !context ||
        !context.canvas
    ) {
        return;
    }

    const canvas =
        context.canvas;

    const canvasWidth =
        canvas.width;

    const canvasHeight =
        canvas.height;

    const scene =
        colaRollTitleCanvasScene;

    /*
     * 画面遷移中は現在画像を保つ。
     * TITLE の時だけ周期を進める。
     */
    if (
        gameState &&
        gameState.phase === "TITLE"
    ) {
        colaRollTitleCanvasUpdateCycle();
    }

    const imageAlpha =
        colaRollTitleCanvasGetImageAlpha();

    context.save();

    context.setTransform(
        1,
        0,
        0,
        1,
        0,
        0
    );

    context.clearRect(
        0,
        0,
        canvasWidth,
        canvasHeight
    );

    /*
     * 一番下には、最初から注文先画面と同じ背景。
     *
     * ここは消えないため、タイトル画像が薄くなると
     * 背景色が自然に現れる。
     */
    colaRollTitleCanvasDrawDispatchBase(
        context,
        canvasWidth,
        canvasHeight
    );

    const currentImage =
        scene.images[
            scene.currentIndex
        ];

    if (
        imageAlpha > 0.001
    ) {
        if (
            scene.phase ===
            "fading"
        ) {
            const nextImage =
                scene.images[
                    scene.nextIndex
                ];

            const progress =
                colaRollTitleCanvasClamp(
                    (
                        colaRollTitleCanvasNow() -
                        scene.fadeStartedAt
                    ) /
                        scene.fadeDuration
                );

            if (
                colaRollTitleCanvasImageReady(
                    nextImage
                )
            ) {
                colaRollTitleCanvasDrawCoverImage(
                    context,
                    currentImage,
                    canvasWidth,
                    canvasHeight,
                    (
                        1 - progress
                    ) *
                        imageAlpha
                );

                colaRollTitleCanvasDrawCoverImage(
                    context,
                    nextImage,
                    canvasWidth,
                    canvasHeight,
                    progress *
                        imageAlpha
                );
            } else {
                colaRollTitleCanvasDrawCoverImage(
                    context,
                    currentImage,
                    canvasWidth,
                    canvasHeight,
                    imageAlpha
                );
            }
        } else {
            colaRollTitleCanvasDrawCoverImage(
                context,
                currentImage,
                canvasWidth,
                canvasHeight,
                imageAlpha
            );
        }

        /*
         * 画像に付いていた暗いベールも、
         * 画像と一緒に薄くする。
         */
        colaRollTitleCanvasDrawVeil(
            context,
            canvasWidth,
            canvasHeight,
            imageAlpha
        );
    }

    context.restore();

    /*
     * タイトル用の粒子と玉ボケを、
     * 背景の上・UIの下に描く。
     */
    drawColaRollTitleAtmosphere();
}




/*
 * タイトル画面の追加演出は、
 * まず背景切り替えの動作確認を終えるまで停止する。
 */
drawColaRollTitleAtmosphere =
    function() {
        var fade =
            colaRollTitleCanvasGetAtmosphereFade();

        if (fade <= 0.001) {
            return;
        }

        var time =
            colaRollTitleCanvasNow();

        noStroke();
        ellipseMode(CENTER);

        colaRollTitleCanvasDrawBokeh(
            WIDTH * 0.090,
            HEIGHT * 0.315,
            Math.max(
                7,
                WIDTH * 0.028
            ),
            28 *
                fade *
                (
                    0.84 +
                    Math.sin(
                        time * 0.88
                    ) * 0.16
                )
        );

        colaRollTitleCanvasDrawBokeh(
            WIDTH * 0.142,
            HEIGHT * 0.286,
            Math.max(
                5,
                WIDTH * 0.019
            ),
            17 *
                fade *
                (
                    0.88 +
                    Math.sin(
                        time * 0.72 + 1.15
                    ) * 0.12
                )
        );

        var particles =
            colaRollTitleCanvasEnsureParticles();

        for (
            var index = 0;
            index < particles.length;
            index += 1
        ) {
            var particle =
                particles[index];

            var travel =
                (
                    time * particle.speed +
                    particle.phase /
                        (Math.PI * 2)
                ) % 1;

            var x =
                WIDTH * particle.baseX +
                Math.sin(
                    time *
                        particle.swaySpeed +
                    particle.phase
                ) *
                    WIDTH *
                    particle.sway;

            var y =
                HEIGHT * particle.baseY +
                HEIGHT *
                    particle.rise *
                    travel;

            var life =
                Math.sin(
                    travel * Math.PI
                );

            var alpha =
                particle.alpha *
                life *
                fade;

            if (particle.warm) {
                fill(
                    255,
                    234,
                    200,
                    alpha
                );
            } else {
                fill(
                    218,
                    233,
                    255,
                    alpha * 0.78
                );
            }

            ellipse(
                x,
                y,
                particle.size
            );

            if (alpha > 10) {
                if (particle.warm) {
                    fill(
                        255,
                        226,
                        184,
                        alpha * 0.14
                    );
                } else {
                    fill(
                        214,
                        230,
                        255,
                        alpha * 0.12
                    );
                }

                ellipse(
                    x,
                    y,
                    particle.size * 1.45
                );
            }
        }

        noStroke();
        ellipseMode(CENTER);
    };




drawColaAmbientBackground =
    function() {
        var phase =
            gameState
                ? gameState.phase
                : "";

        var isTitlePhase =
            phase === "TITLE" ||
            phase ===
                "TITLE_TRANSITION";

        if (isTitlePhase) {
            drawColaRollTitleCanvasScene();
            return;
        }

        colaRollTitleCanvasHideLegacyLayers();

        return colaRollTitleCanvasBaseAmbient.apply(
            this,
            arguments
        );
    };



/*
 * ------------------------------------------------------------
 * SOUND EFFECTS — WEB AUDIO BUILD
 * ------------------------------------------------------------
 *
 * HTMLAudioElement の currentTime = 0 / play() を毎回呼ぶ方式をやめ、
 * 効果音を一度だけ AudioBuffer にデコードしてメモリに保持する。
 *
 * 再生時は、軽量な AudioBufferSourceNode + GainNode を作るだけ。
 * HTML media の seek・pause・再生口の奪い合いを発生させない。
 *
 * - AudioContext は最初のタップで resume() する。
 * - fetch / decodeAudioData は準備キューだけで行う。
 * - 操作・物理演算・draw の中では読込やデコードをしない。
 * - 未準備の音は一回だけ無音にし、操作とフレームを優先する。
 */
const COLA_ROLL_SOUND_CONFIG = {
    directory: "./Sound/",
    sources: {
        start: "sfx_start.mp3",
        cap_lock: "sfx_cap_lock.ogg",
        cap_launch: "sfx_cap_launch.ogg",
        cap_hit: "sfx_cap_hit.ogg",
        cap_stop: "sfx_cap_stop.ogg",
        move_step: "sfx_move_step.ogg",
        material_popup: "sfx_material_popup.ogg",
        ingredient_drop: "sfx_ingredient_drop.ogg",
        ice_drop: "sfx_ice_drop.ogg",
        fizz: "sfx_fizz.ogg",
        spill: "sfx_spill.ogg",
        finish_chime: "sfx_finish_chime.ogg",
        factory_wake: "sfx_factory_wake.ogg",
        lever_lock: "sfx_lever_lock.ogg",
        roulette_tick: "sfx_roulette_tick.ogg",
        roulette_lock: "sfx_roulette_lock.ogg",
        slot_shuffle: "sfx_slot_shuffle.ogg",
        delivery_setdown: "sfx_delivery_setdown.ogg",

        /* 追加：工程・記録の節目を知らせる6音 */
        move_counter_set: "sfx_move_counter_set.ogg",
        route_switch: "sfx_route_switch.ogg",
        capacity_warning: "sfx_capacity_warning.ogg",
        bottle_finish: "sfx_bottle_finish.ogg",
        inspect: "sfx_inspect.ogg",
        history_open: "sfx_history_open.ogg",
        tile_arrival: "sfx_tile_arrival.ogg",
    },
    volumes: {
        start: 0.52,
        cap_lock: 0.32,
        cap_launch: 0.50,
        cap_hit: 0.24,
        cap_stop: 0.44,
        move_step: 0.28,
        material_popup: 0.30,
        ingredient_drop: 0.42,
        ice_drop: 0.40,
        fizz: 0.44,
        spill: 0.52,
        finish_chime: 0.56,
        factory_wake: 0.34,
        lever_lock: 0.42,
        roulette_tick: 0.28,
        roulette_lock: 0.44,
        slot_shuffle: 0.42,
        delivery_setdown: 0.38,

        /* 新しい音は既存の主効果音を邪魔しない控えめな基準音量 */
        move_counter_set: 0.34,
        route_switch: 0.38,
        capacity_warning: 0.34,
        bottle_finish: 0.42,
        inspect: 0.26,
        history_open: 0.30,
        tile_arrival: 0.32,
    },
    cooldowns: {
        start: 0.20,
        cap_lock: 0.08,
        cap_launch: 0.08,
        cap_hit: 0.15,
        cap_stop: 0.16,
        move_step: 0.06,
        material_popup: 0.12,
        ingredient_drop: 0.12,
        ice_drop: 0.12,
        fizz: 0.14,
        spill: 0.18,
        finish_chime: 0.12,
        factory_wake: 0.08,
        lever_lock: 0.08,
        roulette_tick: 0.055,
        roulette_lock: 0.12,
        slot_shuffle: 0.16,
        delivery_setdown: 0.24,

        /* 連続タップや同一フレームの重複から守る */
        move_counter_set: 0.14,
        route_switch: 0.20,
        capacity_warning: 0.40,
        bottle_finish: 0.30,
        inspect: 0.10,
        history_open: 0.18,
        tile_arrival: 0.16,
    },
};

/*
 * 最初の注文票タップの泡音だけは、タイトル表示中の idle 時間に先読みする。
 * それ以外はタイトル遷移の後半から一つずつ非同期デコードする。
 */
const COLA_ROLL_SOUND_BOOT_IDS = [
    "start",
];

const COLA_ROLL_SOUND_WARMUP_IDS = [
    "factory_wake",
    "cap_lock",
    "cap_launch",
    "cap_hit",
    "cap_stop",
    "move_step",
    "lever_lock",
    "roulette_tick",
    "roulette_lock",
    "material_popup",
    "ingredient_drop",
    "ice_drop",
    "fizz",
    "spill",
    "slot_shuffle",
    "finish_chime",
    "delivery_setdown",

    /* 追加した工程・履歴音も、タイトル遷移後に一音ずつデコードする。 */
    "move_counter_set",
    "route_switch",
    "capacity_warning",
    "bottle_finish",
    "inspect",
    "history_open",
    "tile_arrival",
];

const colaRollSoundState = {
    context: null,
    masterGain: null,
    buffers: {},
    loading: {},
    failed: {},
    lastPlayedAt: {},
    bootRequested: false,
    warmupRequested: false,
    warmupQueue: [],
    warmupTimer: null,
    debugLastError: "",
};

function colaRollSoundNow() {
    return (
        typeof performance !== "undefined" &&
        performance.now
    )
        ? performance.now() / 1000
        : Date.now() / 1000;
}

function colaRollSoundClamp(
    value,
    minimum,
    maximum
) {
    return Math.max(
        minimum,
        Math.min(
            maximum,
            value
        )
    );
}

function colaRollGetAudioContextConstructor() {
    const root =
        typeof globalThis !== "undefined"
            ? globalThis
            : (
                typeof window !== "undefined"
                    ? window
                    : null
            );

    if (!root) {
        return null;
    }

    return root.AudioContext ||
        root.webkitAudioContext ||
        null;
}

function colaRollEnsureAudioContext() {
    if (colaRollSoundState.context) {
        return colaRollSoundState.context;
    }

    const AudioContextConstructor =
        colaRollGetAudioContextConstructor();

    if (!AudioContextConstructor) {
        return null;
    }

    try {
        let context = null;

        try {
            context = new AudioContextConstructor(
                {
                    latencyHint: "interactive",
                }
            );
        } catch (optionError) {
            context = new AudioContextConstructor();
        }

        const masterGain =
            context.createGain();

        masterGain.gain.value = 1;
        masterGain.connect(
            context.destination
        );

        colaRollSoundState.context =
            context;
        colaRollSoundState.masterGain =
            masterGain;

        return context;
    } catch (error) {
        colaRollSoundState.debugLastError =
            String(
                error && error.message
                    ? error.message
                    : error
            );

        return null;
    }
}

/*
 * iOS Safari では音を出す AudioContext をユーザー操作から再開する必要がある。
 * ここでは resume 要求だけを行い、読込・デコードはしない。
 */
function colaRollUnlockAudio() {
    const context =
        colaRollEnsureAudioContext();

    if (!context) {
        return false;
    }

    if (
        context.state === "suspended" ||
        context.state === "interrupted"
    ) {
        try {
            const resumeResult =
                context.resume();

            if (
                resumeResult &&
                typeof resumeResult.catch ===
                    "function"
            ) {
                resumeResult.catch(
                    function() {
                        /* 音が許可されない端末でもゲームは続行する。 */
                    }
                );
            }
        } catch (error) {
            /* 音声失敗をゲーム入力へ伝播させない。 */
        }
    }

    return true;
}

function colaRollDecodeSoundData(
    context,
    data
) {
    /*
     * Promise 版と callback 版の両方を扱う。
     * Safari を含むモバイルブラウザでは Promise 版が主だが、
     * 古い実装でもこの関数だけで吸収する。
     */
    return new Promise(
        function(resolve, reject) {
            let settled = false;

            const resolveOnce = function(buffer) {
                if (settled) {
                    return;
                }

                settled = true;
                resolve(buffer);
            };

            const rejectOnce = function(error) {
                if (settled) {
                    return;
                }

                settled = true;
                reject(error);
            };

            try {
                const result =
                    context.decodeAudioData(
                        data,
                        resolveOnce,
                        rejectOnce
                    );

                if (
                    result &&
                    typeof result.then ===
                        "function"
                ) {
                    result.then(
                        resolveOnce
                    ).catch(
                        rejectOnce
                    );
                }
            } catch (error) {
                rejectOnce(error);
            }
        }
    );
}

function colaRollPrepareSound(
    soundId
) {
    if (
        !COLA_ROLL_SOUND_CONFIG.sources[
            soundId
        ]
    ) {
        return Promise.resolve(null);
    }

    if (
        colaRollSoundState.buffers[
            soundId
        ]
    ) {
        return Promise.resolve(
            colaRollSoundState.buffers[
                soundId
            ]
        );
    }

    if (
        colaRollSoundState.loading[
            soundId
        ]
    ) {
        return colaRollSoundState.loading[
            soundId
        ];
    }

    if (
        colaRollSoundState.failed[
            soundId
        ]
    ) {
        return Promise.resolve(null);
    }

    const context =
        colaRollEnsureAudioContext();

    if (
        !context ||
        typeof fetch !== "function"
    ) {
        colaRollSoundState.failed[
            soundId
        ] = true;

        return Promise.resolve(null);
    }

    const url =
        COLA_ROLL_SOUND_CONFIG.directory +
        COLA_ROLL_SOUND_CONFIG.sources[
            soundId
        ];

    const task =
        fetch(
            url,
            {
                cache: "force-cache",
            }
        ).then(
            function(response) {
                if (!response.ok) {
                    throw new Error(
                        "Sound load failed: " +
                        soundId +
                        " (" +
                        String(
                            response.status
                        ) +
                        ")"
                    );
                }

                return response.arrayBuffer();
            }
        ).then(
            function(data) {
                /*
                 * 一部実装では decodeAudioData が ArrayBuffer を detach するため、
                 * 元データを使い回さずこの一回専用として渡す。
                 */
                return colaRollDecodeSoundData(
                    context,
                    data
                );
            }
        ).then(
            function(buffer) {
                colaRollSoundState.buffers[
                    soundId
                ] = buffer;

                delete colaRollSoundState.loading[
                    soundId
                ];

                return buffer;
            }
        ).catch(
            function(error) {
                colaRollSoundState.failed[
                    soundId
                ] = true;

                colaRollSoundState.debugLastError =
                    String(
                        error && error.message
                            ? error.message
                            : error
                    );

                delete colaRollSoundState.loading[
                    soundId
                ];

                return null;
            }
        );

    colaRollSoundState.loading[
        soundId
    ] = task;

    return task;
}

function colaRollPlaySound(
    soundId,
    options
) {
    const buffer =
        colaRollSoundState.buffers[
            soundId
        ];

    /*
     * 再生経路では fetch / decode / retry を絶対に起こさない。
     * 準備できていない一回は無音にして、入力と描画を守る。
     */
    if (!buffer) {
        return false;
    }

    const context =
        colaRollEnsureAudioContext();

    const masterGain =
        colaRollSoundState.masterGain;

    if (!context || !masterGain) {
        return false;
    }

    const settings = options || {};
    const now = colaRollSoundNow();

    const cooldown =
        typeof settings.cooldown === "number"
            ? settings.cooldown
            : (
                COLA_ROLL_SOUND_CONFIG.cooldowns[
                    soundId
                ] ||
                0
            );

    const lastPlayedAt =
        colaRollSoundState.lastPlayedAt[
            soundId
        ];

    if (
        typeof lastPlayedAt === "number" &&
        now - lastPlayedAt < cooldown
    ) {
        return false;
    }

    colaRollSoundState.lastPlayedAt[
        soundId
    ] = now;

    try {
        const source =
            context.createBufferSource();

        const gain =
            context.createGain();

        const volume =
            colaRollSoundClamp(
                typeof settings.volume ===
                    "number"
                    ? settings.volume
                    : (
                        COLA_ROLL_SOUND_CONFIG.volumes[
                            soundId
                        ] ||
                        0.5
                    ),
                0,
                1
            );

        const playbackRate =
            typeof settings.playbackRate ===
                "number"
                ? colaRollSoundClamp(
                    settings.playbackRate,
                    0.5,
                    2
                )
                : 1;

        source.buffer = buffer;

        gain.gain.setValueAtTime(
            volume,
            context.currentTime
        );

        source.playbackRate.setValueAtTime(
            playbackRate,
            context.currentTime
        );

        source.connect(gain);
        gain.connect(masterGain);

        source.onended = function() {
            try {
                source.disconnect();
                gain.disconnect();
            } catch (disconnectError) {
                /* すでに解放済みなら何もしない。 */
            }
        };

        source.start(0);
    } catch (error) {
        return false;
    }

    return true;
}

/*
 * 既存の到着チャイム・工房起動の呼び出し口を維持する。
 * 実装は全て AudioBuffer 再生へ統一する。
 */
function colaRollPlayCriticalSound(
    soundId,
    options
) {
    return colaRollPlaySound(
        soundId,
        options
    );
}

/*
 * lock はタップ時、launch は finishCapPowerSlide() の実発射時。
 * 音の種類もタイミングも以前の設計を保つ。
 */
function colaRollPlayShot() {
    return colaRollPlaySound(
        "cap_lock",
        {
            volume: 0.32,
            cooldown: 0,
        }
    );
}

function colaRollPlayRouletteTick(
    index
) {
    const maximum =
        Math.max(
            1,
            ROULETTE_FLOW_CONFIG.rollCount - 1
        );

    const progress =
        colaRollSoundClamp(
            (index - 1) / maximum,
            0,
            1
        );

    colaRollPlaySound(
        "roulette_tick",
        {
            volume:
                0.23 +
                progress * 0.10,
            playbackRate:
                0.93 +
                progress * 0.10,
            cooldown: 0.055,
        }
    );
}

/*
 * 読込とデコードは一度に重ねず、一つが終わってから次へ進める。
 * Web Audio 化の目的は「再生時の引っかかり」を消すことなので、
 * 準備側でもゲームフレームを奪わないようにする。
 */
function colaRollScheduleNextSoundWarmup(
    delay
) {
    if (
        colaRollSoundState.warmupQueue.length <=
        0
    ) {
        colaRollSoundState.warmupTimer =
            null;
        return;
    }

    const wait =
        typeof delay === "number"
            ? delay
            : 84;

    colaRollSoundState.warmupTimer =
        setTimeout(
            function() {
                const soundId =
                    colaRollSoundState.warmupQueue.shift();

                if (!soundId) {
                    colaRollScheduleNextSoundWarmup(
                        84
                    );
                    return;
                }

                colaRollPrepareSound(
                    soundId
                ).then(
                    function() {
                        colaRollScheduleNextSoundWarmup(
                            84
                        );
                    }
                );
            },
            Math.max(
                0,
                wait
            )
        );
}

function colaRollRequestBootSoundWarmup() {
    if (colaRollSoundState.bootRequested) {
        return;
    }

    colaRollSoundState.bootRequested =
        true;

    /*
     * タイトルの一枚絵が出て落ち着いてから、一音だけ準備する。
     * 最初の注文票タップ時に無理なデコードを起こさない。
     */
    setTimeout(
        function() {
            for (
                let index = 0;
                index < COLA_ROLL_SOUND_BOOT_IDS.length;
                index += 1
            ) {
                colaRollPrepareSound(
                    COLA_ROLL_SOUND_BOOT_IDS[
                        index
                    ]
                );
            }
        },
        220
    );
}

function colaRollRequestSoundWarmup() {
    if (colaRollSoundState.warmupRequested) {
        return;
    }

    colaRollSoundState.warmupRequested =
        true;

    colaRollSoundState.warmupQueue =
        COLA_ROLL_SOUND_WARMUP_IDS.slice();

    /*
     * タイトルの泡と背景切替が済んでから開始する。
     * タイトルタップ直後の見た目を最優先にするため、
     * ここでは即時 fetch / decode をしない。
     */
    colaRollScheduleNextSoundWarmup(
        620
    );
}

/*
 * 最初の「注文を見る」タップで、まず AudioContext を有効化してから
 * タイトル遷移の後半へデコードキューを渡す。
 */
const startTitleTransitionBaseForWebAudio =
    startTitleTransition;

startTitleTransition = function() {
    colaRollUnlockAudio();
    colaRollRequestSoundWarmup();

    return startTitleTransitionBaseForWebAudio.apply(
        this,
        arguments
    );
};

/*
 * どの操作から始まっても iOS のユーザー操作制約を満たす。
 * touched 本体には手を入れず、入口で AudioContext だけを resume する。
 */
const touchedBaseForWebAudioUnlock =
    touched;

touched = function(touch) {
    if (
        touch &&
        touch.state === ENDED
    ) {
        colaRollUnlockAudio();
    }

    return touchedBaseForWebAudioUnlock.apply(
        this,
        arguments
    );
};

/*
 * 起動時の一斉 HTMLAudio preload は廃止。
 * title の静かな idle 時間で start だけデコードしておく。
 */
colaRollRequestBootSoundWarmup();

